from dsl import *
from utils import *


def generate_00576224(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    numcols = unifint(diff_lb, diff_ub, (2, 4))
    chosen = sample(cols, numcols)
    cells = []
    for _ in range(4):
        cells.append(choice(chosen))
    if len(set(cells)) == 1:
        alt = other(chosen, cells[0]) if len(chosen) > 1 else other(cols, cells[0])
        cells[unifint(diff_lb, diff_ub, (0, 3))] = alt
    gi = (
        (cells[0], cells[1]),
        (cells[2], cells[3]),
    )
    go = verify_00576224(gi)
    return {'input': gi, 'output': go}


def generate_007bbfb7(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    h = unifint(diff_lb, diff_ub, (2, 5))
    w = unifint(diff_lb, diff_ub, (2, 5))
    c = canvas(0, (h, w))
    numcd = unifint(diff_lb, diff_ub, (0, (h * w) // 2))
    numc = choice((numcd, h * w - numcd))
    numc = min(max(1, numc), h * w - 1)
    inds = totuple(asindices(c))
    locs = sample(inds, numc)
    fgc = choice(cols)
    gi = fill(c, fgc, locs)
    go = canvas(0, (h**2, w**2))
    for loc in locs:
        go = fill(go, fgc, shift(locs, multiply(loc, (h, w))))
    return {'input': gi, 'output': go}


def generate_009d5c81(diff_lb: float, diff_ub: float) -> dict:
    h = 14
    w = 14
    gi = canvas(0, (h, w))

    marker_up = frozenset({(0, 0), (0, 1), (0, 2), (1, 0), (1, 2), (2, 1)})
    marker_down = frozenset({(0, 1), (1, 0), (1, 1), (1, 2), (2, 0), (2, 2)})
    marker_plus = frozenset({(0, 1), (1, 0), (1, 1), (1, 2), (2, 1)})
    mopts = (marker_up, marker_down, marker_plus)

    mh = unifint(diff_lb, diff_ub, (5, 6))
    mw = unifint(diff_lb, diff_ub, (6, 9))

    max_cells = mh * mw - 1
    n8 = unifint(diff_lb, diff_ub, (max(5, mh + mw - 2), max_cells))

    shape = {(0, 0)}
    frontier = set(dneighbors((0, 0)))
    for _ in range(n8 - 1):
        cand = choice(tuple(frontier))
        shape.add(cand)
        frontier.discard(cand)
        frontier |= set(dneighbors(cand)) - shape
    shape = normalize(frozenset(shape))

    sh = height(shape)
    sw = width(shape)

    top_margin = unifint(diff_lb, diff_ub, (0, 3))
    left_margin = unifint(diff_lb, diff_ub, (0, w - sw))
    max_top = min(6, h - 4 - sh)
    top = min(top_margin, max_top)
    left = left_margin

    shape_shifted = shift(shape, (top, left))
    gi = fill(gi, 8, shape_shifted)

    marker = choice(mopts)
    mleft_max = w - 3
    mleft_pref = unifint(diff_lb, diff_ub, (1, 4))
    mleft = min(mleft_pref, mleft_max)

    min_mtop = lowermost(shape_shifted) + 2
    max_mtop = h - 4
    if min_mtop > max_mtop:
        delta = min_mtop - max_mtop
        top = max(0, top - delta)
        shape_shifted = shift(shape, (top, left))
        gi = canvas(0, (h, w))
        gi = fill(gi, 8, shape_shifted)
        min_mtop = lowermost(shape_shifted) + 2

    mtop = min(max(min_mtop, unifint(diff_lb, diff_ub, (8, 10))), h - 4)
    gi = fill(gi, 1, shift(marker, (mtop, mleft)))

    go = verify_009d5c81(gi)
    return {'input': gi, 'output': go}


def generate_00d62c1b(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(4, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (5, 30))
    w = unifint(diff_lb, diff_ub, (5, 30))
    bgc, fgc = sample(cols, 2)
    gi = canvas(bgc, (h, w))
    nblocks = unifint(diff_lb, diff_ub, (1, (h * w) // 20))
    succ = 0
    tr = 0
    maxtr = 5 * nblocks
    inds = asindices(gi)
    while succ < nblocks and tr < maxtr:
        tr += 1
        oh = randint(3, 8)
        ow = randint(3, 8)
        cands = sfilter(inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
        if len(cands) == 0:
            continue
        loc = choice(totuple(cands))
        loci, locj = loc
        bx = box(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
        bx = bx - set(sample(totuple(corners(bx)), randint(0, 4)))
        if bx.issubset(inds) and len(inds - bx) > (h * w) // 2 + 1:
            gi = fill(gi, fgc, bx)
            succ += 1
            inds = inds - bx
    maxnnoise = max(0, (h * w) // 2 - 1 - colorcount(gi, fgc))
    namt = unifint(diff_lb, diff_ub, (0, maxnnoise))
    noise = sample(totuple(inds), namt)
    gi = fill(gi, fgc, noise)
    objs = objects(gi, T, F, F)
    cands = colorfilter(objs, bgc)
    res = mfilter(cands, compose(flip, rbind(bordering, gi)))
    go = fill(gi, 4, res)
    return {'input': gi, 'output': go}


def generate_00dbd492(diff_lb: float, diff_ub: float) -> dict:
    sizes_all = (5, 7, 9)
    nframes = unifint(diff_lb, diff_ub, (1, 3))
    sizes = sample(sizes_all, nframes)

    maxs = max(sizes)
    hmin = maxs
    wmin = maxs
    h = unifint(diff_lb, diff_ub, (hmin, 30))
    w = unifint(diff_lb, diff_ub, (wmin, 30))

    gi = canvas(0, (h, w))
    occupied = set()

    shuffle(sizes)
    for s in sizes:
        placed = False
        for _ in range(200):
            r = unifint(diff_lb, diff_ub, (0, h - s))
            c = unifint(diff_lb, diff_ub, (0, w - s))
            rect = backdrop(frozenset({(r, c), (r + s - 1, c + s - 1)}))
            if any((i, j) in occupied for i, j in rect):
                continue

            frame = box(frozenset({(r, c), (r + s - 1, c + s - 1)}))
            gi = fill(gi, 2, frame)

            inner = delta(frame)
            inner_cells = totuple(inner)
            if len(inner_cells) > 0:
                maxdots = min(len(inner_cells), max(1, (s - 2) // 2))
                ndots = unifint(diff_lb, diff_ub, (0, maxdots))
                if ndots > 0:
                    dots = sample(inner_cells, ndots)
                    gi = fill(gi, 2, frozenset(dots))

            for ij in rect:
                occupied.add(ij)
            placed = True
            break

        if not placed:
            s = 5
            for r in range(h - s + 1):
                done = False
                for c in range(w - s + 1):
                    rect = backdrop(frozenset({(r, c), (r + s - 1, c + s - 1)}))
                    if any((i, j) in occupied for i, j in rect):
                        continue
                    frame = box(frozenset({(r, c), (r + s - 1, c + s - 1)}))
                    gi = fill(gi, 2, frame)
                    inner = delta(frame)
                    inner_cells = totuple(inner)
                    if len(inner_cells) > 0:
                        ndots = randint(0, min(len(inner_cells), 1))
                        if ndots > 0:
                            dots = sample(inner_cells, ndots)
                            gi = fill(gi, 2, frozenset(dots))
                    for ij in rect:
                        occupied.add(ij)
                    done = True
                    break
                if done:
                    break

    go = verify_00dbd492(gi)
    return {'input': gi, 'output': go}


def generate_017c7c7b(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (0, 2))
    h = unifint(diff_lb, diff_ub, (3, 10))
    w = unifint(diff_lb, diff_ub, (2, 30))
    h += h
    fgc = choice(cols)
    go = canvas(0, (h + h // 2, w))
    oh = unifint(diff_lb, diff_ub, (1, h//3*2))
    ow = unifint(diff_lb, diff_ub, (1, w))
    locj = randint(0, w - ow)
    bounds = asindices(canvas(-1, (oh, ow)))
    ncellsd = unifint(diff_lb, diff_ub, (0, (h * w) // 2))
    ncells = choice((ncellsd, oh * ow - ncellsd))
    ncells = min(max(1, ncells), oh * ow)
    obj = sample(totuple(bounds), ncells)
    for k in range((2*h)//oh):
        go = fill(go, 2, shift(obj, (k*oh, 0)))
    gi = replace(go[:h], 2, fgc)
    return {'input': gi, 'output': go}


def generate_025d127b(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (5, 30))
    w = unifint(diff_lb, diff_ub, (5, 30))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    numcols = unifint(diff_lb, diff_ub, (1, 9))
    ccols = sample(remcols, numcols)
    nobjs = unifint(diff_lb, diff_ub, (1, (h * w) // 20))
    succ = 0
    tr = 0
    maxtr = 5 * nobjs
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    inds = asindices(gi)
    while succ < nobjs and tr < maxtr:
        tr += 1
        oh = randint(3, 6)
        ow = randint(3, 6)
        cands = sfilter(inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
        if len(cands) == 0:
            continue
        loc = choice(totuple(cands))
        topl = connect((0, 0), (0, ow - 1))
        leftl = connect((1, 0), (oh - 2, oh - 3))
        rightl = connect((1, ow), (oh - 2, ow + oh - 3))
        botl = connect((oh - 1, oh - 2), (oh - 1, oh - 3 + ow))
        inobj = topl | leftl | rightl | botl
        outobj = shift(topl, (0, 1)) | botl | shift(leftl, (0, 1)) | connect((1, ow+1), (oh - 3, ow + oh - 3)) | {(oh - 2, ow + oh - 3)}
        outobj = sfilter(outobj, lambda ij: ij[1] <= rightmost(inobj))
        fullobj = inobj | outobj
        inobj = shift(inobj, loc)
        outobj = shift(outobj, loc)
        fullobj = shift(fullobj, loc)
        if fullobj.issubset(inds):
            inds = (inds - fullobj) - mapply(neighbors, fullobj)
            succ += 1
            col = choice(ccols)
            gi = fill(gi, col, inobj)
            go = fill(go, col, outobj)
    return {'input': gi, 'output': go}


def generate_03560426(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    h = 10
    w = 10
    bgc = 0

    nobj = unifint(diff_lb, diff_ub, (3, 4))

    def rand_shape(maxh, maxw):
        oh = unifint(diff_lb, diff_ub, (1, maxh))
        ow = unifint(diff_lb, diff_ub, (1, maxw))
        area = oh * ow
        ncells = unifint(diff_lb, diff_ub, (1, area))
        start = (randint(0, oh - 1), randint(0, ow - 1))
        cells = {start}
        frontier = set()
        for c in cells:
            frontier |= (dneighbors(c) & backdrop(frozenset({(0, (0, 0)), (0, (oh - 1, ow - 1))})))
        for _ in range(area * 3):
            if len(cells) >= ncells:
                break
            candset = set()
            for c in cells:
                for nb in dneighbors(c):
                    if 0 <= nb[0] < oh and 0 <= nb[1] < ow and nb not in cells:
                        candset.add(nb)
            if len(candset) == 0:
                break
            cells.add(choice(tuple(candset)))
        return frozenset(cells)

    for _ in range(200):
        gi = canvas(bgc, (h, w))
        colors = sample(cols, nobj)

        shapes = []
        chain_end = (0, 0)
        ok = True
        for k in range(nobj):
            remh = h - chain_end[0]
            remw = w - chain_end[1]
            if remh <= 0 or remw <= 0:
                ok = False
                break
            shp = rand_shape(remh, remw)
            shp = normalize(shp)
            ch, cw = shape(shp)
            if ch > remh or cw > remw:
                ok = False
                break
            shapes.append(recolor(colors[k], shp))
            chain_end = lrcorner(shift(shp, chain_end))
        if not ok:
            continue

        lefts = []
        prev_left = -1
        placements = []
        occupied = set()
        for obj in shapes:
            oh, ow = shape(obj)
            maxj = w - ow
            minj = prev_left + 1
            if minj > maxj:
                ok = False
                break
            j = unifint(diff_lb, diff_ub, (minj, maxj))
            maxi = h - oh
            i = unifint(diff_lb, diff_ub, (max(0, h - 4), maxi)) if maxi >= max(0, h - 4) else unifint(diff_lb, diff_ub, (0, maxi))
            shifted = shift(obj, (i, j))
            inds = toindices(shifted)
            if len(inds & occupied) > 0:
                ok = False
                break
            occupied |= set(inds)
            placements.append(shifted)
            lefts.append(j)
            prev_left = j
        if not ok:
            continue

        shuffle(placements)
        for obj in placements:
            gi = paint(gi, obj)

        go = verify_03560426(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    gi = canvas(0, (10, 10))
    gi = fill(gi, 1, connect((7, 0), (9, 1)))
    gi = fill(gi, 2, connect((8, 3), (9, 4)))
    gi = fill(gi, 3, connect((8, 6), (9, 7)))
    go = verify_03560426(gi)
    return {'input': gi, 'output': go}


def generate_045e512c(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (11, 30))
    w = unifint(diff_lb, diff_ub, (11, 30))
    while True:
        oh = unifint(diff_lb, diff_ub, (2, min(4, (h - 2) // 3)))
        ow = unifint(diff_lb, diff_ub, (2, min(4, (w - 2) // 3)))
        bounds = asindices(canvas(-1, (oh, ow)))
        c1 = choice(totuple(connect((0, 0), (oh - 1, 0))))
        c2 = choice(totuple(connect((0, 0), (0, ow - 1))))
        c3 = choice(totuple(connect((oh - 1, ow - 1), (oh - 1, 0))))
        c4 = choice(totuple(connect((oh - 1, ow - 1), (0, ow - 1))))
        obj = {c1, c2, c3, c4}
        remcands = totuple(bounds - obj)
        ncells = unifint(diff_lb, diff_ub, (0, len(remcands)))
        for k in range(ncells):
            loc = choice(remcands)
            obj.add(loc)
            remcands = remove(loc, remcands)
        objt = normalize(obj)
        cc = canvas(0, shape(obj))
        cc = fill(cc, 1, objt)
        if len(colorfilter(objects(cc, T, T, F), 1)) == 1:
            break
    loci = randint(oh + 1, h - 2 * oh - 1)
    locj = randint(ow + 1, w - 2 * ow - 1)
    loc = (loci, locj)
    bgc, objc = sample(cols, 2)
    remcols = remove(bgc, remove(objc, cols))
    ncols = unifint(diff_lb, diff_ub, (1, 8))
    ccols = sample(remcols, ncols)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    obj = shift(recolor(objc, obj), loc)
    gi = paint(gi, obj)
    go = paint(go, obj)
    options = totuple(neighbors((0, 0)))
    ndirs = unifint(diff_lb, diff_ub, (1, 8))
    dirs = sample(options, ndirs)
    dcols = [choice(ccols) for k in range(ndirs)]
    hbars = hfrontier((loci - 2, 0)) | hfrontier((loci+oh+1, 0))
    vbars = vfrontier((0, locj - 2)) | vfrontier((0, locj+ow+1))
    bars = hbars | vbars
    ofs = increment((oh, ow))
    for direc, col in zip(dirs, dcols):
        indicatorobj = shift(obj, multiply(direc, increment((oh, ow))))
        indicatorobj = sfilter(indicatorobj, lambda cij: cij[1] in bars)
        nindsd = unifint(diff_lb, diff_ub, (0, len(indicatorobj) - 1))
        ninds = len(indicatorobj) - nindsd
        indicatorobj = set(sample(totuple(indicatorobj), ninds))
        if len(indicatorobj) > 0 and len(indicatorobj) < len(obj):
            gi = fill(gi, col, indicatorobj)
            for k in range(1, 10):
                go = fill(go, col, shift(obj, multiply(multiply(k, direc), ofs)))
    return {'input': gi, 'output': go}


def generate_0520fde7(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(2, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (2, 30))
    w = unifint(diff_lb, diff_ub, (2, 14))
    bgc = 0
    remcols = remove(bgc, cols)
    barcol = choice(remcols)
    remcols = remove(barcol, remcols)
    cola = choice(remcols)
    colb = choice(remcols)
    canv = canvas(bgc, (h, w))
    inds = totuple(asindices(canv))
    gbar = canvas(barcol, (h, 1))
    mp = (h * w) // 2
    devrng = (0, mp)
    deva = unifint(diff_lb, diff_ub, devrng)
    devb = unifint(diff_lb, diff_ub, devrng)
    sgna = choice((+1, -1))
    sgnb = choice((+1, -1))
    deva = sgna * deva
    devb = sgnb * devb
    numa = mp + deva
    numb = mp + devb
    numa = max(min(h * w - 1, numa), 1)
    numb = max(min(h * w - 1, numb), 1)
    a = sample(inds, numa)
    b = sample(inds, numb)
    gia = fill(canv, cola, a)
    gib = fill(canv, colb, b)
    gi = hconcat(hconcat(gia, gbar), gib)
    go = fill(canv, 2, set(a) & set(b))
    if choice((True, False)):
        gi = dmirror(gi)
        go = dmirror(go)
    return {'input': gi, 'output': go}


def generate_05269061(diff_lb: float, diff_ub: float) -> dict:
    dim_bounds = (2, 30)
    colopts = interval(1, 10, 1)
    d = unifint(diff_lb, diff_ub, dim_bounds)
    go = canvas(0, (d, d))
    gi = canvas(0, (d, d))
    if choice((True, False)):
        period_bounds = (2, min(2*d-2, 9))
        num = unifint(diff_lb, diff_ub, period_bounds)
        cols = tuple(choice(colopts) for k in range(num))
        keeps = [choice(interval(j, 2*d-1, num)) for j in range(num)]
        for k, col in enumerate((cols * 30)[:2*d-1]):
            lin = shoot(toivec(k), UP_RIGHT)
            go = fill(go, col, lin)
            if keeps[k % num] == k:
                gi = fill(gi, col, lin)
    else:
        period_bounds = (2, min(d, 9))
        num = unifint(diff_lb, diff_ub, period_bounds)
        cols = tuple(choice(colopts) for k in range(num))
        keeps = [choice(interval(j, d, num)) for j in range(num)]
        for k, col in enumerate((cols * 30)[:d]):
            lin = hfrontier(toivec(k))
            go = fill(go, col, lin)
            if keeps[k % num] == k:
                gi = fill(gi, col, lin)
    if choice((True, False)):
        gi = vmirror(gi)
        go = vmirror(go)
    return {'input': gi, 'output': go}


def generate_05a7bcf2(diff_lb: float, diff_ub: float) -> dict:
    h = 30
    w = 30
    bg = 0
    gi = canvas(bg, (h, w))

    orient_vertical = choice((True, False))

    if orient_vertical:
        div = unifint(diff_lb, diff_ub, (8, 21))
        gi = fill(gi, 8, connect((0, div), (h - 1, div)))

        left_side = choice((True, False))
        if left_side:
            max4w = max(1, div - 2)
            max2w = max(1, w - div - 2)
            nobj = unifint(diff_lb, diff_ub, (1, min(6, h // 3 + 1)))
            used_rows = set()
            for _ in range(nobj):
                oh = unifint(diff_lb, diff_ub, (1, min(5, h)))
                ow4 = unifint(diff_lb, diff_ub, (1, min(5, max4w)))
                ow2 = unifint(diff_lb, diff_ub, (1, min(5, max2w)))
                if h - oh < 0:
                    continue
                for _try in range(50):
                    top = randint(0, h - oh)
                    rows = set(range(top, top + oh))
                    if len(rows & used_rows) == 0:
                        break
                else:
                    continue
                used_rows |= rows
                j4 = randint(0, div - ow4 - 1)
                j2 = randint(div + 1, w - ow2)
                gi = fill(gi, 4, backdrop(frozenset({(top, j4), (top + oh - 1, j4 + ow4 - 1)})))
                gi = fill(gi, 2, backdrop(frozenset({(top, j2), (top + oh - 1, j2 + ow2 - 1)})))
        else:
            max4w = max(1, w - div - 2)
            max2w = max(1, div - 1)
            nobj = unifint(diff_lb, diff_ub, (1, min(6, h // 3 + 1)))
            used_rows = set()
            for _ in range(nobj):
                oh = unifint(diff_lb, diff_ub, (1, min(5, h)))
                ow4 = unifint(diff_lb, diff_ub, (1, min(5, max4w)))
                ow2 = unifint(diff_lb, diff_ub, (1, min(5, max2w)))
                for _try in range(50):
                    top = randint(0, h - oh)
                    rows = set(range(top, top + oh))
                    if len(rows & used_rows) == 0:
                        break
                else:
                    continue
                used_rows |= rows
                j4 = randint(div + 1, w - ow4)
                j2 = randint(0, div - ow2)
                gi = fill(gi, 4, backdrop(frozenset({(top, j4), (top + oh - 1, j4 + ow4 - 1)})))
                gi = fill(gi, 2, backdrop(frozenset({(top, j2), (top + oh - 1, j2 + ow2 - 1)})))
    else:
        div = unifint(diff_lb, diff_ub, (8, 21))
        gi = fill(gi, 8, connect((div, 0), (div, w - 1)))

        top_side = choice((True, False))
        if top_side:
            max4h = max(1, div - 2)
            max2h = max(1, h - div - 2)
            nobj = unifint(diff_lb, diff_ub, (1, min(6, w // 3 + 1)))
            used_cols = set()
            for _ in range(nobj):
                oh4 = unifint(diff_lb, diff_ub, (1, min(5, max4h)))
                oh2 = unifint(diff_lb, diff_ub, (1, min(5, max2h)))
                ow = unifint(diff_lb, diff_ub, (1, min(5, w)))
                for _try in range(50):
                    left = randint(0, w - ow)
                    cols = set(range(left, left + ow))
                    if len(cols & used_cols) == 0:
                        break
                else:
                    continue
                used_cols |= cols
                i4 = randint(0, div - oh4 - 1)
                i2 = randint(div + 1, h - oh2)
                gi = fill(gi, 4, backdrop(frozenset({(i4, left), (i4 + oh4 - 1, left + ow - 1)})))
