def generate_05f2a901(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (8, 30))
    w = unifint(diff_lb, diff_ub, (8, 30))
    objh = unifint(diff_lb, diff_ub, (2, min(w//2, h//2)))
    objw = unifint(diff_lb, diff_ub, (objh, w//2))
    bb = asindices(canvas(-1, (objh, objw)))
    sp = choice(totuple(bb))
    obj = {sp}
    bb = remove(sp, bb)
    ncells = unifint(diff_lb, diff_ub, (objh + objw, objh * objw))
    for k in range(ncells - 1):
        obj.add(choice(totuple((bb - obj) & mapply(dneighbors, obj))))
    if height(obj) * width(obj) == len(obj):
        obj = remove(choice(totuple(obj)), obj)
    obj = normalize(obj)
    objh, objw = shape(obj)
    loci = unifint(diff_lb, diff_ub, (3, h - objh))
    locj = unifint(diff_lb, diff_ub, (0, w - objw))
    loc = (loci, locj)
    bgc, fgc, destc = sample(cols, 3)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    obj = shift(obj, loc)
    gi = fill(gi, fgc, obj)
    sqd = randint(1, min(w, loci - 1))
    locisq = randint(0, loci-sqd-1)
    locjsq = randint(locj-sqd+1, locj+objw-1)
    locsq = (locisq, locjsq)
    sq = backdrop({(locisq, locjsq), (locisq+sqd-1, locjsq+sqd-1)})
    gi = fill(gi, destc, sq)
    go = fill(go, destc, sq)
    while len(obj & sq) == 0:
        obj = shift(obj, (-1, 0))
    obj = shift(obj, (1, 0))
    go = fill(go, fgc, obj)
    mfs = (identity, dmirror, cmirror, vmirror, hmirror, rot90, rot180, rot270)
    nmfs = choice((1, 2))
    for fn in sample(mfs, nmfs):
        gi = fn(gi)
        go = fn(go)
    return {'input': gi, 'output': go}


def generate_0607ce86(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    nrg = unifint(diff_lb, diff_ub, (2, 4))
    ncg = unifint(diff_lb, diff_ub, (2, 4))
    mh = unifint(diff_lb, diff_ub, (4, 6))
    mw = unifint(diff_lb, diff_ub, (4, 6))
    vgap = unifint(diff_lb, diff_ub, (1, 3))
    hgap = unifint(diff_lb, diff_ub, (1, 3))
    top = unifint(diff_lb, diff_ub, (0, 2))
    left = unifint(diff_lb, diff_ub, (0, 2))
    bottom = unifint(diff_lb, diff_ub, (0, 4))
    right = unifint(diff_lb, diff_ub, (0, 4))
    h = top + nrg * mh + (nrg - 1) * vgap + bottom
    w = left + ncg * mw + (ncg - 1) * hgap + right

    motif_cols = sample(cols, min(4, len(cols)))
    if len(motif_cols) < 2:
        motif_cols = (1, 2, 3, 4)

    motif = []
    mode = choice((0, 1, 2))
    for i in range(mh):
        row = []
        for j in range(mw):
            if mode == 0:
                if i == 0:
                    v = motif_cols[0]
                else:
                    if len(motif_cols) >= 3:
                        if j < mw // 2:
                            v = motif_cols[1]
                        elif j == mw // 2 and mw % 2 == 1:
                            v = motif_cols[2]
                        else:
                            v = motif_cols[min(2, len(motif_cols) - 1)]
                    else:
                        v = motif_cols[1]
            elif mode == 1:
                if i == 0:
                    v = motif_cols[0]
                elif i == mh - 1:
                    v = motif_cols[1]
                else:
                    if j == 0 or j == mw - 1:
                        v = motif_cols[min(2, len(motif_cols) - 1)]
                    else:
                        v = motif_cols[min(3, len(motif_cols) - 1)]
            else:
                if i == 0:
                    v = motif_cols[0]
                else:
                    band = (j * len(motif_cols)) // mw
                    if band >= len(motif_cols):
                        band = len(motif_cols) - 1
                    v = motif_cols[band]
            row.append(v)
        motif.append(tuple(row))
    motif = tuple(motif)

    gi = canvas(0, (h, w))
    go = canvas(0, (h, w))

    starts_r = tuple(top + k * (mh + vgap) for k in range(nrg))
    starts_c = tuple(left + k * (mw + hgap) for k in range(ncg))

    for sr in starts_r:
        for sc in starts_c:
            for i in range(mh):
                for j in range(mw):
                    gi = fill(gi, motif[i][j], frozenset({(sr + i, sc + j)}))
                    go = fill(go, motif[i][j], frozenset({(sr + i, sc + j)}))

    copies = nrg * ncg
    max_inside_noise = max(1, (mh * mw) // 3)
    inside_noise_per_copy = unifint(diff_lb, diff_ub, (1, max_inside_noise))
    for sr in starts_r:
        for sc in starts_c:
            cells = [(sr + i, sc + j) for i in range(mh) for j in range(mw)]
            nmut = min(len(cells), inside_noise_per_copy)
            for loc in sample(cells, nmut):
                r, c = loc
                cur = gi[r][c]
                repls = remove(cur, cols)
                gi = fill(gi, choice(repls), frozenset({loc}))

    outside = [(i, j) for i in range(h) for j in range(w)]
    motif_cells = set()
    for sr in starts_r:
        for sc in starts_c:
            motif_cells |= {(sr + i, sc + j) for i in range(mh) for j in range(mw)}
    outside = [x for x in outside if x not in motif_cells]
    if len(outside) > 0:
        max_out_noise = min(len(outside), max(3, (h * w) // 8))
        nout = unifint(diff_lb, diff_ub, (1, max_out_noise))
        for loc in sample(outside, nout):
            gi = fill(gi, choice(cols), frozenset({loc}))

    if gi == go:
        loc = choice(outside) if len(outside) > 0 else (starts_r[0], starts_c[0])
        cur = gi[loc[0]][loc[1]]
        repls = remove(cur, cols) if cur != 0 else cols
        gi = fill(gi, choice(repls), frozenset({loc}))

    return {'input': gi, 'output': go}


