def generate_06df4c85(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    oh = unifint(diff_lb, diff_ub, (1, 4))
    ow = unifint(diff_lb, diff_ub, (1, 4))
    numh = unifint(diff_lb, diff_ub, (3, 31 // (oh + 1)))
    numw = unifint(diff_lb, diff_ub, (3, 31 // (ow + 1)))
    bgc, linc = sample(cols, 2)
    remcols = difference(cols, (bgc, linc))
    ncols = unifint(diff_lb, diff_ub, (1, min(8, (numh * numh) // 3)))
    ccols = sample(remcols, ncols)
    fullh = numh * oh + numh - 1
    fullw = numw * ow + numw - 1
    gi = canvas(linc, (fullh, fullw))
    sgi = asindices(canvas(bgc, (oh, ow)))
    for a in range(numh):
        for b in range(numw):
            gi = fill(gi, bgc, shift(sgi, (a * (oh + 1), b * (ow + 1))))
    go = tuple(e for e in gi)
    sinds = asindices(canvas(-1, (oh, ow)))
    for col in ccols:
        inds = occurrences(go, recolor(bgc, sinds))
        if len(inds) == 0:
            break
        loc = choice(totuple(inds))
        narms = randint(1, 4)
        armdirs = sample(totuple(dneighbors((0, 0))), narms)
        succ = 0
        for armdir in armdirs:
            x, y = armdir
            arm = []
            for k in range(1, max(numh, numw)):
                nextloc = add(loc, (k * x * (oh + 1), k * y * (ow + 1)))
                if nextloc not in inds:
                    break
                arm.append(nextloc)
            if len(arm) < 2:
                continue
            aidx = unifint(diff_lb, diff_ub, (1, len(arm) - 1))
            endp = arm[aidx]
            gi = fill(gi, col, shift(sinds, endp))
            go = fill(go, col, mapply(lbind(shift, sinds), set(arm[:aidx+1])))
            succ += 1
        gi = fill(gi, col, shift(sinds, loc))
        go = fill(go, col, shift(sinds, loc))
    return {'input': gi, 'output': go}


def generate_070dd51e(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 20))
    gi = canvas(0, (h, w))
    cols = interval(1, 10, 1)

    max_pairs = min(8, len(cols), (h + w) // 4)
    npairs = unifint(diff_lb, diff_ub, (2, max(2, max_pairs)))

    nvert_max = min(npairs - 1, w)
    nvert = unifint(diff_lb, diff_ub, (1, max(1, nvert_max)))
    nhorz = npairs - nvert

    chosen_cols = sample(cols, npairs)
    vcols = chosen_cols[:nvert]
    hcols = chosen_cols[nvert:]

    used_vc = set()
    used_hr = set()
    used_hcells = set()
    used_vcells = set()

    # place vertical pairs first
    for col in vcols:
        avail_cs = [j for j in range(w) if j not in used_vc]
        if len(avail_cs) == 0:
            break
        j = choice(avail_cs)
        used_vc.add(j)
        minsep = 2 if h >= 5 else 1
        r1max = h - 1 - minsep
        if r1max < 0:
            r1, r2 = 0, h - 1
        else:
            r1 = unifint(diff_lb, diff_ub, (0, r1max))
            r2 = unifint(diff_lb, diff_ub, (r1 + minsep, h - 1))
        gi = fill(gi, col, frozenset({(r1, j), (r2, j)}))
        used_vcells.add((r1, j))
        used_vcells.add((r2, j))

    # place horizontal pairs with unique rows and avoiding vertical endpoints
    for col in hcols:
        avail_rs = [i for i in range(h) if i not in used_hr]
        if len(avail_rs) == 0:
            break
        shuffle(avail_rs)
        placed = False
        for i in avail_rs:
            forbidden_js = {j for (r, j) in used_vcells if r == i}
            candidates = [j for j in range(w) if j not in forbidden_js]
            if len(candidates) < 2:
                continue
            candidates = sorted(candidates)
            minsep = 2 if w >= 5 else 1
            possible = []
            for aidx in range(len(candidates)):
                for bidx in range(aidx + 1, len(candidates)):
                    j1 = candidates[aidx]
                    j2 = candidates[bidx]
                    if j2 - j1 >= minsep:
                        possible.append((j1, j2))
            if len(possible) == 0:
                continue
            j1, j2 = choice(possible)
            gi = fill(gi, col, frozenset({(i, j1), (i, j2)}))
            used_hr.add(i)
            used_hcells.add((i, j1))
            used_hcells.add((i, j2))
            placed = True
            break
        if not placed:
            # fallback: place anywhere valid on an unused row
            i = choice(avail_rs)
            j1 = unifint(diff_lb, diff_ub, (0, max(0, w - 2)))
            j2 = unifint(diff_lb, diff_ub, (j1 + 1, w - 1))
            gi = fill(gi, col, frozenset({(i, j1), (i, j2)}))
            used_hr.add(i)
            used_hcells.add((i, j1))
            used_hcells.add((i, j2))

    go = verify_070dd51e(gi)
    return {'input': gi, 'output': go}


