def generate_103eff5b(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, remove(8, interval(0, 10, 1)))
    ph = unifint(diff_lb, diff_ub, (3, 5))
    pw = unifint(diff_lb, diff_ub, (2, 4))
