    maxrw = max(pw + 2, pw * fac + pw + 6)
    h = unifint(diff_lb, diff_ub, (maxrh, min(30, maxrh + 10)))
    w = unifint(diff_lb, diff_ub, (maxrw, min(30, maxrw + 10)))

    small = canvas(0, (ph, pw))
    ncols = unifint(diff_lb, diff_ub, (min(3, ph * pw), min(6, ph * pw)))
    usecols = sample(cols, ncols)

    ncells = unifint(diff_lb, diff_ub, (max(4, (ph * pw) // 2), ph * pw))
    inds = sample(totuple(asindices(small)), ncells)

    for ij in inds:
        small = fill(small, choice(usecols), frozenset({ij}))

    if numcolors(small) < 3:
        zinds = totuple(ofcolor(small, 0))
        if len(zinds) > 0:
            for c in sample(usecols, min(2, len(usecols))):
                small = fill(small, c, frozenset({choice(zinds)}))
                zinds = tuple(ij for ij in zinds if index(small, ij) == 0)

    largepat = rot90(small)
    large8 = replace(upscale(largepat, fac), 0, 8)

    lh, lw = shape(large8)

