    small_j = randint(0, w - pw)
    large_j = randint(0, w - lw)

    gi = canvas(0, (h, w))
    gi = paint(gi, shift(asobject(small), (small_i, small_j)))
    gi = paint(gi, shift(asobject(large8), (large_i, large_j)))

    go = verify_103eff5b(gi)
    return {'input': gi, 'output': go}


