def generate_137eaa0f(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (2, 4))
    w = unifint(diff_lb, diff_ub, (2, 4))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    dotc = choice(remcols)
    remcols = remove(dotc, remcols)
    go = canvas(dotc, (h, w))
    inds = totuple(asindices(go))
    loc = choice(inds)
    reminds = remove(loc, inds)
    nc = unifint(diff_lb, diff_ub, (1, min(h * w - 1, 8)))
    choscols = sample(remcols, nc)
    cd = {c: set() for c in choscols}
    for c in choscols:
        ij = choice(reminds)
        cd[c].add(ij)
        reminds = remove(ij, reminds)
    for ri in reminds:
        cd[choice(choscols)].add(ri)
    for c, idxes in cd.items():
        go = fill(go, c, idxes)
    gih = unifint(diff_lb, diff_ub, (min(h, w) * 2, 30))
    giw = unifint(diff_lb, diff_ub, (min(h, w) * 2, 30))
    objs = tuple(
        normalize(insert((dotc, loc), frozenset({(c, ij) for ij in cd[c]}))) \
            for c in choscols
    )
    maxtr = min(h, w) * 2
    maxtrtot = 1000
    while True:
        succ = True
        gi = canvas(bgc, (gih, giw))
        inds = asindices(gi)
        for obj in objs:
            oh, ow = shape(obj)
            succ2 = False
            tr = 0
            while tr < maxtr and not succ2:
                loci = randint(0, gih - oh)
                locj = randint(0, giw - ow)
                plcd = shift(obj, (loci, locj))
                tr += 1
                if toindices(plcd).issubset(inds):
                    succ2 = True
            if succ2:
                gi = paint(gi, plcd)
                inds = difference(inds, toindices(plcd))
                inds = difference(inds, mapply(neighbors, toindices(plcd)))
            else:
                succ = False
                break
        if succ:
            break
        maxtrtot += 1
        if maxtrtot < 1000:
            break
        maxtr = int(maxtr * 1.5)
        gih = randint(gih, 30)
        giw = randint(giw, 30)
    return {'input': gi, 'output': go}


def generate_137f0df0(diff_lb: float, diff_ub: float) -> dict:
    h = 10
    w = 10
    gi = canvas(0, (h, w))

    bh = choice((6, 8, 10))
    bw = choice((6, 8, 9))
    top = choice((0, 1, 2, 3, 4)) if bh < h else 0
    left = choice((0, 1, 2, 3, 4)) if bw < w else 0
    if top + bh > h:
        top = h - bh
    if left + bw > w:
        left = w - bw

    row_step = choice((2, 3))
    col_step = choice((2, 3))
    block_h = choice((1, 2))
    block_w = choice((1, 2))

    row_starts = list(range(top, top + bh - block_h + 1, row_step))
    col_starts = list(range(left, left + bw - block_w + 1, col_step))

    if len(row_starts) < 2:
        row_starts = [top, top + bh - block_h]
    if len(col_starts) < 2:
        col_starts = [left, left + bw - block_w]

    max_rows_pick = len(row_starts)
    max_cols_pick = len(col_starts)
    nrs = unifint(diff_lb, diff_ub, (2, max_rows_pick))
    ncs = unifint(diff_lb, diff_ub, (2, max_cols_pick))
    chosen_rows = sorted(sample(row_starts, nrs))
    chosen_cols = sorted(sample(col_starts, ncs))

    gray = frozenset()
    for r in chosen_rows:
        for c in chosen_cols:
            gray = gray | backdrop(frozenset({(r, c), (r + block_h - 1, c + block_w - 1)}))

    gi = fill(gi, 5, gray)

    if gi == verify_137f0df0(gi):
        r0, r1, c0, c1 = bbox(gray)
        if c1 - c0 + 1 >= 3:
            extra = frozenset({(r0, c0 + 1)})
        elif r1 - r0 + 1 >= 3:
            extra = frozenset({(r0 + 1, c0)})
        else:
            extra = frozenset({(r0, c0)})
            gray = gray - extra
            gi = canvas(0, (h, w))
            gi = fill(gi, 5, gray)

    go = verify_137f0df0(gi)
    return {'input': gi, 'output': go}


def generate_13f06aa5(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 20))
    w = unifint(diff_lb, diff_ub, (10, 20))
    bgc = choice(cols)
    remcols = remove(bgc, cols)

    nptrs = unifint(diff_lb, diff_ub, (1, 4))

    gi = canvas(bgc, (h, w))

    dirs = ['up', 'down', 'left', 'right']
    shuffle(dirs)
    dirs = dirs[:nptrs]

    used = set()
    placed = 0

    for d in dirs:
        for _ in range(100):
            basec, tipc = sample(list(remcols), 2)

            if d in ('up', 'down'):
                bw = unifint(diff_lb, diff_ub, (3, 5))
                if bw % 2 == 0:
                    bw = max(3, bw - 1)
                mid = bw // 2
                if d == 'up':
                    # bar on bottom row, tip one row above at midpoint
                    i0 = randint(1, h - 3)
                    j0 = randint(0, w - bw)
                    cells = set()
                    for jj in range(j0, j0 + bw):
                        cells.add((i0 + 1, jj))
                    tip = (i0, j0 + mid)
                    cells.add(tip)
                else:
                    # bar on top row, tip one row below at midpoint
                    i0 = randint(0, h - 3)
                    j0 = randint(0, w - bw)
                    cells = set()
                    for jj in range(j0, j0 + bw):
                        cells.add((i0, jj))
                    tip = (i0 + 1, j0 + mid)
                    cells.add(tip)
            else:
                bh = unifint(diff_lb, diff_ub, (3, 5))
                if bh % 2 == 0:
                    bh = max(3, bh - 1)
                mid = bh // 2
                if d == 'left':
                    # bar on right column, tip one col to the left at midpoint
                    i0 = randint(0, h - bh)
                    j0 = randint(1, w - 3)
                    cells = set()
                    for ii in range(i0, i0 + bh):
                        cells.add((ii, j0 + 1))
                    tip = (i0 + mid, j0)
                    cells.add(tip)
                else:
                    # bar on left column, tip one col to the right at midpoint
                    i0 = randint(0, h - 3)
                    j0 = randint(0, w - 3)
                    cells = set()
                    for ii in range(i0, i0 + bh):
                        cells.add((ii, j0))
                    tip = (i0 + mid, j0 + 1)
                    cells.add(tip)

            # Check overlap with padding
            padded = set()
            for r, c in cells:
                padded.add((r, c))
                for dr in (-1, 0, 1):
                    for dc in (-1, 0, 1):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < h and 0 <= nc < w:
                            padded.add((nr, nc))

            if padded & used:
                continue

            # All cells must be in bounds
            if any(r < 0 or r >= h or c < 0 or c >= w for r, c in cells):
                continue

            obj = frozenset((basec, ij) for ij in cells if ij != tip)
            obj = obj | frozenset({(tipc, tip)})
            gi = paint(gi, obj)
            used |= padded
            placed += 1
            break

    if placed == 0:
        # Fallback: place a single upward-pointing shape
        basec, tipc = sample(list(remcols), 2)
        i0 = h // 2
        j0 = w // 2
        cells = {(i0 + 1, j0 - 1), (i0 + 1, j0), (i0 + 1, j0 + 1)}
        tip = (i0, j0)
        cells.add(tip)
        obj = frozenset((basec, ij) for ij in cells if ij != tip)
        obj = obj | frozenset({(tipc, tip)})
        gi = paint(gi, obj)

    go = verify_13f06aa5(gi)
    return {'input': gi, 'output': go}


def generate_140c817e(diff_lb: float, diff_ub: float) -> dict:
    bgcols = remove(1, remove(2, remove(3, interval(0, 10, 1))))
    h = unifint(diff_lb, diff_ub, (7, 16))
