def generate_14754a24(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (12, 22))
    w = unifint(diff_lb, diff_ub, (12, 22))
    gi = canvas(0, (h, w))
    inds = set(asindices(gi))

    nnoise5 = unifint(diff_lb, diff_ub, (h * w // 4, h * w // 2))
    if nnoise5 > 0:
        locs5 = sample(totuple(asindices(gi)), min(nnoise5, h * w))
        gi = fill(gi, 5, frozenset(locs5))

    maxpat = max(2, (h * w) // 30)
    npat = unifint(diff_lb, diff_ub, (2, maxpat))

    occupied = set()
    success = 0
    trials = 0
    maxtrials = 200

    shape_types = ("domino_h", "domino_v", "elbow", "triple_h", "triple_v")

    while success < npat and trials < maxtrials:
        trials += 1
        typ = choice(shape_types)
        r = randint(1, h - 2)
        c = randint(1, w - 2)

        if typ == "domino_h":
            fours = {(r, c), (r, c + 1)}
        elif typ == "domino_v":
            fours = {(r, c), (r + 1, c)}
        elif typ == "elbow":
            ori = choice((0, 1, 2, 3))
            if ori == 0:
                fours = {(r, c), (r + 1, c), (r, c + 1)}
            elif ori == 1:
                fours = {(r, c), (r + 1, c), (r, c - 1)}
            elif ori == 2:
                fours = {(r, c), (r - 1, c), (r, c + 1)}
            else:
                fours = {(r, c), (r - 1, c), (r, c - 1)}
        elif typ == "triple_h":
            if 1 <= c <= w - 2:
                fours = {(r, c - 1), (r, c), (r, c + 1)}
            else:
                continue
        else:
            if 1 <= r <= h - 2:
                fours = {(r - 1, c), (r, c), (r + 1, c)}
            else:
                continue

        if any(not (0 < i < h - 1 and 0 < j < w - 1) for i, j in fours):
            continue

        cross_union = set()
        for q in fours:
            cross_union.add(q)
            cross_union |= (dneighbors(q) & asindices(gi))

        diag_union = set()
        for q in fours:
            diag_union |= (ineighbors(q) & asindices(gi))

        if any(p in occupied for p in cross_union | diag_union):
            continue

        gi = fill(gi, 4, frozenset(fours))
        five_targets = frozenset(cross_union - fours)
        gi = fill(gi, 5, five_targets)

        occupied |= cross_union | diag_union
        success += 1

    if success == 0:
        r = h // 2
        c = w // 2
        fours = frozenset({(r, c), (r, c + 1)})
        gi = fill(gi, 4, fours)
        cross_union = set()
        for q in fours:
            cross_union.add(q)
            cross_union |= (dneighbors(q) & asindices(gi))
        gi = fill(gi, 5, frozenset(cross_union - set(fours)))

    nnoise4 = unifint(diff_lb, diff_ub, (1, max(1, h * w // 20)))
    candidates4 = [ij for ij in totuple(asindices(gi)) if gi[ij[0]][ij[1]] != 4]
    shuffle(candidates4)
    for loc in candidates4[:nnoise4]:
        gi = fill(gi, 4, frozenset({loc}))

    go = verify_14754a24(gi)
    if gi == go:
        for ij in totuple(asindices(gi)):
            if gi[ij[0]][ij[1]] == 5:
                gi = fill(gi, 4, frozenset({ij}))
                break
        go = verify_14754a24(gi)
    return {'input': gi, 'output': go}


def generate_1478ab18(diff_lb: float, diff_ub: float) -> dict:
    h = 8
    w = 8
    bgc = 7
    markc = 5

    def valid_pairs():
        pairs = []
        inds = [(i, j) for i in range(h) for j in range(w)]
        for a in inds:
            for b in inds:
                if a == b:
                    continue
                seg = connect(a, b)
                if len(seg) <= 1:
                    continue
                if not (hline(seg) or vline(seg)):
                    continue
                pairs.append((a, b, len(seg)))
        return pairs

    def valid_diag_pairs():
        pairs = []
        inds = [(i, j) for i in range(h) for j in range(w)]
        for a in inds:
            for b in inds:
                if a == b:
                    continue
                seg = connect(a, b)
                if len(seg) <= 1:
                    continue
                if hline(seg) or vline(seg):
                    continue
                if len(seg) > 0:
                    pairs.append((a, b, len(seg)))
        return pairs

    mode = choice(("rowcol", "diag", "mixed"))
    if mode == "rowcol":
        candpairs = valid_pairs()
    elif mode == "diag":
        candpairs = valid_diag_pairs()
    else:
        candpairs = valid_pairs() + valid_diag_pairs()

    maxextra = unifint(diff_lb, diff_ub, (1, 4))
    target_span = unifint(diff_lb, diff_ub, (3, 8))

    scored = []
    for a, b, ln in candpairs:
        x11 = (a[0], b[1])
        x12 = (b[0], a[1])
        third = x12 if x11 in (a, b) else x11
        if third == a or third == b:
            continue
        tri = connect(a, b) | connect(a, third) | connect(b, third)
        if len(tri) <= ln:
            continue
        score = abs(ln - target_span)
        scored.append((score, a, b, ln, third, tri))
    scored = sorted(scored, key=lambda t: t[0])

    picked = None
    topn = min(len(scored), max(1, unifint(diff_lb, diff_ub, (1, min(12, len(scored))))))
    if topn > 0:
        picked = choice(scored[:topn])
    else:
        a, b, ln = choice(candpairs)
        x11 = (a[0], b[1])
        x12 = (b[0], a[1])
        third = x12 if x11 in (a, b) else x11
        tri = connect(a, b) | connect(a, third) | connect(b, third)
        picked = (0, a, b, ln, third, tri)

    _, a, b, _, third, tri = picked
    markers = {a, b, third}

    allinds = [(i, j) for i in range(h) for j in range(w)]
    forbidden = set(tri)
    extras = []

    maxtries = 200
    desired = maxextra
    for _ in range(maxtries):
        if len(extras) >= desired:
            break
        cand = choice(allinds)
        if cand in forbidden or cand in markers or cand in extras:
            continue
        testmarks = set(markers) | set(extras) | {cand}
        ok = True
        bestlen = len(connect(a, b))
        for p in testmarks:
            for q in testmarks:
                if p == q:
                    continue
                seg = connect(p, q)
                if len(seg) <= 1:
                    continue
                if hline(seg) or vline(seg):
                    if len(seg) > bestlen:
                        ok = False
                        break
                else:
                    if len(seg) > 0 and len(seg) > bestlen:
                        ok = False
                        break
            if not ok:
                break
        if ok:
            extras.append(cand)

    gi = canvas(bgc, (h, w))
    gi = fill(gi, markc, frozenset(markers | set(extras)))
    go = verify_1478ab18(gi)
    return {'input': gi, 'output': go}


def generate_14b8e18c(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(2, interval(0, 10, 1))
    bgc = choice(cols)
    objcols = remove(bgc, cols)

    h = unifint(diff_lb, diff_ub, (10, 20))
    w = unifint(diff_lb, diff_ub, (10, 20))
    gi = canvas(bgc, (h, w))

    nsq = unifint(diff_lb, diff_ub, (1, 4))
    nnoise = unifint(diff_lb, diff_ub, (0, 4))

    occupied = set()
    reserved = set()

    def can_place(cells, halo):
        for i, j in cells | halo:
            if not (0 <= i < h and 0 <= j < w):
                return False
        if any((i, j) in occupied for i, j in cells):
            return False
        if any((i, j) in reserved for i, j in halo):
            return False
        return True

    sq_succ = 0
    for _ in range(100):
        if sq_succ >= nsq:
            break
        s = unifint(diff_lb, diff_ub, (2, min(8, h - 2, w - 2)))
        if s < 2 or h - s - 2 < 0 or w - s - 2 < 0:
            continue
        top = randint(1, h - s - 1)
        left = randint(1, w - s - 1)

        full = backdrop(frozenset({(top, left), (top + s - 1, left + s - 1)}))
        halo = outbox(full)
        if not can_place(set(full), set(halo)):
            continue

        col = choice(objcols)
        style = choice(("solid", "ring", "corners", "diagx", "plus"))

        if style == "solid":
            shp = full
        elif style == "ring":
            shp = box(full)
        elif style == "corners":
            shp = corners(full)
        elif style == "diagx":
            shp = connect((top, left), (top + s - 1, left + s - 1)) | connect((top, left + s - 1), (top + s - 1, left))
        else:
            mid = s // 2
            shp = connect((top + mid, left), (top + mid, left + s - 1)) | connect((top, left + mid), (top + s - 1, left + mid))

        gi = fill(gi, col, shp)
        occupied |= set(full)
        reserved |= set(full) | set(halo)
        sq_succ += 1

    noise_succ = 0
    for _ in range(120):
        if noise_succ >= nnoise:
            break
        oh = unifint(diff_lb, diff_ub, (1, min(6, h - 1)))
        ow = unifint(diff_lb, diff_ub, (1, min(6, w - 1)))
        if oh < 1 or ow < 1:
            continue
        if oh == ow and oh > 1:
            continue
        if h - oh < 0 or w - ow < 0:
            continue
        top = randint(0, h - oh)
        left = randint(0, w - ow)
        rect = backdrop(frozenset({(top, left), (top + oh - 1, left + ow - 1)}))
        if any((i, j) in reserved for i, j in rect):
            continue

        col = choice(objcols)
        style = choice(("solid", "lineh", "linev", "corners", "diag"))
        if style == "solid":
            shp = rect
        elif style == "lineh":
            rr = top + randint(0, oh - 1)
            shp = connect((rr, left), (rr, left + ow - 1))
        elif style == "linev":
            cc = left + randint(0, ow - 1)
            shp = connect((top, cc), (top + oh - 1, cc))
        elif style == "corners":
            shp = corners(rect)
        else:
            if oh == 1 or ow == 1:
                shp = rect
            else:
                shp = choice((
                    connect((top, left), (top + min(oh, ow) - 1, left + min(oh, ow) - 1)),
                    connect((top, left + ow - 1), (top + min(oh, ow) - 1, left + ow - min(oh, ow)))
                ))

        gi = fill(gi, col, shp)
        reserved |= set(rect)
        noise_succ += 1

    go = verify_14b8e18c(gi)
    return {'input': gi, 'output': go}


def generate_150deff5(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (2, 8))
    bo = {(0, 0), (0, 1), (1, 0), (1, 1)}
