def generate_17829a00(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(SEVEN, interval(0, 10, 1))
    topc, botc = sample(cols, 2)
    h = unifint(diff_lb, diff_ub, (10, 22))
    w = unifint(diff_lb, diff_ub, (10, 22))

    gi = canvas(SEVEN, (h, w))
    gi = fill(gi, topc, connect((0, 0), (0, w - 1)))
    gi = fill(gi, botc, connect((h - 1, 0), (h - 1, w - 1)))

    interior = frozenset((i, j) for i in range(1, h - 1) for j in range(w))

    ntop = unifint(diff_lb, diff_ub, (2, max(2, min(6, (h - 2) * w // 12))))
    nbot = unifint(diff_lb, diff_ub, (2, max(2, min(6, (h - 2) * w // 12))))

    top_inds = set()
    bot_inds = set()
    occupied = set()

    def rand_connected_shape(maxh, maxw, maxcells):
        oh = randint(1, maxh)
        ow = randint(1, maxw)
        bounds = frozenset((i, j) for i in range(oh) for j in range(ow))
        ncells = randint(1, max(1, min(maxcells, oh * ow)))
        start = (randint(0, oh - 1), randint(0, ow - 1))
        shp = {start}
        for _ in range(ncells - 1):
            fringe = (bounds - shp) & mapply(dneighbors, shp)
            if len(fringe) == 0:
                break
            shp.add(choice(totuple(fringe)))
        return normalize(frozenset(shp))

    def place_shapes(target_set, nobj, upper_part):
        nonlocal occupied
        succ = 0
        tries = 0
        maxtries = 80 * nobj + 80
        while succ < nobj and tries < maxtries:
            tries += 1
            maxh = max(1, min(4, h - 2))
            maxw = max(1, min(5, w))
            shp = rand_connected_shape(maxh, maxw, max(1, maxh * maxw - randint(0, max(0, maxh * maxw - 1))))
            sh = height(shp)
            sw = width(shp)
            if sh > h - 2 or sw > w:
                continue
            if upper_part:
                imax = max(1, (h - 2) // 2 + 1)
                iloc = randint(1, max(1, min(h - 1 - sh, imax)))
            else:
                imin = min(h - 1 - sh, max(1, (h - 2) // 2))
                iloc = randint(max(1, imin), h - 1 - sh)
            jloc = randint(0, w - sw)
            plcd = shift(shp, (iloc, jloc))
            if len(plcd & interior) != len(plcd):
                continue
            if len(plcd & frozenset(occupied)) > 0:
                continue
            target_set |= set(plcd)
            occupied |= set(plcd)
            succ += 1
        return target_set

    top_inds = place_shapes(top_inds, ntop, True)
    bot_inds = place_shapes(bot_inds, nbot, False)

    if len(top_inds) == 0:
        c = randint(0, w - 1)
        r = randint(1, max(1, h // 2))
        top_inds.add((r, c))
    if len(bot_inds) == 0:
        c = randint(0, w - 1)
        r = randint(max(1, h // 2), h - 2)
        if (r, c) in top_inds:
            r = h - 2
        bot_inds.add((r, c))

    gi = fill(gi, topc, frozenset(top_inds))
    gi = fill(gi, botc, frozenset(bot_inds))

    go = verify_17829a00(gi)
    return {'input': gi, 'output': go}


