def generate_18286ef8(diff_lb: float, diff_ub: float) -> dict:
    bgc = 7
    hregs = unifint(diff_lb, diff_ub, (2, 4))
    wregs = unifint(diff_lb, diff_ub, (2, 4))
    rhs = [unifint(diff_lb, diff_ub, (2, 6)) for _ in range(hregs)]
    cws = [unifint(diff_lb, diff_ub, (2, 6)) for _ in range(wregs)]
    H = sum(rhs) + (hregs - 1)
    W = sum(cws) + (wregs - 1)

    gi = canvas(bgc, (H, W))

    row_starts = []
    acc = 0
    for k, rh in enumerate(rhs):
        row_starts.append(acc)
        acc += rh
        if k < hregs - 1:
            gi = fill(gi, 0, connect((acc, 0), (acc, W - 1)))
            acc += 1

    col_starts = []
    acc = 0
    for k, cw in enumerate(cws):
        col_starts.append(acc)
        acc += cw
        if k < wregs - 1:
            gi = fill(gi, 0, connect((0, acc), (H - 1, acc)))
            acc += 1

    regs = []
    for ri in range(hregs):
        for cj in range(wregs):
            regs.append((ri, cj, row_starts[ri], col_starts[cj], rhs[ri], cws[cj]))

    block_regs = [r for r in regs if r[4] >= 3 and r[5] >= 3]
    if len(block_regs) == 0:
        ri, cj, rs, cs, rh, cw = regs[0]
        rhs[ri] = max(rhs[ri], 3)
        cws[cj] = max(cws[cj], 3)
        return generate_18286ef8(diff_lb, diff_ub)

    breg = choice(block_regs)
    bri, bcj, brs, bcs, brh, bcw = breg
    top = brs + randint(0, brh - 3)
    left = bcs + randint(0, bcw - 3)
    block = backdrop(frozenset({(top, left), (top + 2, left + 2)}))
    gi = fill(gi, 5, block)

    nine_pos = (top + randint(0, 2), left + randint(0, 2))
    gi = fill(gi, 9, frozenset({nine_pos}))

    same_region = choice((True, False))
    six_candidates = []
    if same_region:
        for i in range(brs, brs + brh):
            for j in range(bcs, bcs + bcw):
                if (i, j) not in block:
                    six_candidates.append((i, j))
        if len(six_candidates) == 0:
            same_region = False

    if not same_region:
        other_regs = [r for r in regs if not (r[0] == bri and r[1] == bcj)]
        sreg = choice(other_regs)
        sri, scj, srs, scs, srh, scw = sreg
        for i in range(srs, srs + srh):
            for j in range(scs, scs + scw):
                six_candidates.append((i, j))

    six_pos = choice(six_candidates)
    gi = fill(gi, 6, frozenset({six_pos}))

    noise_cols = (1, 2, 3, 4, 8)
    all_free = []
    for ri, cj, rs, cs, rh, cw in regs:
        for i in range(rs, rs + rh):
            for j in range(cs, cs + cw):
                if gi[i][j] == bgc:
                    all_free.append((i, j))
    max_noise = min(len(all_free), unifint(diff_lb, diff_ub, (0, max(0, len(all_free) // 4))))
    if max_noise > 0:
        chosen = sample(all_free, max_noise)
        for cell in chosen:
            gi = fill(gi, choice(noise_cols), frozenset({cell}))

    go = verify_18286ef8(gi)
    return {'input': gi, 'output': go}


def generate_182e5d0f(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (9, 18))
    w = unifint(diff_lb, diff_ub, (9, 18))
    gi = canvas(7, (h, w))

    def inb(c):
        return 0 <= c[0] < h and 0 <= c[1] < w

    def add_path(path, z1, z2, fcell):
        g = gi_holder[0]
        g = fill(g, 3, frozenset(path))
        g = fill(g, 0, frozenset({z1, z2}))
        g = fill(g, 5, frozenset({fcell}))
        gi_holder[0] = g

    def add_nonreducible_path(path, zeros=(), fives=()):
        g = gi_holder[0]
        g = fill(g, 3, frozenset(path))
        if len(zeros) > 0:
            g = fill(g, 0, frozenset(zeros))
        if len(fives) > 0:
            g = fill(g, 5, frozenset(fives))
        gi_holder[0] = g

    occupied = set()
    reserved = set()
    gi_holder = [gi]

    nred = unifint(diff_lb, diff_ub, (1, 3))
    nplain = unifint(diff_lb, diff_ub, (1, 4))
    nlonely5 = unifint(diff_lb, diff_ub, (0, 3))

    dirs = [(0, 1), (1, 0), (0, -1), (-1, 0)]

    for _ in range(80):
        if nred <= 0:
            break
        orient = choice(("h", "v"))
        if orient == "h":
            L = unifint(diff_lb, diff_ub, (3, max(3, min(8, w - 2))))
            if L > w - 2:
                continue
            r = randint(1, h - 2)
            c = randint(1, w - L - 1)
            path = [(r, c + k) for k in range(L)]
            endpoint = path[0]
            second = path[1]
            zcands = [(r - 1, c), (r + 1, c)]
            fcell = (r, c + L)
        else:
            L = unifint(diff_lb, diff_ub, (3, max(3, min(8, h - 2))))
            if L > h - 2:
                continue
            r = randint(1, h - L - 1)
            c = randint(1, w - 2)
            path = [(r + k, c) for k in range(L)]
            endpoint = path[0]
            second = path[1]
            zcands = [(r, c - 1), (r, c + 1)]
            fcell = (r + L, c)
        cells = set(path) | {fcell} | set(zcands)
        halo = set()
        for q in cells:
            halo |= set(dneighbors(q))
        if not all(inb(x) for x in cells):
            continue
        if cells & occupied:
            continue
        if halo & reserved:
            continue
        occupied |= cells
        reserved |= cells | halo
        add_path(path, zcands[0], zcands[1], fcell)
        nred -= 1

    for _ in range(120):
        if nplain <= 0:
            break
        typ = choice(("line", "el"))
        if typ == "line":
            orient = choice(("h", "v"))
            if orient == "h":
                L = unifint(diff_lb, diff_ub, (2, max(2, min(7, w - 2))))
                if L > w - 2:
                    continue
                r = randint(0, h - 1)
                c = randint(0, w - L)
                path = [(r, c + k) for k in range(L)]
            else:
                L = unifint(diff_lb, diff_ub, (2, max(2, min(7, h - 2))))
                if L > h - 2:
                    continue
                r = randint(0, h - L)
                c = randint(0, w - 1)
                path = [(r + k, c) for k in range(L)]
        else:
            lh = unifint(diff_lb, diff_ub, (2, max(2, min(5, h - 1))))
            lw = unifint(diff_lb, diff_ub, (2, max(2, min(5, w - 1))))
            if lh > h or lw > w:
                continue
            r = randint(0, h - lh)
            c = randint(0, w - lw)
            if choice((True, False)):
                path = [(r + k, c) for k in range(lh)] + [(r + lh - 1, c + k) for k in range(1, lw)]
            else:
                path = [(r, c + k) for k in range(lw)] + [(r + k, c + lw - 1) for k in range(1, lh)]
        path = list(dict.fromkeys(path))
        cells = set(path)
        halo = set()
        for q in cells:
            halo |= set(dneighbors(q))
        if cells & occupied:
            continue
        if halo & reserved:
            continue

        zeros = []
        fives = []
        mode = choice(("plain", "zero1", "five_only", "five_and_zero1"))
        if mode in ("zero1", "five_and_zero1"):
            cand = choice(path)
            zopts = [nb for nb in dneighbors(cand) if inb(nb) and nb not in cells and nb not in occupied]
            if len(zopts) > 0:
                zeros = [choice(zopts)]
        if mode in ("five_only", "five_and_zero1"):
            cand = choice(path)
            fopts = [nb for nb in dneighbors(cand) if inb(nb) and nb not in cells and nb not in occupied and nb not in zeros]
            if len(fopts) > 0:
                fives = [choice(fopts)]

        allcells = cells | set(zeros) | set(fives)
        halo2 = set()
        for q in allcells:
            halo2 |= set(dneighbors(q))
        if allcells & occupied:
            continue
        if halo2 & reserved:
            continue

        occupied |= allcells
        reserved |= allcells | halo2
        add_nonreducible_path(path, zeros=zeros, fives=fives)
        nplain -= 1

    for _ in range(80):
        if nlonely5 <= 0:
            break
        cell = (randint(0, h - 1), randint(0, w - 1))
        if cell in occupied:
            continue
        if any(nb in occupied and gi_holder[0][nb[0]][nb[1]] == 3 for nb in dneighbors(cell) if inb(nb)):
            continue
        occupied.add(cell)
        reserved.add(cell)
        gi_holder[0] = fill(gi_holder[0], 5, frozenset({cell}))
        nlonely5 -= 1

    gi = gi_holder[0]
    go = verify_182e5d0f(gi)
    return {'input': gi, 'output': go}


