def generate_1d0a4b61(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(1, 10, 1))
    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (18, 30))

    for _ in range(100):
        ph = choice((4, 5, 6, 7))
        pw = choice((4, 5, 6, 7))
        if ph <= h and pw <= w:
            break
    else:
        ph, pw = 6, 6

    remcols = remove(1, cols)
    palette_size = choice((2, 3, 4))
    palette_size = min(palette_size, len(remcols))
    motif_cols = sample(remcols, palette_size)

    tile_rows = []
    for i in range(ph):
        row = []
        if i == 0:
            row = [1] * pw
        else:
            for j in range(pw):
                if j == 0:
                    row.append(1)
                else:
                    row.append(choice(motif_cols))
        tile_rows.append(row)

    if ph >= 4 and pw >= 4:
        for _k in range(randint(1, max(1, (ph * pw) // 4))):
            ii = randint(1, ph - 1)
            jj = randint(1, pw - 1)
            tile_rows[ii][jj] = choice(motif_cols)

    tile = tuple(tuple(r) for r in tile_rows)

    full_rows = []
    for i in range(h):
        rr = []
        for j in range(w):
            rr.append(tile[i % ph][j % pw])
        full_rows.append(tuple(rr))
    go = tuple(full_rows)

    gi = go

    nrect = unifint(diff_lb, diff_ub, (2, 8))
    maxrh = max(2, h // 3)
    maxrw = max(2, w // 3)
    for _ in range(nrect):
        rh = unifint(diff_lb, diff_ub, (2, maxrh))
        rw = unifint(diff_lb, diff_ub, (2, maxrw))
        si = randint(0, h - rh)
        sj = randint(0, w - rw)
        gi = fill(gi, 0, connect((si, sj), (si + rh - 1, sj + rw - 1)))

    nspeck = unifint(diff_lb, diff_ub, (0, max(1, (h * w) // 20)))
    inds = totuple(asindices(gi))
    if nspeck > 0 and len(inds) > 0:
        for loc in sample(inds, min(nspeck, len(inds))):
            gi = fill(gi, 0, initset(loc))

    if gi == go:
        si = randint(0, h - 2)
        sj = randint(0, w - 2)
        gi = fill(gi, 0, connect((si, sj), (si + 1, sj + 1)))

    return {'input': gi, 'output': go}


