        barcols = sample(tuple(range(left, right + 1)), nbarcols)
        for c in barcols:
            gi = fill(gi, shapec, connect((row - arm, c), (row + arm, c)))
        shape_cells = ofcolor(gi, shapec)

        cols_with_shape = sorted({j for i, j in shape_cells})
