    ncells2 = unifint(diff_lb, diff_ub, (max(4, (bh + bw) // 2), max(4, bh * bw - 1)))

    bounds = asindices(canvas(-1, (bh, bw)))

    def rand_connected(ncells):
        sp = choice(totuple(bounds))
        obj = {sp}
        target = min(ncells, bh * bw)
        for _ in range(target - 1):
            frontier = (bounds - frozenset(obj)) & mapply(dneighbors, frozenset(obj))
            if len(frontier) == 0:
                frontier = bounds - frozenset(obj)
            if len(frontier) == 0:
                break
            obj.add(choice(totuple(frontier)))
        return frozenset(obj)

    obj1 = rand_connected(ncells1)
    obj2 = rand_connected(ncells2)

    for _ in range(50):
        x = normalize(difference(obj1, obj2) | difference(obj2, obj1))
        if len(x) > 0:
            break
        obj2 = rand_connected(ncells2)

    if len(normalize(difference(obj1, obj2) | difference(obj2, obj1))) == 0:
        obj2 = shift(initset((0, 0)), (0, 0))
        obj2 = combine(obj2, initset((0, min(1, bw - 1))))
        obj2 = combine(obj2, initset((min(1, bh - 1), 0)))
        obj2 = frozenset(obj2)

    def colorize(idxset):
        k = min(len(cols), max(2, unifint(diff_lb, diff_ub, (2, 4))))
