    o1 = colorize(obj1)
    o2 = colorize(obj2)

    gi = canvas(0, (gh, gw))

    sep = unifint(diff_lb, diff_ub, (4, 10))
    maxr1 = gh - bh
    maxc1 = gw - bw
    placed = False
    for _ in range(200):
        r1 = randint(0, maxr1)
        c1 = randint(0, maxc1)
        dirs = [(0, 1), (1, 0)]
        shuffle(dirs)
        for dr, dc in dirs:
            if dr == 0:
                r2 = r1
                c2 = c1 + bw + sep
                if c2 <= gw - bw:
                    gi = paint(gi, shift(o1, (r1, c1)))
                    gi = paint(gi, shift(o2, (r2, c2)))
                    placed = True
                    break
                c2 = c1 - bw - sep
                if c2 >= 0:
                    gi = paint(gi, shift(o1, (r1, c1)))
                    gi = paint(gi, shift(o2, (r2, c2)))
                    placed = True
                    break
            else:
                r2 = r1 + bh + sep
                c2 = c1
                if r2 <= gh - bh:
                    gi = paint(gi, shift(o1, (r1, c1)))
                    gi = paint(gi, shift(o2, (r2, c2)))
                    placed = True
                    break
                r2 = r1 - bh - sep
                if r2 >= 0:
                    gi = paint(gi, shift(o1, (r1, c1)))
                    gi = paint(gi, shift(o2, (r2, c2)))
                    placed = True
                    break
        if placed:
            break

    if not placed:
        gh = max(gh, bh * 2 + sep + 2)
        gw = max(gw, bw * 2 + sep + 2)
        gi = canvas(0, (gh, gw))
        r1, c1 = 1, 1
        r2, c2 = 1, 1 + bw + sep
        if c2 > gw - bw:
            r2, c2 = 1 + bh + sep, 1
        gi = paint(gi, shift(o1, (r1, c1)))
        gi = paint(gi, shift(o2, (r2, c2)))

    go = verify_2037f2c7(gi)
