    col_bounds = (-1,) + col_marks + (col_marks[-1] + col_gap,)

    for rr in range(len(row_bounds) - 1):
        for cc in range(len(col_bounds) - 1):
            topb = row_bounds[rr]
            bottb = row_bounds[rr + 1]
            leftb = col_bounds[cc]
            rightb = col_bounds[cc + 1]

            ch = bottb - topb - 1
            cw = rightb - leftb - 1
            if ch < 2 or cw < 2:
                continue

            maxoh = max(1, min(ch - 1, 3))
            maxow = max(1, min(cw - 1, 3))
            oh = unifint(diff_lb, diff_ub, (1, maxoh))
            ow = unifint(diff_lb, diff_ub, (1, maxow))

