            shape_cells = sample(list(product(interval(0, oh, 1), interval(0, ow, 1))), ncells)
            rel = frozenset(shape_cells)
            comps = connected_components(rel, False)
            if len(comps) > 1:
                comp_list = list(comps)
                base = set(comp_list[0])
                for comp in comp_list[1:]:
                    a = choice(list(base))
                    b = choice(list(comp))
                    path = connect(a, b)
                    for p in path:
                        if 0 <= p[0] < oh and 0 <= p[1] < ow:
                            base.add(p)
                rel = frozenset(base)

            if len(rel) == 0:
                rel = frozenset({(0, 0)})

            maxdi = ch - 1 - max(i for i, j in rel)
            maxdj = cw - 1 - max(j for i, j in rel)
            mindi = 0
