def generate_22eb0ac0(diff_lb: float, diff_ub: float) -> dict:
    colopts = interval(0, 10, 1)
    gi = canvas(0, (1, 1))
    h = unifint(diff_lb, diff_ub, (4, 30))
    w = unifint(diff_lb, diff_ub, (4, 30))
    bgc = choice(colopts)
    remcols = remove(bgc, colopts)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    nlocs = unifint(diff_lb, diff_ub, (1, h))
    locs = sample(interval(0, h, 1), nlocs)
    while set(locs).issubset({0, h - 1}):
        locs = sample(interval(0, h, 1), nlocs)
    mp = nlocs // 2
    nbarsdev = unifint(diff_lb, diff_ub, (0, mp))
    nbars = choice((nbarsdev, h - nbarsdev))
    nbars = max(0, min(nbars, nlocs))
    barlocs = sample(locs, nbars)
    nonbarlocs = difference(locs, barlocs)
    barcols = [choice(remcols) for j in range(nbars)]
    acols = [choice(remcols) for j in range(len(nonbarlocs))]
    bcols = [choice(remove(acols[j], remcols)) for j in range(len(nonbarlocs))]
    for bc, bl in zip(barcols, barlocs):
        gi = fill(gi, bc, ((bl, 0), (bl, w - 1)))
        go = fill(go, bc, connect((bl, 0), (bl, w - 1)))
    for (a, b), loc in zip(zip(acols, bcols), nonbarlocs):
        gi = fill(gi, a, {(loc, 0)})
        go = fill(go, a, {(loc, 0)})
        gi = fill(gi, b, {(loc, w - 1)})
        go = fill(go, b, {(loc, w - 1)})
    if choice((True, False)):
        gi = dmirror(gi)
        go = dmirror(go)
    return {'input': gi, 'output': go}


def generate_230f2e48(diff_lb: float, diff_ub: float) -> dict:
    bgc = SEVEN
    h = unifint(diff_lb, diff_ub, (8, 20))
    w = unifint(diff_lb, diff_ub, (8, 20))
    gi = canvas(bgc, (h, w))

    nobj_max = min(4, max(1, (h * w) // 20))
    nobj = unifint(diff_lb, diff_ub, (1, nobj_max))

    occupied = set()

    def cells_for_obj(five, zero, reds):
        return {five, zero} | set(reds)

    def in_bounds(c):
        return 0 <= c[0] < h and 0 <= c[1] < w

    for _ in range(100):
        gi = canvas(bgc, (h, w))
        occupied = set()
        placed = 0
        target = nobj

        for _k in range(target):
            success = False
            for _try in range(200):
                orient = choice((UP, DOWN, LEFT, RIGHT))
                if orient == UP:
                    perps = (LEFT, RIGHT)
                elif orient == DOWN:
                    perps = (LEFT, RIGHT)
                elif orient == LEFT:
                    perps = (UP, DOWN)
                else:
                    perps = (UP, DOWN)

                before_len = unifint(diff_lb, diff_ub, (1, 3))
                after_len = unifint(diff_lb, diff_ub, (1, 5))

                minr = 1
                maxr = h - 2
                minc = 1
                maxc = w - 2
                if minr > maxr or minc > maxc:
                    continue
                zr = randint(minr, maxr)
                zc = randint(minc, maxc)
                zero = (zr, zc)
                five = subtract(zero, multiply(orient, before_len))

                reds_before = [add(five, multiply(orient, t)) for t in range(1, before_len)]
                reds_after = [add(zero, multiply(orient, t)) for t in range(1, after_len + 1)]
                allcells = cells_for_obj(five, zero, reds_before + reds_after)

                if not all(in_bounds(c) for c in allcells):
                    continue
                if any(c in occupied for c in allcells):
                    continue

                perp_ok = False
                for pd in perps:
                    branch = [add(zero, multiply(pd, t)) for t in range(1, after_len + 1)]
                    if all(in_bounds(c) for c in branch):
                        perp_ok = True
                        break
                if not perp_ok:
                    continue

                gi = fill(gi, FIVE, frozenset({five}))
                gi = fill(gi, ZERO, frozenset({zero}))
                gi = fill(gi, TWO, frozenset(reds_before + reds_after))
                occupied |= allcells
                success = True
                placed += 1
                break
            if not success:
                break

        if placed == target:
            go = verify_230f2e48(gi)
            if gi != go:
                return {'input': gi, 'output': go}

    h = max(h, 8)
    w = max(w, 8)
    gi = canvas(bgc, (h, w))
    r = h // 2
    c = max(3, min(w - 4, w // 2))
    five = (r, c - 2)
    zero = (r, c)
    reds = frozenset({(r, c - 1), (r, c + 1), (r, c + 2)})
    gi = fill(gi, FIVE, frozenset({five}))
    gi = fill(gi, ZERO, frozenset({zero}))
    gi = fill(gi, TWO, reds)
    go = verify_230f2e48(gi)
    return {'input': gi, 'output': go}


