def generate_2546ccf6(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc = 0
    linc = choice(remove(bgc, cols))
    remcols = remove(bgc, remove(linc, cols))

    nr = unifint(diff_lb, diff_ub, (3, 5))
    nc = unifint(diff_lb, diff_ub, (3, 5))
    maxch = min(6, (30 - nr + 1) // nr)
    maxcw = min(6, (30 - nc + 1) // nc)
    ch = unifint(diff_lb, diff_ub, (3, maxch))
    cw = unifint(diff_lb, diff_ub, (3, maxcw))

    h = nr * ch + (nr - 1)
    w = nc * cw + (nc - 1)

    gi = canvas(bgc, (h, w))

    for r in range(1, nr):
        gi = fill(gi, linc, connect((r * ch + (r - 1), 0), (r * ch + (r - 1), w - 1)))
    for c in range(1, nc):
        gi = fill(gi, linc, connect((0, c * cw + (c - 1)), (h - 1, c * cw + (c - 1))))

    # 2x2 block top-left must be in 0..nr-3 so that all 4 quadrant corners
    # stay within 0..nr-2, avoiding verifier eager-eval IndexError on x6[nr-1]
    nquad_r = unifint(diff_lb, diff_ub, (1, nr - 2))
    nquad_c = unifint(diff_lb, diff_ub, (1, nc - 2))
    quad_rs = sample(list(range(0, nr - 2)), nquad_r)
    quad_cs = sample(list(range(0, nc - 2)), nquad_c)

    maxcols = min(8, len(remcols), nquad_r * nquad_c)
    ncols = unifint(diff_lb, diff_ub, (1, maxcols))
    usecols = sample(remcols, ncols)
    shuffle(usecols)

    qps = [(r, c) for r in quad_rs for c in quad_cs]
    shuffle(qps)
    qps = qps[:ncols]

    def cell_origin(rr, cc):
        return (rr * (ch + 1), cc * (cw + 1))

    for idx, (qr, qc) in enumerate(qps):
        col = usecols[idx]
        miss = choice(((0, 0), (0, 1), (1, 0), (1, 1)))

        ph = unifint(diff_lb, diff_ub, (2, ch))
        pw = unifint(diff_lb, diff_ub, (2, cw))
        maxcells = ph * pw - 1
        npix = unifint(diff_lb, diff_ub, (2, maxcells))

        allinds = totuple(asindices(canvas(-1, (ph, pw))))
        anchor = choice(allinds)
        shp = {anchor}
        frontier = set(neighbors(anchor) & set(allinds))
        tries = 0
        while len(shp) < npix and tries < ph * pw * 4:
            tries += 1
            cands = tuple(frontier - shp)
            if len(cands) == 0:
                break
            loc = choice(cands)
            shp.add(loc)
            frontier |= set(neighbors(loc) & set(allinds))
        if len(shp) < 2:
            shp = {(0, 0), (ph - 1, pw - 1)} if ph > 1 and pw > 1 else {(0, 0), (0, min(1, pw - 1))}

        mini = min(i for i, j in shp)
        minj = min(j for i, j in shp)
        shp = frozenset((i - mini, j - minj) for i, j in shp)
        ph2 = height(shp)
        pw2 = width(shp)

        # Compute rotated shape indices
        rotshp = ofcolor(rot180(fill(canvas(0, (ph2, pw2)), 1, shp)), 1)

        offi = randint(0, ch - ph2)
        offj = randint(0, cw - pw2)

        for dr in (0, 1):
            for dc in (0, 1):
                if (dr, dc) == miss:
                    continue
                ori = cell_origin(qr + dr, qc + dc)
                patch = shp if (dr, dc) == (0, 0) or (dr, dc) == (1, 1) else rotshp
                patch = shift(patch, (ori[0] + offi, ori[1] + offj))
                gi = fill(gi, col, patch)

    go = verify_2546ccf6(gi)
    return {'input': gi, 'output': go}


def generate_256b0a75(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(EIGHT, interval(1, 10, 1))
    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (18, 30))
    gi = canvas(ZERO, (h, w))

    rh = unifint(diff_lb, diff_ub, (5, min(12, h - 4)))
    rw = unifint(diff_lb, diff_ub, (5, min(12, w - 4)))
    r0 = randint(4, h - rh - 4)
    c0 = randint(4, w - rw - 4)
    r1 = r0 + rh - 1
    c1 = c0 + rw - 1

    fillcol = choice(cols)
    corners = [(r0, c0), (r0, c1), (r1, c0), (r1, c1)]
    misscorner = choice(corners)

    frame = box(frozenset({(r0, c0), (r1, c1)}))
    interior = backdrop(frozenset({(r0 + 1, c0 + 1), (r1 - 1, c1 - 1)})) if rh > 2 and rw > 2 else frozenset()

    partial8 = set()
    for cr, cc in corners:
        if (cr, cc) != misscorner:
            partial8.add((cr, cc))
    side_choices = ['top', 'bottom', 'left', 'right']
    shuffle(side_choices)
    nsides = unifint(diff_lb, diff_ub, (1, 4))
    chosen_sides = side_choices[:nsides]
    for s in chosen_sides:
        if s == 'top':
            seglen = unifint(diff_lb, diff_ub, (1, max(1, rw - 2)))
            start = randint(c0, c1 - seglen + 1)
            partial8 |= set(connect((r0, start), (r0, start + seglen - 1)))
        elif s == 'bottom':
            seglen = unifint(diff_lb, diff_ub, (1, max(1, rw - 2)))
            start = randint(c0, c1 - seglen + 1)
            partial8 |= set(connect((r1, start), (r1, start + seglen - 1)))
        elif s == 'left':
            seglen = unifint(diff_lb, diff_ub, (1, max(1, rh - 2)))
            start = randint(r0, r1 - seglen + 1)
            partial8 |= set(connect((start, c0), (start + seglen - 1, c0)))
        else:
            seglen = unifint(diff_lb, diff_ub, (1, max(1, rh - 2)))
            start = randint(r0, r1 - seglen + 1)
            partial8 |= set(connect((start, c1), (start + seglen - 1, c1)))
    gi = fill(gi, EIGHT, frozenset(partial8))
    gi = fill(gi, fillcol, frozenset({misscorner}))

    occ = frame | interior
    dirs = [UP, DOWN, LEFT, RIGHT]
    nseeds = unifint(diff_lb, diff_ub, (6, min(20, (h * w) // 18)))
    tries = 0
    placed = 0
    maxtries = 20 * nseeds
    while placed < nseeds and tries < maxtries:
        tries += 1
        d = choice(dirs)
        col = choice(cols)
        if d == UP:
            rr = randint(0, max(0, r0 - 1))
            cc = randint(c0, c1)
            if (rr, cc) in occ:
                continue
            blocked = False
            for k in range(rr + 1, r0):
                if gi[k][cc] != ZERO:
                    blocked = True
                    break
            if blocked:
                continue
            gi = fill(gi, col, frozenset({(rr, cc)}))
            occ = insert((rr, cc), occ)
            placed += 1
        elif d == DOWN:
            rr = randint(r1, h - 1)
            cc = randint(c0, c1)
            if (rr, cc) in occ:
                continue
            blocked = False
            for k in range(r1 + 1, rr):
                if gi[k][cc] != ZERO:
                    blocked = True
                    break
            if blocked:
                continue
            gi = fill(gi, col, frozenset({(rr, cc)}))
            occ = insert((rr, cc), occ)
            placed += 1
        elif d == LEFT:
            rr = randint(r0, r1)
            cc = randint(0, max(0, c0 - 1))
            if (rr, cc) in occ:
                continue
            blocked = False
            for k in range(cc + 1, c0):
                if gi[rr][k] != ZERO:
                    blocked = True
                    break
            if blocked:
                continue
            gi = fill(gi, col, frozenset({(rr, cc)}))
            occ = insert((rr, cc), occ)
            placed += 1
        else:
            rr = randint(r0, r1)
            cc = randint(c1, w - 1)
            if (rr, cc) in occ:
                continue
            blocked = False
            for k in range(c1 + 1, cc):
                if gi[rr][k] != ZERO:
                    blocked = True
                    break
            if blocked:
                continue
            gi = fill(gi, col, frozenset({(rr, cc)}))
            occ = insert((rr, cc), occ)
            placed += 1

    nnoise = unifint(diff_lb, diff_ub, (4, min(18, (h * w) // 25)))
    freecells = [ij for ij in totuple(asindices(gi)) if ij not in occ and gi[ij[0]][ij[1]] == ZERO]
    shuffle(freecells)
    for ij in freecells[:nnoise]:
        gi = fill(gi, choice(cols), frozenset({ij}))

    go = verify_256b0a75(gi)
    return {'input': gi, 'output': go}


def generate_25c199f5(diff_lb: float, diff_ub: float) -> dict:
    bg = 7
    div = 6
    cols = (1, 5)

    def rand_nonbg_row():
        typ = unifint(diff_lb, diff_ub, (0, 4))
        c = choice(cols)
        row = [bg] * 5
        if typ == 0:
            a = unifint(diff_lb, diff_ub, (0, 4))
            b = unifint(diff_lb, diff_ub, (a, 4))
            for j in range(a, b + 1):
                row[j] = c
        elif typ == 1:
            a = unifint(diff_lb, diff_ub, (0, 3))
            b = unifint(diff_lb, diff_ub, (a + 1, 4))
            row[a] = c
            row[b] = c
        elif typ == 2:
            k = unifint(diff_lb, diff_ub, (1, 4))
            js = sample(interval(0, 5, 1), k)
            for j in js:
                row[j] = c
        elif typ == 3:
            a = unifint(diff_lb, diff_ub, (0, 2))
            for j in range(a, a + 3):
                row[j] = c
        else:
            a = unifint(diff_lb, diff_ub, (0, 1))
            for j in range(a, a + 4):
                row[j] = c
        return tuple(row)

    while True:
        counts = [unifint(diff_lb, diff_ub, (0, 3)) for _ in range(3)]
        if sum(counts) > 0 and sum(counts) <= 5:
            break

    panels = []
    for p in range(3):
        rows = [tuple(repeat(bg, 5)) for _ in range(5)]
        if counts[p] > 0:
            pos = sample(interval(0, 5, 1), counts[p])
            pos = sorted(pos)
            for r in pos:
                rows[r] = rand_nonbg_row()
        panels.append(tuple(rows))

    gi = hconcat(hconcat(panels[0], canvas(div, (5, 1))), hconcat(panels[1], hconcat(canvas(div, (5, 1)), panels[2])))
    go = verify_25c199f5(gi)
    return {'input': gi, 'output': go}


def generate_25d487eb(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
