def generate_292dd178(diff_lb: float, diff_ub: float) -> dict:
    bgc = choice(remove(1, remove(2, interval(0, 10, 1))))
    h = unifint(diff_lb, diff_ub, (7, 20))
    w = unifint(diff_lb, diff_ub, (7, 20))
    gi = canvas(bgc, (h, w))

    max_objs = 3
    nobj = unifint(diff_lb, diff_ub, (1, max_objs))
    placed = []

    def rect_perim(top, left, hh, ww):
        corners = frozenset({(top, left), (top, left + ww - 1), (top + hh - 1, left), (top + hh - 1, left + ww - 1)})
        return box(corners)

    for _ in range(100):
        if len(placed) >= nobj:
            break
        hh = unifint(diff_lb, diff_ub, (3, min(6, h - 1)))
        ww = unifint(diff_lb, diff_ub, (3, min(6, w - 1)))
        if hh > h or ww > w:
            continue
        top = randint(0, h - hh)
        left = randint(0, w - ww)

        side = choice((0, 1, 2, 3))
        if side == 0:
            gap = (top, randint(left, left + ww - 1))
            raydir = UP
        elif side == 1:
            gap = (top + hh - 1, randint(left, left + ww - 1))
            raydir = DOWN
        elif side == 2:
            gap = (randint(top, top + hh - 1), left)
            raydir = LEFT
        else:
            gap = (randint(top, top + hh - 1), left + ww - 1)
            raydir = RIGHT

        per = rect_perim(top, left, hh, ww)
        objcells = difference(per, initset(gap))

        ok = True
        for oc in objcells:
            if oc[0] < 0 or oc[0] >= h or oc[1] < 0 or oc[1] >= w:
                ok = False
                break
        if not ok:
            continue

        for prev in placed:
            if len(intersection(objcells, prev)) > 0:
                ok = False
                break
        if not ok:
            continue

        gi = fill(gi, 1, objcells)
        placed.append(objcells)

    if len(placed) == 0:
        hh, ww = 4, 4
        top, left = 1, 1
        per = rect_perim(top, left, hh, ww)
        gap = (top + 1, left)
        gi = fill(gi, 1, difference(per, initset(gap)))

    go = verify_292dd178(gi)
    return {'input': gi, 'output': go}


