def generate_2a5f8217(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(1, remove(0, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (6, 16))
    w = unifint(diff_lb, diff_ub, (6, 16))
    gi = canvas(0, (h, w))
    occ = set()
    used_shapes = set()
    paired_norms = set()
    npairs = unifint(diff_lb, diff_ub, (1, 4))

    def normshape(cells):
        mi = min(i for i, j in cells)
        mj = min(j for i, j in cells)
        return frozenset((i - mi, j - mj) for i, j in cells)

    def transforms(cells):
        obj = recolor(1, cells)
        sh = shape(cells)
        g = fill(canvas(0, sh), 1, cells)
        variants = []
        for fn in (identity, rot90, rot180, rot270, hmirror, vmirror, dmirror, cmirror):
            tg = fn(g)
            t = ofcolor(tg, 1)
            if len(t) > 0:
                variants.append(frozenset(t))
        out = []
        seen = set()
        for v in variants:
            if v not in seen:
                seen.add(v)
                out.append(v)
        return out

    def random_shape(maxh, maxw):
        oh = unifint(diff_lb, diff_ub, (1, maxh))
        ow = unifint(diff_lb, diff_ub, (1, maxw))
        ncmax = max(1, min(oh * ow, unifint(diff_lb, diff_ub, (1, max(1, oh * ow)))))
        start = (randint(0, oh - 1), randint(0, ow - 1))
        cells = {start}
        bb = frozenset((i, j) for i in range(oh) for j in range(ow))
        target = randint(1, ncmax)
        for _ in range(target - 1):
            frontier = (bb - frozenset(cells)) & mapply(dneighbors, frozenset(cells))
            if len(frontier) == 0:
                break
            cells.add(choice(totuple(frontier)))
        return normshape(cells)

    def can_place(shape, loc):
        placed = shift(shape, loc)
        inds = toindices(placed)
        for i, j in inds:
            if not (0 <= i < h and 0 <= j < w):
                return False
        halo = inds | mapply(neighbors, inds)
        return len(halo & frozenset(occ)) == 0

    def place(shape, color, loc):
        nonlocal gi, occ
        placed = shift(shape, loc)
        gi = fill(gi, color, placed)
        occ |= set(toindices(placed))

    succ = 0
    tries = 0
    maxtries = 300
    while succ < npairs and tries < maxtries:
        tries += 1
        maxoh = max(1, min(5, h - 1))
        maxow = max(1, min(5, w - 1))
        shp = random_shape(maxoh, maxow)
        if len(shp) == 0:
            continue
        ns = normshape(shp)
        if ns in used_shapes:
            continue
        sh1 = shp
        sh2 = shp
        ph1, pw1 = shape(sh1)
        ph2, pw2 = shape(sh2)
        cands1 = []
        cands2 = []
        for i in range(h - ph1 + 1):
            for j in range(w - pw1 + 1):
                if can_place(sh1, (i, j)):
                    cands1.append((i, j))
        if len(cands1) == 0:
            continue
        loc1 = choice(cands1)
        temp_occ = set(occ) | set(toindices(shift(sh1, loc1)))
        for i in range(h - ph2 + 1):
            for j in range(w - pw2 + 1):
                inds = toindices(shift(sh2, (i, j)))
                halo = inds | mapply(neighbors, inds)
                if len(halo & frozenset(temp_occ)) == 0:
                    cands2.append((i, j))
        if len(cands2) == 0:
            continue
        loc2 = choice(cands2)
        col = choice(cols)
        place(sh1, 1, loc1)
        place(sh2, col, loc2)
        used_shapes.add(ns)
        paired_norms.add(ns)
        succ += 1

    if succ == 0:
        shp = frozenset({(0, 0), (1, 0), (1, 1), (1, 2), (2, 1)})
        place(shp, 1, (0, 0))
        col = choice(cols)
        li = max(0, h - 3)
        lj = max(0, w - 3)
        place(shp, col, (li, lj))

    nnoise = unifint(diff_lb, diff_ub, (0, 3))
    for _ in range(nnoise):
        for __ in range(50):
            oh = unifint(diff_lb, diff_ub, (1, min(4, h)))
            ow = unifint(diff_lb, diff_ub, (1, min(4, w)))
            shp = random_shape(oh, ow)
            ns = normshape(shp)
            if ns in used_shapes or ns in paired_norms:
                continue
            ph, pw = shape(shp)
            cands = []
            for i in range(h - ph + 1):
                for j in range(w - pw + 1):
                    if can_place(shp, (i, j)):
                        cands.append((i, j))
            if len(cands) == 0:
                continue
            loc = choice(cands)
            col = choice(cols)
            place(shp, col, loc)
            used_shapes.add(ns)
            break

    go = verify_2a5f8217(gi)
    return {'input': gi, 'output': go}


