def generate_2c0b0aff(diff_lb: float, diff_ub: float) -> dict:
    def make_patch(ph, pw, nplus, extra3):
        g = canvas(8, (ph, pw))
        centers = []
        for i in range(1, ph - 1):
            for j in range(1, pw - 1):
                centers.append((i, j))
        shuffle(centers)
        chosen = []
        used = set()
        for c in centers:
            cross = {c} | set(dneighbors(c))
            if len(cross) != 5:
                continue
            ok = True
            for u in chosen:
                if c in ({u} | set(dneighbors(u))):
                    ok = False
                    break
            if ok:
                chosen.append(c)
                used |= cross
                if len(chosen) == nplus:
                    break
        if len(chosen) < nplus:
            chosen = []
            used = set()
            for i in range(1, ph - 1, 3):
                for j in range(1, pw - 1, 3):
                    c = (i, j)
                    cross = {c} | set(dneighbors(c))
                    if all(0 <= a < ph and 0 <= b < pw for a, b in cross):
                        chosen.append(c)
                        used |= cross
                        if len(chosen) == nplus:
                            break
                if len(chosen) == nplus:
                    break
        for c in chosen:
            g = fill(g, 3, frozenset({c}) | dneighbors(c))
        allinds = set(totuple(asindices(g)))
        rem = list(allinds - used)
        shuffle(rem)
        extra = rem[:extra3]
        if len(extra) > 0:
            g = fill(g, 3, frozenset(extra))
        return g

    npatches = unifint(diff_lb, diff_ub, (2, 5))
    dims = []
    for _ in range(npatches):
        ph = unifint(diff_lb, diff_ub, (4, 10))
        pw = unifint(diff_lb, diff_ub, (4, 11))
        dims.append((ph, pw))

    plus_counts = []
    for ph, pw in dims:
        mx = max(1, ((ph - 2) * (pw - 2) + 8) // 9)
        plus_counts.append(unifint(diff_lb, diff_ub, (1, mx)))

    winner = randint(0, npatches - 1)
    plus_counts[winner] = max(plus_counts) + 1
    for k in range(npatches):
        if k != winner and plus_counts[k] >= plus_counts[winner]:
            plus_counts[k] = max(1, plus_counts[winner] - 1)

    patches = []
    for k, (ph, pw) in enumerate(dims):
        area = ph * pw
        extra3max = max(0, area // 4)
        extra3 = unifint(diff_lb, diff_ub, (0, extra3max))
        patches.append(make_patch(ph, pw, plus_counts[k], extra3))

    row_heights = []
    rows = []
    remaining = list(range(npatches))
    while len(remaining) > 0:
        take = randint(1, min(2, len(remaining)))
        row = remaining[:take]
        remaining = remaining[take:]
        rows.append(row)
        row_heights.append(max(dims[idx][0] for idx in row))

    row_grids = []
    total_w = 0
    for row in rows:
        parts = []
        for t, idx in enumerate(row):
            ph, pw = dims[idx]
            padtop = randint(0, max(0, max(dims[i][0] for i in row) - ph))
            padbot = max(dims[i][0] for i in row) - ph - padtop
            pg = patches[idx]
            if padtop > 0:
                pg = vconcat(canvas(0, (padtop, pw)), pg)
            if padbot > 0:
                pg = vconcat(pg, canvas(0, (padbot, pw)))
            parts.append(pg)
            if t != len(row) - 1:
                gapw = unifint(diff_lb, diff_ub, (2, 4))
                parts.append(canvas(0, (max(dims[i][0] for i in row), gapw)))
        rg = parts[0]
        for p in parts[1:]:
            rg = hconcat(rg, p)
        row_grids.append(rg)
        total_w = max(total_w, len(rg[0]))

    padded_rows = []
    for rg in row_grids:
        rh, rw = shape(rg)
        leftpad = randint(0, max(0, total_w - rw))
        rightpad = total_w - rw - leftpad
        if leftpad > 0:
            rg = hconcat(canvas(0, (rh, leftpad)), rg)
        if rightpad > 0:
            rg = hconcat(rg, canvas(0, (rh, rightpad)))
        padded_rows.append(rg)

    assembled = padded_rows[0]
    for k in range(1, len(padded_rows)):
        gaph = unifint(diff_lb, diff_ub, (2, 4))
        assembled = vconcat(assembled, canvas(0, (gaph, total_w)))
        assembled = vconcat(assembled, padded_rows[k])

    ah, aw = shape(assembled)
    top = unifint(diff_lb, diff_ub, (1, max(1, (30 - ah) // 2)))
    left = unifint(diff_lb, diff_ub, (1, max(1, (30 - aw) // 2)))
    bottom = unifint(diff_lb, diff_ub, (1, max(1, 30 - ah - top)))
    right = unifint(diff_lb, diff_ub, (1, max(1, 30 - aw - left)))

    gi = canvas(0, (ah + top + bottom, aw + left + right))
    gi = paint(gi, shift(asobject(assembled), (top, left)))
    go = verify_2c0b0aff(gi)
    return {'input': gi, 'output': go}


def generate_2c608aff(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)    
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    boxh = unifint(diff_lb, diff_ub, (2, h // 2))
    boxw = unifint(diff_lb, diff_ub, (2, w // 2))
    loci = randint(0, h - boxh)
    locj = randint(0, w - boxw)
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    ccol = choice(remcols)
    remcols = remove(ccol, remcols)
    dcol = choice(remcols)
    bd = backdrop(frozenset({(loci, locj), (loci + boxh - 1, locj + boxw - 1)}))
    gi = canvas(bgc, (h, w))
    gi = fill(gi, ccol, bd)
    reminds = totuple(asindices(gi) - backdrop(outbox(bd)))
    noiseb = max(1, len(reminds) // 4)
    nnoise = unifint(diff_lb, diff_ub, (0, noiseb))
    noise = sample(reminds, nnoise)
    gi = fill(gi, dcol, noise)
    go = tuple(e for e in gi)
    hs = interval(loci, loci + boxh, 1)
    ws = interval(locj, locj + boxw, 1)
    for ij in noise:
        a, b = ij
        if a in hs:
            go = fill(go, dcol, connect(ij, (a, locj)))
        elif b in ws:
            go = fill(go, dcol, connect(ij, (loci, b)))
    go = fill(go, ccol, bd)
    return {'input': gi, 'output': go}


def generate_2c737e39(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(FIVE, interval(1, 10, 1))
    h = unifint(diff_lb, diff_ub, (9, 18))
    w = unifint(diff_lb, diff_ub, (9, 18))

    for _ in range(200):
        gi = canvas(ZERO, (h, w))

        ph = unifint(diff_lb, diff_ub, (3, min(6, h - 3)))
        pw = unifint(diff_lb, diff_ub, (2, min(6, w - 3)))

        ai = unifint(diff_lb, diff_ub, (0, h - ph))
        aj = unifint(diff_lb, diff_ub, (0, w - pw))

        anchor_i = ai + unifint(diff_lb, diff_ub, (0, ph - 1))
        anchor_j = aj + unifint(diff_lb, diff_ub, (0, pw - 1))
        anchor = (anchor_i, anchor_j)

        shape_cells = {anchor}
        n_extra = unifint(diff_lb, diff_ub, (3, max(3, min(ph * pw - 1, 8))))
        frontier = set(dneighbors(anchor)) & set(connect((ai, aj), (ai + ph - 1, aj + pw - 1)))
        frontier.discard(anchor)

        for _k in range(n_extra):
            if len(frontier) == 0:
                break
            cell = choice(tuple(frontier))
            shape_cells.add(cell)
            frontier.discard(cell)
            newn = set(dneighbors(cell)) & set(connect((ai, aj), (ai + ph - 1, aj + pw - 1)))
            frontier |= (newn - shape_cells)

        if len(shape_cells) < 4:
            continue

        non_anchor = tuple(c for c in shape_cells if c != anchor)
        ncols = unifint(diff_lb, diff_ub, (1, min(4, len(cols))))
        usecols = sample(cols, ncols)

        obj = {(FIVE, anchor)}
        for c in non_anchor:
            obj.add((choice(usecols), c))
        gi = paint(gi, frozenset(obj))

        offsets = tuple(subtract(c, anchor) for c in shape_cells)
        valid_targets = []
        for ti in range(h):
            for tj in range(w):
                if (ti, tj) == anchor:
                    continue
                ok = True
                for di, dj in offsets:
                    ni, nj = ti + di, tj + dj
                    if not (0 <= ni < h and 0 <= nj < w):
                        ok = False
                        break
                    if (ni, nj) in shape_cells and (ni, nj) != anchor:
                        ok = False
                        break
                if ok:
                    valid_targets.append((ti, tj))

        if len(valid_targets) == 0:
            continue

        target = choice(valid_targets)
        gi = fill(gi, FIVE, initset(target))
        go = verify_2c737e39(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    gi = canvas(ZERO, (9, 10))
    obj = frozenset({
        (1, (0, 3)),
        (1, (1, 3)),
        (1, (1, 4)),
        (5, (2, 3)),
        (2, (2, 4)),
        (2, (3, 4)),
        (3, (3, 5)),
    })
    gi = paint(gi, obj)
    gi = fill(gi, FIVE, initset((6, 2)))
    go = verify_2c737e39(gi)
    return {'input': gi, 'output': go}


def generate_2ccd9fef(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)

    orient_vertical = choice((True, False))
    npanels = unifint(diff_lb, diff_ub, (3, 4))
    ph = unifint(diff_lb, diff_ub, (6, 10))
    pw = unifint(diff_lb, diff_ub, (8, 12))

    bgc = choice(cols)
    framec = choice(remove(bgc, cols))
    remcols = remove(bgc, remove(framec, cols))
    nshape_cols = unifint(diff_lb, diff_ub, (1, 2))
    shapecols = sample(remcols, nshape_cols)

    panel = canvas(bgc, (ph, pw))

    # fixed frame/template, repeated identically in every panel
    # use sparse decorative frame marks similar to training examples
    frame_inds = set()
    # corners / near-corners
    frame_inds.add((0, 0))
    frame_inds.add((0, pw - 1))
    frame_inds.add((ph - 1, 0))
    frame_inds.add((ph - 1, pw - 1))
    if pw >= 4:
        frame_inds.add((0, 1))
        frame_inds.add((ph - 1, 1))
        frame_inds.add((0, pw - 2))
        frame_inds.add((ph - 1, pw - 2))
    if ph >= 4:
        frame_inds.add((1, 0))
        frame_inds.add((1, pw - 1))
        frame_inds.add((ph - 2, 0))
        frame_inds.add((ph - 2, pw - 1))
    # a few extra symmetric frame cells
    if ph >= 7 and pw >= 9:
        if choice((True, False)):
            frame_inds.add((1, 1))
            frame_inds.add((1, pw - 2))
            frame_inds.add((ph - 2, 1))
            frame_inds.add((ph - 2, pw - 2))
    panel = fill(panel, framec, frozenset(frame_inds))

    # build 1-2 moving/growing shapes inside the panel
    # keep them away from borders/frame
    inner_top = 2
    inner_left = 2
    inner_bottom = ph - 3
    inner_right = pw - 3

    # ensure enough room
    if inner_bottom < inner_top:
        inner_top = 1
        inner_bottom = ph - 2
    if inner_right < inner_left:
        inner_left = 1
        inner_right = pw - 2

    stages = [panel for _ in range(npanels)]

    nobjects = nshape_cols
    for oi in range(nobjects):
        col = shapecols[oi]

        horizontal = choice((True, False))
        if horizontal and inner_right - inner_left + 1 >= npanels:
            r = randint(inner_top, inner_bottom)
            maxlen = max(npanels, min(inner_right - inner_left + 1, unifint(diff_lb, diff_ub, (npanels, max(npanels, inner_right - inner_left + 1)))))
            startc = randint(inner_left, inner_right - maxlen + 1)
            full = frozenset((r, c) for c in range(startc, startc + maxlen))
            mode = choice(("grow", "shift", "disappear"))
            for k in range(npanels):
                if mode == "grow":
                    seglen = max(1, min(maxlen, k + 1 + randint(0, max(0, maxlen - npanels))))
                    inds = frozenset((r, c) for c in range(startc, startc + seglen))
                elif mode == "shift":
                    seglen = max(1, min(maxlen - npanels + 1 if maxlen >= npanels else 1, unifint(diff_lb, diff_ub, (1, max(1, maxlen - npanels + 1)))))
                    offs = min(k, maxlen - seglen)
                    inds = frozenset((r, c) for c in range(startc + offs, startc + offs + seglen))
                else:
                    if k == npanels - 1:
                        inds = frozenset()
                    else:
                        seglen = max(1, min(maxlen, k + 1))
                        inds = frozenset((r, c) for c in range(startc, startc + seglen))
        elif (not horizontal) and inner_bottom - inner_top + 1 >= npanels:
            c = randint(inner_left, inner_right)
            maxlen = max(npanels, min(inner_bottom - inner_top + 1, unifint(diff_lb, diff_ub, (npanels, max(npanels, inner_bottom - inner_top + 1)))))
            startr = randint(inner_top, inner_bottom - maxlen + 1)
            mode = choice(("grow", "shift", "disappear"))
            for k in range(npanels):
                if mode == "grow":
                    seglen = max(1, min(maxlen, k + 1 + randint(0, max(0, maxlen - npanels))))
                    inds = frozenset((r, c) for r in range(startr, startr + seglen))
                elif mode == "shift":
                    seglen = max(1, min(maxlen - npanels + 1 if maxlen >= npanels else 1, unifint(diff_lb, diff_ub, (1, max(1, maxlen - npanels + 1)))))
                    offs = min(k, maxlen - seglen)
                    inds = frozenset((r, c) for r in range(startr + offs, startr + offs + seglen))
                else:
                    if k == npanels - 1:
                        inds = frozenset()
                    else:
                        seglen = max(1, min(maxlen, k + 1))
                        inds = frozenset((r, c) for r in range(startr, startr + seglen))
        else:
            # fallback small rectangle growing horizontally
            rh = min(2, max(1, inner_bottom - inner_top + 1))
            rw = max(npanels, min(4, inner_right - inner_left + 1))
            r0 = randint(inner_top, max(inner_top, inner_bottom - rh + 1))
            c0 = randint(inner_left, max(inner_left, inner_right - rw + 1))
            for k in range(npanels):
                ww = min(rw, k + 1)
                inds = frozenset((r0 + a, c0 + b) for a in range(rh) for b in range(ww))

                stages[k] = fill(stages[k], col, inds)
            continue

        for k in range(npanels):
            if 'inds' in locals():
                pass
        # repaint per stage by recomputing to avoid stale inds
        if horizontal and inner_right - inner_left + 1 >= npanels:
            for k in range(npanels):
                if mode == "grow":
                    seglen = max(1, min(maxlen, k + 1 + randint(0, 0)))
                    inds = frozenset((r, c) for c in range(startc, startc + seglen))
                elif mode == "shift":
                    seglen = max(1, min(maxlen - npanels + 1 if maxlen >= npanels else 1, max(1, maxlen - npanels + 1)))
                    offs = min(k, maxlen - seglen)
                    inds = frozenset((r, c) for c in range(startc + offs, startc + offs + seglen))
                else:
                    if k == npanels - 1:
                        inds = frozenset()
                    else:
                        seglen = max(1, min(maxlen, k + 1))
                        inds = frozenset((r, c) for c in range(startc, startc + seglen))
                stages[k] = fill(stages[k], col, inds)
        elif (not horizontal) and inner_bottom - inner_top + 1 >= npanels:
            for k in range(npanels):
                if mode == "grow":
                    seglen = max(1, min(maxlen, k + 1 + randint(0, 0)))
                    inds = frozenset((r, c) for r in range(startr, startr + seglen))
                elif mode == "shift":
                    seglen = max(1, min(maxlen - npanels + 1 if maxlen >= npanels else 1, max(1, maxlen - npanels + 1)))
                    offs = min(k, maxlen - seglen)
                    inds = frozenset((r, c) for r in range(startr + offs, startr + offs + seglen))
                else:
                    if k == npanels - 1:
                        inds = frozenset()
                    else:
                        seglen = max(1, min(maxlen, k + 1))
                        inds = frozenset((r, c) for r in range(startr, startr + seglen))
                stages[k] = fill(stages[k], col, inds)

    # shuffle stage order a bit but keep at least two informative stages
    if choice((True, False)):
        order_idx = list(range(npanels))
        shuffle(order_idx)
        stages = [stages[i] for i in order_idx]

    gi = stages[0]
    for k in range(1, npanels):
        gi = vconcat(gi, stages[k]) if orient_vertical else hconcat(gi, stages[k])

    go = verify_2ccd9fef(gi)
    return {'input': gi, 'output': go}


def generate_2dc579da(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (3, 30))
    w = unifint(diff_lb, diff_ub, (3, 30))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    linc = choice(remcols)
    remcols = remove(linc, remcols)
    dotc = choice(remcols)
    hdev = unifint(diff_lb, diff_ub, (0, (h - 2) // 2))
    lineh = choice((hdev, h - 2 - hdev))
    lineh = max(min(h - 2, lineh), 1)
    wdev = unifint(diff_lb, diff_ub, (0, (w - 2) // 2))
    linew = choice((wdev, w - 2 - wdev))
    linew = max(min(w - 2, linew), 1)
    locidev = unifint(diff_lb, diff_ub, (1, h // 2))
    loci = choice((h // 2 - locidev, h // 2 + locidev))
    loci = min(max(1, loci), h - lineh - 1)
    locjdev = unifint(diff_lb, diff_ub, (1, w // 2))
    locj = choice((w // 2 - locjdev, w // 2 + locjdev))
    locj = min(max(1, locj), w - linew - 1)
    gi = canvas(bgc, (h, w))
    for a in range(loci, loci + lineh):
        gi = fill(gi, linc, connect((a, 0), (a, w - 1)))
    for b in range(locj, locj + linew):
        gi = fill(gi, linc, connect((0, b), (h - 1, b)))
    doth = randint(1, loci)
    dotw = randint(1, locj)
    dotloci = randint(0, loci - doth)
    dotlocj = randint(0, locj - dotw)
    dot = backdrop(frozenset({(dotloci, dotlocj), (dotloci + doth - 1, dotlocj + dotw - 1)}))
    gi = fill(gi, dotc, dot)
    go = crop(gi, (0, 0), (loci, locj))
    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = rotf(go)
    return {'input': gi, 'output': go}


def generate_2dd70a9a(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (2, 3))
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc, fgc = sample(cols, 2)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    if choice((True, False)):
        oh = unifint(diff_lb, diff_ub, (5, h - 2))
        ow = unifint(diff_lb, diff_ub, (3, w - 2))
        loci = randint(1, h - oh - 1)
        locj = randint(1, w - ow - 1)
        hli = randint(loci+2, loci+oh-3)
        sp = {(loci+oh-1, locj), (loci+oh-2, locj)}
        ep = {(loci, locj+ow-1), (loci+1, locj+ow-1)}
        bp1 = (hli-1, locj)
        bp2 = (hli, locj+ow)
        ln1 = connect((loci+oh-1, locj), (hli, locj))
        ln2 = connect((hli, locj), (hli, locj+ow-1))
        ln3 = connect((hli, locj+ow-1), (loci+2, locj+ow-1))
    else:
        oh = unifint(diff_lb, diff_ub, (3, h-2))
        ow = unifint(diff_lb, diff_ub, (3, w-2))
        loci = randint(1, h - oh - 1)
        locj = randint(1, w - ow - 1)
        if choice((True, False)):
            sp1j = randint(locj, locj+ow-3)
            ep1j = locj
        else:
            ep1j = randint(locj, locj+ow-3)
            sp1j = locj
        sp = {(loci, sp1j), (loci, sp1j+1)}
        ep = {(loci+oh-1, ep1j), (loci+oh-1, ep1j+1)}
        bp1 = (loci, locj+ow)
        bp2 = (loci+oh, locj+ow-1)
        ln1 = connect((loci, sp1j+2), (loci, locj+ow-1))
        ln2 = connect((loci, locj+ow-1), (loci+oh-1, locj+ow-1))
        ln3 = connect((loci+oh-1, ep1j+2), (loci+oh-1, locj+ow-1))
    gi = fill(gi, 3, sp)
    gi = fill(gi, 2, ep)
    go = fill(go, 3, sp)
    go = fill(go, 2, ep)
    lns = ln1 | ln2 | ln3
    bps = {bp1, bp2}
    gi = fill(gi, fgc, bps)
    go = fill(go, fgc, bps)
    go = fill(go, 3, lns)
    inds = ofcolor(go, bgc)
    namt = unifint(diff_lb, diff_ub, (0, len(inds) // 2))
    noise = sample(totuple(inds), namt)
    gi = fill(gi, fgc, noise)
    go = fill(go, fgc, noise)
    mfs = (identity, dmirror, cmirror, vmirror, hmirror, rot90, rot180, rot270)
    nmfs = choice((1, 2))
    for fn in sample(mfs, nmfs):
        gi = fn(gi)
        go = fn(go)
    return {'input': gi, 'output': go}


def generate_2de01db2(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (3, 8))
    w = unifint(diff_lb, diff_ub, (8, 16))
    rows = []
    sigcols = (FOUR, SIX, EIGHT)
    noisecands = (ONE, TWO, THREE, FIVE, SEVEN, NINE)

    used_sig = []
    for i in range(h):
        if i < 3:
            rowc = sigcols[i]
        else:
            rowc = choice(sigcols)
        used_sig.append(rowc)

        minmain = 1
        maxmain = max(1, w - 1)
        nmain = unifint(diff_lb, diff_ub, (minmain, maxmain))
        nmain = min(max(1, nmain), w - 1)

        alljs = list(range(w))
        mainjs = set(sample(alljs, nmain))

        maxnoise = w - nmain
        if maxnoise > 0:
            nnoise = unifint(diff_lb, diff_ub, (0, maxnoise))
        else:
            nnoise = 0
        remjs = [j for j in alljs if j not in mainjs]
        noisejs = set(sample(remjs, nnoise)) if nnoise > 0 else set()

        row = []
        for j in range(w):
            if j in mainjs:
                row.append(rowc)
            elif j in noisejs:
                row.append(choice(noisecands))
            else:
                row.append(ZERO)
        rows.append(tuple(row))

    gi = tuple(rows)
    go = verify_2de01db2(gi)

    if gi == go:
        rowc = choice(sigcols)
        base = canvas(ZERO, (1, w))
        pos = choice(tuple(range(w)))
        r = fill(base, rowc, frozenset({(0, pos)}))[0]
        gi = (r,) + gi[1:]
        go = verify_2de01db2(gi)

    return {'input': gi, 'output': go}


def generate_2dee498d(diff_lb: float, diff_ub: float) -> dict:
    dim_bounds = (1, 30)
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (1, 30))
    w = unifint(diff_lb, diff_ub, (1, 10))
    bgc = choice(cols)
    go = canvas(bgc, (h, w))
    remcols = remove(bgc, cols)
    numc = unifint(diff_lb, diff_ub, (1, min(9, h * w)))
    colsch = sample(remcols, numc)
    inds = totuple(asindices(go))
    for col in colsch:
        num = unifint(diff_lb, diff_ub, (1, max(1, len(inds) // numc)))
        chos = sample(inds, num)
        go = fill(go, col, chos)
        inds = difference(inds, chos)
    gi = hconcat(go, hconcat(go, go))
    return {'input': gi, 'output': go}


def generate_2e65ae53(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    bc = choice(interval(1, 10, 1))
    rem = remove(bc, interval(1, 10, 1))
    tlc, trc, blc, brc = sample(rem, 4)

    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (18, 30))
    gi = canvas(bgc, (h, w))

    nframes_target = unifint(diff_lb, diff_ub, (3, 6))
    placed = []

    for _ in range(100):
        if len(placed) >= nframes_target:
            break
        fh = unifint(diff_lb, diff_ub, (5, min(11, h - 1)))
        fw = unifint(diff_lb, diff_ub, (5, min(11, w - 1)))
        if fh < 5 or fw < 5:
            continue
        r1 = randint(0, h - fh)
        c1 = randint(0, w - fw)
        r2 = r1 + fh - 1
        c2 = c1 + fw - 1
        hdiv = randint(r1 + 2, r2 - 2)
        vdiv = randint(c1 + 2, c2 - 2)

        cells = box(frozenset({(r1, c1), (r2, c2)})) | connect((hdiv, c1), (hdiv, c2)) | connect((r1, vdiv), (r2, vdiv))
        bb = backdrop(frozenset({(r1, c1), (r2, c2)}))
        ok = True
        for fr in placed:
            or1, oc1, or2, oc2 = fr[0], fr[1], fr[2], fr[3]
            obb = backdrop(frozenset({(or1, oc1), (or2, oc2)}))
            if len(intersection(bb, obb)) > 0:
                ok = False
                break
        if not ok:
            continue

        gi = fill(gi, bc, cells)
        placed.append((r1, c1, r2, c2, hdiv, vdiv))

    if len(placed) < 2:
        fh = 7
        fw = 7
        gi = canvas(bgc, (18, 18))
        h = 18
        w = 18
        placed = []
        specs = [(1, 1), (1, 10), (10, 1)]
        for r1, c1 in specs:
            r2 = r1 + fh - 1
            c2 = c1 + fw - 1
            hdiv = r1 + 3
            vdiv = c1 + 3
            cells = box(frozenset({(r1, c1), (r2, c2)})) | connect((hdiv, c1), (hdiv, c2)) | connect((r1, vdiv), (r2, vdiv))
            gi = fill(gi, bc, cells)
            placed.append((r1, c1, r2, c2, hdiv, vdiv))

    roles = [0, 1, 2, 3]
    shuffle(roles)
    guaranteed = roles[:]
    if len(placed) < 4:
        guaranteed = roles[:len(placed)]

    for idx, fr in enumerate(placed):
        r1, c1, r2, c2, hdiv, vdiv = fr
        quads = [
            ((r1 + 1, hdiv - 1, c1 + 1, vdiv - 1), tlc),
            ((r1 + 1, hdiv - 1, vdiv + 1, c2 - 1), trc),
            ((hdiv + 1, r2 - 1, c1 + 1, vdiv - 1), blc),
            ((hdiv + 1, r2 - 1, vdiv + 1, c2 - 1), brc),
        ]

        present = set()
        if idx < len(guaranteed):
            present.add(guaranteed[idx])
        extra_count = randint(0, 3)
        extras = [q for q in range(4) if q not in present]
        if len(extras) > 0 and extra_count > 0:
            for q in sample(extras, min(extra_count, len(extras))):
                present.add(q)

        for qix in present:
            (rs, re, cs, ce), col = quads[qix]
            qh = re - rs + 1
            qw = ce - cs + 1
            if qh <= 0 or qw <= 0:
                continue
            mode = choice((0, 1, 2))
            if mode == 0:
                inds = backdrop(frozenset({(rs, cs), (re, ce)}))
                gi = fill(gi, col, inds)
            elif mode == 1:
                ph = randint(1, qh)
                pw = randint(1, qw)
                pr = randint(rs, rs + qh - ph)
                pc = randint(cs, cs + qw - pw)
                inds = backdrop(frozenset({(pr, pc), (pr + ph - 1, pc + pw - 1)}))
                gi = fill(gi, col, inds)
            else:
                allinds = totuple(backdrop(frozenset({(rs, cs), (re, ce)})))
                npts = randint(1, max(1, min(len(allinds), 4)))
                inds = frozenset(sample(allinds, npts))
                gi = fill(gi, col, inds)

    go = verify_2e65ae53(gi)
    return {'input': gi, 'output': go}


def generate_2f0c5170(diff_lb: float, diff_ub: float) -> dict:
    bgc = 8
    anchorc = choice((1, 2, 3))
    gh = unifint(diff_lb, diff_ub, (16, 28))
    gw = unifint(diff_lb, diff_ub, (16, 28))

    ph = unifint(diff_lb, diff_ub, (4, 8))
    pw = unifint(diff_lb, diff_ub, (4, 9))
    th = unifint(diff_lb, diff_ub, (4, 9))
    tw = unifint(diff_lb, diff_ub, (4, 9))

    ai_p = unifint(diff_lb, diff_ub, (1, ph - 2))
    aj_p = unifint(diff_lb, diff_ub, (1, pw - 2))
    ai_t = unifint(diff_lb, diff_ub, (1, th - 2))
    aj_t = unifint(diff_lb, diff_ub, (1, tw - 2))

    patt = canvas(0, (ph, pw))
    patt = fill(patt, anchorc, frozenset({(ai_p, aj_p)}))

    maxup = ai_p
    maxdown = ph - 1 - ai_p
    maxleft = aj_p
    maxright = pw - 1 - aj_p

    nup = unifint(diff_lb, diff_ub, (0, maxup))
    ndown = unifint(diff_lb, diff_ub, (0, maxdown))
    nleft = unifint(diff_lb, diff_ub, (0, maxleft))
    nright = unifint(diff_lb, diff_ub, (0, maxright))

    cross = set()
    for k in range(1, nup + 1):
        cross.add((ai_p - k, aj_p))
    for k in range(1, ndown + 1):
        cross.add((ai_p + k, aj_p))
    for k in range(1, nleft + 1):
        cross.add((ai_p, aj_p - k))
    for k in range(1, nright + 1):
        cross.add((ai_p, aj_p + k))

    if len(cross) == 0:
        dirs = []
        if ai_p > 0:
            dirs.append((-1, 0))
        if ai_p < ph - 1:
            dirs.append((1, 0))
        if aj_p > 0:
            dirs.append((0, -1))
        if aj_p < pw - 1:
            dirs.append((0, 1))
        di, dj = choice(tuple(dirs))
        cross.add((ai_p + di, aj_p + dj))

    patt = fill(patt, 4, frozenset(cross))

    diagcands = []
    for di in (-1, 1):
        for dj in (-1, 1):
            ni, nj = ai_p + di, aj_p + dj
            if 0 <= ni < ph and 0 <= nj < pw:
                diagcands.append((ni, nj))
    if len(diagcands) > 0:
        ndiag = unifint(diff_lb, diff_ub, (0, len(diagcands)))
        if ndiag > 0:
            patt = fill(patt, 4, frozenset(sample(diagcands, ndiag)))

    extra = set()
    for i in range(ph):
        for j in range(pw):
            if patt[i][j] == 0 and abs(i - ai_p) + abs(j - aj_p) == 2:
                extra.add((i, j))
    extra = tuple(extra)
    if len(extra) > 0:
        nextra = unifint(diff_lb, diff_ub, (0, min(len(extra), 3)))
        if nextra > 0:
            patt = fill(patt, 4, frozenset(sample(extra, nextra)))

    gi = canvas(bgc, (gh, gw))

    for _ in range(100):
        ptop = randint(1, gh - ph - 1)
        pleft = randint(1, gw - pw - 1)
        ttop = randint(1, gh - th - 1)
        tleft = randint(1, gw - tw - 1)
        sep = not (
            ptop <= ttop + th - 1 and ttop <= ptop + ph - 1 and
            pleft <= tleft + tw - 1 and tleft <= pleft + pw - 1
        )
        if sep:
            break
    else:
        ptop, pleft = 1, 1
        ttop, tleft = gh - th - 1, gw - tw - 1

    gi = fill(gi, 0, shift(asindices(canvas(0, (ph, pw))), (ptop, pleft)))
    gi = fill(gi, 0, shift(asindices(canvas(0, (th, tw))), (ttop, tleft)))

    pobj = shift(asobject(patt), (ptop, pleft))
    gi = paint(gi, pobj)
    gi = fill(gi, anchorc, frozenset({(ttop + ai_t, tleft + aj_t)}))

    go = verify_2f0c5170(gi)
    return {'input': gi, 'output': go}


def generate_2f767503(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (10, 20))
    w = unifint(diff_lb, diff_ub, (10, 20))
