def generate_358ba94e(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    fgc = choice(cols)
    h = unifint(diff_lb, diff_ub, (14, 22))
    w = unifint(diff_lb, diff_ub, (18, 26))
    gi = canvas(0, (h, w))

    # 5x5 box and 7x7 margin as proper filled rectangles
    box5 = backdrop(frozenset({(0, (0, 0)), (0, (4, 4))}))
    margin7 = backdrop(frozenset({(0, (0, 0)), (0, (6, 6))}))

    # Interior positions where holes can go (rows 1-3, cols 1-3 inside the 5x5)
    all_holes = tuple(product(interval(1, 4, 1), interval(1, 4, 1)))
    maj_n = unifint(diff_lb, diff_ub, (1, 4))
    other_opts = remove(maj_n, interval(1, 5, 1))
    other_n = choice(other_opts)

    nmaj = unifint(diff_lb, diff_ub, (2, 4))
    nother = 1
    nshapes = nmaj + nother

    shapes = []
    for _ in range(nmaj):
        holes = frozenset(sample(totuple(all_holes), maj_n))
        shapes.append(holes)
    holes = frozenset(sample(totuple(all_holes), other_n))
    shapes.append(holes)
    shuffle(shapes)

    occ = set()
    placed = 0
    maxtr = 500
    tr = 0
    while placed < nshapes and tr < maxtr:
        tr += 1
        loci = randint(0, h - 5)
        locj = randint(0, w - 5)
        bb = shift(box5, (loci, locj))
        margin = shift(margin7, (loci - 1, locj - 1))
        if len(frozenset(margin) & frozenset(occ)) != 0:
            continue
        gi = fill(gi, fgc, bb)
        gi = fill(gi, 0, shift(shapes[placed], (loci, locj)))
        occ |= set(bb)
        placed += 1

    if placed < nshapes:
        step = 7
        coords = []
        for i in range(0, h - 4, step):
            for j in range(0, w - 4, step):
                coords.append((i, j))
        for k in range(min(nshapes - placed, len(coords))):
            loci, locj = coords[k]
            bb = shift(box5, (loci, locj))
            gi = fill(gi, fgc, bb)
            gi = fill(gi, 0, shift(shapes[placed], (loci, locj)))
            placed += 1
            if placed == nshapes:
                break

    go = verify_358ba94e(gi)
    return {'input': gi, 'output': go}


