def generate_37d3e8b2(diff_lb: float, diff_ub: float) -> dict:
    def make_shape_with_holes(hh, ww, nholes):
        shp = canvas(8, (hh, ww))
        used = set()
        maxholes = max(1, ((hh - 2) * (ww - 2)) // 4)
        nholes = min(nholes, maxholes)
        for _ in range(200):
            holes = []
            used = set()
            ok = True
            for k in range(nholes):
                placed = False
                for _r in range(200):
                    hi = choice((1, 2))
                    hj = choice((1, 2))
                    if hh - hi - 1 < 1 or ww - hj - 1 < 1:
                        continue
                    i = randint(1, hh - hi - 1)
                    j = randint(1, ww - hj - 1)
                    cells = {(a, b) for a in range(i, i + hi) for b in range(j, j + hj)}
                    halo = set()
                    for a, b in cells:
                        halo |= set(neighbors((a, b)))
                        halo.add((a, b))
                    halo = {(a, b) for a, b in halo if 0 <= a < hh and 0 <= b < ww}
                    if any((a, b) in used for a, b in halo):
                        continue
                    holes.append(cells)
                    used |= halo
                    placed = True
                    break
                if not placed:
                    ok = False
                    break
            if not ok:
                continue
            g = shp
            for cells in holes:
                g = fill(g, 0, frozenset(cells))
            if len(connected_components(delta(asobject(g)))) == nholes:
                return g
        g = shp
        placed = 0
        for i in range(1, hh - 1, 2):
            for j in range(1, ww - 1, 2):
                if placed < nholes:
                    g = fill(g, 0, frozenset({(i, j)}))
                    placed += 1
        return g

    nobj = unifint(diff_lb, diff_ub, (3, 6))
    dims = []
    holecounts = []
    for _ in range(nobj):
        hh = unifint(diff_lb, diff_ub, (3, 7))
        ww = unifint(diff_lb, diff_ub, (3, 7))
        maxh = max(1, min(5, ((hh - 2) * (ww - 2) + 3) // 4))
        nh = unifint(diff_lb, diff_ub, (1, maxh))
        dims.append((hh, ww))
        holecounts.append(nh)

    row_heights = [0, 0]
    row_widths = [0, 0]
    rows = [[], []]
    for idx, d in enumerate(dims):
        r = 0 if row_widths[0] <= row_widths[1] else 1
        rows[r].append(idx)
        row_widths[r] += d[1] + 2
        row_heights[r] = max(row_heights[r], d[0])

    h = max(10, min(30, row_heights[0] + row_heights[1] + 5))
    w = max(10, min(30, max(row_widths[0], row_widths[1]) + 3))
    gi = canvas(0, (h, w))

    top_margin = 1
    left_margin = 1
    row_gap = 2
    ystarts = [top_margin, top_margin + row_heights[0] + row_gap]

    for ridx in range(2):
        x = left_margin
        for idx in rows[ridx]:
            hh, ww = dims[idx]
            shp = make_shape_with_holes(hh, ww, holecounts[idx])
            gi = paint(gi, shift(asobject(shp), (ystarts[ridx], x)))
            x += ww + 2

    go = verify_37d3e8b2(gi)
    return {'input': gi, 'output': go}


