def generate_396d80d7(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc = choice(cols)
    rem = remove(bgc, cols)
    innerc, outerc = sample(rem, 2)

    h = 16
    w = 16
    gi = canvas(bgc, (h, w))

    typ = choice((0, 1))

    if typ == 0:
        # H-like motif matching example 1 distribution
        top = unifint(diff_lb, diff_ub, (3, 6))
        left = unifint(diff_lb, diff_ub, (3, 6))
        barh = unifint(diff_lb, diff_ub, (2, 4))
        gapw = unifint(diff_lb, diff_ub, (1, 3))
        sideh = 2 * barh - 1
        totalw = 2 + gapw + 2
        if top + sideh > h - 3:
            top = h - 3 - sideh
        if left + totalw > w - 3:
            left = w - 3 - totalw

        leftbar_top = connect((top, left + 1), (top, left + 2))
        rightbar_top = connect((top, left + 3 + gapw), (top, left + 4 + gapw))
        leftdiag1 = initset((top + 1, left))
        rightdiag1 = initset((top + 1, left + 5 + gapw))
        midrow1 = connect((top + 2, left + 1), (top + 2, left + 2))
        midrow2 = connect((top + 2, left + 3 + gapw), (top + 2, left + 4 + gapw))
        center1 = initset((top + 2, left + 2 + gapw))
        leftdiag2 = initset((top + 3, left))
        rightdiag2 = initset((top + 3, left + 5 + gapw))
        botrow1 = connect((top + 4, left + 1), (top + 4, left + 2))
        botrow2 = connect((top + 4, left + 3 + gapw), (top + 4, left + 4 + gapw))
        center2 = initset((top + 4, left + 2 + gapw))

        outer = leftbar_top | rightbar_top | leftdiag1 | rightdiag1 | midrow1 | midrow2 | leftdiag2 | rightdiag2 | botrow1 | botrow2
        inner = center1 | center2

        gi = fill(gi, outerc, outer)
        gi = fill(gi, innerc, inner)
    else:
        # Diamond/ring motif matching example 2 distribution
        top = unifint(diff_lb, diff_ub, (4, 6))
        left = unifint(diff_lb, diff_ub, (4, 6))
        if top + 5 > h - 2:
            top = h - 2 - 5
        if left + 5 > w - 2:
            left = w - 2 - 5

        outer = (
            connect((top, left + 2), (top, left + 3)) |
            initset((top + 1, left + 1)) |
            initset((top + 1, left + 4)) |
            initset((top + 2, left)) |
            initset((top + 2, left + 5)) |
            initset((top + 3, left)) |
            initset((top + 3, left + 5)) |
            initset((top + 4, left + 1)) |
            initset((top + 4, left + 4)) |
            connect((top + 5, left + 2), (top + 5, left + 3))
        )
        inner = backdrop(frozenset({(top + 2, left + 2), (top + 3, left + 3)}))

        gi = fill(gi, outerc, outer)
        gi = fill(gi, innerc, inner)

    go = verify_396d80d7(gi)
    return {'input': gi, 'output': go}


