def generate_3ad05f52(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    wallc = 8
    seedc = choice(remove(wallc, remove(bgc, interval(0, 10, 1))))

    cellh = choice((3, 4, 5))
    cellw = choice((3, 4, 5))
    rows = unifint(diff_lb, diff_ub, (2, 5))
    cols = unifint(diff_lb, diff_ub, (2, 5))
    h = rows * (cellh - 1) + 1
    w = cols * (cellw - 1) + 1

    gi = canvas(bgc, (h, w))

    # full lattice of 8-walls
    for r in range(rows + 1):
        rr = r * (cellh - 1)
        gi = fill(gi, wallc, connect((rr, 0), (rr, w - 1)))
    for c in range(cols + 1):
        cc = c * (cellw - 1)
        gi = fill(gi, wallc, connect((0, cc), (h - 1, cc)))

    # carve doorways in selected internal walls to create pipe-like connectivity
    # horizontal internal walls
    for r in range(1, rows):
        rr = r * (cellh - 1)
        for c in range(cols):
            if randint(0, 1) == 1:
                left = c * (cellw - 1) + 1
                right = (c + 1) * (cellw - 1) - 1
                if left <= right:
                    doorw = randint(1, max(1, right - left + 1))
                    start = randint(left, right - doorw + 1)
                    gi = fill(gi, bgc, connect((rr, start), (rr, start + doorw - 1)))
    # vertical internal walls
    for c in range(1, cols):
        cc = c * (cellw - 1)
        for r in range(rows):
            if randint(0, 1) == 1:
                top = r * (cellh - 1) + 1
                bot = (r + 1) * (cellh - 1) - 1
                if top <= bot:
                    doorh = randint(1, max(1, bot - top + 1))
                    start = randint(top, bot - doorh + 1)
                    gi = fill(gi, bgc, connect((start, cc), (start + doorh - 1, cc)))

    # optionally open a few outer-border gaps so some structures are not fully closed
    sideopts = []
    if rows >= 1 and cols >= 1:
        sideopts = ['top', 'bottom', 'left', 'right']
    ngaps = unifint(diff_lb, diff_ub, (0, 3))
    chosen_sides = sample(sideopts, min(len(sideopts), ngaps))
    for side in chosen_sides:
        if side == 'top':
            c = randint(0, cols - 1)
            left = c * (cellw - 1) + 1
            right = (c + 1) * (cellw - 1) - 1
            if left <= right:
                doorw = randint(1, max(1, right - left + 1))
                start = randint(left, right - doorw + 1)
                gi = fill(gi, bgc, connect((0, start), (0, start + doorw - 1)))
        elif side == 'bottom':
            c = randint(0, cols - 1)
            left = c * (cellw - 1) + 1
            right = (c + 1) * (cellw - 1) - 1
            if left <= right:
                doorw = randint(1, max(1, right - left + 1))
                start = randint(left, right - doorw + 1)
                gi = fill(gi, bgc, connect((h - 1, start), (h - 1, start + doorw - 1)))
        elif side == 'left':
            r = randint(0, rows - 1)
            top = r * (cellh - 1) + 1
            bot = (r + 1) * (cellh - 1) - 1
            if top <= bot:
                doorh = randint(1, max(1, bot - top + 1))
                start = randint(top, bot - doorh + 1)
                gi = fill(gi, bgc, connect((start, 0), (start + doorh - 1, 0)))
        else:
            r = randint(0, rows - 1)
            top = r * (cellh - 1) + 1
            bot = (r + 1) * (cellh - 1) - 1
            if top <= bot:
                doorh = randint(1, max(1, bot - top + 1))
                start = randint(top, bot - doorh + 1)
                gi = fill(gi, bgc, connect((start, w - 1), (start + doorh - 1, w - 1)))

    # place one seed patch inside a cell interior
    sr = randint(0, rows - 1)
    sc = randint(0, cols - 1)
    itop = sr * (cellh - 1) + 1
    ileft = sc * (cellw - 1) + 1
    ibot = (sr + 1) * (cellh - 1) - 1
    iright = (sc + 1) * (cellw - 1) - 1
    ph = randint(1, max(1, ibot - itop + 1))
    pw = randint(1, max(1, iright - ileft + 1))
    pr = randint(itop, ibot - ph + 1)
    pc = randint(ileft, iright - pw + 1)
    gi = fill(gi, seedc, backdrop(frozenset({(pr, pc), (pr + ph - 1, pc + pw - 1)})))

    # add zero padding around the structure, matching training distribution
    topm = unifint(diff_lb, diff_ub, (0, 4))
    botm = unifint(diff_lb, diff_ub, (0, 4))
    leftm = unifint(diff_lb, diff_ub, (0, 4))
    rightm = unifint(diff_lb, diff_ub, (0, 4))

    if topm > 0:
        gi = vconcat(canvas(bgc, (topm, width(gi))), gi)
    if botm > 0:
        gi = vconcat(gi, canvas(bgc, (botm, width(gi))))
    if leftm > 0:
        gi = hconcat(canvas(bgc, (height(gi), leftm)), gi)
    if rightm > 0:
        gi = hconcat(gi, canvas(bgc, (height(gi), rightm)))

    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = verify_3ad05f52(gi)
    return {'input': gi, 'output': go}


