def generate_3b4c2228(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (5, 9))
    w = unifint(diff_lb, diff_ub, (5, 9))
    gi = canvas(0, (h, w))

    maxr = h - 1
    maxc = w - 1
    all_tl = [(i, j) for i in range(maxr) for j in range(maxc)]
    shuffle(all_tl)

    target = unifint(diff_lb, diff_ub, (1, min(3, len(all_tl))))
    sqs = []

    for loc in all_tl:
        if len(sqs) >= target:
            break
        ok = True
        for oi, oj in sqs:
            if abs(loc[0] - oi) <= 1 and abs(loc[1] - oj) <= 1:
                ok = False
                break
        if ok:
            sqs.append(loc)

    if len(sqs) == 0:
        sqs = [(0, 0)]
        target = 1

    for i, j in sqs:
        gi = fill(gi, 3, connect((i, j), (i + 1, j + 1)))

    noise2 = unifint(diff_lb, diff_ub, (0, max(1, (h * w) // 5)))
    noise3 = unifint(diff_lb, diff_ub, (0, max(1, (h * w) // 6)))

    protected = set()
    for i, j in sqs:
        protected |= set(connect((i, j), (i + 1, j + 1)))
        for a in range(max(0, i - 1), min(h, i + 3)):
            for b in range(max(0, j - 1), min(w, j + 3)):
                protected.add((a, b))

    free = [ij for ij in totuple(asindices(gi)) if ij not in protected and gi[ij[0]][ij[1]] == 0]
    shuffle(free)

    n2 = min(noise2, len(free))
    if n2 > 0:
        gi = fill(gi, 2, frozenset(free[:n2]))
    free = [ij for ij in free[n2:] if gi[ij[0]][ij[1]] == 0]

    singles = []
    for ij in free:
        if len(singles) >= noise3:
            break
        r, c = ij
        if r + 1 < h and c + 1 < w:
            block = {(r, c), (r + 1, c), (r, c + 1), (r + 1, c + 1)}
            greens = sum(1 for x in block if gi[x[0]][x[1]] == 3)
            if greens >= 1:
                continue
        if r - 1 >= 0 and c + 1 < w:
            block = {(r - 1, c), (r, c), (r - 1, c + 1), (r, c + 1)}
            greens = sum(1 for x in block if gi[x[0]][x[1]] == 3)
            if greens >= 1:
                continue
        if r + 1 < h and c - 1 >= 0:
            block = {(r, c - 1), (r + 1, c - 1), (r, c), (r + 1, c)}
            greens = sum(1 for x in block if gi[x[0]][x[1]] == 3)
            if greens >= 1:
                continue
        if r - 1 >= 0 and c - 1 >= 0:
            block = {(r - 1, c - 1), (r, c - 1), (r - 1, c), (r, c)}
            greens = sum(1 for x in block if gi[x[0]][x[1]] == 3)
            if greens >= 1:
                continue
        singles.append(ij)

    if len(singles) > 0:
        gi = fill(gi, 3, frozenset(singles))

    go = verify_3b4c2228(gi)
    return {'input': gi, 'output': go}


def generate_3bd292e8(diff_lb: float, diff_ub: float) -> dict:
    for _ in range(100):
        h = unifint(diff_lb, diff_ub, (7, 12))
        w = unifint(diff_lb, diff_ub, (7, 12))
        gi = canvas(SEVEN, (h, w))

        npaths = unifint(diff_lb, diff_ub, (2, max(2, (h + w) // 3)))
        occupied = set()

        for _k in range(npaths):
            orient = choice((0, 1))
            if orient == 0:
                ln = unifint(diff_lb, diff_ub, (2, max(2, h - 2)))
                i = randint(0, h - 1)
                j0 = randint(0, w - ln)
                cells = connect((i, j0), (i, j0 + ln - 1))
            else:
                ln = unifint(diff_lb, diff_ub, (2, max(2, w - 2)))
                j = randint(0, w - 1)
                i0 = randint(0, h - ln)
                cells = connect((i0, j), (i0 + ln - 1, j))

            if len(cells & frozenset(occupied)) > 0:
                continue
            occupied |= set(cells)
            gi = fill(gi, TWO, cells)

        sevens = ofcolor(gi, SEVEN)
        comps = connected_components(sevens, False)
        if len(comps) < 2:
            continue

        start = (h - 1, 0)
        if start not in sevens:
            continue

        good = True
        for comp in comps:
            touched = set()
            for ij in comp:
                for nb in dneighbors(ij):
                    if 0 <= nb[0] < h and 0 <= nb[1] < w and gi[nb[0]][nb[1]] == TWO:
                        touched.add(nb)
            if len(touched) == 0:
                good = False
                break
        if not good:
            continue

        go = verify_3bd292e8(gi)
        if gi != go and palette(gi) == frozenset({TWO, SEVEN}) and FIVE in palette(go) and THREE in palette(go):
            return {'input': gi, 'output': go}

    h = 7
    w = 7
    gi = canvas(SEVEN, (h, w))
    reds = frozenset({
        (0, 2), (1, 2), (1, 3), (1, 4), (2, 4),
        (3, 0), (3, 1), (3, 4), (3, 5), (3, 6),
        (4, 1), (5, 1), (5, 2), (5, 3), (5, 4), (6, 4)
    })
    gi = fill(gi, TWO, reds)
    go = verify_3bd292e8(gi)
    return {'input': gi, 'output': go}


