def generate_3cd86f4f(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (3, 12))
    w = unifint(diff_lb, diff_ub, (3, 12))
    cols = interval(1, 10, 1)

    mode = choice((0, 1, 2, 3))

    if mode == 0:
        c1, c2, c3 = sample(cols, 3)
        rows = []
        for i in range(h):
            row = []
            for j in range(w):
                if j < i:
                    row.append(c1)
                elif j == i and i < w:
                    row.append(c2)
                else:
                    row.append(c3)
            rows.append(tuple(row))
        gi = tuple(rows)

    elif mode == 1:
        bgc, stripec, diagc = sample(cols, 3)
        rows = []
        for i in range(h):
            row = []
            for j in range(w):
                v = stripec if j == 0 else bgc
                if i == j or i + j == w - 1:
                    v = diagc
                row.append(v)
