def generate_3d6c6e23(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(ZERO, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (12, 28))
    maxw = min(15, h - 1 if h > 1 else 1)
    w = unifint(diff_lb, diff_ub, (7, maxw))
    gi = canvas(ZERO, (h, w))

    ncols_max = min(4, w)
    nocc_cols = unifint(diff_lb, diff_ub, (1, ncols_max))
    center = w // 2
    cand_cols = [j for j in range(w) if abs(j - center) <= (h - 1) // 2]
    if len(cand_cols) < nocc_cols:
        cand_cols = list(range(w))
    occ_cols = sample(cand_cols, nocc_cols)
    occ_cols.sort()

    for j in occ_cols:
        maxcells = min(h - 1, 2 * min(j, w - 1 - j) + 1)
        maxlayers = 0
        s = 0
        while s < maxcells:
            maxlayers += 1
            s += 2 * (maxlayers - 1) + 1
        nlayers = unifint(diff_lb, diff_ub, (1, maxlayers))
        total = 0
        for k in range(nlayers):
            total += 2 * k + 1

        if nlayers == 1:
            layer_sizes = [total]
        else:
            cuts_needed = nlayers - 1
            possible = list(range(1, total))
            if len(possible) >= cuts_needed:
                cuts = sorted(sample(possible, cuts_needed))
            else:
                cuts = list(range(1, nlayers))
            prev = 0
            layer_sizes = []
            for c in cuts + [total]:
                layer_sizes.append(c - prev)
                prev = c

        layer_colors = sample(cols, nlayers)
        rows_available = list(range(h))
        shuffle(rows_available)
        ptr = 0
        for sz, c in zip(layer_sizes, layer_colors):
            chosen_rows = sorted(rows_available[ptr:ptr + sz])
            ptr += sz
            for i in chosen_rows:
                gi = fill(gi, c, initset((i, j)))

    go = verify_3d6c6e23(gi)
    return {'input': gi, 'output': go}


