def generate_414297c0(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(2, interval(1, 10, 1))
    bgc = 0
    rectc = choice(cols)
    marker_cols_all = remove(rectc, cols)
    nmarkers = unifint(diff_lb, diff_ub, (2, 4))
    marker_cols = sample(marker_cols_all, nmarkers)

    rh = unifint(diff_lb, diff_ub, (5, 12))
    rw = unifint(diff_lb, diff_ub, (5, 12))

    maxph = max(3, min(8, 30 - rh - 2))
    maxpw = max(3, min(8, 30 - rw - 2))
    ph = unifint(diff_lb, diff_ub, (3, maxph))
    pw = unifint(diff_lb, diff_ub, (3, maxpw))

    H = unifint(diff_lb, diff_ub, (max(rh + 4, ph + 2), 30))
    W = unifint(diff_lb, diff_ub, (max(rw + 4, pw + 2), 30))

    gi = canvas(bgc, (H, W))

    recti = randint(0, H - rh)
    rectj = randint(0, W - rw)
    rect_patch = connect((recti, rectj), (recti + rh - 1, rectj + rw - 1))
    gi = fill(gi, rectc, rect_patch)

    inside_cells = [(i, j) for i in range(1, rh - 1) for j in range(1, rw - 1)]
    shuffle(inside_cells)
    marker_locs_rel = inside_cells[:nmarkers]

    used_abs = set()
    for c, (ri, rj) in zip(marker_cols, marker_locs_rel):
        gi = fill(gi, c, frozenset({(recti + ri, rectj + rj)}))
        used_abs.add((recti + ri, rectj + rj))

    all_positions = [(i, j) for i in range(H - ph + 1) for j in range(W - pw + 1)]
    shuffle(all_positions)
    patloc = None
    rect_box = rect_patch
    for pi, pj in all_positions:
        pbox = connect((pi, pj), (pi + ph - 1, pj + pw - 1))
        if len(intersection(pbox, rect_box)) == 0:
            patloc = (pi, pj)
            break
    if patloc is None:
        pi, pj = 0, 0
        if recti == 0 and rectj == 0:
            pi, pj = H - ph, W - pw
        patloc = (pi, pj)
    pi, pj = patloc

    pattern_cells = set()
    anchor_positions = []
    for idx, c in enumerate(marker_cols):
        if idx == 0:
            ai = randint(1, ph - 2)
            aj = randint(1, pw - 2)
        else:
            cands = [(i, j) for i in range(1, ph - 1) for j in range(1, pw - 1) if (i, j) not in pattern_cells]
            if len(cands) == 0:
                cands = [(1, 1)]
            ai, aj = choice(cands)
        anchor_positions.append((ai, aj))
        pattern_cells.add((ai, aj))
        gi = fill(gi, c, frozenset({(pi + ai, pj + aj)}))

    for idx, (c, (ai, aj)) in enumerate(zip(marker_cols, anchor_positions)):
        maxreds = unifint(diff_lb, diff_ub, (2, 5))
        neighs = list(dneighbors((ai, aj)))
        neighs = [(u, v) for (u, v) in neighs if 0 <= u < ph and 0 <= v < pw]
        shuffle(neighs)
        reds = []
        for uv in neighs:
            if uv not in pattern_cells:
                reds.append(uv)
            if len(reds) >= maxreds:
                break
        if len(reds) == 0:
            fallback = [(ai - 1, aj), (ai + 1, aj), (ai, aj - 1), (ai, aj + 1)]
            for uv in fallback:
                u, v = uv
                if 0 <= u < ph and 0 <= v < pw and uv not in pattern_cells:
                    reds.append(uv)
                    break
        for uv in reds:
            pattern_cells.add(uv)
            gi = fill(gi, 2, frozenset({(pi + uv[0], pj + uv[1])}))

    noise_cols = remove(rectc, remove(2, marker_cols_all))
    nnoise = unifint(diff_lb, diff_ub, (0, 6))
    freecells = [(i, j) for i in range(H) for j in range(W) if gi[i][j] == bgc]
    shuffle(freecells)
    for loc in freecells[:nnoise]:
        gi = fill(gi, choice(noise_cols), frozenset({loc}))

    go = verify_414297c0(gi)
    return {'input': gi, 'output': go}


def generate_41ace6b5(diff_lb: float, diff_ub: float) -> dict:
    ncols = unifint(diff_lb, diff_ub, (4, 7))
    w = 2 * ncols - 1
    min_h = 5
    max_h = min(30, 4 + ncols + 10)
    h = unifint(diff_lb, diff_ub, (min_h, max_h))
    twor = unifint(diff_lb, diff_ub, (2, h - 3))
    max8 = twor
    max1 = h - twor - 2

    gi = canvas(7, (h, w))

    oddcols = interval(0, w, 2)
    evencols = interval(1, w, 2)

    gi = fill(gi, 2, product(initset(twor), oddcols))
    gi = fill(gi, 5, product(initset(twor + 1), oddcols))

    max8_global = unifint(diff_lb, diff_ub, (0, max8))
    if max1 > 0:
        max1_global = unifint(diff_lb, diff_ub, (1, max1))
    else:
        max1_global = 0

    cols_with_8 = list(evencols)
    shuffle(cols_with_8)
    if len(cols_with_8) > 0:
        k8 = unifint(diff_lb, diff_ub, (1, len(cols_with_8)))
        cols_with_8 = cols_with_8[:k8]
    else:
        cols_with_8 = []

    cols_with_1 = list(evencols)
    shuffle(cols_with_1)
    if len(cols_with_1) > 0:
        k1 = unifint(diff_lb, diff_ub, (1, len(cols_with_1)))
        cols_with_1 = cols_with_1[:k1]
    else:
        cols_with_1 = []

    for j in evencols:
        ecount = 0
        ocount = 0
        if j in cols_with_8 and max8_global > 0:
            ecount = unifint(diff_lb, diff_ub, (1, max8_global))
        if j in cols_with_1 and max1_global > 0:
            ocount = unifint(diff_lb, diff_ub, (1, max1_global))

        if ecount > 0:
            estart = twor - ecount
            gi = fill(gi, 8, connect((estart, j), (twor - 1, j)))
        if ocount > 0:
            ostart = twor + 2 + (max1_global - ocount)
            gi = fill(gi, 1, connect((ostart, j), (twor + 1 + max1_global, j)))

    go = verify_41ace6b5(gi)
    return {'input': gi, 'output': go}


def generate_41e4d17e(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(6, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (6, 30))
    w = unifint(diff_lb, diff_ub, (6, 30))
    num = unifint(diff_lb, diff_ub, (1, (h * w) // 16))
    bgc, fgc = sample(cols, 2)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    inds = asindices(gi)
    bx = box(frozenset({(0, 0), (4, 4)}))
    bd = backdrop(bx)
    maxtrials = 4 * num
    succ = 0
    tr = 0
    while succ < num and tr < maxtrials:
        loc = choice(totuple(inds))
        bxs = shift(bx, loc)
        if bxs.issubset(set(inds)):
            gi = fill(gi, fgc, bxs)
            go = fill(go, fgc, bxs)
            cen = center(bxs)
            frns = hfrontier(cen) | vfrontier(cen)
            kep = frns & ofcolor(go, bgc)
            go = fill(go, 6, kep)
            inds = difference(inds, shift(bd, loc))
            succ += 1
        tr += 1
    return {'input': gi, 'output': go}


def generate_423a55dc(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (7, 14))
    w = unifint(diff_lb, diff_ub, (7, 16))
    fg = choice(cols)
    gi = canvas(0, (h, w))

    oh = unifint(diff_lb, diff_ub, (2, min(6, h - 2)))
    ow = unifint(diff_lb, diff_ub, (3, min(7, w - 1)))

    top = unifint(diff_lb, diff_ub, (1, h - oh - 1))
    left_min = oh - 1
    left_max = w - ow
    if left_min > left_max:
        left = left_max
    else:
        left = unifint(diff_lb, diff_ub, (left_min, left_max))

    shape_type = choice(("rect", "ring", "E", "C", "H", "U", "P", "F", "mixed"))
    cells = set()

    if shape_type == "rect":
        cells |= set(connect((0, 0), (oh - 1, ow - 1)))
    elif shape_type == "ring":
        cells |= set(connect((0, 0), (0, ow - 1)))
        cells |= set(connect((oh - 1, 0), (oh - 1, ow - 1)))
        cells |= set(connect((0, 0), (oh - 1, 0)))
        cells |= set(connect((0, ow - 1), (oh - 1, ow - 1)))
    elif shape_type == "E":
        cells |= set(connect((0, 0), (oh - 1, 0)))
        cells |= set(connect((0, 0), (0, ow - 1)))
        mid = oh // 2
        cells |= set(connect((mid, 0), (mid, max(1, ow - 2))))
        cells |= set(connect((oh - 1, 0), (oh - 1, ow - 1)))
    elif shape_type == "C":
        cells |= set(connect((0, 0), (0, ow - 1)))
        cells |= set(connect((0, 0), (oh - 1, 0)))
        cells |= set(connect((oh - 1, 0), (oh - 1, ow - 1)))
    elif shape_type == "H":
        cells |= set(connect((0, 0), (oh - 1, 0)))
        cells |= set(connect((0, ow - 1), (oh - 1, ow - 1)))
        mid = oh // 2
        cells |= set(connect((mid, 0), (mid, ow - 1)))
    elif shape_type == "U":
        cells |= set(connect((0, 0), (oh - 1, 0)))
        cells |= set(connect((0, ow - 1), (oh - 1, ow - 1)))
        cells |= set(connect((oh - 1, 0), (oh - 1, ow - 1)))
    elif shape_type == "P":
        split = max(1, oh // 2)
        cells |= set(connect((0, 0), (oh - 1, 0)))
        cells |= set(connect((0, 0), (0, ow - 1)))
        cells |= set(connect((split, 0), (split, ow - 1)))
        cells |= set(connect((0, ow - 1), (split, ow - 1)))
    elif shape_type == "F":
        cells |= set(connect((0, 0), (oh - 1, 0)))
        cells |= set(connect((0, 0), (0, ow - 1)))
        mid = oh // 2
        cells |= set(connect((mid, 0), (mid, max(1, ow - 2))))
    else:
        cells |= set(connect((oh - 1, 0), (oh - 1, ow - 1)))
        ncols = unifint(diff_lb, diff_ub, (2, min(ow, 5)))
        colchoices = sample(tuple(range(ow)), ncols)
        for cj in colchoices:
            topend = randint(0, oh - 1)
            cells |= set(connect((topend, cj), (oh - 1, cj)))
        nrows = unifint(diff_lb, diff_ub, (0, min(oh - 1, 3)))
        rowchoices = sample(tuple(range(oh - 1)), nrows) if oh > 1 else []
        for ri in rowchoices:
            endj = randint(0, ow - 1)
            cells |= set(connect((ri, 0), (ri, endj)))

    if not any(i == oh - 1 for i, j in cells):
        cells |= set(connect((oh - 1, 0), (oh - 1, ow - 1)))

    shifted = shift(frozenset(cells), (top, left))
    gi = fill(gi, fg, shifted)
    go = verify_423a55dc(gi)
    return {'input': gi, 'output': go}


def generate_4258a5f9(diff_lb: float, diff_ub: float) -> dict:
    colopts = remove(1, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (2, 30))
    w = unifint(diff_lb, diff_ub, (2, 30))
