def generate_4290ef0e(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    while True:
        d = unifint(diff_lb, diff_ub, (2, 7))
        h, w = d, d
        fullh = unifint(diff_lb, diff_ub, (4*d, 30))
        fullw = unifint(diff_lb, diff_ub, (4*d, 30))
        bgc = choice(cols)
        remcols = remove(bgc, cols)
        ccols = sample(remcols, d)
        quad = canvas(bgc, (d+1, d+1))
        for idx, c in enumerate(ccols):
            linlen = randint(2, w-idx+1)
            quad = fill(quad, c, (connect((idx, idx), (idx+linlen-1, idx))))
            quad = fill(quad, c, (connect((idx, idx), (idx, idx+linlen-1))))
        go = canvas(bgc, (d+1, 2*d+1))
        qobj1 = asobject(quad)
        qobj2 = shift(asobject(vmirror(quad)), (0, d))
        go = paint(go, qobj1)
        go = paint(go, qobj2)
        go = vconcat(go, hmirror(go)[1:])
        if choice((True, False)):
            go = fill(go, choice(difference(remcols, ccols)), {center(asindices(go))})
        objs = partition(go)
        objs = sfilter(objs, lambda o: color(o) != bgc)
        gi = canvas(bgc, (fullh, fullw))
        objs = order(objs, width)
        fullinds = asindices(gi)
        inds = asindices(gi)
        fullsuc = True
        for obj in objs:
            objn = normalize(obj)
            obji = toindices(objn)
            d = width(obj)
            dh = max(0, d//2-1)
            cands = sfilter(fullinds, lambda ij: ij[0] <= fullh - d and ij[1] <= fullw - d)
            cands = cands | shift(cands, (-dh, 0)) | shift(cands, (0, -dh)) | shift(cands, (dh, 0)) | shift(cands, (0, dh))
            maxtr = 10
            tr = 0
            succ = False
            if len(cands) == 0:
                break
            while tr < maxtr and not succ:
                tr += 1    
                loc = choice(totuple(cands))
                if (shift(obji, loc) & fullinds).issubset(inds):
                    succ = True
                    break
            if not succ:
                fullsuc = False
                break
            gi = paint(gi, shift(objn, loc))
            inds = inds - shift(obji, loc)
        if not fullsuc:
            continue
        break
    return {'input': gi, 'output': go}


def generate_42918530(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    cols = remove(bgc, interval(0, 10, 1))

    nrows = unifint(diff_lb, diff_ub, (2, 4))
    ncols = 3
    ncells = nrows * ncols

    # Need at least one color appearing 2+ times so verifier has something to fill
    # Pick how many unique colors (must be < ncells to guarantee duplicates)
    max_uniq = min(len(cols), ncells - 1)
    min_uniq = max(1, min(2, max_uniq))
    nuniq = unifint(diff_lb, diff_ub, (min_uniq, max_uniq))

    usecols = sample(list(cols), nuniq)

    # Build color list: start with one of each unique color, fill rest with duplicates
    color_list = list(usecols)
    extra = ncells - nuniq
    for _ in range(extra):
        color_list.append(choice(usecols))
    shuffle(color_list)

    # Ensure at least one color appears 2+ times
    from collections import Counter
    counts = Counter(color_list)
    dup_colors = [c for c, cnt in counts.items() if cnt >= 2]
    if not dup_colors:
        # Force a duplicate by replacing one cell's color with another's
        idx0, idx1 = sample(range(ncells), 2)
        color_list[idx1] = color_list[idx0]
        counts = Counter(color_list)
        dup_colors = [c for c, cnt in counts.items() if cnt >= 2]

    def rand_pattern():
        interior = canvas(0, (3, 3))
        allinds = totuple(asindices(interior))
        k = unifint(diff_lb, diff_ub, (1, 5))
        cells = frozenset(sample(allinds, k))
        return fill(interior, 1, cells)

    # Generate a pattern for each color that appears 2+ times
    patterns = {}
    for c in dup_colors:
        patterns[c] = rand_pattern()

    positions = [(r, c) for r in range(nrows) for c in range(ncols)]

    # For each duplicated color: pick one position to show the template,
    # at least one other must be empty (so verifier fills it = non-degenerate)
    template_pos = {}
    empty_positions = set()

    for c in dup_colors:
        cpos = [i for i, cc in enumerate(color_list) if cc == c]
        tp = choice(cpos)
        template_pos[c] = tp
        others = [i for i in cpos if i != tp]
        # At least one must be empty
        n_empty = randint(1, len(others))
        empties = sample(others, n_empty)
        for e in empties:
            empty_positions.add(e)

    # For non-duplicated colors and remaining positions, optionally add random interior marks
    # These won't affect the verifier (unique colors have no template to propagate)
    # For dup colors at non-template, non-empty positions, can show the correct pattern
    # or some other pattern or nothing

    h = 6 * nrows + 1
    w = 19
    gi = canvas(bgc, (h, w))

    frame_inds = box(frozenset({(0, 0), (4, 4)}))

    for idx in range(ncells):
        rr, cc = positions[idx]
        color = color_list[idx]
        top = 1 + 6 * rr
        left = 1 + 6 * cc

        # Draw the 5x5 frame border
        gi = fill(gi, color, shift(frame_inds, (top, left)))

        if idx in empty_positions:
            # Leave interior empty (all 0) — verifier will fill this
            pass
        elif color in patterns and template_pos.get(color) == idx:
            # This is the template position — draw the pattern
            pat_inds = ofcolor(patterns[color], 1)
            gi = fill(gi, color, shift(pat_inds, (top + 1, left + 1)))
        elif color in patterns:
            # Another instance of a dup color, not template and not empty
            # Show the correct pattern (like the template) or random content
            if choice((True, False)):
                pat_inds = ofcolor(patterns[color], 1)
                gi = fill(gi, color, shift(pat_inds, (top + 1, left + 1)))
            else:
                # Random different pattern so it's not confused as template
                alt = rand_pattern()
                for _ in range(10):
                    if alt != patterns[color]:
                        break
                    alt = rand_pattern()
                alt_inds = ofcolor(alt, 1)
                gi = fill(gi, color, shift(alt_inds, (top + 1, left + 1)))
        else:
            # Unique color — can have any interior or be empty
            if choice((True, False)):
                pat = rand_pattern()
                pat_inds = ofcolor(pat, 1)
                gi = fill(gi, color, shift(pat_inds, (top + 1, left + 1)))

    go = verify_42918530(gi)
    return {'input': gi, 'output': go}


def generate_42a15761(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (5, 12))
    nblocks = unifint(diff_lb, diff_ub, (3, 6))
    w = 4 * nblocks - 1

    basecol = choice((1, 2, 3, 4, 5, 6, 7, 8, 9))
    gi = canvas(basecol, (h, w))

    for b in range(1, nblocks):
        sepj = 4 * b - 1
        gi = fill(gi, 0, connect((0, sepj), (h - 1, sepj)))

    blocks = []
    maxz = 3 * h - 1
    target_counts = sample(interval(0, maxz + 1, 1), nblocks)
    shuffle(target_counts)

    for zc in target_counts:
        block = canvas(basecol, (h, 3))
        if zc > 0:
            inds = totuple(asindices(block))
            zinds = sample(inds, zc)
            block = fill(block, 0, frozenset(zinds))
        blocks.append(block)

    counts = [colorcount(b, 0) for b in blocks]
    ordered = tuple(sorted(counts))
    if tuple(counts) == ordered:
        if nblocks >= 2:
            i = randint(0, nblocks - 2)
            blocks[i], blocks[i + 1] = blocks[i + 1], blocks[i]

    assembled = blocks[0]
    for k in range(1, nblocks):
        assembled = hconcat(assembled, hconcat(canvas(0, (h, 1)), blocks[k]))
    gi = assembled

    go = verify_42a15761(gi)
    return {'input': gi, 'output': go}


