    mh = unifint(diff_lb, diff_ub, (2, min(6, 30 // ph)))
    mw = unifint(diff_lb, diff_ub, (2, min(6, 30 // pw)))

    top_h = ph
    left_w = 3 * ncols
    right_w = ncols * pw + (ncols - 1)
    bottom_h = mh
    total_h = top_h + 1 + bottom_h
    total_w = left_w + right_w

    gi = canvas(0, (total_h, total_w))

    for k, c in enumerate(active):
        cells = frozenset({(0, 3 * k), (0, 3 * k + 1), (1, 3 * k), (1, 3 * k + 1)})
        gi = fill(gi, c, cells)

