def generate_4364c1c4(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 20))
    w = unifint(diff_lb, diff_ub, (10, 20))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    gi = canvas(bgc, (h, w))

    npairs = unifint(diff_lb, diff_ub, (1, max(1, min(3, h // 5, (w - 2) // 3))))

    occupied = set()
    made = 0

    for _ in range(300):
        if made >= npairs:
            break

        topc, botc = sample(list(remcols), 2)

        # Build a stepped shape: 1 or 2 rectangular blocks stacked vertically
        # Each block is a horizontal span (left_offset, width) repeated for some rows
        def make_shape():
            nblocks = choice((1, 1, 2))
            rows_spec = []  # list of (left, width) per row
            w1 = randint(2, min(7, w - 4))
            h1 = randint(1, min(4, max(1, h // 4)))
            for _ in range(h1):
                rows_spec.append((0, w1))
            if nblocks == 2:
                w2 = randint(2, min(7, w - 4))
                h2 = randint(1, min(3, max(1, h // 4)))
                # align second block: either left-aligned (0) or shifted
                if w2 <= w1:
                    off2 = randint(0, w1 - w2)
                else:
                    off2 = -randint(0, w2 - w1)
                for _ in range(h2):
                    rows_spec.append((off2, w2))
            # Build indices at origin
            inds = frozenset((r, c) for r, row in enumerate(rows_spec)
                             for c in range(row[0], row[0] + row[1]))
            return inds, len(rows_spec)

        top_inds, top_h = make_shape()
        bot_inds_base, bot_h = make_shape()

        total_h = top_h + bot_h
        if total_h > h:
            continue

        # Place bottom shape directly below top shape
        bot_inds = frozenset((r + top_h, c) for r, c in bot_inds_base)

        # Combined shape must be adjacent
        if not adjacent(top_inds, bot_inds):
            # The bottom row of top and top row of bot must share a column
            # If make_shape produced shapes with no column overlap at the boundary, skip
            continue

        # Now position the pair on the grid
        # Need room: leftmost(top) - 1 >= 0 after shift, rightmost(bot) + 1 < w after shift
        all_inds = top_inds | bot_inds
        min_c = min(c for _, c in all_inds)
        max_c = max(c for _, c in all_inds)

        # After transform: top shifts left 1, bot shifts right 1
        # So we need: placed_min_c + min_c_of_top - 1 >= 0
        # and: placed_min_c + max_c_of_bot + 1 < w
        top_min_c = min(c for _, c in top_inds)
        top_max_c = max(c for _, c in top_inds)
        bot_min_c = min(c for _, c in bot_inds)
        bot_max_c = max(c for _, c in bot_inds)

        # Column offset: shift everything so it fits
        # After placing at col offset dc:
        #   top shifted left: dc + top_min_c - 1 >= 0 → dc >= 1 - top_min_c
        #   bot shifted right: dc + bot_max_c + 1 <= w - 1 → dc <= w - 2 - bot_max_c
        dc_lo = max(0, 1 - top_min_c)
        dc_hi = min(w - 1 - max_c, w - 2 - bot_max_c)
        if dc_lo > dc_hi:
            continue

        dc = randint(dc_lo, dc_hi)

        # Row offset
        dr_lo = 0
        dr_hi = h - total_h
        if dr_lo > dr_hi:
            continue
        dr = randint(dr_lo, dr_hi)

        placed_top = frozenset((r + dr, c + dc) for r, c in top_inds)
        placed_bot = frozenset((r + dr, c + dc) for r, c in bot_inds)
        placed_all = placed_top | placed_bot

        # Check bounds and no overlap with existing objects
        ok = True
        for i, j in placed_all:
            if not (0 <= i < h and 0 <= j < w):
                ok = False
                break
            if (i, j) in occupied:
                ok = False
                break
        if not ok:
            continue

        # Also check shifted positions stay in bounds
        for i, j in shift(placed_top, tojvec(-1)):
            if not (0 <= i < h and 0 <= j < w):
                ok = False
                break
        if not ok:
            continue
        for i, j in shift(placed_bot, tojvec(1)):
            if not (0 <= i < h and 0 <= j < w):
                ok = False
                break
        if not ok:
            continue

        occupied |= placed_all
        gi = fill(gi, topc, placed_top)
        gi = fill(gi, botc, placed_bot)
        made += 1

    if made == 0:
        # Fallback: simple pair of rectangles
        topc, botc = sample(list(remcols), 2)
        top = frozenset((r, c) for r in range(2) for c in range(1, 4))
        bot = frozenset((r, c) for r in range(2, 4) for c in range(1, 4))
        gi = fill(gi, topc, top)
        gi = fill(gi, botc, bot)

    go = verify_4364c1c4(gi)
    return {'input': gi, 'output': go}


