def generate_465b7d93(diff_lb: float, diff_ub: float) -> dict:
    bgc = 7
    h = unifint(diff_lb, diff_ub, (10, 20))
    w = unifint(diff_lb, diff_ub, (10, 20))
    gi = canvas(bgc, (h, w))

    in_h = unifint(diff_lb, diff_ub, (1, max(1, h - 4)))
    in_w = unifint(diff_lb, diff_ub, (1, max(1, w - 4)))
    rh = in_h + 2
    rw = in_w + 2
    loci = randint(0, h - rh)
    locj = randint(0, w - rw)
    rect = connect((loci, locj), (loci, locj + rw - 1)) | connect((loci + rh - 1, locj), (loci + rh - 1, locj + rw - 1)) | connect((loci, locj), (loci + rh - 1, locj)) | connect((loci, locj + rw - 1), (loci + rh - 1, locj + rw - 1))
    gi = fill(gi, 6, rect)

    shpcol = choice(remove(6, remove(bgc, interval(0, 10, 1))))

    shape_kind = choice(("single", "rect", "L"))
    if shape_kind == "single":
        sh = 1
        sw = 1
        rel = frozenset({(0, 0)})
    elif shape_kind == "rect":
        sh = unifint(diff_lb, diff_ub, (2, min(4, h - 1)))
        sw = unifint(diff_lb, diff_ub, (2, min(4, w - 1)))
        rel = frozenset((i, j) for i in range(sh) for j in range(sw))
    else:
        sh = unifint(diff_lb, diff_ub, (2, min(5, h - 1)))
        sw = unifint(diff_lb, diff_ub, (2, min(5, w - 1)))
        armh = randint(1, sh)
        armw = randint(1, sw)
        rel = frozenset({(i, 0) for i in range(armh)} | {(armh - 1, j) for j in range(armw)})
        if choice((True, False)):
            rel = vmirror(rel)
            rel = normalize(rel)
        if choice((True, False)):
            rel = hmirror(rel)
            rel = normalize(rel)
        sh, sw = shape(rel)

    forbidden = backdrop(rect)
    placements = []
    for i in range(h - sh + 1):
        for j in range(w - sw + 1):
            placed = shift(rel, (i, j))
            if len(intersection(placed, forbidden)) == 0:
                placements.append((i, j))
    if len(placements) == 0:
        rel = frozenset({(0, 0)})
        sh, sw = 1, 1
        placements = []
        for i in range(h):
            for j in range(w):
                if (i, j) not in forbidden:
                    placements.append((i, j))
    pi, pj = choice(placements)
    shp = shift(rel, (pi, pj))
    gi = fill(gi, shpcol, shp)

    go = verify_465b7d93(gi)
    return {'input': gi, 'output': go}


