def generate_46c35fc7(diff_lb: float, diff_ub: float) -> dict:
    bgc = 7
    h = unifint(diff_lb, diff_ub, (7, 20))
    w = unifint(diff_lb, diff_ub, (7, 20))
    gi = canvas(bgc, (h, w))

    max_blocks = max(1, (h // 4) * (w // 4))
    nblocks = unifint(diff_lb, diff_ub, (1, min(6, max_blocks)))

    occupied = set()
    blocks = []

    for _ in range(200):
        if len(blocks) >= nblocks:
            break
        loci = randint(0, h - 3)
        locj = randint(0, w - 3)
        patch = connect((loci, locj), (loci + 2, locj + 2))
        halo = outbox(patch)
        if len((set(patch) | set(halo)) & occupied) != 0:
            continue

        vals = [unifint(diff_lb, diff_ub, (0, 9)) for _ in range(9)]
        if all(v == bgc for v in vals):
            k = randint(0, 8)
            vals[k] = choice((0, 1, 2, 3, 4, 5, 6, 8, 9))

        subg = tuple(tuple(vals[r * 3 + c] for c in range(3)) for r in range(3))
        obj = shift(asobject(subg), (loci, locj))
        gi = paint(gi, obj)
        occupied |= set(patch) | set(halo)
        blocks.append((loci, locj))

    if len(blocks) == 0:
        loci, locj = 0, 0
        vals = [unifint(diff_lb, diff_ub, (0, 9)) for _ in range(9)]
        if all(v == bgc for v in vals):
            vals[0] = choice((0, 1, 2, 3, 4, 5, 6, 8, 9))
        subg = tuple(tuple(vals[r * 3 + c] for c in range(3)) for r in range(3))
        gi = paint(gi, asobject(subg))

    go = verify_46c35fc7(gi)
    return {'input': gi, 'output': go}


