def generate_470c91de(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(SEVEN, remove(EIGHT, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (9, 16))
    w = unifint(diff_lb, diff_ub, (9, 16))
    gi = canvas(SEVEN, (h, w))

    maxn = min(5, max(2, (h * w) // 18))
    nobj = unifint(diff_lb, diff_ub, (2, maxn))

    occupied = set()
    succ = 0
    tr = 0
    maxtr = 200

    while succ < nobj and tr < maxtr:
        tr += 1
        used_colors = {color(obj) for obj in objects(gi, T, F, T) if color(obj) != SEVEN}
        color_choices = tuple(c for c in cols if c not in used_colors)
        c = choice(color_choices) if len(color_choices) > 0 else choice(cols)

        rh = unifint(diff_lb, diff_ub, (2, min(5, h - 2)))
        rw = unifint(diff_lb, diff_ub, (2, min(5, w - 2)))

        corner = choice(("tl", "tr", "bl", "br"))

        if corner == "tl":
            lo_rr, hi_rr = 1, h - rh
            lo_cc, hi_cc = 1, w - rw
        elif corner == "tr":
            lo_rr, hi_rr = 1, h - rh
            lo_cc, hi_cc = 0, w - rw - 1
        elif corner == "bl":
            lo_rr, hi_rr = 0, h - rh - 1
            lo_cc, hi_cc = 1, w - rw
        else:
            lo_rr, hi_rr = 0, h - rh - 1
            lo_cc, hi_cc = 0, w - rw - 1

        if lo_rr > hi_rr or lo_cc > hi_cc:
            continue

        rr = randint(lo_rr, hi_rr)
        cc = randint(lo_cc, hi_cc)

        full_rect = backdrop(frozenset({(rr, cc), (rr + rh - 1, cc + rw - 1)}))

        if corner == "tl":
            mr, mc = rr, cc
        elif corner == "tr":
            mr, mc = rr, cc + rw - 1
        elif corner == "bl":
            mr, mc = rr + rh - 1, cc
        else:
            mr, mc = rr + rh - 1, cc + rw - 1

        marker = frozenset({(mr, mc)})
        body = full_rect - marker

        halo = full_rect | outbox(full_rect)
        if any(ij in occupied for ij in halo):
            continue

        if corner == "tl":
            dr, dc = -1, -1
        elif corner == "tr":
            dr, dc = -1, 1
        elif corner == "bl":
            dr, dc = 1, -1
        else:
            dr, dc = 1, 1

        shifted = shift(full_rect, (dr, dc))
        if not all(0 <= r < h and 0 <= c2 < w for r, c2 in shifted):
            continue

        gi = fill(gi, c, body)
        gi = fill(gi, EIGHT, marker)
        occupied |= set(halo)
        succ += 1

    if succ == 0:
        c = choice(cols)
        full_rect = backdrop(frozenset({(1, 1), (2, 2)}))
        marker = frozenset({(1, 1)})
        body = full_rect - marker
        gi = fill(gi, c, body)
        gi = fill(gi, EIGHT, marker)

    go = verify_470c91de(gi)
    return {'input': gi, 'output': go}


def generate_47c1f68c(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    h = unifint(diff_lb, diff_ub, (2, 14))
    w = unifint(diff_lb, diff_ub, (2, 14))
    bgc, linc = sample(cols, 2)
    remcols = difference(cols, (bgc, linc))
    objc = choice(remcols)
    canv = canvas(bgc, (h, w))
    nc = unifint(diff_lb, diff_ub, (1, h * w - 1))
    bx = asindices(canv)
    obj = {choice(totuple(bx))}
    for kk in range(nc - 1):
        dns = mapply(neighbors, obj)
        ch = choice(totuple(bx & dns))
        obj.add(ch)
        bx = bx - {ch}
    obj = recolor(objc, obj)
    gi = paint(canv, obj)
    gi1 = hconcat(hconcat(gi, canvas(linc, (h, 1))), canv)
    gi2 = hconcat(hconcat(canv, canvas(linc, (h, 1))), canv)
    gi = vconcat(vconcat(gi1, canvas(linc, (1, 2*w+1))), gi2)
    go = paint(canv, obj)
    go = hconcat(go, vmirror(go))
    go = vconcat(go, hmirror(go))
    go = replace(go, objc, linc)
    scf = choice((identity, hmirror, vmirror, compose(hmirror, vmirror)))
    gi = scf(gi)
    go = scf(go)
    return {'input': gi, 'output': go}


