def generate_484b58aa(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    hp = unifint(diff_lb, diff_ub, (2, h//2-1))
    wp = unifint(diff_lb, diff_ub, (2, w//2-1))
    pinds = asindices(canvas(-1, (hp, wp)))
    noisec = choice(cols)
    remcols = remove(noisec, cols)
    numc = unifint(diff_lb, diff_ub, (2, 9))
    ccols = sample(remcols, numc)
    pobj = frozenset({(choice(ccols), ij) for ij in pinds})
    go = canvas(-1, (h, w))
    locs = set()
    ofs = randint(1, hp - 1)
    for a in range(2*(h//hp+1)):
        for b in range(w//wp+1):
            loci = hp * a - ofs * b
            locj = wp * b
            locs.add((loci, locj))
            go = paint(go, shift(pobj, (loci, locj)))
    numpatches = unifint(diff_lb, diff_ub, (1, (h * w) // 20))
    gi = tuple(e for e in go)
    places = apply(lbind(shift, pinds), locs)
    succ = 0
    tr = 0
    maxtr = 5 * numpatches
    while succ < numpatches and tr < maxtr:
        tr += 1
        ph = randint(2, 6)
        pw = randint(2, 6)
        loci = randint(0, h - ph)
        locj = randint(0, w - pw)
        ptch = backdrop(frozenset({(loci, locj), (loci + ph - 1, locj + pw - 1)}))
        gi2 = fill(gi, noisec, ptch)
        if pobj in apply(normalize, apply(rbind(toobject, gi2), places)):
            if len(sfilter(gi2, lambda r: noisec not in r)) >= 2 and len(sfilter(dmirror(gi2), lambda r: noisec not in r)) >= 2:
                succ += 1
                gi = gi2
    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = rotf(go)
    return {'input': gi, 'output': go}


def generate_4852f2fa(diff_lb: float, diff_ub: float) -> dict:
    h = 9
    w = 9
    n4 = unifint(diff_lb, diff_ub, (1, 4))
    side = unifint(diff_lb, diff_ub, (2, 4))
    maxcells = side * side - 1
    ncells = unifint(diff_lb, diff_ub, (3, maxcells))
    ncells = max(1, min(maxcells, ncells))

    bounds = asindices(canvas(-1, (side, side)))
    start = choice(totuple(bounds))
    shp = {start}
    frontier = (neighbors(start) & bounds) - shp
    steps = ncells - 1
    for _ in range(steps):
        if len(frontier) == 0:
            rem = tuple(bounds - shp)
            if len(rem) == 0:
                break
            nxt = choice(rem)
        else:
            nxt = choice(totuple(frontier))
        shp.add(nxt)
        frontier = ((mapply(neighbors, shp) & bounds) - shp)
    shp = frozenset(shp)
    shp = normalize(shp)
    ph, pw = shape(shp)

    top_pad = side - ph
    left_pad = side - pw

    gi = canvas(0, (h, w))

    maxi = h - ph
    maxj = w - pw
    loci = unifint(diff_lb, diff_ub, (0, maxi))
    locj = unifint(diff_lb, diff_ub, (0, maxj))
    gi = fill(gi, 8, shift(shp, (loci, locj)))

    free = list(asindices(gi) - shift(shp, (loci, locj)))
    shuffle(free)
    for pos in free[:n4]:
        gi = fill(gi, 4, frozenset({pos}))

    go = verify_4852f2fa(gi)
    return {'input': gi, 'output': go}


def generate_48634b99(diff_lb: float, diff_ub: float) -> dict:
    h = 16
    w = 16
    gi = canvas(7, (h, w))

    n_objs = unifint(diff_lb, diff_ub, (7, 12))
    maxlen = min(8, h - 2)
    lengths = []
    for _ in range(n_objs):
        lengths.append(unifint(diff_lb, diff_ub, (1, maxlen)))

    src_idx = randint(0, n_objs - 1)
    seglen = unifint(diff_lb, diff_ub, (1, lengths[src_idx]))
    lengths[src_idx] = max(lengths[src_idx], seglen)

    candidates = [k for k in range(n_objs) if k != src_idx and lengths[k] == lengths[src_idx]]
    if len(candidates) == 0:
        tgt_idx = choice([k for k in range(n_objs) if k != src_idx])
        lengths[tgt_idx] = lengths[src_idx]
    else:
        tgt_idx = choice(candidates)

    topflag = choice((True, False))

    objs = []
    occupied = set()
    cols = list(range(w))
    shuffle(cols)

    for k in range(n_objs):
        L = lengths[k]
        placed = False
        for _ in range(200):
            j = randint(0, w - 1)
            i = randint(0, h - L)
            cells = connect((i, j), (i + L - 1, j))
            ok = True
            for c in cells:
                if c in occupied:
                    ok = False
                    break
            if ok:
                for c in cells:
                    for nb in dneighbors(c):
                        if 0 <= nb[0] < h and 0 <= nb[1] < w and nb in occupied:
                            ok = False
                            break
                if ok:
                    objs.append((i, j, L))
                    occupied |= set(cells)
                    gi = fill(gi, 8, cells)
                    placed = True
                    break
        if not placed:
            for j in range(w):
                for i in range(h - L + 1):
                    cells = connect((i, j), (i + L - 1, j))
                    ok = True
                    for c in cells:
                        if c in occupied:
                            ok = False
                            break
                    if ok:
                        for c in cells:
                            for nb in dneighbors(c):
                                if 0 <= nb[0] < h and 0 <= nb[1] < w and nb in occupied:
                                    ok = False
                                    break
                            if not ok:
                                break
                    if ok:
                        objs.append((i, j, L))
                        occupied |= set(cells)
                        gi = fill(gi, 8, cells)
                        placed = True
                        break
                if placed:
                    break

    if len(objs) < n_objs:
        objs = []
        gi = canvas(7, (h, w))
        occupied = set()
        lengths = [1, 2, 3, 4, 5, 5, 3, 2]
        n_objs = len(lengths)
        src_idx = 4
        tgt_idx = 5
        seglen = 2
        topflag = choice((True, False))
        fixed_cols = [1, 4, 7, 9, 11, 13, 15, 2]
        for k, L in enumerate(lengths):
            j = fixed_cols[k]
            i = randint(0, h - L)
            cells = connect((i, j), (i + L - 1, j))
            objs.append((i, j, L))
            gi = fill(gi, 8, cells)

    si, sj, sL = objs[src_idx]
    if topflag:
        seg = connect((si, sj), (si + seglen - 1, sj))
    else:
        seg = connect((si + sL - seglen, sj), (si + sL - 1, sj))
    gi = fill(gi, 9, seg)

    go = verify_48634b99(gi)
    return {'input': gi, 'output': go}


def generate_48d8fb45(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    nobjs = unifint(diff_lb, diff_ub, (2, (h * w) // 15))
    tr = 0
    maxtr = 4 * nobjs
    done = False
    succ = 0
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    gi = canvas(bgc, (h, w))
    inds = asindices(gi)
    while tr < maxtr and succ < nobjs:
        oh = randint(2, 6)
        ow = randint(2, 6)
        bx = asindices(canvas(-1, (oh, ow)))
        nc = randint(3, oh * ow)
        sp = choice(totuple(bx))
        bx = remove(sp, bx)
        obj = {sp}
        for k in range(nc - 1):
            obj.add(choice(totuple((bx - obj) & mapply(neighbors, obj))))
        if not done:
            done = True
            idx = choice(totuple(obj))
            coll = choice(remcols)
            obj2 = {(coll, idx)}
            obj3 = recolor(choice(remove(coll, remcols)), remove(idx, obj))
            obj = obj2 | obj3
            go = paint(canvas(bgc, shape(obj3)), normalize(obj3))
        else:
            obj = recolor(choice(remcols), obj)
        locopts = sfilter(inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
        tr += 1
        if len(locopts) == 0:
            continue
        loc = choice(totuple(locopts))
        plcd = shift(obj, loc)
        plcdi = toindices(plcd)
        if plcdi.issubset(inds):
            gi = paint(gi, plcd)
            succ += 1
            inds = (inds - plcdi) - mapply(neighbors, plcdi)
    return {'input': gi, 'output': go}


def generate_48f8583b(diff_lb: float, diff_ub: float) -> dict:
    # 3x3 grid with 2-4 non-zero colors
    # The least frequent color must be strictly unique (no ties)
    ncols = unifint(diff_lb, diff_ub, (2, 4))
    palette = sample(range(1, 10), ncols)
    total = 9
    least_ct = unifint(diff_lb, diff_ub, (1, 3))
    # Each other color must have count > least_ct
    # So we need: least_ct + (ncols-1)*(least_ct+1) <= 9
    min_other = least_ct + 1
    needed = least_ct + (ncols - 1) * min_other
    if needed > total:
        # Reduce ncols or least_ct to fit
        # Try reducing least_ct first
        for lc in range(least_ct, 0, -1):
            if lc + (ncols - 1) * (lc + 1) <= total:
                least_ct = lc
                min_other = lc + 1
                needed = lc + (ncols - 1) * min_other
                break
        else:
            # Reduce ncols to 2
            ncols = 2
            palette = palette[:2]
            min_other = least_ct + 1
            needed = least_ct + min_other
    least_idx = randint(0, ncols - 1)
    counts = [0] * ncols
    counts[least_idx] = least_ct
    rem = total - least_ct
    other_idxs = [i for i in range(ncols) if i != least_idx]
    if len(other_idxs) == 1:
        counts[other_idxs[0]] = rem
    else:
        # Distribute rem among others, each getting at least min_other
        bases = [min_other] * len(other_idxs)
        extra = rem - sum(bases)
        for k, idx in enumerate(other_idxs):
            if k == len(other_idxs) - 1:
                addv = extra
            else:
                addv = randint(0, extra)
            counts[idx] = bases[k] + addv
            extra -= addv
        # Shuffle to avoid ordering bias
        vals = [counts[idx] for idx in other_idxs]
        shuffle(vals)
        for idx, v in zip(other_idxs, vals):
            counts[idx] = v
    cells = []
    for c, ct in zip(palette, counts):
        cells.extend([c] * ct)
    shuffle(cells)
    gi = tuple(tuple(cells[i * 3:(i + 1) * 3]) for i in range(3))
    go = verify_48f8583b(gi)
    return {'input': gi, 'output': go}


def generate_4938f0c2(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 31))
    w = unifint(diff_lb, diff_ub, (10, 31))
    oh = unifint(diff_lb, diff_ub, (2, (h - 3) // 2))
    ow = unifint(diff_lb, diff_ub, (2, (w - 3) // 2))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    cc = choice(remcols)
    remcols = remove(cc, remcols)
    objc = choice(remcols)
    sg = canvas(bgc, (oh, ow))
    locc = (oh - 1, ow - 1)
    sg = fill(sg, cc, {locc})
    reminds = totuple(remove(locc, asindices(sg)))
    ncells = unifint(diff_lb, diff_ub, (1, max(1, int((2/3) * oh * ow))))
    cells = sample(reminds, ncells)
    while ncells == 4 and shape(cells) == (2, 2):
        ncells = unifint(diff_lb, diff_ub, (1, max(1, int((2/3) * oh * ow))))
        cells = sample(reminds, ncells)
    sg = fill(sg, objc, cells)
    G1 = sg
    G2 = vmirror(sg)
    G3 = hmirror(sg)
    G4 = vmirror(hmirror(sg))
    vbar = canvas(bgc, (oh, 1))
    hbar = canvas(bgc, (1, ow))
    cp = canvas(cc, (1, 1))
    topg = hconcat(hconcat(G1, vbar), G2)
    botg = hconcat(hconcat(G3, vbar), G4)
    ggm = hconcat(hconcat(hbar, cp), hbar)
    GG = vconcat(vconcat(topg, ggm), botg)
    gg = asobject(GG)
    canv = canvas(bgc, (h, w))
    loci = randint(0, h - 2 * oh - 1)
    locj = randint(0, w - 2 * ow - 1)
    loc = (loci, locj)
    go = paint(canv, shift(gg, loc))
    gi = paint(canv, shift(asobject(sg), loc))
    gi = fill(gi, cc, ofcolor(go, cc))
    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = rotf(go)
    ccpi, ccpj = center(ofcolor(gi, cc))
    gi = gi[:ccpi] + gi[ccpi+1:]
    gi = tuple(r[:ccpj] + r[ccpj + 1:] for r in gi)
    go = go[:ccpi] + go[ccpi+1:]
    go = tuple(r[:ccpj] + r[ccpj + 1:] for r in go)
    return {'input': gi, 'output': go}


def generate_494ef9d7(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (3, 12))
    w = unifint(diff_lb, diff_ub, (5, 12))
    gi = canvas(0, (h, w))

    target_rows = interval(0, h, 1)
    max_targets = max(1, h // 2)
    ntarget = unifint(diff_lb, diff_ub, (1, max_targets))
    ntarget = min(ntarget, h)
    trows = sample(list(target_rows), ntarget)

    for i in trows:
        pairkind = choice(((4, 7), (1, 8)))
        leftc = pairkind[0]
        rightc = pairkind[1]
        j1 = randint(0, w - 2)
        minj2 = j1 + 2
        if minj2 >= w:
            j1 = max(0, w - 3)
            minj2 = j1 + 2
        j2 = randint(minj2, w - 1)
        gi = fill(gi, leftc, frozenset({(i, j1)}))
        gi = fill(gi, rightc, frozenset({(i, j2)}))

    other_rows = [i for i in range(h) if i not in trows]
    nonzero_cols = remove(0, interval(0, 10, 1))

    for i in other_rows:
        mode = choice((0, 1, 2, 2, 3))
        if mode == 0:
            continue
        elif mode == 1:
            j = randint(0, w - 1)
            c = choice(nonzero_cols)
            gi = fill(gi, c, frozenset({(i, j)}))
        elif mode == 2:
            js = sample(list(interval(0, w, 1)), 2)
            js = tuple(sorted(js))
            badpairs = (frozenset({4, 7}), frozenset({1, 8}))
            for _ in range(20):
                c1 = choice(nonzero_cols)
                c2 = choice(nonzero_cols)
                if frozenset({c1, c2}) not in badpairs:
                    break
            gi = fill(gi, c1, frozenset({(i, js[0])}))
            gi = fill(gi, c2, frozenset({(i, js[1])}))
        else:
            n = unifint(diff_lb, diff_ub, (3, min(4, w)))
            js = sample(list(interval(0, w, 1)), n)
            for j in js:
                c = choice(nonzero_cols)
                gi = fill(gi, c, frozenset({(i, j)}))

