def generate_4acc7107(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    h = 10
    w = 10

    def make_shape(maxh, maxw, color):
        sh = unifint(diff_lb, diff_ub, (1, maxh))
        sw = unifint(diff_lb, diff_ub, (1, maxw))
        nmin = 1
        nmax = max(1, sh * sw - 1)
        ncells = unifint(diff_lb, diff_ub, (nmin, nmax))
        cells = sample(totuple(product(interval(0, sh, 1), interval(0, sw, 1))), ncells)
        inds = frozenset(cells)
        comps = connected_components(inds, False)
        if len(comps) > 1:
            comp_list = list(comps)
            base = set(comp_list[0])
            for comp in comp_list[1:]:
                a = choice(tuple(base))
                b = choice(tuple(comp))
                if a[0] == b[0] or a[1] == b[1]:
                    bridge = connect(a, b)
                else:
                    mid = (a[0], b[1]) if choice((True, False)) else (b[0], a[1])
                    bridge = connect(a, mid) | connect(mid, b)
                base |= set(comp) | set(bridge)
            inds = frozenset(base)
        return recolor(color, inds)

    def dims_ok(o1, o2):
        n1 = normalize(o1)
        n2 = normalize(o2)
        stack_h = height(n1) + 1 + height(n2)
        stack_w = max(width(n1), width(n2))
        return stack_h <= h and stack_w <= 4

    def place_two(objs, forbidden):
        o1, o2 = objs
        i1 = toindices(o1)
        i2 = toindices(o2)
        h1, w1 = height(o1), width(o1)
        h2, w2 = height(o2), width(o2)
        cands1 = []
        for r1 in range(0, h - h1 + 1):
            for c1 in range(0, w - w1 + 1):
                s1 = shift(i1, (r1, c1))
                if len(s1 & forbidden) == 0:
                    cands1.append((r1, c1, s1))
        shuffle(cands1)
        for r1, c1, s1 in cands1:
            forb2 = forbidden | s1
            cands2 = []
            for r2 in range(0, h - h2 + 1):
                for c2 in range(0, w - w2 + 1):
                    s2 = shift(i2, (r2, c2))
                    if len(s2 & forb2) == 0:
                        cands2.append((r2, c2, s2))
            shuffle(cands2)
            for r2, c2, s2 in cands2:
                if leftmost(s1) == leftmost(s2):
                    continue
                return shift(o1, (r1, c1)), shift(o2, (r2, c2)), forbidden | s1 | s2
        return None

    for _ in range(100):
        c1, c2 = sample(cols, 2)

        for _ in range(100):
            a1 = make_shape(3, 4, c1)
            a2 = make_shape(3, 4, c1)
            b1 = make_shape(3, 4, c2)
            b2 = make_shape(3, 4, c2)
            if dims_ok(a1, a2) and dims_ok(b1, b2):
                break
        else:
            continue

        ga = place_two((a1, a2), frozenset())
        if ga is None:
            continue
        pa1, pa2, occ = ga
        gb = place_two((b1, b2), occ)
        if gb is None:
            continue
        pb1, pb2, occ2 = gb

        objs = objects(canvas(0, (h, w)), T, F, T)
        gi = canvas(0, (h, w))
        gi = paint(gi, pa1)
        gi = paint(gi, pa2)
        gi = paint(gi, pb1)
        gi = paint(gi, pb2)

        xobjs = objects(gi, T, F, T)
        if len(xobjs) != 4:
            continue
        if len(colorfilter(xobjs, c1)) != 2 or len(colorfilter(xobjs, c2)) != 2:
            continue

        mins = []
        for cc in (c1, c2):
            co = colorfilter(xobjs, cc)
            mins.append(minimum(apply(leftmost, co)))
        if mins[0] == mins[1]:
            continue

        go = verify_4acc7107(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    c1, c2 = 1, 2
    gi = canvas(0, (10, 10))
    gi = fill(gi, c1, frozenset({(1, 1), (1, 2), (2, 1)}))
    gi = fill(gi, c1, frozenset({(6, 3), (7, 2), (7, 3), (7, 4)}))
    gi = fill(gi, c2, frozenset({(1, 6), (2, 5), (2, 6), (2, 7), (3, 6)}))
    gi = fill(gi, c2, frozenset({(5, 5), (5, 6), (5, 7)}))
    go = verify_4acc7107(gi)
    return {'input': gi, 'output': go}


def generate_4b6b68e5(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    h = unifint(diff_lb, diff_ub, (14, 24))
    w = unifint(diff_lb, diff_ub, (14, 24))
    gi = canvas(0, (h, w))

    nclosed = unifint(diff_lb, diff_ub, (1, 3))
    nopen = unifint(diff_lb, diff_ub, (1, 3))
    nsingle = unifint(diff_lb, diff_ub, (2, 8))

    occupied = set()

    def rect_ring(top, left, rh, rw):
        outer = box(frozenset({(top, left), (top + rh - 1, left + rw - 1)}))
        inner = frozenset((i, j) for i in range(top + 1, top + rh - 1) for j in range(left + 1, left + rw - 1))
        return outer, inner

    def can_place(cells, margin=True):
        for i, j in cells:
            if not (0 <= i < h and 0 <= j < w):
                return False
            if (i, j) in occupied:
                return False
            if margin:
                for ni, nj in neighbors((i, j)):
                    if 0 <= ni < h and 0 <= nj < w and (ni, nj) in occupied:
                        return False
        return True

    closed_done = 0
    for _ in range(80):
        if closed_done >= nclosed:
            break
        rh = unifint(diff_lb, diff_ub, (5, min(10, h - 2)))
        rw = unifint(diff_lb, diff_ub, (5, min(10, w - 2)))
        if rh >= h or rw >= w:
            continue
        top = randint(1, h - rh - 1) if h - rh - 1 >= 1 else 0
        left = randint(1, w - rw - 1) if w - rw - 1 >= 1 else 0
        ring, inner = rect_ring(top, left, rh, rw)
        if len(inner) == 0 or not can_place(ring | inner, True):
            continue
        ringc = choice(cols)
        innercols = sample(remove(ringc, cols), choice((2, 3)))
        majc = choice(innercols)
        inner_list = list(inner)
        shuffle(inner_list)
        majn = max(1, (2 * len(inner_list)) // 3)
        majset = frozenset(inner_list[:majn])
        rem = inner - majset
        gi = fill(gi, ringc, ring)
        gi = fill(gi, majc, majset)
        if len(rem) > 0:
            rem_list = list(rem)
            shuffle(rem_list)
            split = len(rem_list) // 2
            gi = fill(gi, innercols[1], frozenset(rem_list[:split]))
            if len(innercols) > 2:
                gi = fill(gi, innercols[2], frozenset(rem_list[split:]))
            else:
                if len(rem_list[split:]) > 0:
                    gi = fill(gi, innercols[1], frozenset(rem_list[split:]))
        occupied |= set(ring) | set(inner)
        closed_done += 1

    open_done = 0
    for _ in range(80):
        if open_done >= nopen:
            break
        rh = unifint(diff_lb, diff_ub, (4, min(9, h)))
        rw = unifint(diff_lb, diff_ub, (4, min(9, w)))
        top = randint(0, h - rh)
        left = randint(0, w - rw)
        ring = box(frozenset({(top, left), (top + rh - 1, left + rw - 1)}))
        if len(ring) < 4:
            continue
        gapn = choice((1, 1, 2))
        gapcells = set(sample(totuple(ring), gapn))
        shape = ring - gapcells
        extra = frozenset()
        if choice((True, False)):
            gc = choice(totuple(shape))
            nbs = [x for x in dneighbors(gc) if 0 <= x[0] < h and 0 <= x[1] < w and x not in ring]
            if len(nbs) > 0:
                extra = frozenset({choice(nbs)})
        shape2 = shape | extra
        if not can_place(shape2, True):
            continue
        c = choice(cols)
        gi = fill(gi, c, shape2)
        occupied |= set(shape2)
        open_done += 1

    single_done = 0
    for _ in range(120):
        if single_done >= nsingle:
            break
        loc = (randint(0, h - 1), randint(0, w - 1))
        if can_place(frozenset({loc}), True):
            gi = fill(gi, choice(cols), frozenset({loc}))
            occupied.add(loc)
            single_done += 1

    go = verify_4b6b68e5(gi)
    if gi == go:
        for _ in range(50):
            rh = 5
            rw = 5
            if h <= rh + 2 or w <= rw + 2:
                break
            top = randint(1, h - rh - 1)
            left = randint(1, w - rw - 1)
            ring, inner = rect_ring(top, left, rh, rw)
            if can_place(ring | inner, True):
                ringc = choice(cols)
                remcands = remove(ringc, cols)
                majc, minc = sample(remcands, 2)
                inner_list = list(inner)
                shuffle(inner_list)
                majset = frozenset(inner_list[:max(1, len(inner_list) - 2)])
                minset = inner - majset
                gi = fill(gi, ringc, ring)
                gi = fill(gi, majc, majset)
                gi = fill(gi, minc, minset)
                break
        go = verify_4b6b68e5(gi)
    return {'input': gi, 'output': go}


