    base = tuple(pcols[j % ncols] for j in range(wp))
    rows = []
    for i in range(hp):
        sh = i % wp
        row = tuple(base[(j + sh) % wp] for j in range(wp))
        rows.append(row)
    tile = tuple(rows)

    full = tuple(
        tuple(tile[i % hp][j % wp] for j in range(w))
        for i in range(h)
    )

    vis_h = unifint(diff_lb, diff_ub, (max(hp, 2), h - 1))
