def generate_50aad11f(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(SIX, remove(ZERO, interval(0, 10, 1)))
    nobj = unifint(diff_lb, diff_ub, (2, 4))
    orient_horizontal = choice((True, False))

    if orient_horizontal:
        maxh = max(8, 30 // nobj)
        h = unifint(diff_lb, diff_ub, (8, 14))
        w = unifint(diff_lb, diff_ub, (max(12, 6 * nobj), 30))
    else:
        h = unifint(diff_lb, diff_ub, (max(12, 6 * nobj), 30))
        w = unifint(diff_lb, diff_ub, (8, 14))

    gi = canvas(ZERO, (h, w))

    if orient_horizontal:
        segw = max(4, w // nobj)
        starts = [k * segw for k in range(nobj)]
        ends = [w - 1 if k == nobj - 1 else min(w - 1, (k + 1) * segw - 1) for k in range(nobj)]
    else:
        segh = max(4, h // nobj)
        starts = [k * segh for k in range(nobj)]
        ends = [h - 1 if k == nobj - 1 else min(h - 1, (k + 1) * segh - 1) for k in range(nobj)]

    used_colors = sample(cols, nobj)
    shape_cells = []
    marker_cells = []

    for k in range(nobj):
        colork = used_colors[k]
        if orient_horizontal:
            c0 = starts[k]
            c1 = ends[k]
            availw = c1 - c0 + 1
            sh = unifint(diff_lb, diff_ub, (3, min(5, h - 3)))
            sw = unifint(diff_lb, diff_ub, (3, min(5, availw - 1 if availw > 4 else availw)))
            top = unifint(diff_lb, diff_ub, (1, h - sh - 2))
            left_lo = c0 + 1 if availw - sw - 1 >= 1 else c0
            left_hi = c1 - sw
            if left_hi < left_lo:
                left_lo = c0
            left = unifint(diff_lb, diff_ub, (left_lo, left_hi))
        else:
            r0 = starts[k]
            r1 = ends[k]
            availh = r1 - r0 + 1
            sh = unifint(diff_lb, diff_ub, (3, min(5, availh - 1 if availh > 4 else availh)))
            sw = unifint(diff_lb, diff_ub, (3, min(5, w - 3)))
            top_lo = r0 + 1 if availh - sh - 1 >= 1 else r0
            top_hi = r1 - sh
            if top_hi < top_lo:
                top_lo = r0
            top = unifint(diff_lb, diff_ub, (top_lo, top_hi))
            left = unifint(diff_lb, diff_ub, (1, w - sw - 2))

        cells = {(top + i, left + j) for i in range(sh) for j in range(sw)}
        rem_budget = unifint(diff_lb, diff_ub, (max(1, (sh * sw) // 6), max(1, (sh * sw) // 3)))
        rem_budget = min(rem_budget, sh * sw - 1)

        for _ in range(rem_budget):
            cand = []
            for cell in cells:
                if len(cells) <= 1:
                    break
                trial = set(cells)
                trial.remove(cell)
                comps = connected_components(frozenset(trial), False)
                if len(comps) == 1:
                    cand.append(cell)
            if len(cand) == 0:
                break
            cells.remove(choice(cand))

        shp = frozenset(cells)
        gi = fill(gi, SIX, shp)
        shape_cells.append(shp)

        if orient_horizontal:
            opts = []
            for rr in range(max(0, top - 2), min(h, top + sh + 3)):
                for cc in range(c0, c1 + 1):
                    loc = (rr, cc)
                    if loc in cells:
                        continue
                    if manhattan(initset(loc), shp) >= 2:
                        opts.append(loc)
            if len(opts) == 0:
                for rr in range(h):
                    for cc in range(w):
                        loc = (rr, cc)
                        if loc not in cells and manhattan(initset(loc), shp) >= 2:
                            opts.append(loc)
        else:
            opts = []
            for rr in range(r0, r1 + 1):
                for cc in range(max(0, left - 2), min(w, left + sw + 3)):
                    loc = (rr, cc)
                    if loc in cells:
                        continue
                    if manhattan(initset(loc), shp) >= 2:
                        opts.append(loc)
            if len(opts) == 0:
                for rr in range(h):
                    for cc in range(w):
                        loc = (rr, cc)
                        if loc not in cells and manhattan(initset(loc), shp) >= 2:
                            opts.append(loc)

        if len(opts) == 0:
            mloc = (0, 0)
        else:
            opts = sorted(opts, key=lambda loc: manhattan(initset(loc), shp))
            take = min(len(opts), max(1, unifint(diff_lb, diff_ub, (1, min(6, len(opts))))))
            mloc = choice(opts[:take])

        gi = fill(gi, colork, frozenset({mloc}))
        marker_cells.append(mloc)

    go = verify_50aad11f(gi)
    return {'input': gi, 'output': go}


