def generate_50cb2852(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(8, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    num = unifint(diff_lb, diff_ub, (1, 8))
    indss = asindices(gi)
    maxtrials = 4 * num
    tr = 0
    succ = 0
    while succ < num and tr <= maxtrials:
        if len(remcols) == 0 or len(indss) == 0:
            break
        oh = randint(3, 7)
        ow = randint(3, 7)
        subs = totuple(sfilter(indss, lambda ij: ij[0] < h - oh and ij[1] < w - ow))
        if len(subs) == 0:
            tr += 1
            continue
        loci, locj = choice(subs)
        obj = frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)})
        bd = backdrop(obj)
        col = choice(remcols)
        if bd.issubset(indss):
            remcols = remove(col, remcols)
            gi = fill(gi, col, bd)
            go = fill(go, 8, bd)
            go = fill(go, col, box(obj))
            box(obj)
            succ += 1
            indss = indss - bd
        tr += 1
    return {'input': gi, 'output': go}


def generate_50f325b5(diff_lb: float, diff_ub: float) -> dict:
    cols = (0, 2, 3, 4, 7, 8)
    h = unifint(diff_lb, diff_ub, (11, 20))
    w = unifint(diff_lb, diff_ub, (15, 20))
    gi = canvas(choice(cols[:-1]), (h, w))

    # add noisy background using colors seen in training, with many 3s present
    cells = totuple(asindices(gi))
    nnoise = unifint(diff_lb, diff_ub, (h * w // 2, (4 * h * w) // 5))
    noise_cells = sample(cells, nnoise)
    for ij in noise_cells:
        c = choice((0, 2, 3, 4, 7))
        gi = fill(gi, c, frozenset({ij}))

    # fixed 8-cell template family: connected, sparse, 3x3 bbox
    base = frozenset({
        (0, 0), (0, 1), (0, 2),
        (1, 1),
        (2, 0), (2, 1), (2, 2),
        (1, 0)
    })

    def variants(p):
        xs = set()
        ps = (p, hmirror(p), vmirror(p), hmirror(vmirror(p)))
        for q in ps:
            xs.add(normalize(q))
            xs.add(normalize(dmirror(q)))
        return tuple(xs)

    vars8 = variants(base)
    template = choice(vars8)

    # place the unique 8 template
    th, tw = shape(template)
    loci = randint(0, h - th)
    locj = randint(0, w - tw)
    tloc = (loci, locj)
    gi = fill(gi, 8, shift(template, tloc))

    occupied = set(shift(template, tloc))
    forbidden = set(occupied)

    # place several matching 3-shapes elsewhere, non-overlapping
    nmatches = unifint(diff_lb, diff_ub, (1, 4))
    placed = 0
    for _ in range(200):
        if placed >= nmatches:
            break
        shp = choice(vars8)
        sh, sw = shape(shp)
        i = randint(0, h - sh)
        j = randint(0, w - sw)
        pl = shift(shp, (i, j))
        inds = set(pl)
        if inds & forbidden:
            continue
        # keep some separation to avoid accidental merged-looking clusters
        halo = set()
        for a, b in inds:
            halo |= set(neighbors((a, b)))
        if halo & occupied:
            continue
        gi = fill(gi, 3, pl)
        occupied |= inds
        forbidden |= inds | halo
        placed += 1

    # add extra random 3s, but avoid accidentally creating more matches
    nextra3 = unifint(diff_lb, diff_ub, (5, max(6, h * w // 8)))
    freecells = [ij for ij in cells if ij not in forbidden and gi[ij[0]][ij[1]] != 8]
    shuffle(freecells)
    for ij in freecells[:nextra3]:
        gi = fill(gi, 3, frozenset({ij}))

    go = verify_50f325b5(gi)
    return {'input': gi, 'output': go}


def generate_5117e062(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    nobjs = unifint(diff_lb, diff_ub, (2, (h * w) // 15))
    tr = 0
    maxtr = 4 * nobjs
    done = False
    succ = 0
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    gi = canvas(bgc, (h, w))
    inds = asindices(gi)
    while tr < maxtr and succ < nobjs:
        oh = randint(2, 6)
        ow = randint(2, 6)
        bx = asindices(canvas(-1, (oh, ow)))
        nc = randint(3, oh * ow)
        sp = choice(totuple(bx))
        bx = remove(sp, bx)
        obj = {sp}
        for k in range(nc - 1):
            obj.add(choice(totuple((bx - obj) & mapply(neighbors, obj))))
        if not done:
            done = True
            idx = choice(totuple(obj))
            coll = choice(remcols)
            obj2 = {(coll, idx)}
            coll2 = choice(remove(coll, remcols))
            obj3 = recolor(coll2, remove(idx, obj))
            obj = obj2 | obj3
            go = fill(canvas(bgc, shape(obj)), coll2, normalize(obj))
        else:
            obj = recolor(choice(remcols), obj)
        locopts = sfilter(inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
        tr += 1
        if len(locopts) == 0:
            continue
        loc = choice(totuple(locopts))
        plcd = shift(obj, loc)
        plcdi = toindices(plcd)
        if plcdi.issubset(inds):
            gi = paint(gi, plcd)
            succ += 1
            inds = (inds - plcdi) - mapply(neighbors, plcdi)
    return {'input': gi, 'output': go}


def generate_5168d44c(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (7, 30))
    w = unifint(diff_lb, diff_ub, (7, 30))
    doth = unifint(diff_lb, diff_ub, (1, h//3))
    dotw = unifint(diff_lb, diff_ub, (1, w//3))
    borderh = unifint(diff_lb, diff_ub, (1, h//4))
    borderw = unifint(diff_lb, diff_ub, (1, w//4))
    direc = choice((DOWN, RIGHT, UNITY))
    dotloci = randint(0, h - doth - 1 if direc == RIGHT else h - doth - borderh - 1)
    dotlocj = randint(0, w - dotw - 1 if direc == DOWN else w - dotw - borderw - 1)
    dotloc = (dotloci, dotlocj)
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    dotcol = choice(remcols)
    remcols = remove(dotcol, remcols)
    boxcol = choice(remcols)
    gi = canvas(bgc, (h, w))
    dotshap = (doth, dotw)
    starterdot = backdrop(frozenset({dotloc, add(dotloc, decrement(dotshap))}))
    bordershap = (borderh, borderw)
    offset = add(multiply(direc, dotshap), multiply(direc, bordershap))
    itv = interval(-15, 16, 1)
    itv = apply(lbind(multiply, offset), itv)
    dots = mapply(lbind(shift, starterdot), itv)
    gi = fill(gi, dotcol, dots)
    protobx = backdrop(frozenset({
        (dotloci - borderh, dotlocj - borderw),
        (dotloci + doth + borderh - 1, dotlocj + dotw + borderw - 1),
    }))
    bx = protobx - starterdot
    bxshifted = shift(bx, offset)
    go = fill(gi, boxcol, bxshifted)
    gi = fill(gi, boxcol, bx)
    return {'input': gi, 'output': go}


def generate_516b51b7(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (8, 22))
    w = unifint(diff_lb, diff_ub, (8, 22))
    gi = canvas(0, (h, w))

    maxrects = min(5, max(2, (h * w) // 30))
    nrects = unifint(diff_lb, diff_ub, (2, maxrects))

    occ = set()
    rects = []

    for _ in range(100):
        if len(rects) >= nrects:
            break
        rh = unifint(diff_lb, diff_ub, (3, max(3, min(9, h - 1))))
        rw = unifint(diff_lb, diff_ub, (3, max(3, min(9, w - 1))))
        if rh > h or rw > w:
            continue
        i0 = randint(0, h - rh)
        j0 = randint(0, w - rw)

        cells = {(i, j) for i in range(i0, i0 + rh) for j in range(j0, j0 + rw)}

        ok = True
        for i, j in cells:
            for ni in range(i - 1, i + 2):
                for nj in range(j - 1, j + 2):
                    if (ni, nj) in occ:
                        ok = False
                        break
                if not ok:
                    break
            if not ok:
                break
        if not ok:
            continue

        rects.append((i0, j0, rh, rw))
        occ |= cells

    if len(rects) == 0:
        rh = min(5, h)
        rw = min(5, w)
        i0 = (h - rh) // 2
        j0 = (w - rw) // 2
        rects = [(i0, j0, rh, rw)]

    for i0, j0, rh, rw in rects:
        patch = frozenset((i, j) for i in range(i0, i0 + rh) for j in range(j0, j0 + rw))
        gi = fill(gi, 1, patch)

    go = verify_516b51b7(gi)
    if gi == go:
        return generate_516b51b7(diff_lb, diff_ub)
    return {'input': gi, 'output': go}


def generate_5207a7b5(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (8, 30))
    w = unifint(diff_lb, diff_ub, (4, 30))
    maxbar = min(h - 1, w + 1)
    if maxbar < 2:
        h, w = 8, 4
        maxbar = 5
    barh = unifint(diff_lb, diff_ub, (2, maxbar))
    barcol_min = 1 if w == 1 else 1
    barcol_max = w - 2 if w >= 3 else w - 1
    if barcol_max < 1:
        w = 4
        barcol_max = 2
    j = unifint(diff_lb, diff_ub, (1, barcol_max))
    gi = canvas(0, (h, w))
    gi = fill(gi, 5, connect((0, j), (barh - 1, j)))
    go = verify_5207a7b5(gi)
    return {'input': gi, 'output': go}


def generate_522fdd07(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(7, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (12, 22))
    w = unifint(diff_lb, diff_ub, (12, 22))
    gi = canvas(7, (h, w))

    maxobjs = min(6, (h * w) // 9)
    nobjs = unifint(diff_lb, diff_ub, (3, max(3, maxobjs)))
    used = set()
    placed = 0

    for _ in range(100):
        if placed >= nobjs:
            break
        col = choice(cols)
        make_single = choice((True, False, False))
        if make_single:
            i = randint(0, h - 1)
            j = randint(0, w - 1)
            if (i, j) in used:
                continue
            gi = fill(gi, col, frozenset({(i, j)}))
            used.add((i, j))
            placed += 1
        else:
            oh = unifint(diff_lb, diff_ub, (3, min(9, h)))
            ow = unifint(diff_lb, diff_ub, (3, min(9, w)))
            if oh < 3:
                oh = 3
            if ow < 3:
                ow = 3
            if h - oh < 0 or w - ow < 0:
                continue
            i0 = randint(0, h - oh)
            j0 = randint(0, w - ow)
            patch = connect((i0, j0), (i0 + oh - 1, j0 + ow - 1))
            if any((i, j) in used for (i, j) in patch):
                continue
            gi = fill(gi, col, patch)
            used |= set(patch)
            placed += 1

    if placed < 3:
        fallback_specs = [
            (choice(cols), (1, 1), (3, 3)),
            (choice(cols), (h - 4, max(0, w - 4)), (3, 3)),
            (choice(cols), (h // 2, w // 2), (1, 1)),
        ]
        gi = canvas(7, (h, w))
        for col, (i0, j0), (oh, ow) in fallback_specs:
            if oh == 1 and ow == 1:
                gi = fill(gi, col, frozenset({(max(0, min(h - 1, i0)), max(0, min(w - 1, j0)))}))
            else:
                a = (max(0, min(h - oh, i0)), max(0, min(w - ow, j0)))
                gi = fill(gi, col, connect(a, (a[0] + oh - 1, a[1] + ow - 1)))

    go = verify_522fdd07(gi)
    return {'input': gi, 'output': go}


def generate_52364a65(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc = choice(cols)
    fgcols = remove(bgc, cols)

    h = unifint(diff_lb, diff_ub, (8, 18))
    w = unifint(diff_lb, diff_ub, (8, 18))
    gi = canvas(bgc, (h, w))

    nobj_max = min(5, len(fgcols), max(2, (h * w) // 18))
    nobj = unifint(diff_lb, diff_ub, (2, nobj_max))
    objcols = sample(fgcols, nobj)

    occupied = set()

    def comps_after_add(cells):
        return connected_components(frozenset(occupied | cells), False)

    for col in objcols:
        placed = False
        for _ in range(100):
            oh = unifint(diff_lb, diff_ub, (2, min(6, h)))
            ow = unifint(diff_lb, diff_ub, (1, min(6, w)))
            loci = randint(0, h - oh)
            locj = randint(0, w - ow)

            fullrect = backdrop(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
            ncells_min = max(1, oh * ow // 2)
            ncells = unifint(diff_lb, diff_ub, (ncells_min, oh * ow))

            sp = choice(totuple(fullrect))
            cells = {sp}
            for _k in range(ncells - 1):
                frontier = (fullrect - frozenset(cells)) & mapply(dneighbors, frozenset(cells))
                if len(frontier) == 0:
                    break
                cells.add(choice(totuple(frontier)))
            cells = frozenset(cells)

            if len(cells) == 0:
                continue
            if len(cells & frozenset(occupied)) > 0:
                continue
            if len(comps_after_add(cells)) != len(connected_components(frozenset(occupied), False)) + 1:
                continue

            gi = fill(gi, col, cells)
            occupied |= set(cells)
            placed = True
            break

        if not placed:
            for _ in range(100):
                oh = unifint(diff_lb, diff_ub, (2, min(5, h)))
                ow = unifint(diff_lb, diff_ub, (1, min(5, w)))
                loci = randint(0, h - oh)
                locj = randint(0, w - ow)
                cells = backdrop(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
                if len(cells & frozenset(occupied)) > 0:
                    continue
                if len(comps_after_add(cells)) != len(connected_components(frozenset(occupied), False)) + 1:
                    continue
                gi = fill(gi, col, cells)
                occupied |= set(cells)
                placed = True
                break

    if gi == verify_52364a65(gi):
        col = choice(totuple(remove(bgc, palette(gi)) if len(remove(bgc, palette(gi))) > 0 else fgcols))
        for _ in range(100):
            if w < 3:
                break
            loci = randint(0, h - 1)
            locj = randint(0, w - 3)
            cells = frozenset({(loci, locj), (loci, locj + 1), (loci, locj + 2)})
            if len(cells & frozenset(occupied)) > 0:
                continue
            if len(comps_after_add(cells)) != len(connected_components(frozenset(occupied), False)) + 1:
                continue
            gi = fill(gi, col, cells)
            occupied |= set(cells)
            break

    go = verify_52364a65(gi)
    return {'input': gi, 'output': go}


def generate_5289ad53(diff_lb: float, diff_ub: float) -> dict:
    bgc = choice(remove(2, remove(3, interval(0, 10, 1))))
    h = unifint(diff_lb, diff_ub, (10, 18))
    w = unifint(diff_lb, diff_ub, (10, 20))
    maxobjs = min(6, (h * w) // 6)
    n3 = unifint(diff_lb, diff_ub, (1, max(1, maxobjs - 1)))
    n2 = unifint(diff_lb, diff_ub, (1, max(1, maxobjs - n3)))
    if n3 + n2 > 6:
        n2 = 6 - n3
    if n2 < 1:
        n2 = 1
        n3 = min(5, n3)
    gi = canvas(bgc, (h, w))
    occupied = set()

    def far_enough(cells):
        for i, j in cells:
            for ni in range(i - 1, i + 2):
                for nj in range(j - 1, j + 2):
                    if (ni, nj) in occupied:
                        return False
        return True

    def place_segment(col):
        nonlocal gi, occupied
        for _ in range(100):
            horiz = choice((True, False))
            if horiz:
                ln = unifint(diff_lb, diff_ub, (2, min(6, w)))
                i = randint(0, h - 1)
                j = randint(0, w - ln)
                cells = connect((i, j), (i, j + ln - 1))
            else:
                ln = unifint(diff_lb, diff_ub, (2, min(6, h)))
                i = randint(0, h - ln)
                j = randint(0, w - 1)
                cells = connect((i, j), (i + ln - 1, j))
            if far_enough(cells):
                gi = fill(gi, col, cells)
                occupied |= set(cells)
                return True
        return False

    for _ in range(n3):
        place_segment(3)
    for _ in range(n2):
        place_segment(2)

    go = verify_5289ad53(gi)
    return {'input': gi, 'output': go}


def generate_52df9849(diff_lb: float, diff_ub: float) -> dict:
    bgc = choice(interval(0, 10, 1))
    cols = remove(bgc, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (10, 24))
    w = unifint(diff_lb, diff_ub, (10, 24))
    gi = canvas(bgc, (h, w))

    nobj = unifint(diff_lb, diff_ub, (2, 4))
    used = set()

    def free(patch):
        for ij in patch:
            if ij in used:
                return False
        return True

    # place at least one rectangle-outline object
    rect_done = False
    for _ in range(100):
        if rect_done:
            break
        c = choice(cols)
        rh = unifint(diff_lb, diff_ub, (3, max(3, min(8, h - 1))))
        rw = unifint(diff_lb, diff_ub, (3, max(3, min(8, w - 1))))
        if rh > h or rw > w:
            continue
        i0 = unifint(diff_lb, diff_ub, (0, h - rh))
        j0 = unifint(diff_lb, diff_ub, (0, w - rw))
        patch = box(connect((i0, j0), (i0 + rh - 1, j0 + rw - 1)))
        if free(patch):
            gi = fill(gi, c, patch)
            used |= set(patch)
            cols = remove(c, cols)
            rect_done = True

    # place remaining line objects, mostly crossing-capable
    made = 1 if rect_done else 0
    for _ in range(200):
        if made >= nobj or len(cols) == 0:
            break
        c = choice(cols)
        typ = choice(("h", "v", "d1", "d2"))
        if typ == "h":
            ln = unifint(diff_lb, diff_ub, (4, max(4, min(12, w))))
            if ln > w:
                continue
            i = unifint(diff_lb, diff_ub, (0, h - 1))
            j0 = unifint(diff_lb, diff_ub, (0, w - ln))
            miss = unifint(diff_lb, diff_ub, (1, ln - 2))
            patch = difference(connect((i, j0), (i, j0 + ln - 1)), initset((i, j0 + miss)))
        elif typ == "v":
            ln = unifint(diff_lb, diff_ub, (4, max(4, min(12, h))))
            if ln > h:
                continue
            i0 = unifint(diff_lb, diff_ub, (0, h - ln))
            j = unifint(diff_lb, diff_ub, (0, w - 1))
            miss = unifint(diff_lb, diff_ub, (1, ln - 2))
            patch = difference(connect((i0, j), (i0 + ln - 1, j)), initset((i0 + miss, j)))
        elif typ == "d1":
            ln = unifint(diff_lb, diff_ub, (4, max(4, min(10, h, w))))
            if ln > h or ln > w:
                continue
            i0 = unifint(diff_lb, diff_ub, (0, h - ln))
            j0 = unifint(diff_lb, diff_ub, (0, w - ln))
            miss = unifint(diff_lb, diff_ub, (1, ln - 2))
            patch = difference(connect((i0, j0), (i0 + ln - 1, j0 + ln - 1)), initset((i0 + miss, j0 + miss)))
        else:
            ln = unifint(diff_lb, diff_ub, (4, max(4, min(10, h, w))))
            if ln > h or ln > w:
                continue
            i0 = unifint(diff_lb, diff_ub, (0, h - ln))
            j0 = unifint(diff_lb, diff_ub, (ln - 1, w - 1))
            miss = unifint(diff_lb, diff_ub, (1, ln - 2))
            patch = difference(connect((i0, j0), (i0 + ln - 1, j0 - ln + 1)), initset((i0 + miss, j0 - miss)))
        if free(patch):
            gi = fill(gi, c, patch)
            used |= set(patch)
            cols = remove(c, cols)
            made += 1

    # fallback if somehow too few objects
    if made < 2 and len(cols) > 0:
        c = choice(cols)
        i = h // 2
        j0 = max(0, w // 2 - 2)
        j1 = min(w - 1, j0 + 4)
        patch = difference(connect((i, j0), (i, j1)), initset((i, (j0 + j1) // 2)))
        gi = fill(gi, c, patch)

    go = verify_52df9849(gi)
    return {'input': gi, 'output': go}


def generate_52fd389e(diff_lb: float, diff_ub: float) -> dict:
    h = 25
    w = 25
    gi = canvas(0, (h, w))
    nobj = unifint(diff_lb, diff_ub, (2, 4))
    embed_cols = sample((1, 2, 3, 5, 6, 7, 8, 9), nobj)
    placed = []

    for k in range(nobj):
        for _ in range(200):
            rh = unifint(diff_lb, diff_ub, (3, 10))
            rw = unifint(diff_lb, diff_ub, (3, 10))
            interior_size = (rh - 2) * (rw - 2)
            if interior_size < 1:
                continue
            maxembed = min(interior_size, 5)
            nemb = unifint(diff_lb, diff_ub, (1, maxembed))
            pad = nemb
            mini = pad
            minj = pad
            maxi = h - rh - pad
            maxj = w - rw - pad
            if maxi < mini or maxj < minj:
                continue
            i0 = unifint(diff_lb, diff_ub, (mini, maxi))
            j0 = unifint(diff_lb, diff_ub, (minj, maxj))
            i1 = i0 + rh - 1
            j1 = j0 + rw - 1

            ok = True
            for (a0, a1, b0, b1, p) in placed:
                if not (i1 + pad < a0 - p or a1 + p < i0 - pad or j1 + pad < b0 - p or b1 + p < j0 - pad):
                    ok = False
                    break
            if not ok:
                continue

            rect = product(interval(i0, i1 + 1, 1), interval(j0, j1 + 1, 1))
            gi = fill(gi, 4, rect)
            interior = product(interval(i0 + 1, i1, 1), interval(j0 + 1, j1, 1))
            cells = sample(totuple(interior), nemb)
            gi = fill(gi, embed_cols[k], frozenset(cells))
            placed.append((i0, i1, j0, j1, pad))
            break

    if len(placed) == 0:
        i0, j0, rh, rw = 2, 2, 3, 3
        rect = product(interval(i0, i0 + rh, 1), interval(j0, j0 + rw, 1))
        gi = fill(gi, 4, rect)
        gi = fill(gi, 1, frozenset({(i0 + 1, j0 + 1)}))

    go = verify_52fd389e(gi)
    return {'input': gi, 'output': go}


def generate_538b439f(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (12, 24))
    w = unifint(diff_lb, diff_ub, (12, 24))

    bgc = choice(cols)
    rem = remove(bgc, cols)
    linec = choice(rem)
    rem2 = remove(linec, rem)
    rectc = choice(rem2)

    orient = choice((0, 1))  # 0 vertical, 1 horizontal

    if orient == 0:
        if w < 5:
            w = 5
        axis = unifint(diff_lb, diff_ub, (1, w - 2))
        gi = canvas(bgc, (h, w))
        gi = fill(gi, linec, connect((0, axis), (h - 1, axis)))

        nrects = unifint(diff_lb, diff_ub, (1, max(1, min(4, h // 3))))
        occ = set()
        placed = 0
        tries = 0
        maxtries = 200

        while placed < nrects and tries < maxtries:
            tries += 1
            side = choice((-1, 1))
            maxrw = max(1, min(5, axis if side == -1 else w - axis - 1))
            if maxrw <= 0:
                continue
            rw = unifint(diff_lb, diff_ub, (1, maxrw))
            rh = unifint(diff_lb, diff_ub, (1, min(5, h)))
            if rh > h:
                rh = h
            if side == -1:
                maxdist = axis - rw
            else:
                maxdist = w - axis - rw
            if maxdist < 0:
                continue
            dist = unifint(diff_lb, diff_ub, (0, maxdist))
            r0 = randint(0, h - rh)
            if side == -1:
                c0 = axis - dist - rw
            else:
                c0 = axis + 1 + dist
            c1 = c0 + rw - 1
            mr0 = r0
            mr1 = r0 + rh - 1
            mc0 = 2 * axis - c1
            mc1 = 2 * axis - c0
            if mc0 < 0 or mc1 >= w:
                continue
            rect1 = connect((r0, c0), (r0 + rh - 1, c1))
            rect2 = connect((mr0, mc0), (mr1, mc1))
            if any((i, j) in occ or gi[i][j] == linec for i, j in rect1 | rect2):
                continue
            gi = fill(gi, rectc, rect1)
            occ |= set(rect1) | set(rect2)
            placed += 1

        if placed == 0:
            rh = 2 if h >= 2 else 1
            rw = 2 if axis >= 2 else 1
            r0 = 0
            c0 = max(0, axis - rw)
            rect1 = connect((r0, c0), (r0 + rh - 1, c0 + rw - 1))
            gi = fill(gi, rectc, rect1)

    else:
        if h < 5:
            h = 5
        axis = unifint(diff_lb, diff_ub, (1, h - 2))
        gi = canvas(bgc, (h, w))
        gi = fill(gi, linec, connect((axis, 0), (axis, w - 1)))

        nrects = unifint(diff_lb, diff_ub, (1, max(1, min(4, w // 3))))
        occ = set()
        placed = 0
        tries = 0
        maxtries = 200

        while placed < nrects and tries < maxtries:
            tries += 1
            side = choice((-1, 1))
            maxrh = max(1, min(5, axis if side == -1 else h - axis - 1))
            if maxrh <= 0:
                continue
            rh = unifint(diff_lb, diff_ub, (1, maxrh))
            rw = unifint(diff_lb, diff_ub, (1, min(5, w)))
            if rw > w:
                rw = w
            if side == -1:
                maxdist = axis - rh
            else:
                maxdist = h - axis - rh
            if maxdist < 0:
                continue
            dist = unifint(diff_lb, diff_ub, (0, maxdist))
            c0 = randint(0, w - rw)
            if side == -1:
                r0 = axis - dist - rh
            else:
                r0 = axis + 1 + dist
            r1 = r0 + rh - 1
            mr0 = 2 * axis - r1
            mr1 = 2 * axis - r0
            mc0 = c0
            mc1 = c0 + rw - 1
            if mr0 < 0 or mr1 >= h:
                continue
            rect1 = connect((r0, c0), (r1, c0 + rw - 1))
            rect2 = connect((mr0, mc0), (mr1, mc1))
            if any((i, j) in occ or gi[i][j] == linec for i, j in rect1 | rect2):
                continue
            gi = fill(gi, rectc, rect1)
            occ |= set(rect1) | set(rect2)
            placed += 1

        if placed == 0:
            rh = 2 if axis >= 2 else 1
            rw = 2 if w >= 2 else 1
            r0 = max(0, axis - rh)
            c0 = 0
            rect1 = connect((r0, c0), (r0 + rh - 1, c0 + rw - 1))
            gi = fill(gi, rectc, rect1)

    noisecands = remove(rectc, remove(linec, remove(bgc, cols)))
    nnoise = unifint(diff_lb, diff_ub, (0, max(1, (h * w) // 12)))
    free = [ij for ij in totuple(asindices(gi)) if gi[ij[0]][ij[1]] == bgc]
    if len(free) > 0 and nnoise > 0:
        nnoise = min(nnoise, len(free))
        for ij in sample(free, nnoise):
            gi = fill(gi, choice(noisecands), frozenset({ij}))

    go = verify_538b439f(gi)
    return {'input': gi, 'output': go}


def generate_539a4f51(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    d = unifint(diff_lb, diff_ub, (2, 15))
    h, w = d, d
    gi = canvas(0, (h, w))
    numc = unifint(diff_lb, diff_ub, (2, 9))
    ccols = sample(cols, numc)
    numocc = unifint(diff_lb, diff_ub, (1, d))
    arr = [choice(ccols) for k in range(numocc)]
    while len(set(arr)) == 1:
        arr = [choice(ccols) for k in range(d)]
    for j, col in enumerate(arr):
        gi = fill(gi, col, connect((j, 0), (j, j)) | connect((0, j), (j, j)))
    go = canvas(0, (2*d, 2*d))
    for j in range(2*d):
        col = arr[j % len(arr)]
        go = fill(go, col, connect((j, 0), (j, j)) | connect((0, j), (j, j)))
    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = rotf(go)
    return {'input': gi, 'output': go}


def generate_53b68214(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    while True:
        h = unifint(diff_lb, diff_ub, (2, 6))
        w = unifint(diff_lb, diff_ub, (8, 30))
        bgc = choice(cols)
        remcols = remove(bgc, cols)
        ncols = unifint(diff_lb, diff_ub, (1, 9))
        ccols = sample(remcols, ncols)
        oh = unifint(diff_lb, diff_ub, (1, h//2))
        ow = unifint(diff_lb, diff_ub, (1, w//2-1))
        bounds = asindices(canvas(-1, (oh, ow)))
        ncells = unifint(diff_lb, diff_ub, (1, oh * ow))
        obj = sample(totuple(bounds), ncells)
        obj = {(choice(ccols), ij) for ij in obj}
        obj = normalize(obj)
        oh, ow = shape(obj)
        locj = randint(0, w//2)
        plcd = shift(obj, (0, locj))
        go = canvas(bgc, (10, w))
        hoffs = randint(0, ow//2 + 1)
        for k in range(10//oh+1):
            go = paint(go, shift(plcd, (k*oh, k*hoffs)))
        if len(palette(go[h:])) > 1:
            break
    gi = go[:h]
    if choice((True, False)):
        gi = vmirror(gi)
        go = vmirror(go)
    return {'input': gi, 'output': go}


def generate_543a7ed5(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (3, 4))    
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    numc = unifint(diff_lb, diff_ub, (1, 7))
    ccols = sample(remcols, numc)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    num = unifint(diff_lb, diff_ub, (1, (h * w) // 25))
    indss = asindices(gi)
    maxtrials = 4 * num
    tr = 0
    succ = 0
    while succ < num and tr <= maxtrials:
        if len(indss) == 0:
            break
        oh = randint(4, 8)
        ow = randint(4, 8)
        subs = totuple(sfilter(indss, lambda ij: ij[0] < h - oh and ij[1] < w - ow))
        if len(subs) == 0:
            tr += 1
            continue
        loci, locj = choice(subs)
        obj = frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)})
        bd = backdrop(obj)
        col = choice(ccols)
        if bd.issubset(indss):
            bdibd = backdrop(frozenset({(loci+1, locj+1), (loci + oh - 2, locj + ow - 2)}))
            go = fill(go, col, bdibd)
            go = fill(go, 3, box(bd))
            gi = fill(gi, col, bdibd)
            if oh > 5 and ow > 5 and randint(1, 10) != 1:
                ulci, ulcj = ulcorner(bdibd)
                lrci, lrcj = lrcorner(bdibd)
                aa = randint(ulci + 1, lrci - 1)
                aa = randint(ulci + 1, aa)
                bb = randint(ulcj + 1, lrcj - 1)
                bb = randint(ulcj + 1, bb)
                cc = randint(aa, lrci - 1)
                dd = randint(bb, lrcj - 1)
                cc = randint(cc, lrci - 1)
                dd = randint(dd, lrcj - 1)
                ins = backdrop({(aa, bb), (cc, dd)})
                go = fill(go, 4, ins)
                gi = fill(gi, bgc, ins)
            succ += 1
            indss = indss - bd
        tr += 1
    return {'input': gi, 'output': go}


def generate_54d82841(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(4, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (5, 30))
    w = unifint(diff_lb, diff_ub, (5, 30))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    nshps = unifint(diff_lb, diff_ub, (1, w // 3))
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    locs = interval(1, w - 1, 1)
    for k in range(nshps):
        if len(locs) == 0:
            break
        loc = choice(locs)
        locs = remove(loc, locs)
        locs = remove(loc + 1, locs)
        locs = remove(loc - 1, locs)
        locs = remove(loc + 2, locs)
        locs = remove(loc - 2, locs)
        loci = randint(1, h - 1)
        col = choice(remcols)
        ij = (loci, loc)
        shp = neighbors(ij) - connect((loci + 1, loc - 1), (loci + 1, loc + 1))
        gi = fill(gi, col, shp)
        go = fill(go, col, shp)
        go = fill(go, 4, {(h - 1, loc)})
    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = rotf(go)
    return {'input': gi, 'output': go}


def generate_54d9e175(diff_lb: float, diff_ub: float) -> dict:
    cols = (0, 5)
    h = unifint(diff_lb, diff_ub, (2, 5))
    w = unifint(diff_lb, diff_ub, (2, 5))
    nh = unifint(diff_lb, diff_ub, (1, 31 // (h + 1)))
    nw = unifint(diff_lb, diff_ub, (1 if nh > 1 else 2, 31 // (w + 1)))
    fullh = (h + 1) * nh - 1
    fullw = (w + 1) * nw - 1
    linc, bgc = sample(cols, 2)
