def generate_5792cb4d(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = w = 10
    bgc = choice(cols)
    pathcols_pool = remove(bgc, cols)

    maxlen = unifint(diff_lb, diff_ub, (5, 16))
    for _ in range(100):
        gi = canvas(bgc, (h, w))

        sr = unifint(diff_lb, diff_ub, (1, h - 2))
        sc = unifint(diff_lb, diff_ub, (1, w - 2))
        path = [(sr, sc)]
        used = {path[0]}

        target_len = maxlen
        cur = path[0]

        for _k in range(target_len - 1):
            canddirs = [UP, DOWN, LEFT, RIGHT]
            shuffle(canddirs)
            cands = []
            for d in canddirs:
                nxt = add(cur, d)
                i, j = nxt
                if not (1 <= i < h - 1 and 1 <= j < w - 1):
                    continue
                if nxt in used:
                    continue
                nbs = dneighbors(nxt) & frozenset(used)
                if size(nbs) != 1:
                    continue
                ok = True
                for uu in used:
                    if manhattan(initset(uu), initset(nxt)) == 1 and uu != cur:
                        ok = False
                        break
                if ok:
                    cands.append(nxt)
            if len(cands) == 0:
                break
            cur = choice(cands)
            path.append(cur)
            used.add(cur)

        if len(path) < 5:
            continue

        end1 = path[0]
        end2 = path[-1]
        deg1 = size(dneighbors(end1) & frozenset(path))
        deg2 = size(dneighbors(end2) & frozenset(path))
        if deg1 != 1 or deg2 != 1:
            continue

        good = True
        pset = frozenset(path)
        for p in path[1:-1]:
            if size(dneighbors(p) & pset) != 2:
                good = False
                break
        if not good:
            continue

        ncols = unifint(diff_lb, diff_ub, (2, min(9, len(path))))
        seq = [choice(pathcols_pool) for _ in range(len(path))]
        change_positions = sample(interval(1, len(path), 1), ncols - 1) if ncols > 1 else []
        shuffle(change_positions)
        change_positions = sorted(change_positions)
        chosen_cols = sample(pathcols_pool, ncols)
        segstarts = [0] + change_positions
        segends = change_positions + [len(path)]
        for col, a, b in zip(chosen_cols, segstarts, segends):
            for idx in range(a, b):
                seq[idx] = col

        if seq == list(reversed(seq)):
            seq[0] = chosen_cols[0]
            seq[-1] = other(pathcols_pool, seq[0]) if len(pathcols_pool) > 1 else seq[-1]
            if seq == list(reversed(seq)):
                continue

        for loc, col in zip(path, seq):
            gi = fill(gi, col, initset(loc))

        go = verify_5792cb4d(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    gi = canvas(8, (10, 10))
    path = [(4, 2), (5, 2), (5, 3), (5, 4), (5, 5), (5, 6), (5, 7), (6, 7)]
    seq = [4, 7, 1, 6, 5, 6, 1, 2]
    for loc, col in zip(path, seq):
        gi = fill(gi, col, initset(loc))
    go = verify_5792cb4d(gi)
    return {'input': gi, 'output': go}


def generate_57aa92db(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    oh = randint(2, 5)
    ow = randint(2, 5)
    bounds = asindices(canvas(-1, (oh, ow)))
    obj = {choice(totuple(bounds))}
    ncellsd = unifint(diff_lb, diff_ub, (0, (oh * ow) // 2))
    ncells = choice((ncellsd, oh * ow - ncellsd))
    ncells = min(max(3, ncells), oh * ow)
    for k in range(ncells - 1):
        obj.add(choice(totuple((bounds - obj) & mapply(neighbors, obj))))
    obj = normalize(obj)
    oh, ow = shape(obj)
    fixp = choice(totuple(obj))
    bgc, fixc, mainc = sample(cols, 3)
    remcols = difference(cols, (bgc, fixc, mainc))
    gi = canvas(bgc, (h, w))
    obj = {(fixc, fixp)} | recolor(mainc, remove(fixp, obj))
    loci = randint(0, h - oh)
    locj = randint(0, w - ow)
    plcd = shift(obj, (loci, locj))
    gi = paint(gi, plcd)
    go = tuple(e for e in gi)
    inds = ofcolor(gi, bgc) - mapply(neighbors, toindices(plcd))
    nocc = unifint(diff_lb, diff_ub, (1, (h * w) // (4 * len(obj))))
    tr = 0
    succ = 0
    maxtr = 5 * nocc
    while succ < nocc and tr < maxtr:
        tr += 1
        fac = randint(1, 4)
        objups = upscale(obj, fac)
        hh, ww = shape(objups)
        cands = sfilter(inds, lambda ij: ij[0] <= h - hh and ij[1] <= w - ww)
        if len(cands) == 0:
            continue
        loc = choice(totuple(cands))
        objupsplcd = shift(objups, loc)
        objupsplcdi = toindices(objupsplcd)
        if objupsplcdi.issubset(inds):
            succ += 1
            newc = choice(remcols)
            fixp2 = sfilter(objupsplcd, lambda cij: cij[0] == fixc)
            inds = inds - mapply(neighbors, objupsplcdi)
            gi = paint(gi, fixp2)
            go = paint(go, fixp2)
            remobjfull = toindices(objupsplcd - fixp2)
            ntorem = unifint(diff_lb, diff_ub, (0, max(0, len(remobjfull) - 1)))
            ntokeep = len(remobjfull) - ntorem
            tokeep = {choice(totuple(remobjfull & outbox(fixp2)))}
            fixp2i = toindices(fixp2)
            for k in range(ntokeep - 1):
                fullopts = remobjfull & mapply(neighbors, tokeep | fixp2i)
                remopts = fullopts - tokeep
                tokeep.add(choice(totuple(remopts)))
            gi = fill(gi, newc, tokeep)
            go = fill(go, newc, remobjfull)
    return {'input': gi, 'output': go}


def generate_57edb29d(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(4, interval(0, 10, 1))
    symc = choice(cols)
    rem = remove(symc, cols)

    npan = unifint(diff_lb, diff_ub, (3, 5))
    basecols = sample(rem, npan)
    plain_idx = randint(0, npan - 1)

    # Decide layout: split npan panels into rows
    row_counts = []
    remaining = npan
    while remaining > 0:
        mx = min(remaining, 3)
        rc = randint(1, mx)
        row_counts.append(rc)
        remaining -= rc

    if len(row_counts) > 1:
        shuffle(row_counts)

    # Assign panel indices to rows
    panel_order = list(range(npan))
    shuffle(panel_order)
    rows = []
    idx = 0
    for cnt in row_counts:
        rows.append(panel_order[idx:idx + cnt])
        idx += cnt

    nrows = len(rows)
    max_per_row = max(row_counts)

    # Determine panel dimensions, constrained so grid fits in 30x30
    # Total height = sum of row heights + nrows + 1 (separators)
    # Total width = max row width + 2 (outer borders) + (panels_in_row - 1) separators
    max_panel_h = min(12, (30 - nrows - 1) // nrows)
    max_panel_w = min(12, (30 - 2 - (max_per_row - 1)) // max_per_row)
    max_panel_h = max(max_panel_h, 4)
    max_panel_w = max(max_panel_w, 4)

    panel_dims = []
    for _ in range(npan):
        ph = unifint(diff_lb, diff_ub, (4, max_panel_h))
        pw = unifint(diff_lb, diff_ub, (4, max_panel_w))
        panel_dims.append((ph, pw))

    # Compute symbol positions
    # The verifier computes min(dist_from_top_edge, dist_from_bottom_edge) and
    # min(dist_from_left_edge, dist_from_right_edge) for each symbol cell within
    # the interior (excluding the 1-cell border). We place symbols at consistent
    # (min_row_dist, min_col_dist) positions across all decorated panels.
    minh = min(h for h, w in panel_dims)
    minw = min(w for h, w in panel_dims)
    # Interior size of smallest panel
    ih = minh - 2
    iw = minw - 2
    maxir = max(1, (ih + 1) // 2)  # max distinct row distances from edge
    maxjc = max(1, (iw + 1) // 2)  # max distinct col distances from edge
    nsym = unifint(diff_lb, diff_ub, (1, max(1, min(6, maxir * maxjc))))
    allpairs = [(a, b) for a in range(maxir) for b in range(maxjc)]
    shuffle(allpairs)
    sympairs = allpairs[:nsym]

    # Build panels
    panels = []
    for k in range(npan):
        ph, pw = panel_dims[k]
        bc = basecols[k]
        g = canvas(bc, (ph, pw))
        if k != plain_idx:
            inds = set()
            pih = ph - 2  # interior height
            piw = pw - 2  # interior width
            for a, b in sympairs:
                if a < (pih + 1) // 2 and b < (piw + 1) // 2:
                    # Place at all 4 symmetric positions
                    r_positions = {1 + a, ph - 2 - a}
                    c_positions = {1 + b, pw - 2 - b}
                    for rr in r_positions:
                        for cc in c_positions:
                            inds.add((rr, cc))
            if len(inds) == 0:
                # Ensure at least one symbol cell
                inds.add((1, 1))
                if ph > 3:
                    inds.add((ph - 2, 1))
                if pw > 3:
                    inds.add((1, pw - 2))
                if ph > 3 and pw > 3:
                    inds.add((ph - 2, pw - 2))
            g = fill(g, symc, frozenset(inds))
        panels.append(g)

    # Compute grid dimensions
    rowhs = [max(panel_dims[i][0] for i in row) for row in rows]
    rowws = []
    for row in rows:
        w = sum(panel_dims[i][1] for i in row) + len(row) - 1  # separators between panels
        rowws.append(w)
    H = sum(rowhs) + nrows + 1  # row separators + top/bottom borders
    W = max(rowws) + 2  # left/right borders

    gi = canvas(4, (H, W))

    # Paint panels onto grid
    top = 1
    for rr_idx, row in enumerate(rows):
        left = 1
        for i in row:
            gi = paint(gi, shift(asobject(panels[i]), (top, left)))
            left += panel_dims[i][1] + 1  # +1 for color-4 separator
        top += rowhs[rr_idx] + 1  # +1 for color-4 separator row

    go = verify_57edb29d(gi)
    return {'input': gi, 'output': go}


def generate_5833af48(diff_lb: float, diff_ub: float) -> dict:
    cols = totuple(remove(0, remove(2, remove(8, interval(0, 10, 1)))))
    bg = 0
    rectc = choice(cols)

    # Stamp dimensions (the small pattern template)
    sh = unifint(diff_lb, diff_ub, (2, 4))
    sw = unifint(diff_lb, diff_ub, (2, 4))

    # Choose stamp 8-pattern: at least 1 cell, at most sh*sw-1 cells
    n8 = unifint(diff_lb, diff_ub, (1, max(1, sh * sw - 1)))
    all_stamp_cells = [(i, j) for i in range(sh) for j in range(sw)]
    stamp_8_cells = set(sample(all_stamp_cells, n8))
    if len(stamp_8_cells) == sh * sw:
        stamp_8_cells.remove(choice(list(stamp_8_cells)))

    # Tile counts: how many stamp-sized tiles in the rectangle
    rh = unifint(diff_lb, diff_ub, (2, 4))
    rw = unifint(diff_lb, diff_ub, (2, 5))

    # Scale factor for the map — must have rectw > mapw, i.e. sw*rw > rw*scale, i.e. sw > scale
    max_scale = min(2, sw - 1)
    scale = unifint(diff_lb, diff_ub, (1, max(1, max_scale)))

    # Derived dimensions
    recth = sh * rh
    rectw = sw * rw
    maph = rh * scale
    mapw = rw * scale

    top_h = max(sh, maph)
    gap_rows = unifint(diff_lb, diff_ub, (1, 2))

    # Width components: stamp(sw) + gap_col(1) + map(mapw)
    top_w = sw + 1 + mapw
    content_w = max(top_w, rectw)

    # Margins, constrained to keep grid <= 30
    max_left = max(0, min(3, (30 - content_w) // 2))
    left_margin = unifint(diff_lb, diff_ub, (0, max_left))
    max_right = max(0, min(3, 30 - content_w - left_margin))
    right_margin = unifint(diff_lb, diff_ub, (0, max_right))
    max_bottom = max(0, min(3, 30 - top_h - gap_rows - recth))
    bottom_margin = unifint(diff_lb, diff_ub, (0, max_bottom))

    total_h = top_h + gap_rows + recth + bottom_margin
    total_w = left_margin + content_w + right_margin

    if total_h > 30 or total_w > 30 or total_h < 1 or total_w < 1:
        return generate_5833af48(diff_lb, diff_ub)

    gi = canvas(bg, (total_h, total_w))

    # Place stamp (top-left area): 2 for non-8 cells, 8 for pattern
    stamp_top = 0
    if top_h > sh:
        stamp_top = unifint(diff_lb, diff_ub, (0, top_h - sh))
    stamp_left = left_margin

    for i in range(sh):
        for j in range(sw):
            r, c = stamp_top + i, stamp_left + j
            if (i, j) in stamp_8_cells:
                gi = fill(gi, 8, frozenset({(r, c)}))
            else:
                gi = fill(gi, 2, frozenset({(r, c)}))

    # Place map (top-right area)
    map_top = 0
    if top_h > maph:
        map_top = unifint(diff_lb, diff_ub, (0, top_h - maph))
    map_left = left_margin + sw + 1  # 1 column gap

    # Choose coarse positions (which tiles get the stamp)
    npos = unifint(diff_lb, diff_ub, (1, max(1, rh * rw - 1)))
    coarse_cells = [(i, j) for i in range(rh) for j in range(rw)]
    coarse_positions = set(sample(coarse_cells, min(npos, len(coarse_cells))))
    if len(coarse_positions) == 0:
        coarse_positions.add((0, 0))

    # Fill entire map with rect_color
    map_inds = frozenset((map_top + i, map_left + j) for i in range(maph) for j in range(mapw))
    gi = fill(gi, rectc, map_inds)

    # Overwrite 8-positions with scale x scale blocks
    for mi, mj in coarse_positions:
        bi = map_top + mi * scale
        bj = map_left + mj * scale
        block = frozenset((bi + di, bj + dj) for di in range(scale) for dj in range(scale))
        gi = fill(gi, 8, block)

    # Place rectangle below (solid rect_color)
    rect_top = top_h + gap_rows
    rect_left = left_margin
    rect_inds = frozenset((rect_top + i, rect_left + j) for i in range(recth) for j in range(rectw))
    gi = fill(gi, rectc, rect_inds)

    go = verify_5833af48(gi)
    return {'input': gi, 'output': go}


def generate_58743b76(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, remove(8, interval(0, 10, 1)))
    for _ in range(100):
        wh = unifint(diff_lb, diff_ub, (4, 14))
        ww = unifint(diff_lb, diff_ub, (4, 14))
        if wh % 2 == 1:
            wh += 1
        if ww % 2 == 1:
            ww += 1
        wh = min(wh, 14)
        ww = min(ww, 14)

        corner = choice([(0, 0), (0, 1), (1, 0), (1, 1)])
        top_margin = 2 if corner[0] == 0 else unifint(diff_lb, diff_ub, (0, 2))
        bottom_margin = 2 if corner[0] == 1 else unifint(diff_lb, diff_ub, (0, 2))
        left_margin = 2 if corner[1] == 0 else unifint(diff_lb, diff_ub, (0, 2))
        right_margin = 2 if corner[1] == 1 else unifint(diff_lb, diff_ub, (0, 2))

        h = wh + top_margin + bottom_margin
        w = ww + left_margin + right_margin
        if h < 4 or w < 4 or h > 30 or w > 30:
            continue

        work_r0 = top_margin
        work_c0 = left_margin
        work = backdrop(frozenset({(work_r0, work_c0), (work_r0 + wh - 1, work_c0 + ww - 1)}))

        if corner == (0, 0):
            key_r0, key_c0 = 0, 0
        elif corner == (0, 1):
            key_r0, key_c0 = 0, w - 2
        elif corner == (1, 0):
            key_r0, key_c0 = h - 2, 0
        else:
            key_r0, key_c0 = h - 2, w - 2

        keycols = sample(cols, 4)
        remaining = cols
        for c in keycols:
            remaining = remove(c, remaining)
        marker_color = choice(remaining)

        gi = canvas(8, (h, w))
        gi = fill(gi, 0, work)
        gi = fill(gi, keycols[0], frozenset({(key_r0, key_c0)}))
        gi = fill(gi, keycols[1], frozenset({(key_r0, key_c0 + 1)}))
        gi = fill(gi, keycols[2], frozenset({(key_r0 + 1, key_c0)}))
        gi = fill(gi, keycols[3], frozenset({(key_r0 + 1, key_c0 + 1)}))

        top_rows = interval(work_r0, work_r0 + wh // 2, 1)
        bot_rows = interval(work_r0 + wh // 2, work_r0 + wh, 1)
        left_cols_r = interval(work_c0, work_c0 + ww // 2, 1)
        right_cols_r = interval(work_c0 + ww // 2, work_c0 + ww, 1)

        q1 = frozenset((i, j) for i in top_rows for j in left_cols_r)
        q2 = frozenset((i, j) for i in top_rows for j in right_cols_r)
        q3 = frozenset((i, j) for i in bot_rows for j in left_cols_r)
        q4 = frozenset((i, j) for i in bot_rows for j in right_cols_r)

        quadrants = [q1, q2, q3, q4]
        markers = set()
        for q in quadrants:
            qsz = len(q)
            n = unifint(diff_lb, diff_ub, (1, max(1, qsz // 4)))
            markers |= set(sample(totuple(q), n))

        gi = fill(gi, marker_color, frozenset(markers))
        go = verify_58743b76(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    wh, ww = 8, 8
    h, w = 10, 10
    gi = canvas(8, (h, w))
    work = backdrop(frozenset({(2, 2), (9, 9)}))
    gi = fill(gi, 0, work)
    gi = fill(gi, 1, frozenset({(0, 0)}))
    gi = fill(gi, 4, frozenset({(0, 1)}))
    gi = fill(gi, 3, frozenset({(1, 0)}))
    gi = fill(gi, 2, frozenset({(1, 1)}))
    gi = fill(gi, 7, frozenset({(3, 3), (3, 7), (7, 3), (7, 7)}))
    go = verify_58743b76(gi)
    return {'input': gi, 'output': go}


def generate_58c02a16(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(7, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (6, 30))
    w = unifint(diff_lb, diff_ub, (6, 30))

    for _ in range(100):
        th = unifint(diff_lb, diff_ub, (3, min(6, h - 1)))
        tw = unifint(diff_lb, diff_ub, (3, min(6, w - 1)))
        a, b = sample(cols, 2)

        rows = [list(repeat(7, w)) for _ in range(h)]

        na = unifint(diff_lb, diff_ub, (2, max(2, (th * tw) // 2)))
        nb = unifint(diff_lb, diff_ub, (1, max(1, (th * tw) // 3)))

        allcells = [(i, j) for i in range(th) for j in range(tw)]
        acells = sample(allcells, min(len(allcells), na))
        rem = [ij for ij in allcells if ij not in acells]
        if len(rem) == 0:
            continue
        bcells = sample(rem, min(len(rem), nb))

        used_rows = {i for i, j in acells + bcells}
        used_cols = {j for i, j in acells + bcells}
        if len(used_rows) < th or len(used_cols) < tw:
            continue

        for i, j in acells:
            rows[i][j] = a
        for i, j in bcells:
            rows[i][j] = b

        gi = tuple(tuple(r) for r in rows)
        go = verify_58c02a16(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    th = 3
    tw = 3
    a, b = sample(cols, 2)
    gi = canvas(7, (h, w))
    gi = fill(gi, a, frozenset({(0, 0), (1, 1), (2, 2)}))
    gi = fill(gi, b, frozenset({(0, 2), (2, 0)}))
    go = verify_58c02a16(gi)
    return {'input': gi, 'output': go}


def generate_58e15b12(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (14, 24))
    cols = (1, 2, 3, 4, 5, 7, 8, 9)
    c1, c2 = sample(cols, 2)

    for _ in range(200):
        h1 = unifint(diff_lb, diff_ub, (1, max(1, h // 4)))
        h2 = unifint(diff_lb, diff_ub, (1, max(1, h // 4)))

        maxk1u = max(0, rbind(divide, h1)(decrement(minimum((h1 - 1, w - 2)))))
        maxk1d = max(0, rbind(divide, h1)(minimum((h - h1, w - 2))))
        maxk2u = max(0, rbind(divide, h2)(decrement(minimum((h2 - 1, w - 2)))))
        maxk2d = max(0, rbind(divide, h2)(minimum((h - h2, w - 2))))

        if maxk1u + maxk1d < 1 or maxk2u + maxk2d < 1:
            continue

        top1_min = max(0, h1 * maxk1u)
        top1_max = min(h - h1, h - 1 - h1 * maxk1d)
        top2_min = max(0, h2 * maxk2u)
        top2_max = min(h - h2, h - 1 - h2 * maxk2d)
        if top1_min > top1_max or top2_min > top2_max:
            continue

        r1 = randint(top1_min, top1_max)
        r2 = randint(top2_min, top2_max)

        k1u = r1 // h1
        k1d = (h - 1 - (r1 + h1 - 1)) // h1
        k2u = r2 // h2
        k2d = (h - 1 - (r2 + h2 - 1)) // h2

        if k1u + k1d < 1 or k2u + k2d < 1:
            continue

        j1l = randint(0, w - 3)
        j1r = randint(j1l + 2, w - 1)
        j2l = randint(0, w - 3)
        j2r = randint(j2l + 2, w - 1)

        def trail_cells(top, hh, jl, jr):
            out = set()
            k = 0
            while True:
                rt = top + k * hh
                rb = rt + hh - 1
                cl = jl - k
                cr = jr + k
                if rt < 0 or rb >= h or (cl < 0 and cr >= w):
                    break
                for rr in range(rt, rb + 1):
                    if 0 <= cl < w:
                        out.add((rr, cl))
                    if 0 <= cr < w:
                        out.add((rr, cr))
                k += 1
            k = 1
            while True:
                rt = top - k * hh
                rb = rt + hh - 1
                cl = jl - k
                cr = jr + k
                if rb < 0 or rt >= h or (cl < 0 and cr >= w):
                    break
                for rr in range(rt, rb + 1):
                    if 0 <= cl < w:
                        out.add((rr, cl))
                    if 0 <= cr < w:
                        out.add((rr, cr))
                k += 1
            return frozenset(out)

        t1 = trail_cells(r1, h1, j1l, j1r)
        t2 = trail_cells(r2, h2, j2l, j2r)
        inter = t1 & t2

        if len(inter) == 0 and choice((True, False)):
            continue

        gi = canvas(0, (h, w))
        gi = fill(gi, c1, connect((r1, j1l), (r1 + h1 - 1, j1l)))
        gi = fill(gi, c1, connect((r1, j1r), (r1 + h1 - 1, j1r)))
        gi = fill(gi, c2, connect((r2, j2l), (r2 + h2 - 1, j2l)))
        gi = fill(gi, c2, connect((r2, j2r), (r2 + h2 - 1, j2r)))

        go = verify_58e15b12(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    h = 24
    w = 19
    gi = canvas(0, (h, w))
    gi = fill(gi, 3, connect((6, 4), (9, 4)))
    gi = fill(gi, 3, connect((6, 8), (9, 8)))
    gi = fill(gi, 8, connect((19, 11), (19, 11)))
    gi = fill(gi, 8, connect((19, 13), (19, 13)))
    go = verify_58e15b12(gi)
    return {'input': gi, 'output': go}


