def generate_5a5a2103(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc, linc = sample(cols, 2)
    remcols = difference(cols, (bgc, linc))

    cellh = unifint(diff_lb, diff_ub, (4, 6))
    cellw = unifint(diff_lb, diff_ub, (4, 6))
    nrows = unifint(diff_lb, diff_ub, (2, max(2, min(5, 30 // (cellh + 1)))))
    ncols = unifint(diff_lb, diff_ub, (3, max(3, min(5, 30 // (cellw + 1)))))

    h = nrows * cellh + (nrows - 1)
    w = ncols * cellw + (ncols - 1)

    rowcols = sample(remcols, nrows)
    shapec = choice(difference(remcols, rowcols)) if len(difference(remcols, rowcols)) > 0 else choice(rowcols)

    gi = canvas(bgc, (h, w))

    for r in range(1, nrows):
        gi = fill(gi, linc, connect((r * cellh + (r - 1), 0), (r * cellh + (r - 1), w - 1)))
    for c in range(1, ncols):
        gi = fill(gi, linc, connect((0, c * cellw + (c - 1)), (h - 1, c * cellw + (c - 1))))

    marker_h = 2
    marker_w = 2

    max_th = max(2, cellh - 1)
    max_tw = max(2, cellw - 1)
    th = unifint(diff_lb, diff_ub, (2, max_th))
    tw = unifint(diff_lb, diff_ub, (2, max_tw))
    if th == 2 and tw == 2:
        tw = min(cellw - 1, 3) if cellw >= 3 else 2

    allcells = [(rr, cc) for rr in range(nrows) for cc in range(ncols)]
    template_cell = choice([(rr, cc) for rr in range(nrows) for cc in range(1, ncols)])

    trow0 = template_cell[0] * (cellh + 1)
    tcol0 = template_cell[1] * (cellw + 1)

    max_off_i = cellh - th
    max_off_j = cellw - tw
    offi = unifint(diff_lb, diff_ub, (0, max_off_i))
    offj = unifint(diff_lb, diff_ub, (0, max_off_j))

    template_box = asindices(canvas(0, (th, tw)))
    ncells = unifint(diff_lb, diff_ub, (max(3, (th * tw) // 2), th * tw - 1))
    cells = set(sample(totuple(template_box), ncells))

    if len(connected_components(frozenset(cells), False)) != 1:
        seed = choice(totuple(template_box))
        cells = {seed}
        target = ncells
        for _ in range(th * tw * 3):
            if len(cells) >= target:
                break
            frontier = (mapply(dneighbors, frozenset(cells)) & template_box) - frozenset(cells)
            if len(frontier) == 0:
                break
            cells.add(choice(totuple(frontier)))
        while len(cells) < target:
            frontier = (mapply(dneighbors, frozenset(cells)) & template_box) - frozenset(cells)
            if len(frontier) == 0:
                rem = template_box - frozenset(cells)
                if len(rem) == 0:
                    break
                cells.add(choice(totuple(rem)))
            else:
                cells.add(choice(totuple(frontier)))

    if len(cells) == th * tw:
        cells.remove(choice(totuple(cells)))

    if len(connected_components(frozenset(cells), False)) != 1:
        comps = list(connected_components(frozenset(cells), False))
        base = set(choice(comps))
        others = [c for c in comps if c != frozenset(base)]
        for comp in others:
            target_cell = choice(totuple(comp))
            for _ in range(th * tw * 2):
                frontier = (dneighbors(choice(totuple(base))) & template_box) - frozenset(base)
                if len(frontier) > 0:
                    base.add(choice(totuple(frontier)))
                    break
            base.add(target_cell)
        cells = base

    template_inds = shift(frozenset(cells), (trow0 + offi, tcol0 + offj))
    gi = fill(gi, shapec, template_inds)

    for rr in range(nrows):
        row0 = rr * (cellh + 1)
        marker = shift(asindices(canvas(0, (marker_h, marker_w))), (row0 + 1, 1))
        gi = fill(gi, rowcols[rr], marker)

    go = verify_5a5a2103(gi)
    return {'input': gi, 'output': go}


def generate_5a719d11(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    bandh = unifint(diff_lb, diff_ub, (5, 8))
    nbands = unifint(diff_lb, diff_ub, (2, 4))
    seps = [2 for _ in range(nbands - 1)]
    h = nbands * bandh + sum(seps)
    w = 17
    leftw = 8
    rightw = 8
    gi = canvas(0, (h, w))

    def comps_to_indices(comps, top, left):
        res = frozenset()
        for comp in comps:
            res = res | shift(comp, (top, left))
        return res

    def random_shape(ph, pw, n):
        cells = {(randint(0, ph - 1), randint(0, pw - 1))}
        target = max(1, min(n, ph * pw))
        for _ in range(target - 1):
            frontier = set()
            for c in cells:
                frontier |= set(dneighbors(c))
            opts = [(i, j) for (i, j) in frontier if 0 <= i < ph and 0 <= j < pw and (i, j) not in cells]
            if len(opts) == 0:
                rem = [(i, j) for i in range(ph) for j in range(pw) if (i, j) not in cells]
                if len(rem) == 0:
                    break
                cells.add(choice(rem))
            else:
                cells.add(choice(opts))
        return frozenset(cells)

    def make_panel(ph, pw, bgc, shapec):
        maxcells = max(3, min(ph * pw - 1, unifint(diff_lb, diff_ub, (4, max(4, min(12, ph * pw - 1))))))
        for _ in range(50):
            shp = random_shape(ph, pw, maxcells)
            if len(shp) == 0 or len(shp) >= ph * pw:
                continue
            if len(connected_components(shp, False)) != 1:
                continue
            if len(shp) >= (ph * pw) // 2:
                continue
            return fill(canvas(bgc, (ph, pw)), shapec, shp)
        shp = frozenset({(ph // 2, pw // 2)})
        return fill(canvas(bgc, (ph, pw)), shapec, shp)

    used_pairs = []
    for b in range(nbands):
        top = b * (bandh + 2)
        samebg = choice((True, False, False))
        if samebg:
            bg = choice(cols)
            lbg = bg
            rbg = bg
            rem = remove(bg, cols)
            lc, rc = sample(rem, 2)
        else:
            lbg, rbg = sample(cols, 2)
            rem = difference(cols, (lbg, rbg))
            if len(rem) >= 2:
                lc, rc = sample(rem, 2)
            else:
                lc = choice(remove(lbg, cols))
                rc = choice(remove(rbg, cols))
                if lc == rc:
                    rc = choice(remove(lc, remove(rbg, cols))) if len(remove(lc, remove(rbg, cols))) > 0 else choice(remove(rbg, cols))
        if lc == lbg:
            lc = choice(remove(lbg, cols))
        if rc == rbg:
            rc = choice(remove(rbg, cols))
        lp = make_panel(bandh, leftw, lbg, lc)
        rp = make_panel(bandh, rightw, rbg, rc)
        gi = paint(gi, recolor(lbg, shift(asindices(lp), (top, 0))))
        gi = paint(gi, recolor(rbg, shift(asindices(rp), (top, 9))))
        gi = fill(gi, lc, shift(ofcolor(lp, lc), (top, 0)))
        gi = fill(gi, rc, shift(ofcolor(rp, rc), (top, 9)))
        used_pairs.append((lbg, rbg, lc, rc))

    go = verify_5a719d11(gi)
    if gi == go:
        top = 0
        lbg, rbg, lc, rc = used_pairs[0]
        if lbg == rbg:
            alt = choice(remove(lbg, cols))
            patch = frozenset({(top + bandh // 2, 1), (top + bandh // 2, 2), (top + bandh // 2, 3)})
            gi = fill(gi, alt, patch)
            go = verify_5a719d11(gi)
    return {'input': gi, 'output': go}


def generate_5ad4f10b(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    nbh = {(0, 0), (1, 0), (0, 1), (1, 1)}
    nbhs = apply(lbind(shift, nbh), {(0, 0), (-1, 0), (0, -1), (-1, -1)})
    oh = unifint(diff_lb, diff_ub, (2, 6))
    ow = unifint(diff_lb, diff_ub, (2, 6))
    bounds = asindices(canvas(-1, (oh, ow)))
    ncellsd = unifint(diff_lb, diff_ub, (1, (oh * ow) // 2))
    ncells = choice((ncellsd, oh * ow - ncellsd))
    ncells = min(max(1, ncells), oh * ow - 1)
    obj = set(sample(totuple(bounds), ncells))
    while len(sfilter(obj, lambda ij: sum([len(obj & shift(nbh, ij)) < 4 for nbh in nbhs]) > 0)) == 0:
        ncellsd = unifint(diff_lb, diff_ub, (1, (oh * ow) // 2))
        ncells = choice((ncellsd, oh * ow - ncellsd))
        ncells = min(max(1, ncells), oh * ow)
        obj = set(sample(totuple(bounds), ncells))
    obj = normalize(obj)
    oh, ow = shape(obj)
    bgc, noisec, objc = sample(cols, 3)
    go = canvas(bgc, (oh, ow))
    go = fill(go, noisec, obj)
    fac = unifint(diff_lb, diff_ub, (2, min(28//oh, 28//ow)))
    gobj = asobject(upscale(replace(go, noisec, objc), fac))
    oh, ow = shape(gobj)
    h = unifint(diff_lb, diff_ub, (oh+2, 30))
    w = unifint(diff_lb, diff_ub, (ow+2, 30))
    loci = randint(1, h - oh-1)
    locj = randint(1, w - ow-1)
    gi = canvas(bgc, (h, w))
    gi = paint(gi, shift(gobj, (loci, locj)))
    cands = ofcolor(gi, bgc)
    namt = unifint(diff_lb, diff_ub, (2, max(1, len(cands) // 4)))
    noise = sample(totuple(cands), namt)
    gi = fill(gi, noisec, noise)
    return {'input': gi, 'output': go}


def generate_5ad8a7c0(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (4, 15))
    w = unifint(diff_lb, diff_ub, (5, 15))
    gi = canvas(0, (h, w))

    # The verifier finds x3 = max(leftmost per row), x4 = min(rightmost per row),
    # then fills rows whose red endpoints exactly equal (x3, x4).
    # Choose the innermost bracket columns (the target endpoints).
    x3 = unifint(diff_lb, diff_ub, (0, max(0, w - 4)))
    x4 = unifint(diff_lb, diff_ub, (x3 + 2, w - 1))

    # Pick rows to have red cells
    nrows = unifint(diff_lb, diff_ub, (2, min(h, 10)))
    red_rows = sorted(sample(list(range(h)), nrows))

    # At least 1 target row (endpoints at x3, x4 — will be filled by verifier)
    n_target = unifint(diff_lb, diff_ub, (1, max(1, nrows - 1)))
    target_set = set(sample(red_rows, n_target))

    for r in red_rows:
        if r in target_set:
            gi = fill(gi, 2, frozenset({(r, x3), (r, x4)}))
        else:
            # Wider bracket: leftmost < x3 or rightmost > x4 (at least one strict)
            # so this row won't match the target and won't be filled
            can_left = x3 > 0
            can_right = x4 < w - 1
            if can_left and can_right:
                mode = choice([0, 1, 2])
            elif can_left:
                mode = 0
            elif can_right:
                mode = 1
            else:
                # Can't go wider; make this a target row too
                gi = fill(gi, 2, frozenset({(r, x3), (r, x4)}))
                continue
            if mode == 0:
                lr = randint(0, x3 - 1)
                rr = x4
            elif mode == 1:
                lr = x3
                rr = randint(x4 + 1, w - 1)
            else:
                lr = randint(0, x3 - 1)
                rr = randint(x4 + 1, w - 1)
            gi = fill(gi, 2, frozenset({(r, lr), (r, rr)}))

    go = verify_5ad8a7c0(gi)
    return {'input': gi, 'output': go}


def generate_5adee1b2(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    h = 20
    w = 20
    bgc = 0

    nleg = unifint(diff_lb, diff_ub, (1, 3))
    objcols = sample(cols, nleg)
    rem = tuple(c for c in cols if c not in objcols)
    framecols = sample(rem, nleg)

    gi = canvas(bgc, (h, w))

    max_start = h - 2 * nleg
    top_pad = unifint(diff_lb, diff_ub, (0, max_start))
    legend_rows = []
    for k in range(nleg):
        r = top_pad + 2 * k
        legend_rows.append(r)
        gi = fill(gi, objcols[k], frozenset({(r, 0), (r + 1, 0)}))
        gi = fill(gi, framecols[k], frozenset({(r, 1), (r + 1, 1)}))

    reserved = set()
    for r in legend_rows:
        reserved |= {(r, 0), (r + 1, 0), (r, 1), (r + 1, 1)}

    def make_shape(ph, pw, density_lo=0.45):
        cells = {(0, 0)}
        target = max(3, unifint(diff_lb, diff_ub, (3, max(3, (ph * pw * 3) // 4))))
        target = min(target, ph * pw)
        frontier = set()
        frontier |= {(1, 0), (0, 1)}
        if ph > 1 and pw > 1:
            frontier |= {(1, 1)}
        while len(cells) < target and frontier:
            cand = choice(tuple(frontier))
            frontier.remove(cand)
            i, j = cand
            if 0 <= i < ph and 0 <= j < pw:
                cells.add(cand)
                for ni, nj in ((i - 1, j), (i + 1, j), (i, j - 1), (i, j + 1)):
                    if 0 <= ni < ph and 0 <= nj < pw and (ni, nj) not in cells:
                        frontier.add((ni, nj))
        if len(cells) < max(2, int(ph * pw * density_lo)):
            allc = [(i, j) for i in range(ph) for j in range(pw) if (i, j) not in cells]
            shuffle(allc)
            need = max(0, max(2, int(ph * pw * density_lo)) - len(cells))
            for c in allc[:need]:
                cells.add(c)
        rs = [i for i, j in cells]
        cs = [j for i, j in cells]
        mini, maxi = min(rs), max(rs)
        minj, maxj = min(cs), max(cs)
        norm = frozenset((i - mini, j - minj) for i, j in cells)
        return norm

    occupied = set(reserved)
    nobj_base = unifint(diff_lb, diff_ub, (1, 3))
    for idx in range(nleg):
        objcol = objcols[idx]
        nobj = max(1, nobj_base + choice((0, 1)))
        placed = 0
        for _ in range(200):
            if placed >= nobj:
                break
            ph = unifint(diff_lb, diff_ub, (3, 6))
            pw = unifint(diff_lb, diff_ub, (3, 6))
            shape = make_shape(ph, pw)
            sh = height(shape)
            sw = width(shape)
            if sh > h - 2 or sw > w - 3:
                continue
            loci = randint(1, h - sh - 1)
            locj = randint(2, w - sw - 1)
            placed_shape = shift(shape, (loci, locj))
            bbox = backdrop(placed_shape)
            obox = outbox(placed_shape)
            if any((i, j) in occupied for i, j in bbox | obox):
                continue
            gi = fill(gi, objcol, placed_shape)
            occupied |= set(bbox) | set(obox)
            placed += 1

        if placed == 0:
            ph = 3
            pw = 3
            shape = frozenset({(0, 1), (1, 0), (1, 1), (1, 2), (2, 1)})
            for loci in range(1, h - ph):
                done = False
                for locj in range(2, w - pw):
                    placed_shape = shift(shape, (loci, locj))
                    bbox = backdrop(placed_shape)
                    obox = outbox(placed_shape)
                    if not any((i, j) in occupied for i, j in bbox | obox):
                        gi = fill(gi, objcol, placed_shape)
                        occupied |= set(bbox) | set(obox)
                        done = True
                        break
                if done:
                    break

    go = verify_5adee1b2(gi)
    return {'input': gi, 'output': go}


def generate_5af49b42(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (10, 20))
    w = unifint(diff_lb, diff_ub, (10, 20))
    gi = canvas(0, (h, w))

    use_top = choice((True, False))
    use_bottom = choice((True, False))
    if not use_top and not use_bottom:
        use_bottom = True

    maxlen = min(7, w)
    minlen = 3
    n_top = 0
    n_bottom = 0
    if use_top:
        n_top = choice((1, 2))
    if use_bottom:
        n_bottom = choice((1, 2))

    def make_segments(nseg):
        if nseg == 1:
            ln = unifint(diff_lb, diff_ub, (minlen, maxlen))
            start = randint(0, w - ln)
            return [(start, ln)]
        ln1 = unifint(diff_lb, diff_ub, (minlen, min(maxlen, w - minlen - 1)))
        ln2 = unifint(diff_lb, diff_ub, (minlen, min(maxlen, w - ln1 - 1)))
        if ln1 + ln2 + 1 > w:
            ln2 = max(minlen, w - ln1 - 1)
            if ln1 + ln2 + 1 > w:
                ln1 = max(minlen, w - ln2 - 1)
        starts = []
        for _ in range(100):
            s1 = randint(0, w - ln1)
            s2 = randint(0, w - ln2)
            e1 = s1 + ln1 - 1
            e2 = s2 + ln2 - 1
            if e1 < s2 - 1 or e2 < s1 - 1:
                starts = [(s1, ln1), (s2, ln2)]
                break
        if len(starts) == 0:
            s1 = 0
            s2 = w - ln2
            if s1 + ln1 < s2:
                starts = [(s1, ln1), (s2, ln2)]
            else:
                ln1 = min(maxlen, max(minlen, w // 2 - 1))
                ln2 = min(maxlen, max(minlen, w - ln1 - 1))
                starts = [(0, ln1), (w - ln2, ln2)]
        starts = sorted(starts)
        return starts

    top_segs = make_segments(n_top) if use_top else []
    bottom_segs = make_segments(n_bottom) if use_bottom else []

    used_colors = set()
    templates = []

    def add_row_templates(rowi, segs):
        nonlocal gi, used_colors, templates
        for st, ln in segs:
            avail = [c for c in cols if c not in used_colors]
            if len(avail) < ln:
                avail = list(cols)
            seq = sample(avail, ln)
            used_colors |= set(seq)
            templates.append((rowi, st, tuple(seq)))
            inds = frozenset((rowi, st + k) for k in range(ln))
            for k, c in enumerate(seq):
                gi = fill(gi, c, frozenset({(rowi, st + k)}))

    if use_top:
        add_row_templates(0, top_segs)
    if use_bottom:
        add_row_templates(h - 1, bottom_segs)

    color_to_seq = {}
    for _, _, seq in templates:
        for c in seq:
            color_to_seq[c] = seq

    all_template_colors = list(color_to_seq.keys())
    max_isolated = min(len(all_template_colors), unifint(diff_lb, diff_ub, (2, 6)))
    n_iso = max_isolated

    interior_rows = list(range(1, h - 1))
    interior_cols = list(range(w))
    occupied = set()
    for r, st, seq in templates:
        for k in range(len(seq)):
            occupied.add((r, st + k))

    placed = []
    candidate_cells = [(i, j) for i in interior_rows for j in interior_cols]
    shuffle(candidate_cells)
    shuffle(all_template_colors)

    for col in all_template_colors:
        if len(placed) >= n_iso:
            break
        seq = color_to_seq[col]
        idx = seq.index(col)
        okspots = []
        for i, j in candidate_cells:
            if (i, j) in occupied:
                continue
            if (i, j - 1) in occupied or (i, j + 1) in occupied:
                continue
            okspots.append((i, j))
        if len(okspots) == 0:
            break
        i, j = choice(okspots)
        gi = fill(gi, col, frozenset({(i, j)}))
        occupied.add((i, j))
        placed.append((i, j, col))

    if len(placed) == 0:
        seq = templates[0][2]
        col = seq[0]
        i = 1
        j = 0
        gi = fill(gi, col, frozenset({(i, j)}))

    go = verify_5af49b42(gi)
    return {'input': gi, 'output': go}


def generate_5b37cb25(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = 30
    w = 30

    cornerc = choice(cols)
    rem = remove(cornerc, cols)
    topc, botc, leftc, rightc, bgc, objc = sample(rem, 6)

    gi = canvas(bgc, (h, w))

    gi = fill(gi, topc, connect((0, 1), (0, w - 2)))
    gi = fill(gi, botc, connect((h - 1, 1), (h - 1, w - 2)))
    gi = fill(gi, leftc, connect((1, 0), (h - 2, 0)))
    gi = fill(gi, rightc, connect((1, w - 1), (h - 2, w - 1)))
    gi = fill(gi, cornerc, frozenset({(0, 0), (0, w - 1), (h - 1, 0), (h - 1, w - 1)}))

    interior_top = 1
    interior_left = 1
    ih = h - 2
    iw = w - 2

    max_notches = max(4, unifint(diff_lb, diff_ub, (4, 12)))
    dirs = ['U', 'D', 'L', 'R']
    shuffle(dirs)

    used_centers = set()
    notch_specs = []

    def cross_cells(c):
        i, j = c
        return {(i, j), (i - 1, j), (i + 1, j), (i, j - 1), (i, j + 1)}

    def notch_cells(c, d):
        i, j = c
        if d == 'U':
            return {(i, j), (i + 1, j), (i, j - 1), (i, j + 1)}
        if d == 'D':
            return {(i, j), (i - 1, j), (i, j - 1), (i, j + 1)}
        if d == 'L':
            return {(i, j), (i - 1, j), (i + 1, j), (i, j + 1)}
        return {(i, j), (i - 1, j), (i + 1, j), (i, j - 1)}

    for d in dirs:
        if len(notch_specs) >= max_notches:
            break
        for _ in range(100):
            i = unifint(diff_lb, diff_ub, (3, h - 4))
            j = unifint(diff_lb, diff_ub, (3, w - 4))
            c = (i, j)
            cc = cross_cells(c)
            ok = True
            for u in used_centers:
                if cc & cross_cells(u):
                    ok = False
                    break
            if ok:
                notch_specs.append((c, d))
                used_centers.add(c)
                break

    extra_target = max(0, max_notches - len(notch_specs))
    for _ in range(extra_target):
        d = choice(dirs)
        placed = False
        for _ in range(100):
            i = unifint(diff_lb, diff_ub, (3, h - 4))
            j = unifint(diff_lb, diff_ub, (3, w - 4))
            c = (i, j)
            cc = cross_cells(c)
            ok = True
            for u in used_centers:
                if cc & cross_cells(u):
                    ok = False
                    break
            if ok:
                notch_specs.append((c, d))
                used_centers.add(c)
                placed = True
                break
        if not placed:
            break

    objcells = set()
    for c, d in notch_specs:
        objcells |= notch_cells(c, d)

    nrects = unifint(diff_lb, diff_ub, (2, 6))
    for _ in range(nrects):
        rh = unifint(diff_lb, diff_ub, (3, 10))
        rw = unifint(diff_lb, diff_ub, (3, 10))
        r0 = unifint(diff_lb, diff_ub, (2, h - rh - 3))
        c0 = unifint(diff_lb, diff_ub, (2, w - rw - 3))
        objcells |= connect((r0, c0), (r0 + rh - 1, c0 + rw - 1))

    for _ in range(unifint(diff_lb, diff_ub, (10, 40))):
        if len(objcells) == 0:
            break
        cell = choice(tuple(objcells))
        for nb in dneighbors(cell):
            ii, jj = nb
            if 1 <= ii <= h - 2 and 1 <= jj <= w - 2:
                objcells.add(nb)

    for c, d in notch_specs:
        nc = notch_cells(c, d)
        objcells |= nc
        if d == 'U':
            objcells.discard((c[0] - 1, c[1]))
        elif d == 'D':
            objcells.discard((c[0] + 1, c[1]))
        elif d == 'L':
            objcells.discard((c[0], c[1] - 1))
        else:
            objcells.discard((c[0], c[1] + 1))
        objcells.discard(c)

    gi = fill(gi, objc, frozenset(objcells))

    go = verify_5b37cb25(gi)
    return {'input': gi, 'output': go}


def generate_5b526a93(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))

    max_nr = max(2, (h - 3) // 4 + 1)
    max_nc = max(2, (w - 3) // 4 + 1)
    nr = unifint(diff_lb, diff_ub, (2, max_nr))
    nc = unifint(diff_lb, diff_ub, (2, max_nc))

    row_gap_max = max(1, (h - 3) // (nr - 1) - 3)
    col_gap_max = max(1, (w - 3) // (nc - 1) - 3)
    rgap = unifint(diff_lb, diff_ub, (1, row_gap_max))
    cgap = unifint(diff_lb, diff_ub, (1, col_gap_max))

    total_h = 3 + (nr - 1) * (3 + rgap)
    total_w = 3 + (nc - 1) * (3 + cgap)

    top = unifint(diff_lb, diff_ub, (0, h - total_h))
    left = unifint(diff_lb, diff_ub, (0, w - total_w))

    rows = tuple(top + k * (3 + rgap) for k in range(nr))
    cols = tuple(left + k * (3 + cgap) for k in range(nc))

    all_positions = [(r, c) for r in rows for c in cols]
    nall = len(all_positions)
    npresent = unifint(diff_lb, diff_ub, (2, nall - 1))
    present = sample(all_positions, npresent)

    gi = canvas(0, (h, w))
    ring = box(asindices(canvas(-1, (3, 3))))

    for loc in present:
        gi = fill(gi, 1, shift(ring, loc))

    go = verify_5b526a93(gi)
    return {'input': gi, 'output': go}


def generate_5b692c0f(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    objcols = remove(FOUR, remove(bgc, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (12, 24))
    w = unifint(diff_lb, diff_ub, (12, 24))
    gi = canvas(bgc, (h, w))

    nobjmax = 3
    nobj = unifint(diff_lb, diff_ub, (1, nobjmax))
    occupied = set()

    def inb(cells):
        return all(0 <= i < h and 0 <= j < w for i, j in cells)

    def disjoint(cells):
        for i, j in cells:
            if (i, j) in occupied:
                return False
        return True

    def add_cells(cells):
        for ij in cells:
            occupied.add(ij)

    made = 0
    tries = 0
    maxtries = 300

    while made < nobj and tries < maxtries:
        tries += 1
        orient = choice(("v", "h"))
        col = choice(objcols)

        if orient == "v":
            axis_len = unifint(diff_lb, diff_ub, (4, 8))
            half_w = unifint(diff_lb, diff_ub, (2, 5))
            top = randint(1, max(1, h - axis_len - 1))
            axis_j = randint(half_w, w - half_w - 1)
            axis_is = sample(interval(top, top + axis_len, 1), randint(max(2, axis_len // 2), axis_len))
            axis = frozenset((i, axis_j) for i in axis_is)

            side_full = choice(("L", "R"))
            fuller = set()
            sparser = set()
            for i in range(top, top + axis_len):
                for d in range(1, half_w + 1):
                    if choice((True, False)):
                        if side_full == "L":
                            fuller.add((i, axis_j - d))
                        else:
                            fuller.add((i, axis_j + d))
                    if randint(0, 99) < 35:
                        if side_full == "L":
                            sparser.add((i, axis_j + d))
                        else:
                            sparser.add((i, axis_j - d))

            if len(fuller) == 0:
                i = choice(interval(top, top + axis_len, 1))
                d = randint(1, half_w)
                if side_full == "L":
                    fuller.add((i, axis_j - d))
                else:
                    fuller.add((i, axis_j + d))

            cells = axis | fuller | sparser
            if not inb(cells):
                continue
            if not disjoint(cells):
                continue

            gi = fill(gi, FOUR, axis)
            gi = fill(gi, col, fuller | sparser)
            add_cells(cells)
            made += 1

        else:
            axis_len = unifint(diff_lb, diff_ub, (4, 8))
            half_h = unifint(diff_lb, diff_ub, (2, 5))
            left = randint(1, max(1, w - axis_len - 1))
            axis_i = randint(half_h, h - half_h - 1)
            axis_js = sample(interval(left, left + axis_len, 1), randint(max(2, axis_len // 2), axis_len))
            axis = frozenset((axis_i, j) for j in axis_js)

            side_full = choice(("U", "D"))
            fuller = set()
            sparser = set()
            for j in range(left, left + axis_len):
                for d in range(1, half_h + 1):
                    if choice((True, False)):
                        if side_full == "U":
                            fuller.add((axis_i - d, j))
                        else:
                            fuller.add((axis_i + d, j))
                    if randint(0, 99) < 35:
                        if side_full == "U":
                            sparser.add((axis_i + d, j))
                        else:
                            sparser.add((axis_i - d, j))

            if len(fuller) == 0:
                j = choice(interval(left, left + axis_len, 1))
                d = randint(1, half_h)
                if side_full == "U":
                    fuller.add((axis_i - d, j))
                else:
                    fuller.add((axis_i + d, j))

            cells = axis | fuller | sparser
            if not inb(cells):
                continue
            if not disjoint(cells):
                continue

            gi = fill(gi, FOUR, axis)
            gi = fill(gi, col, fuller | sparser)
            add_cells(cells)
            made += 1

    if made == 0:
        axis_i = h // 2
        left = max(1, w // 2 - 2)
        axis = frozenset((axis_i, j) for j in range(left, left + 5))
        fuller = frozenset((axis_i - 1, j) for j in range(left, left + 5))
        gi = fill(gi, FOUR, axis)
        gi = fill(gi, 1, fuller)

    go = verify_5b692c0f(gi)
    return {'input': gi, 'output': go}


