def generate_5ecac7f7(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(7, remove(6, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (3, 7))
    pw = unifint(diff_lb, diff_ub, (3, 9))
    w = 3 * pw + 2

    def grow_shape(h, pw, cells_init, forbidden):
        maxcells = max(1, unifint(diff_lb, diff_ub, (1, max(1, h * pw // 3))))
        cells = set(cells_init)
        frontier = set(cells)
        for _ in range(maxcells - len(cells)):
            nbrs = set()
            for c in frontier:
                for n in neighbors(c):
                    nbrs.add(n)
            cands = [(i, j) for (i, j) in nbrs if 0 <= i < h and 0 <= j < pw and (i, j) not in cells and (i, j) not in forbidden]
            if len(cands) == 0:
                break
            nc = choice(cands)
            cells.add(nc)
            frontier.add(nc)
        return frozenset(cells)

    def make_panel(h, pw):
        # Need 3 objects with distinct column centers
        # Place 3 anchor cells in different column regions
        if pw < 3:
            col_positions = sample(list(range(pw)), min(3, pw))
            while len(col_positions) < 3:
                col_positions.append(randint(0, pw - 1))
        else:
            # Divide columns into 3 regions to ensure distinct center columns
            third = pw / 3.0
            c0 = randint(0, max(0, int(third) - 1))
            c1 = randint(int(third), max(int(third), int(2 * third) - 1))
            c2 = randint(int(2 * third), pw - 1)
            col_positions = [c0, c1, c2]

        row_positions = [randint(0, h - 1) for _ in range(3)]
        color_list = sample(list(cols), 3)

        all_cells = set()
        obj_cells_list = []
        for k in range(3):
            anchor = (row_positions[k], col_positions[k])
            if anchor in all_cells:
                # Find alternative anchor nearby
                found = False
                for di in range(h):
                    for dj in range(pw):
                        for ri, rj in [(row_positions[k] + di, col_positions[k] + dj),
                                       (row_positions[k] - di, col_positions[k] + dj),
                                       (row_positions[k] + di, col_positions[k] - dj),
                                       (row_positions[k] - di, col_positions[k] - dj)]:
                            if 0 <= ri < h and 0 <= rj < pw and (ri, rj) not in all_cells:
                                anchor = (ri, rj)
                                found = True
                                break
                        if found:
                            break
                    if found:
                        break
            shape = grow_shape(h, pw, {anchor}, all_cells)
            obj_cells_list.append(shape)
            all_cells |= set(shape)

        panel = canvas(7, (h, pw))
        for k in range(3):
            panel = fill(panel, color_list[k], obj_cells_list[k])
        return panel

    for _ in range(100):
        left_panel = make_panel(h, pw)
        mid_panel = make_panel(h, pw)
        right_panel = make_panel(h, pw)
        bar = canvas(6, (h, 1))
        gi = hconcat(hconcat(hconcat(left_panel, bar), mid_panel), hconcat(bar, right_panel))
        try:
            go = verify_5ecac7f7(gi)
            if gi != go:
                return {'input': gi, 'output': go}
        except:
            continue
    # fallback
    go = verify_5ecac7f7(gi)
    return {'input': gi, 'output': go}


def generate_5ffb2104(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (5, 14))
    w = unifint(diff_lb, diff_ub, (6, 18))
