def generate_6350f1f4(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, remove(5, interval(0, 10, 1)))
    maj, minor = sample(cols, 2)

    th = unifint(diff_lb, diff_ub, (2, 4))
    tw = unifint(diff_lb, diff_ub, (2, 4))
    nr = unifint(diff_lb, diff_ub, (2, 4))
    nc = unifint(diff_lb, diff_ub, (2, 4))

    h = nr * th + (nr - 1)
    w = nc * tw + (nc - 1)

    gi = canvas(0, (h, w))

    # choose reference pattern: exactly two colors, no 5, majority/minority
    area = th * tw
    maxminor = max(1, area // 2 - 1)
    nminor = unifint(diff_lb, diff_ub, (1, maxminor))
    allcells = totuple(asindices(canvas(0, (th, tw))))
    minor_cells = frozenset(sample(allcells, nminor))
    ref = fill(canvas(maj, (th, tw)), minor, minor_cells)

    rr = randint(0, nr - 1)
    rc = randint(0, nc - 1)

    for tr in range(nr):
        for tc in range(nc):
            r0 = tr * (th + 1)
            c0 = tc * (tw + 1)

            if tr == rr and tc == rc:
                block = ref
            else:
                kind = choice(("maj", "minor", "mixed5", "mixed5", "mixed5"))
                if kind == "maj":
                    block = canvas(maj, (th, tw))
                elif kind == "minor":
                    block = canvas(minor, (th, tw))
                else:
                    block = canvas(maj, (th, tw))
                    n5 = randint(1, max(1, area - 1))
                    five_cells = sample(allcells, n5)
                    block = fill(block, 5, frozenset(five_cells))
                    if randint(0, 1) == 1:
                        rem = [ij for ij in allcells if ij not in five_cells]
                        if len(rem) > 0:
                            nm = randint(1, len(rem))
                            block = fill(block, minor, frozenset(sample(rem, nm)))

            obj = shift(asobject(block), (r0, c0))
            gi = paint(gi, obj)

    # separator rows/cols made only of 0s and 5s, with some 5 noise
    for sr in range(th, h, th + 1):
        if randint(0, 1) == 1:
            gi = fill(gi, 5, frozenset({(sr, j) for j in range(w) if randint(0, 3) == 0}))
    for sc in range(tw, w, tw + 1):
        if randint(0, 1) == 1:
            gi = fill(gi, 5, frozenset({(i, sc) for i in range(h) if randint(0, 3) == 0}))

    go = verify_6350f1f4(gi)
    return {'input': gi, 'output': go}


def generate_63613498(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc, sepc = sample(cols, 2)
    remcols = remove(bgc, remove(sepc, cols))
    ncols = unifint(diff_lb, diff_ub, (1, 8))
    ccols = sample(remcols, ncols)
    objh = unifint(diff_lb, diff_ub, (1, h//3))
    objw = unifint(diff_lb, diff_ub, (1, w//3))
    bounds = asindices(canvas(-1, (objh, objw)))
    sp = choice(totuple(bounds))
    obj = {sp}
    ncells = unifint(diff_lb, diff_ub, (1, (objh * objw)))
    for k in range(ncells - 1):
        obj.add(choice(totuple((bounds - obj) & mapply(dneighbors, obj))))
    gi = canvas(bgc, (h, w))
    objc = choice(ccols)
    gi = fill(gi, objc, obj)
    sep = connect((objh+1, 0), (objh+1, objw+1)) | connect((0, objw+1), (objh+1, objw+1))
    gi = fill(gi, sepc, sep)
    inds = asindices(gi)
    inds -= backdrop(sep)
    nobjs = unifint(diff_lb, diff_ub, (1, (h * w) // 20))
    succ = 0
    tr = 0
    maxtr = 5 * nobjs
    baseobj = normalize(obj)
    obj = normalize(obj)
    go = tuple(e for e in gi)
    while (succ < nobjs and tr < maxtr) or succ == 0:
        tr += 1
        oh, ow = shape(obj)
        cands = sfilter(inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
        if len(cands) == 0:
            break
        loc = choice(totuple(cands))
        plcd = shift(obj, loc)
        if plcd.issubset(inds):
            col = choice(ccols)
            gi = fill(gi, col, plcd)
            go = fill(go, sepc if succ == 0 else col, plcd)
            succ += 1
            inds = (inds - plcd) - mapply(dneighbors, plcd)
        objh = randint(1, h // 3)
        objw = randint(2 if objh == 1 else 1, w // 3)
        if choice((True, False)):
            objh, objw = objw, objh
        bounds = asindices(canvas(-1, (objh, objw)))
        sp = choice(totuple(bounds))
        obj = {sp}
        ncells = unifint(diff_lb, diff_ub, (1, (objh * objw)))
        for k in range(ncells - 1):
            obj.add(choice(totuple((bounds - obj) & mapply(dneighbors, obj))))
        obj = normalize(obj)
        obj = set(obj)
        if obj == baseobj:
            if len(obj) < objh * objw:
                obj.add(choice(totuple((bounds - obj) & mapply(dneighbors, obj))))
            else:
                obj = remove(choice(totuple(corners(obj))), obj)
        obj = normalize(obj)
    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = rotf(go)
    return {'input': gi, 'output': go}


def generate_639f5a19(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    h = unifint(diff_lb, diff_ub, (14, 30))
