def generate_66f2d22f(diff_lb: float, diff_ub: float) -> dict:
    h, w = 4, 7
    nzero = unifint(diff_lb, diff_ub, (1, h * w - 1))
    allcells = totuple(asindices(canvas(0, (h, w))))
    overlap = frozenset(sample(allcells, nzero))
    left = canvas(choice((2, 3)), (h, w))
    right = canvas(choice((2, 3)), (h, w))
    left = fill(left, 0, overlap)
    right = fill(right, 0, overlap)

    rem = tuple(ij for ij in allcells if ij not in overlap)
    extra_left_n = unifint(diff_lb, diff_ub, (0, len(rem)))
    extra_right_n = unifint(diff_lb, diff_ub, (0, len(rem)))
    extra_left = frozenset(sample(rem, extra_left_n)) if extra_left_n > 0 else frozenset()
    extra_right = frozenset(sample(rem, extra_right_n)) if extra_right_n > 0 else frozenset()

    left = fill(left, 0, extra_left)
    right = fill(right, 0, extra_right)

    if intersection(extra_left, extra_right):
        only_left = difference(extra_left, extra_right)
        if len(only_left) > 0:
            right = fill(right, choice((2, 3)), intersection(extra_left, extra_right))
        else:
            only_right = difference(extra_right, extra_left)
            if len(only_right) > 0:
                left = fill(left, choice((2, 3)), intersection(extra_left, extra_right))

    if left == right:
        candidates = tuple(ij for ij in rem if ij not in overlap)
        if len(candidates) > 0:
            ij = choice(candidates)
            if left[ij[0]][ij[1]] == 0:
                left = fill(left, choice((2, 3)), initset(ij))
            else:
                left = fill(left, 0, initset(ij))

    gi = hconcat(left, right)
    go = verify_66f2d22f(gi)
    return {'input': gi, 'output': go}


