    remcols = remove(floorc, cols)

    ngaps = unifint(diff_lb, diff_ub, (1, max(1, w // 3)))
    maxgaplen = max(1, w - (ngaps + 1))
    gaplens = []
    remw = w
    for k in range(ngaps):
        left = ngaps - k - 1
        hi = min(maxgaplen, remw - (left + 1))
        lo = 1
        gl = unifint(diff_lb, diff_ub, (lo, hi))
        gaplens.append(gl)
        remw -= gl
    floorlens = []
    for k in range(ngaps + 1):
        left = ngaps - k
        hi = remw - left
        lo = 1
        fl = unifint(diff_lb, diff_ub, (lo, hi))
        floorlens.append(fl)
        remw -= fl

    row_above = []
    gaps = []
    j = 0
    for k in range(ngaps):
        fl = floorlens[k]
        row_above += [floorc] * fl
        j += fl
        gl = gaplens[k]
        gaps.append((j, gl))
        row_above += [0] * gl
        j += gl
    row_above += [floorc] * floorlens[-1]

    gi = canvas(0, (h, w))
    gi = fill(gi, floorc, connect((h - 1, 0), (h - 1, w - 1)))
    floor_above_inds = frozenset((h - 2, jj) for jj, v in enumerate(row_above) if v == floorc)
    gi = fill(gi, floorc, floor_above_inds)

    gaps_sorted = tuple(sorted(gaps, key=lambda x: x[1]))
    nuse = len(gaps_sorted)
    shape_colors = sample(remcols, nuse)

    occupied = set()
    topmax = max(0, h - 3)
    for idx, (start, glen) in enumerate(gaps_sorted):
        area = unifint(diff_lb, diff_ub, (1, max(1, glen * topmax)))
        fullrows = area // glen
        rem = area % glen
        cells = []
        for rr in range(fullrows):
            for cc in range(glen):
                cells.append((rr, cc))
        if rem > 0:
            for cc in range(rem):
                cells.append((fullrows, cc))
        shp_h = 0 if len(cells) == 0 else max(i for i, j2 in cells) + 1
        if shp_h == 0:
            shp_h = 1
            cells = [(0, 0)]
        maxr = h - 3 - shp_h
        if maxr < 0:
            maxr = 0

        placed = False
        for _ in range(100):
            r0 = unifint(diff_lb, diff_ub, (0, maxr))
            c0 = unifint(diff_lb, diff_ub, (0, max(0, w - glen)))
            inds = frozenset((r0 + a, c0 + b) for a, b in cells)
            if all((i, j2) not in occupied for i, j2 in inds):
                occupied |= set(inds)
                gi = fill(gi, shape_colors[idx], inds)
                placed = True
                break
        if not placed:
            c0 = start
            r0 = 0
            inds = frozenset((r0 + a, c0 + b) for a, b in cells if r0 + a < h - 2 and c0 + b < w)
            occupied |= set(inds)
            gi = fill(gi, shape_colors[idx], inds)

    go = verify_67c52801(gi)
    return {'input': gi, 'output': go}


