    c1 = (2, 2)
    c2 = (12, 12)
    o1 = (1, 2)
    o2 = (12, 13)
    gi = fill(gi, 2, difference(dneighbors(c1), initset(o1)))
    gi = fill(gi, 2, difference(dneighbors(c2), initset(o2)))
    gi = fill(gi, 5, initset(c1))
    gi = fill(gi, 5, initset(c2))
    go = verify_692cd3b6(gi)
