def generate_6df30ad6(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(5, remove(0, interval(0, 10, 1)))
    h = 10
    w = 10

    for _ in range(100):
        gi = canvas(0, (h, w))

        # build a single connected 5-shape, typically compact and central
        sh = unifint(diff_lb, diff_ub, (1, 5))
        sw = unifint(diff_lb, diff_ub, (1, 5))
        area = sh * sw
        n5 = unifint(diff_lb, diff_ub, (max(1, area // 2), area))
        top = randint(1, h - sh - 1)
        left = randint(1, w - sw - 1)

        cells = set()
        allbox = [(i, j) for i in range(sh) for j in range(sw)]
        start = choice(allbox)
        cells.add(start)
        frontier = set([start])
        while len(cells) < n5:
            cands = set()
            for p in frontier:
                cands |= (dneighbors(p) & frozenset(allbox))
            cands -= cells
            if len(cands) == 0:
                break
            nxt = choice(tuple(cands))
            cells.add(nxt)
            frontier.add(nxt)
        if len(cells) == 0:
            continue
        five_inds = shift(frozenset(cells), (top, left))
        gi = fill(gi, 5, five_inds)

        # choose distractor colors and counts
        ncols = unifint(diff_lb, diff_ub, (2, 4))
        dcols = sample(cols, ncols)
        counts = {}
        for c in dcols:
            counts[c] = unifint(diff_lb, diff_ub, (1, 4))

        # choose winner color with smallest count among tied nearest candidates
        winner = choice(dcols)
        mincnt = counts[winner]
        for c in dcols:
            if counts[c] < mincnt:
                winner = c
                mincnt = counts[c]

        # place one guaranteed nearest winner cell adjacent-ish to 5-shape
        neigh = set()
        for ij in five_inds:
            neigh |= dneighbors(ij)
        neigh = [ij for ij in neigh if 0 <= ij[0] < h and 0 <= ij[1] < w and ij not in five_inds]
        if len(neigh) == 0:
            continue
        winloc = choice(neigh)
        gi = fill(gi, winner, frozenset({winloc}))
        counts[winner] -= 1

        occupied = set(toindices(five_inds)) | {winloc}

        # place all other colors at distance >=2 from 5-shape
        farcells = []
        for i in range(h):
            for j in range(w):
                if (i, j) in occupied:
                    continue
                if manhattan(frozenset({(i, j)}), five_inds) >= 2:
                    farcells.append((i, j))
        shuffle(farcells)

        need = sum(max(0, v) for v in counts.values())
        if len(farcells) < need:
            continue

        idx = 0
        for c in dcols:
            for _k in range(max(0, counts[c])):
                loc = farcells[idx]
                idx += 1
                gi = fill(gi, c, frozenset({loc}))
                occupied.add(loc)

        # ensure winner is uniquely optimal under verifier score 100*dist + colorcount
        objs = objects(gi, True, False, True)
        fives = colorfilter(objs, 5)
        if len(fives) != 1:
            continue
        fiveobj = first(totuple(fives))
        others = difference(objs, fives)
        if len(others) == 0:
            continue

        def score(o):
            return 100 * manhattan(o, fiveobj) + colorcount(gi, color(o))

        best = argmin(others, score)
        if color(best) != winner:
            continue

        go = verify_6df30ad6(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    # fallback
    gi = canvas(0, (10, 10))
    five_inds = frozenset({(4, 3), (4, 4), (4, 5), (4, 6)})
    gi = fill(gi, 5, five_inds)
    gi = fill(gi, 6, frozenset({(2, 3), (6, 3), (8, 9)}))
    gi = fill(gi, 4, frozenset({(0, 1), (0, 8), (7, 1)}))
    gi = fill(gi, 3, frozenset({(1, 6), (3, 9), (5, 0), (8, 5), (9, 1)}))
    go = verify_6df30ad6(gi)
    return {'input': gi, 'output': go}


