def generate_6ecd11f4(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (2, 7))
    w = unifint(diff_lb, diff_ub, (2, 7))
    bgc, fgc = sample(cols, 2)
    remcols = remove(bgc, cols)
    ncols = unifint(diff_lb, diff_ub, (2, 9))
    ccols = sample(remcols, ncols)
    inds = asindices(canvas(bgc, (h, w)))
    nlocsd = unifint(diff_lb, diff_ub, (0, (h * w) // 2))
    nlocs = choice((nlocsd, h * w - nlocsd))
    nlocs = min(max(3, nlocs), h * w - 1)
    sp = choice(totuple(inds))
    inds = remove(sp, inds)
    shp = {sp}
    for j in range(nlocs):
        ij = choice(totuple((inds - shp) & mapply(neighbors, shp)))
        shp.add(ij)
    shp = normalize(shp)
    h, w = shape(shp)
    canv = canvas(bgc, (h, w))
    objbase = fill(canv, fgc, shp)
    maxhscf = (2*h+h+1) // h
    maxwscf = (2*w+w+1) // w
    hscf = unifint(diff_lb, diff_ub, (2, maxhscf))
    wscf = unifint(diff_lb, diff_ub, (2, maxwscf))
    obj = asobject(hupscale(vupscale(objbase, hscf), wscf))
    oh, ow = shape(obj)
    inds = asindices(canv)
    objx = {(choice(ccols), ij) for ij in inds}
    if len(palette(objx)) == 1:
        objxodo = first(objx)
        objx = insert((choice(remove(objxodo[0], ccols)), objxodo[1]), remove(objxodo, objx))
    fullh = unifint(diff_lb, diff_ub, (hscf*h+h+1, 30))
    fullw = unifint(diff_lb, diff_ub, (wscf*w+w+1, 30))
    gi = canvas(bgc, (fullh, fullw))
    fullinds = asindices(gi)
    while True:
        loci = randint(0, fullh - oh)
        locj = randint(0, fullw - ow)
        loc = (loci, locj)
        gix = paint(gi, shift(obj, loc))
        ofc = ofcolor(gix, fgc)
        delt = (fullinds - ofc)
        delt2 = delt - mapply(neighbors, ofc)
        scands = sfilter(
            delt2,
            lambda ij: ij[0] <= fullh - oh and ij[1] <= fullw - ow
        )
        if len(scands) == 0:
            continue
        locc = choice(totuple(scands))
        shftd = shift(objx, locc)
        if toindices(shftd).issubset(delt2):
            gi = paint(gix, shftd)
            break
    go = paint(canv, objx)
    go = fill(go, bgc, ofcolor(objbase, bgc))
    return {'input': gi, 'output': go}


def generate_6f473927(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (3, 12))
    w = unifint(diff_lb, diff_ub, (3, 10))

    gi = canvas(0, (h, w))

    touch_left = choice((True, False))

    max_cells = max(1, min(h * w - 1, unifint(diff_lb, diff_ub, (3, max(3, h * w - 1)))))
    start_r = unifint(diff_lb, diff_ub, (0, h - 1))
    start_c = 0 if touch_left else unifint(diff_lb, diff_ub, (1, w - 1))

    red = {(start_r, start_c)}
    frontier = {(start_r, start_c)}

    target = max_cells
    for _ in range(target * 4 + 20):
        if len(red) >= target:
            break
        if len(frontier) == 0:
            frontier = set(red)
        cell = choice(tuple(frontier))
        nbs = []
        for nb in dneighbors(cell):
            a, b = nb
            if 0 <= a < h and 0 <= b < w and (a, b) not in red:
                nbs.append((a, b))
        if len(nbs) == 0:
            frontier.discard(cell)
            continue
        nb = choice(tuple(nbs))
        red.add(nb)
        frontier.add(nb)

    if not touch_left:
        cols = [j for _, j in red]
        if min(cols) == 0:
            shifted = set()
            for a, b in red:
                if b + 1 < w:
                    shifted.add((a, b + 1))
                else:
                    shifted.add((a, b))
            red = shifted
            cols = [j for _, j in red]
            if min(cols) == 0:
                dj = 1 - min(cols)
                if max(cols) + dj < w:
                    red = {(a, b + dj) for a, b in red}

    for ij in red:
        gi = fill(gi, 2, frozenset({ij}))

    go = verify_6f473927(gi)
    return {'input': gi, 'output': go}


