def generate_73ccf9c2(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    bgc = 0
    fgc = choice(cols)

    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (18, 30))
    gi = canvas(bgc, (h, w))

    nobj = unifint(diff_lb, diff_ub, (3, 6))

    def rand_sym_shape():
        hh = unifint(diff_lb, diff_ub, (3, 7))
        halfw = unifint(diff_lb, diff_ub, (1, 3))
        oddflag = choice((0, 1))
        ww = 2 * halfw + oddflag
        cells = set()
        for i in range(hh):
            if oddflag == 1:
                center = halfw
                if choice((True, False)):
                    cells.add((i, center))
                for j in range(halfw):
                    if choice((True, False)):
                        cells.add((i, j))
                        cells.add((i, ww - 1 - j))
            else:
                for j in range(halfw):
                    if choice((True, False)):
                        cells.add((i, j))
                        cells.add((i, ww - 1 - j))
        if len(cells) == 0:
            i = randint(0, hh - 1)
            if oddflag == 1:
                cells.add((i, halfw))
            else:
                j = randint(0, halfw - 1)
                cells.add((i, j))
                cells.add((i, ww - 1 - j))
        return frozenset(cells)

    def rand_nonsym_shape():
        hh = unifint(diff_lb, diff_ub, (4, 6))
        ww = unifint(diff_lb, diff_ub, (4, 7))
        total = hh * ww
        nc = unifint(diff_lb, diff_ub, (max(4, total // 4), max(5, (2 * total) // 3)))
        inds = list(product(interval(0, hh, 1), interval(0, ww, 1)))
        shuffle(inds)
        cells = set(inds[:nc])
        if len(cells) == 0:
            cells.add((0, 0))
        for _ in range(20):
            g = canvas(0, (hh, ww))
            g = fill(g, 1, frozenset(cells))
            if g != vmirror(g):
                return frozenset(cells)
            a = choice(tuple(cells))
            b = (a[0], ww - 1 - a[1])
            if b in cells and len(cells) > 1:
                cells.remove(a)
            else:
                cands = [ij for ij in inds if ij not in cells and (ij[0], ww - 1 - ij[1]) not in cells]
                if len(cands) > 0:
                    cells.add(choice(cands))
                else:
                    cells.add(choice(inds))
        if ww >= 2:
            cells.add((0, 0))
            cells.discard((0, ww - 1))
        return frozenset(cells)

    objs = [rand_sym_shape() for _ in range(nobj - 1)]
    trg = rand_nonsym_shape()
    objs.append(trg)
    shuffle(objs)

    occupied = set()
    placed = []
    for obj in objs:
        oh, ow = shape(obj)
        placed_ok = False
        for _ in range(200):
            loci = randint(0, h - oh)
            locj = randint(0, w - ow)
            sh = shift(obj, (loci, locj))
            shinds = toindices(sh)
            if len(shinds & occupied) > 0:
                continue
            if len(mapply(neighbors, shinds) & occupied) > 0:
                continue
            gi = fill(gi, fgc, shinds)
            occupied |= shinds
            placed.append(sh)
            placed_ok = True
            break
        if not placed_ok:
            gi = canvas(bgc, (21, 21))
            fgc = choice(cols)
            s1 = frozenset({(0, 1), (1, 0), (1, 1), (1, 2), (2, 1)})
            s2 = frozenset({(0, 1), (1, 0), (1, 1), (1, 2), (2, 0), (2, 2)})
            s3 = frozenset({(0, 0), (0, 2), (1, 1), (2, 0), (2, 2)})
            gi = fill(gi, fgc, shift(s1, (2, 2)))
            gi = fill(gi, fgc, shift(s2, (8, 10)))
            gi = fill(gi, fgc, shift(s3, (14, 3)))
            go = verify_73ccf9c2(gi)
            return {'input': gi, 'output': go}

    go = verify_73ccf9c2(gi)
    return {'input': gi, 'output': go}


