def generate_753ea09b(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = 30
    w = 30
    bgc, majc, minc = sample(cols, 3)

    gi = canvas(bgc, (h, w))

    side = choice(("left", "right", "top", "bottom"))
    if side in ("left", "right"):
        c0 = unifint(diff_lb, diff_ub, (4, 10)) if side == "left" else unifint(diff_lb, diff_ub, (19, 25))
        c1 = unifint(diff_lb, diff_ub, (18, 25)) if side == "left" else unifint(diff_lb, diff_ub, (4, 11))
        r0 = unifint(diff_lb, diff_ub, (1, 6))
        r1 = unifint(diff_lb, diff_ub, (23, 28))
        if r1 - r0 < 16:
            r0, r1 = 2, 27
        if side == "left" and c1 <= c0 + 6:
            c1 = c0 + 8
        if side == "right" and c0 <= c1 + 6:
            c0 = c1 + 8
        p0 = (r0, c0)
        p1 = (r1, c1)
    else:
        r0 = unifint(diff_lb, diff_ub, (4, 10)) if side == "top" else unifint(diff_lb, diff_ub, (19, 25))
        r1 = unifint(diff_lb, diff_ub, (18, 25)) if side == "top" else unifint(diff_lb, diff_ub, (4, 11))
        c0 = unifint(diff_lb, diff_ub, (1, 6))
        c1 = unifint(diff_lb, diff_ub, (23, 28))
        if c1 - c0 < 16:
            c0, c1 = 2, 27
        if side == "top" and r1 <= r0 + 6:
            r1 = r0 + 8
        if side == "bottom" and r0 <= r1 + 6:
            r0 = r1 + 8
        p0 = (r0, c0)
        p1 = (r1, c1)

    def make_path(a, b, steps_lo, steps_hi):
        (r, c) = a
        (tr, tc) = b
        path = [a]
        nsteps = unifint(diff_lb, diff_ub, (steps_lo, steps_hi))
        for k in range(nsteps):
            rem = nsteps - k
            dr = tr - r
            dc = tc - c
            cand = []
            if dr != 0:
                cand.append((r + (1 if dr > 0 else -1), c))
            if dc != 0:
                cand.append((r, c + (1 if dc > 0 else -1)))
            if abs(dr) + abs(dc) < rem:
                if 1 <= r - 1 <= h - 2:
                    cand.append((r - 1, c))
                if 1 <= r + 1 <= h - 2:
                    cand.append((r + 1, c))
                if 1 <= c - 1 <= w - 2:
                    cand.append((r, c - 1))
                if 1 <= c + 1 <= w - 2:
                    cand.append((r, c + 1))
            uniq = []
            seen = set()
            for q in cand:
                if q not in seen and 1 <= q[0] <= h - 2 and 1 <= q[1] <= w - 2:
                    uniq.append(q)
                    seen.add(q)
            if len(uniq) == 0:
                break
            nxt = choice(uniq)
            r, c = nxt
            path.append(nxt)
        while (r, c) != (tr, tc):
            if r != tr:
                r = r + (1 if tr > r else -1)
            elif c != tc:
                c = c + (1 if tc > c else -1)
            if 1 <= r <= h - 2 and 1 <= c <= w - 2:
                path.append((r, c))
            else:
                break
        out = []
        prev = None
        for q in path:
            if q != prev:
                out.append(q)
            prev = q
        return tuple(out)

    man = abs(p1[0] - p0[0]) + abs(p1[1] - p0[1])
    extra = unifint(diff_lb, diff_ub, (4, 18))
    path1 = make_path(p0, p1, man + extra, man + extra + 8)
    path2 = make_path(p0, p1, man + extra + 6, man + extra + 18)

    if len(path1) < 2:
        path1 = (p0, p1)
    if len(path2) < 2:
        path2 = (p0, p1)

    gi = fill(gi, majc, frozenset(path1))
    gi = fill(gi, majc, frozenset(path2))

    nnoise = unifint(diff_lb, diff_ub, (18, 45))
    forbidden = set(path1) | set(path2)
    cand = [(i, j) for i in range(h) for j in range(w) if (i, j) not in forbidden]
    if len(cand) > 0:
        noise_cells = sample(cand, min(nnoise, len(cand)))
        gi = fill(gi, minc, frozenset(noise_cells))

    nmaj_noise = unifint(diff_lb, diff_ub, (0, 10))
    cand2 = [(i, j) for i in range(h) for j in range(w) if gi[i][j] == bgc]
    if len(cand2) > 0 and nmaj_noise > 0:
        extra_maj = sample(cand2, min(nmaj_noise, len(cand2)))
        gi = fill(gi, majc, frozenset(extra_maj))

    go = verify_753ea09b(gi)
    if gi == go:
        fallback = frozenset({(0, 0), (0, 1), (1, 0)})
        gi = fill(gi, minc, fallback)
        go = verify_753ea09b(gi)
    return {'input': gi, 'output': go}


