def generate_770cc55f(diff_lb: float, diff_ub: float) -> dict:
    w = unifint(diff_lb, diff_ub, (4, 12))
    halfspan = unifint(diff_lb, diff_ub, (3, 10))
    h = 2 * halfspan + 1
    mid = halfspan

    segcol = choice(remove(2, remove(0, remove(4, interval(0, 10, 1)))))
    gi = canvas(0, (h, w))
    gi = fill(gi, 2, connect((mid, 0), (mid, w - 1)))

    top_len = unifint(diff_lb, diff_ub, (1, w - 1))
    bot_len = unifint(diff_lb, diff_ub, (1, w - 1))

    inter_len = unifint(diff_lb, diff_ub, (1, min(top_len, bot_len)))
    top_only = top_len - inter_len
    bot_only = bot_len - inter_len
    rem = w - inter_len - top_only - bot_only

    left_gap = randint(0, rem)
    right_gap = rem - left_gap

    order = choice((0, 1))
    if order == 0:
        top_start = left_gap
        bot_start = left_gap + top_only
    else:
        bot_start = left_gap
        top_start = left_gap + bot_only

    top_seg = connect((0, top_start), (0, top_start + top_len - 1))
    bot_seg = connect((h - 1, bot_start), (h - 1, bot_start + bot_len - 1))

    gi = fill(gi, segcol, top_seg)
    gi = fill(gi, segcol, bot_seg)

    go = verify_770cc55f(gi)
    return {'input': gi, 'output': go}


def generate_776ffc46(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc, sqc, inc, outc = sample(cols, 4)
    gi = canvas(bgc, (h, w))
    sqh = randint(3, h//3+1)
    sqw = randint(3, w//3+1)
    loci = randint(0, 3)
    locj = randint(0, w - sqw)
    bx = box(frozenset({(loci, locj), (loci + sqh - 1, locj + sqw - 1)}))
    bounds = asindices(canvas(-1, (sqh - 2, sqw - 2)))
    obj = {choice(totuple(bounds))}
    ncells = randint(1, (sqh - 2) * (sqw - 2))
    for k in range(ncells - 1):
        obj.add(choice(totuple((bounds - obj) & mapply(dneighbors, obj))))
    obj = normalize(obj)
    oh, ow = shape(obj)
    objp = shift(obj, (loci+1+randint(0, sqh-oh-2), locj+1+randint(0, sqw-ow-2)))
    gi = fill(gi, sqc, bx)
    gi = fill(gi, inc, objp)
    inds = (ofcolor(gi, bgc) - backdrop(bx)) - mapply(neighbors, backdrop(bx))
    cands = sfilter(inds, lambda ij: shift(obj, ij).issubset(inds))
    loc = choice(totuple(cands))
    plcd = shift(obj, loc)
    gi = fill(gi, outc, plcd)
    inds = (inds - plcd) - mapply(neighbors, plcd)
    noccs = unifint(diff_lb, diff_ub, (0, (h * w) // 20))
    succ = 0
    tr = 0
    maxtr = 5 * noccs
    fullinds = asindices(gi)
    while tr < maxtr and succ < noccs:
        tr += 1
        if choice((True, False)):
            sqh = randint(3, h//3+1)
            sqw = randint(3, w//3+1)
            bx = box(frozenset({(0, 0), (sqh - 1, sqw - 1)}))
            bounds = asindices(canvas(-1, (sqh - 2, sqw - 2)))
            obj2 = {choice(totuple(bounds))}
            ncells = randint(1, (sqh - 2) * (sqw - 2))
            for k in range(ncells - 1):
                obj2.add(choice(totuple((bounds - obj2) & mapply(dneighbors, obj2))))
            if normalize(obj2) == obj:
                if len(obj2) < (sqh - 2) * (sqw - 2):
                    obj2.add(choice(totuple((bounds - obj2) & mapply(dneighbors, obj2))))
                else:
                    continue
            obj2 = normalize(obj2)
            ooh, oow = shape(obj2)
            cands1 = connect((-1, -1), (-1, w - sqw + 1))
            cands2 = connect((h-sqh+1, -1), (h-sqh+1, w - sqw + 1))
            cands3 = connect((-1, -1), (h - sqh + 1, -1))
            cands4 = connect((-1, w-sqw+1), (h - sqh + 1, w-sqw+1))
            cands = cands1 | cands2 | cands3 | cands4
            if len(cands) == 0:
                continue
            loc = choice(totuple(cands))
            sloci, slocj = loc
            plcdbx = shift(bx, loc)
            if (backdrop(plcdbx) & fullinds).issubset(inds):
                succ += 1
                oloci = randint(sloci+1, sloci+1+randint(0, sqh-ooh-2))
                olocj = randint(slocj+1, slocj+1+randint(0, sqw-oow-2))
                gi = fill(gi, sqc, plcdbx)
                gi = fill(gi, inc, shift(obj2, (oloci, olocj)))
                inds = inds - backdrop(outbox(plcdbx))
        else:
            ooh = randint(1, h//3-1)
            oow = randint(1, w//3-1)
            bounds = asindices(canvas(-1, (ooh, oow)))
            obj2 = {choice(totuple(bounds))}
            ncells = randint(1, oow * ooh)
            for k in range(ncells - 1):
                obj2.add(choice(totuple((bounds - obj2) & mapply(dneighbors, obj2))))
            if normalize(obj2) == obj:
                if len(obj2) < ooh * oow:
                    obj2.add(choice(totuple((bounds - obj2) & mapply(dneighbors, obj2))))
                else:
                    continue
        if choice((True, False, False)):
            obj2 = obj
        obj2 = normalize(obj2)
        ooh, oow = shape(obj2)
        for kk in range(randint(1, 3)):
            cands = sfilter(inds, lambda ij: ij[0] <= h - ooh and ij[1] <= w - oow)
            if len(cands) == 0:
                continue
            loc = choice(totuple(cands))
            plcd = shift(obj2, loc)
            if plcd.issubset(inds):
                succ += 1
                inds = (inds - plcd) - mapply(neighbors, plcd)
                gi = fill(gi, outc, plcd)
    objs = objects(gi, T, F, F)
    objs = colorfilter(objs, outc)
    objs = mfilter(objs, lambda o: equality(normalize(toindices(o)), obj))
    go = fill(gi, inc, objs)
    return {'input': gi, 'output': go}


def generate_77fdfe62(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (1, 13))
    w = unifint(diff_lb, diff_ub, (1, 13))
    c1, c2, c3, c4, barc, bgc, inc = sample(cols, 7)
    qd = canvas(bgc, (h, w))
    inds = totuple(asindices(qd))
    fullh = 2 * h + 4
    fullw = 2 * w + 4
    n1 = unifint(diff_lb, diff_ub, (1, h * w))
    n2 = unifint(diff_lb, diff_ub, (1, h * w))
    n3 = unifint(diff_lb, diff_ub, (1, h * w))
    n4 = unifint(diff_lb, diff_ub, (1, h * w))
    i1 = sample(inds, n1)
    i2 = sample(inds, n2)
    i3 = sample(inds, n3)
    i4 = sample(inds, n4)
    gi = canvas(bgc, (2 * h + 4, 2 * w + 4))
    gi = fill(gi, barc, connect((1, 0), (1, fullw - 1)))
    gi = fill(gi, barc, connect((fullh - 2, 0), (fullh - 2, fullw - 1)))
    gi = fill(gi, barc, connect((0, 1), (fullh - 1, 1)))
    gi = fill(gi, barc, connect((0, fullw - 2), (fullh - 1, fullw - 2)))
    gi = fill(gi, c1, {(0, 0)})
    gi = fill(gi, c2, {(0, fullw - 1)})
    gi = fill(gi, c3, {(fullh - 1, 0)})
    gi = fill(gi, c4, {(fullh - 1, fullw - 1)})
    gi = fill(gi, inc, shift(i1, (2, 2)))
    gi = fill(gi, inc, shift(i2, (2, 2+w)))
    gi = fill(gi, inc, shift(i3, (2+h, 2)))
    gi = fill(gi, inc, shift(i4, (2+h, 2+w)))
    go = canvas(bgc, (2 * h, 2 * w))
    go = fill(go, c1, shift(i1, (0, 0)))
    go = fill(go, c2, shift(i2, (0, w)))
    go = fill(go, c3, shift(i3, (h, 0)))
    go = fill(go, c4, shift(i4, (h, w)))
    return {'input': gi, 'output': go}


def generate_780d0b14(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    nh = unifint(diff_lb, diff_ub, (2, 6))
    nw = unifint(diff_lb, diff_ub, (2, 6))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    ncols = unifint(diff_lb, diff_ub, (3, 9))
    ccols = sample(remcols, ncols)
    go = canvas(-1, (nh, nw))
    obj = {(choice(ccols), ij) for ij in asindices(go)}
    go = paint(go, obj)
    while len(dedupe(go)) < nh or len(dedupe(dmirror(go))) < nw:
        obj = {(choice(ccols), ij) for ij in asindices(go)}
        go = paint(go, obj)
    h = unifint(diff_lb, diff_ub, (2*nh+nh-1, 30))
    w = unifint(diff_lb, diff_ub, (2*nw+nw-1, 30))
    hdist = [2 for k in range(nh)]
    for k in range(h - 2 * nh - nh + 1):
        idx = randint(0, nh - 1)
        hdist[idx] += 1
    wdist = [2 for k in range(nw)]
    for k in range(w - 2 * nw - nw + 1):
        idx = randint(0, nw - 1)
        wdist[idx] += 1
    gi = merge(tuple(repeat(r, c) + (repeat(bgc, nw),) for r, c in zip(go, hdist)))[:-1]
    gi = dmirror(merge(tuple(repeat(r, c) + (repeat(bgc, h),) for r, c in zip(dmirror(gi), wdist)))[:-1])
    objs = objects(gi, T, F, F)
    bgobjs = colorfilter(objs, bgc)
    objs = objs - bgobjs
    for obj in objs:
        gi = fill(gi, bgc, sample(totuple(toindices(obj)), unifint(diff_lb, diff_ub, (1, len(obj) // 2))))
    return {'input': gi, 'output': go}


def generate_782b5218(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (6, 30))
    w = unifint(diff_lb, diff_ub, (6, 30))
    cols = remove(2, interval(0, 10, 1))
    third = choice(remove(0, cols))
    gi = canvas(0, (h, w))

    mode = choice((0, 1, 2))
    lows = []

    if mode == 0:
        base = unifint(diff_lb, diff_ub, (1, h - 2))
        for _ in range(w):
            lows.append(base)
    elif mode == 1:
        cur = unifint(diff_lb, diff_ub, (1, h - 2))
        lows.append(cur)
        maxstep = max(1, unifint(diff_lb, diff_ub, (1, max(1, h // 4))))
        for _ in range(1, w):
            step = choice((-maxstep, -1, 0, 1, maxstep))
            cur = min(max(0, cur + step), h - 1)
            lows.append(cur)
    else:
        start = unifint(diff_lb, diff_ub, (0, max(0, h - 2)))
        end = unifint(diff_lb, diff_ub, (1, h - 1))
        if w == 1:
            lows = [start]
        else:
            for j in range(w):
                val = start + ((end - start) * j) // (w - 1)
                lows.append(min(max(0, val), h - 1))

    for j, low in enumerate(lows):
        n2 = unifint(diff_lb, diff_ub, (1, min(3, low + 1)))
        rows = sample(tuple(range(low + 1)), n2)
        if low not in rows:
            rows = list(rows)
            rows[0] = low
        for i in rows:
            gi = fill(gi, 2, frozenset({(i, j)}))

    noise = unifint(diff_lb, diff_ub, (max(1, (h * w) // 8), max(1, (3 * h * w) // 5)))
    inds = totuple(asindices(gi))
    for loc in sample(inds, min(noise, len(inds))):
        if index(gi, loc) != 2:
            gi = fill(gi, choice((0, third)), frozenset({loc}))

    if colorcount(gi, third) == 0:
        non2 = difference(asindices(gi), ofcolor(gi, 2))
        if len(non2) > 0:
            gi = fill(gi, third, frozenset({choice(totuple(non2))}))

    go = verify_782b5218(gi)
    return {'input': gi, 'output': go}


def generate_7837ac64(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    oh = unifint(diff_lb, diff_ub, (2, 6))
    ow = unifint(diff_lb, diff_ub, (2, 6))
    bgc, linc = sample(cols, 2)
    remcols = remove(bgc, remove(linc, cols))
    numcols = unifint(diff_lb, diff_ub, (1, 8))
    ccols = sample(remcols, numcols)
    go = canvas(bgc, (oh, ow))
    inds = asindices(go)
    fullinds = asindices(go)
    nocc = unifint(diff_lb, diff_ub, (1, oh * ow))
    for k in range(nocc):
        mpr = {
            cc: sfilter(
                inds | mapply(neighbors, ofcolor(go, cc)),
                lambda ij: (neighbors(ij) & fullinds).issubset(inds | ofcolor(go, cc))
            ) for cc in ccols
        }
        mpr = [(kk, vv) for kk, vv in mpr.items() if len(vv) > 0]
        if len(mpr) == 0:
            break
        col, locs = choice(mpr)
        loc = choice(totuple(locs))
        go = fill(go, col, {loc})
        inds = remove(loc, inds)
    obj = fullinds - ofcolor(go, bgc)
    go = subgrid(obj, go)
    oh, ow = shape(go)
    sqsizh = unifint(diff_lb, diff_ub, (2, (30 - oh - 1) // oh))
    sqsizw = unifint(diff_lb, diff_ub, (2, (30 - ow - 1) // ow))
    fullh = oh + 1 + oh * sqsizh
    fullw = ow + 1 + ow * sqsizw
    gi = canvas(linc, (fullh, fullw))
    sq = backdrop(frozenset({(0, 0), (sqsizh - 1, sqsizw - 1)}))
    obj = asobject(go)
    for col, ij in obj:
        plcd = shift(sq, add((1, 1), multiply(ij, (sqsizh+1, sqsizw+1))))
        gi = fill(gi, bgc, plcd)
        if col != bgc:
            gi = fill(gi, col, corners(outbox(plcd)))
    gih = unifint(diff_lb, diff_ub, (fullh, 30))
    giw = unifint(diff_lb, diff_ub, (fullw, 30))
    loci = randint(0, gih - fullh)
    locj = randint(0, giw - fullw)
    gigi = canvas(bgc, (gih, giw))
    plcd = shift(asobject(gi), (loci, locj))
    gigi = paint(gigi, plcd)
    ulci, ulcj = ulcorner(plcd)
    lrci, lrcj = lrcorner(plcd)
    for a in range(ulci, gih+1, sqsizh+1):
        gigi = fill(gigi, linc, hfrontier((a, 0)))
    for a in range(ulci, -1, -sqsizh-1):
        gigi = fill(gigi, linc, hfrontier((a, 0)))
    for b in range(ulcj, giw+1, sqsizw+1):
        gigi = fill(gigi, linc, vfrontier((0, b)))
    for b in range(ulcj, -1, -sqsizw-1):
        gigi = fill(gigi, linc, vfrontier((0, b)))
    gi = paint(gigi, plcd)
    gop = palette(go)
    while True:
        go2 = identity(go)
        for c in set(ccols) & gop:
            o1 = frozenset({(c, ORIGIN), (bgc, RIGHT), (c, (0, 2))})
            o2 = dmirror(o1)
            go2 = fill(go2, c, combine(
                shift(occurrences(go, o1), RIGHT),
                shift(occurrences(go, o2), DOWN)
            ))
        if go2 == go:
            break
        go = go2
    return {'input': gi, 'output': go}


def generate_78e78cff(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (7, 20))
    w = unifint(diff_lb, diff_ub, (7, 20))
    bgc, shapec, specc = sample(cols, 3)

    axis = unifint(diff_lb, diff_ub, (2, w - 3))
    top = unifint(diff_lb, diff_ub, (1, max(1, h // 2 - 1)))
    bot = unifint(diff_lb, diff_ub, (max(top + 1, h // 2), h - 2))

    gi = canvas(bgc, (h, w))

    nrows = unifint(diff_lb, diff_ub, (2, min(6, bot - top + 1)))
    shape_rows = sorted(sample(tuple(range(top, bot + 1)), nrows))

    used_pairs = []
    for r in shape_rows:
        max_left = axis - 1
        max_right = w - axis - 1
        if max_left <= 0 or max_right <= 0:
            continue

        mode = choice((0, 1, 2))
        if mode == 0:
            llen = 1
            rlen = 1
        elif mode == 1:
            llen = unifint(diff_lb, diff_ub, (1, max(1, min(3, max_left))))
            rlen = unifint(diff_lb, diff_ub, (1, max(1, min(3, max_right))))
        else:
            llen = unifint(diff_lb, diff_ub, (1, max_left))
            rlen = unifint(diff_lb, diff_ub, (1, max_right))

        lstart_lo = 0
        lstart_hi = axis - llen
        rstart_lo = axis + 1
        rstart_hi = w - rlen

        if lstart_lo > lstart_hi or rstart_lo > rstart_hi:
            continue

        lstart = unifint(diff_lb, diff_ub, (lstart_lo, lstart_hi))
        rstart = unifint(diff_lb, diff_ub, (rstart_lo, rstart_hi))

        left_inds = connect((r, lstart), (r, lstart + llen - 1))
        right_inds = connect((r, rstart), (r, rstart + rlen - 1))
        gi = fill(gi, shapec, left_inds | right_inds)
        used_pairs.append((r, lstart, lstart + llen - 1, rstart, rstart + rlen - 1))

    if len(used_pairs) == 0:
        r = (top + bot) // 2
        lstart = max(0, axis - 2)
        rend = min(w - 1, axis + 2)
        left_inds = connect((r, lstart), (r, axis - 1))
        right_inds = connect((r, axis + 1), (r, rend))
        gi = fill(gi, shapec, left_inds | right_inds)
        used_pairs.append((r, lstart, axis - 1, axis + 1, rend))

    if len(used_pairs) >= 2 and choice((True, False)):
        r1 = used_pairs[0][0]
        r2 = used_pairs[-1][0]
        c = choice((used_pairs[0][1], used_pairs[0][2], used_pairs[-1][3], used_pairs[-1][4]))
        if 0 <= c < w:
            gi = fill(gi, shapec, connect((r1, c), (r2, c)))

    if len(used_pairs) >= 2 and choice((True, False)):
        a = choice(used_pairs)
        b = choice(used_pairs)
        c1 = choice((a[1], a[2]))
        c2 = choice((b[3], b[4]))
        if c1 <= c2:
            rr = choice(shape_rows)
            gi = fill(gi, shapec, connect((rr, c1), (rr, c2)))

    spec_row = unifint(diff_lb, diff_ub, (0, h - 1))
    gi = fill(gi, specc, frozenset({(spec_row, axis)}))

    go = verify_78e78cff(gi)
    return {'input': gi, 'output': go}


def generate_79369cc6(diff_lb: float, diff_ub: float) -> dict:
    # Background colors used in training examples: 0, 1, 8
    bgcols = (0, 1, 8)
    h = unifint(diff_lb, diff_ub, (12, 22))
    w = unifint(diff_lb, diff_ub, (12, 22))

    # Create a 3x3 template with only colors 4 and 6
    # Must have at least 2 cells of color 6 and at least 1 cell of color 4
    all_positions = [(r, c) for r in range(3) for c in range(3)]
    nsix = unifint(diff_lb, diff_ub, (2, 6))
    six_positions = frozenset(sample(all_positions, nsix))
    four_positions = frozenset(set(all_positions) - six_positions)
    if len(four_positions) == 0:
        # Need at least one 4
        drop = choice(list(six_positions))
        six_positions = six_positions - {drop}
        four_positions = frozenset({drop})

    # Build the template grid (3x3)
    template = tuple(
        tuple(SIX if (r, c) in six_positions else FOUR for c in range(3))
        for r in range(3)
    )

    # Get all 8 orientations of the six-pattern
    def get_six_indices(tpl):
        return frozenset((r, c) for r in range(len(tpl)) for c in range(len(tpl[0])) if tpl[r][c] == SIX)

    def get_four_indices(tpl):
        return frozenset((r, c) for r in range(len(tpl)) for c in range(len(tpl[0])) if tpl[r][c] == FOUR)

    orientations = []
    seen = set()
    for t in (template, rot90(template), rot180(template), rot270(template),
              hmirror(template), vmirror(template), dmirror(template), cmirror(template)):
        si = get_six_indices(t)
        fi = get_four_indices(t)
        key = (frozenset(si), frozenset(fi))
        if key not in seen:
            seen.add(key)
            orientations.append((si, fi))

    # Place the template at a random location
    template_six = six_positions
    template_four = four_positions

    # Create noisy background grid with colors from bgcols and scattered 6s
    gi = canvas(choice(bgcols), (h, w))

    # Fill with random noise from bgcols
    for r in range(h):
        for c in range(w):
            gi = fill(gi, choice(bgcols), frozenset({(r, c)}))

    # Scatter some 6s around
    nnoise6 = unifint(diff_lb, diff_ub, (max(8, (h * w) // 12), max(12, (h * w) // 5)))
    noise_locs = sample(list(asindices(gi)), min(nnoise6, h * w))
    gi = fill(gi, SIX, frozenset(noise_locs))

    # Find valid placement positions for 3x3 blocks (ensuring no overlap)
    allstarts = [(r, c) for r in range(h - 2) for c in range(w - 2)]
    shuffle(allstarts)

    # Place template
    template_loc = allstarts[0]
    placed = [template_loc]

    # Place additional match locations (magenta pattern matches, but no yellow)
    nmatches = unifint(diff_lb, diff_ub, (1, max(1, min(6, len(allstarts) // 10))))
    match_locs = []
    for st in allstarts[1:]:
        if len(match_locs) >= nmatches:
            break
        # Ensure no overlap with placed blocks
        ok = True
        for p in placed:
            if abs(st[0] - p[0]) < 3 and abs(st[1] - p[1]) < 3:
                ok = False
                break
        if ok:
            match_locs.append(st)
            placed.append(st)

    # Paint the template: both 6s and 4s in template position
    for (r, c) in template_six:
        gi = fill(gi, SIX, frozenset({(template_loc[0] + r, template_loc[1] + c)}))
    for (r, c) in template_four:
        gi = fill(gi, FOUR, frozenset({(template_loc[0] + r, template_loc[1] + c)}))

    # Paint match locations: only 6s in the pattern (using some orientation)
    for st in match_locs:
        ori_six, ori_four = choice(orientations)
        for (r, c) in ori_six:
            gi = fill(gi, SIX, frozenset({(st[0] + r, st[1] + c)}))
        # Make sure the four-positions are NOT 6 (and NOT 4) - they should be noise
        for (r, c) in ori_four:
            ar, ac = st[0] + r, st[1] + c
            if gi[ar][ac] == SIX or gi[ar][ac] == FOUR:
                gi = fill(gi, choice(bgcols), frozenset({(ar, ac)}))

    go = verify_79369cc6(gi)
    if gi == go:
        # No changes detected, add another match
        if len(allstarts) > len(placed):
            for st in allstarts:
                ok = True
                for p in placed:
                    if abs(st[0] - p[0]) < 3 and abs(st[1] - p[1]) < 3:
                        ok = False
                        break
                if ok:
                    ori_six, ori_four = choice(orientations)
                    for (r, c) in ori_six:
                        gi = fill(gi, SIX, frozenset({(st[0] + r, st[1] + c)}))
                    for (r, c) in ori_four:
                        ar, ac = st[0] + r, st[1] + c
