def generate_7acdf6d3(diff_lb: float, diff_ub: float) -> dict:
    bgc = choice(interval(0, 10, 1))
    rem = remove(bgc, interval(0, 10, 1))
    cshape, cstray = sample(rem, 2)

    h = unifint(diff_lb, diff_ub, (10, 22))
    w = unifint(diff_lb, diff_ub, (10, 22))

    gi = canvas(bgc, (h, w))

    orient = choice((0, 1))
    if orient == 0:
        max_rows = max(1, min(6, h - 2))
        nrows = unifint(diff_lb, diff_ub, (1, max_rows))
        row_gap = choice((1, 1, 1, 2))
        shape_h = 1 + (nrows - 1) * row_gap
        row0 = randint(1, h - shape_h - 1) if h - shape_h - 1 >= 1 else 0
        rows = [row0 + k * row_gap for k in range(nrows)]

        max_pairs = max(1, min(4, w // 4))
        npairs = unifint(diff_lb, diff_ub, (1, max_pairs))
        col_gap = choice((1, 1, 2))
        shape_w = 1 + (npairs - 1) * col_gap
        col0 = randint(1, w - shape_w - 1) if w - shape_w - 1 >= 1 else 0
        cols = [col0 + k * col_gap for k in range(npairs)]

        shape_inds = frozenset((i, j) for i in rows for j in cols)
    else:
        max_rows = max(2, min(6, h - 2))
        nrows = unifint(diff_lb, diff_ub, (2, max_rows))
        row_gap = choice((1, 1, 1, 2))
        shape_h = 1 + (nrows - 1) * row_gap
        row0 = randint(1, h - shape_h - 1) if h - shape_h - 1 >= 1 else 0
        rows = [row0 + k * row_gap for k in range(nrows)]

        maxw = min(w - 2, 8)
        left = randint(1, max(1, w - 5))
        right = randint(left + 2, min(w - 2, left + maxw - 1))
        shape_inds = set()
        for i in rows:
            shape_inds.add((i, left))
            shape_inds.add((i, right))
        shape_inds = frozenset(shape_inds)

    interior = frozenset()
    for i in range(min(r for r, _ in shape_inds), max(r for r, _ in shape_inds) + 1):
        rowcells = [j for r, j in shape_inds if r == i]
        if len(rowcells) >= 2:
            seg = connect((i, min(rowcells)), (i, max(rowcells)))
            interior = interior | difference(seg, shape_inds)

    if len(interior) == 0:
        if len(rows) >= 1:
            i = rows[0]
            if orient == 0 and len(cols) >= 2:
                interior = difference(connect((i, min(cols)), (i, max(cols))), shape_inds)
            elif orient == 1:
                interior = difference(connect((i, left), (i, right)), shape_inds)

    nstray = len(interior)
    gi = fill(gi, cshape, shape_inds)

    free = difference(asindices(gi), shape_inds | interior)
    free = sfilter(free, lambda ij: all(abs(ij[0] - si) + abs(ij[1] - sj) > 1 for si, sj in shape_inds))
    free = sfilter(free, lambda ij: all(abs(ij[0] - si) + abs(ij[1] - sj) > 1 for si, sj in interior))
    free_t = totuple(free)

    if len(free_t) < nstray:
        free = difference(asindices(gi), shape_inds | interior)
        free_t = totuple(free)

    stray = sample(free_t, nstray)
    gi = fill(gi, cstray, stray)

    go = verify_7acdf6d3(gi)
    return {'input': gi, 'output': go}


