    while len(placed) < npatches and tr < maxtr:
        tr += 1
        ph = unifint(diff_lb, diff_ub, (2, min(8, h - 2)))
        pw = unifint(diff_lb, diff_ub, (3, min(8, w - 2)))
        cands = []
        for i in range(h - ph + 1):
            for j in range(w - pw + 1):
                ok = True
                for (oi, oj, oh, ow) in placed:
                    if not (i + ph + 1 <= oi or oi + oh + 1 <= i or j + pw + 1 <= oj or oj + ow + 1 <= j):
                        ok = False
                        break
                if ok:
                    cands.append((i, j))
        if len(cands) == 0:
            continue
        loci, locj = choice(cands)
        rect = frozenset((r, c) for r in range(loci, loci + ph) for c in range(locj, locj + pw))
        gi = fill(gi, 1, rect)

        area = ph * pw
        mx = max(1, area // 3)
        if len(placed) == 0:
            cnt = unifint(diff_lb, diff_ub, (1, mx))
        else:
            prevmin = min(counts)
            upper = min(mx, max(1, prevmin + 3))
            cnt = unifint(diff_lb, diff_ub, (1, upper))
        innercells = sample(sorted(rect), cnt)
