        r1 = frozenset((r, c) for r in range(1, 4) for c in range(1, 5))
        r2 = frozenset((r, c) for r in range(6, 10) for c in range(6, 11))
        gi = fill(gi, 1, r1)
        gi = fill(gi, 1, r2)
