    for r in range(1, hcells):
        rr = r * cellh + (r - 1)
        gi = fill(gi, 5, connect((rr, 0), (rr, w - 1)))
    for c in range(1, wcells):
        cc = c * cellw + (c - 1)
        gi = fill(gi, 5, connect((0, cc), (h - 1, cc)))

    row_starts = tuple(r * (cellh + 1) for r in range(hcells))
    col_starts = tuple(c * (cellw + 1) for c in range(wcells))

    comps = []
    for rs in row_starts:
        for cs in col_starts:
            comps.append(frozenset((i, j) for i in range(rs, rs + cellh) for j in range(cs, cs + cellw)))

    ncomp = len(comps)
    majcols = [choice((1, 2)) for _ in range(ncomp)]
    if len(set(majcols)) == 1 and ncomp > 1:
        majcols[randint(0, ncomp - 1)] = 3 - majcols[0]

    for idx, comp in enumerate(comps):
        maj = majcols[idx]
        oth = 3 - maj
        boundary = mapply(dneighbors, comp) - comp
        boundary = frozenset((i, j) for i, j in boundary if 0 <= i < h and 0 <= j < w and gi[i][j] == 5)
        btuple = totuple(boundary)
        if len(btuple) == 0:
            continue
        nmaj = unifint(diff_lb, diff_ub, (1, len(btuple)))
        maxoth = max(0, nmaj - 1)
        noth = 0 if maxoth == 0 else unifint(diff_lb, diff_ub, (0, maxoth))
        majcells = sample(btuple, nmaj)
        rem = [x for x in btuple if x not in majcells]
        othcells = sample(rem, noth) if noth > 0 and len(rem) >= noth else []
        gi = fill(gi, maj, frozenset(majcells))
        gi = fill(gi, oth, frozenset(othcells))

    if palette(gi) == frozenset({0, 1, 5}) or palette(gi) == frozenset({0, 2, 5}):
        wallcells = totuple(ofcolor(gi, 5))
        if len(wallcells) > 0:
            cand = choice(wallcells)
            missing = 2 if 1 in palette(gi) else 1
            gi = fill(gi, missing, frozenset({cand}))

    go = verify_7c8af763(gi)
    return {'input': gi, 'output': go}


