    parts = [set() for _ in range(nwin)]
    for cell in fullpat:
        k = randint(0, nwin - 1)
        parts[k].add(cell)

    for idx in range(nwin):
        if len(parts[idx]) == 0:
            donor_choices = [k for k in range(nwin) if len(parts[k]) > 1]
            if len(donor_choices) > 0:
                dk = choice(donor_choices)
                moved = choice(tuple(parts[dk]))
                parts[dk].remove(moved)
                parts[idx].add(moved)
            else:
                parts[idx].add(choice(tuple(fullpat)))

    windows = []
    for _ in range(200):
        if len(windows) == nwin:
            break
        r = randint(1, H - wh - 1)
        c = randint(1, W - ww - 1)
        rect = frozenset((i, j) for i in range(r, r + wh) for j in range(c, c + ww))
        ok = True
        for prev in windows:
            prow, pcol = prev
            if not (r + wh + 1 <= prow or prow + wh + 1 <= r or c + ww + 1 <= pcol or pcol + ww + 1 <= c):
                ok = False
                break
        if ok:
            windows.append((r, c))

    if len(windows) < nwin:
        step_r = wh + 3
        step_c = ww + 3
        candidates = []
        for r in range(1, H - wh):
            for c in range(1, W - ww):
                candidates.append((r, c))
        shuffle(candidates)
        windows = []
