def generate_7d419a02(diff_lb: float, diff_ub: float) -> dict:
    orient_vertical = choice((True, False))
    if orient_vertical:
        nrows = unifint(diff_lb, diff_ub, (3, 5))
        ncols = unifint(diff_lb, diff_ub, (3, 7))
        h = 3 * nrows + 1
        w = 3 * ncols + 1
        body_rg = unifint(diff_lb, diff_ub, (1, nrows - 1))
        body_cg = unifint(diff_lb, diff_ub, (1, ncols - 2))
    else:
        nrows = unifint(diff_lb, diff_ub, (3, 7))
        ncols = unifint(diff_lb, diff_ub, (3, 5))
        h = 3 * nrows + 1
        w = 3 * ncols + 1
        body_rg = unifint(diff_lb, diff_ub, (1, nrows - 2))
        body_cg = unifint(diff_lb, diff_ub, (1, ncols - 1))

    gi = canvas(0, (h, w))

    for rg in range(nrows):
        for cg in range(ncols):
            block = shift(asindices(canvas(-1, (2, 2))), (1 + 3 * rg, 1 + 3 * cg))
            if rg == body_rg and cg == body_cg:
                gi = fill(gi, 6, block)
            else:
                d = abs(rg - body_rg) if orient_vertical else abs(cg - body_cg)
                if d > 0:
                    axisdist = abs(cg - body_cg) if orient_vertical else abs(rg - body_rg)
                    maxaxis = d
                    if axisdist < maxaxis:
                        pnum = max(1, 6 - d)
                        pden = 6
                        if randint(1, pden) <= pnum:
                            gi = fill(gi, 8, block)

    go = verify_7d419a02(gi)
    return {'input': gi, 'output': go}


def generate_7d7772cc(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 22))
    w = unifint(diff_lb, diff_ub, (10, 22))
    orient = choice(("h", "v"))

    if orient == "h":
        # horizontal separator
        sep_r = unifint(diff_lb, diff_ub, (3, h - 4))
        bg, sep_col = sample(list(cols), 2)
        rem = [c for c in cols if c != bg and c != sep_col]
        ndc = unifint(diff_lb, diff_ub, (2, min(5, len(rem))))
        dot_colors = sample(rem, ndc)

        # which side is movable
        mov_top = choice((True, False))
        if mov_top:
            fix_adj = sep_r + 1      # fixed dots row (just below separator)
            fix_rows = range(sep_r + 1, h)
            near = sep_r - 1         # movable near edge
            far = 0                  # movable far edge
            mov_valid = list(range(1, sep_r - 1))  # valid rows for movable dots
        else:
            fix_adj = sep_r - 1      # fixed dots row (just above separator)
            fix_rows = range(0, sep_r)
            near = sep_r + 1
            far = h - 1
            mov_valid = list(range(sep_r + 2, h - 1))

        if len(mov_valid) == 0:
            mov_valid = [near]

        mov_dot_row = choice(mov_valid)

        # build grid: all bg
        gi = canvas(bg, (h, w))

        # draw separator line
        gi = fill(gi, sep_col, connect((sep_r, 0), (sep_r, w - 1)))

        # draw frame on fixed side (left and right edges)
        for r in fix_rows:
            gi = fill(gi, sep_col, frozenset({(r, 0), (r, w - 1)}))

        # pick dot column positions (inside frame, spaced apart)
        available = list(range(1, w - 1))
        n_dots = unifint(diff_lb, diff_ub, (3, min(8, len(available) // 2)))
        # sample every-other to get spacing
        odds = [c for c in available if c % 2 == 1]
        evens = [c for c in available if c % 2 == 0]
        pool = odds if len(odds) >= n_dots else available
        if len(pool) < n_dots:
            pool = available
        dot_cols = sorted(sample(pool, n_dots))

        # decide which dots match colors (near) vs differ (far)
        n_match = unifint(diff_lb, diff_ub, (1, max(1, n_dots - 1)))
        match_set = set(sample(range(n_dots), n_match))

        for idx, jj in enumerate(dot_cols):
            fc = choice(dot_colors)
            if idx in match_set:
                mc = fc
            else:
                other = [c for c in dot_colors if c != fc]
                mc = choice(other) if other else fc
            gi = fill(gi, fc, frozenset({(fix_adj, jj)}))
            gi = fill(gi, mc, frozenset({(mov_dot_row, jj)}))

        go = verify_7d7772cc(gi)
        return {'input': gi, 'output': go}

    else:
        # vertical separator
        sep_c = unifint(diff_lb, diff_ub, (3, w - 4))
        bg, sep_col = sample(list(cols), 2)
        rem = [c for c in cols if c != bg and c != sep_col]
        ndc = unifint(diff_lb, diff_ub, (2, min(5, len(rem))))
        dot_colors = sample(rem, ndc)

        mov_left = choice((True, False))
        if mov_left:
            fix_adj = sep_c + 1
            fix_cols = range(sep_c + 1, w)
            near = sep_c - 1
            far = 0
            mov_valid = list(range(1, sep_c - 1))
        else:
            fix_adj = sep_c - 1
            fix_cols = range(0, sep_c)
            near = sep_c + 1
            far = w - 1
            mov_valid = list(range(sep_c + 2, w - 1))

        if len(mov_valid) == 0:
            mov_valid = [near]

        mov_dot_col = choice(mov_valid)

        gi = canvas(bg, (h, w))

        # draw separator line
        gi = fill(gi, sep_col, connect((0, sep_c), (h - 1, sep_c)))

        # draw frame on fixed side (top and bottom edges)
        for c in fix_cols:
            gi = fill(gi, sep_col, frozenset({(0, c), (h - 1, c)}))

        # pick dot row positions
        available = list(range(1, h - 1))
        n_dots = unifint(diff_lb, diff_ub, (3, min(8, len(available) // 2)))
        odds = [r for r in available if r % 2 == 1]
        pool = odds if len(odds) >= n_dots else available
        if len(pool) < n_dots:
            pool = available
        dot_rows = sorted(sample(pool, n_dots))

        n_match = unifint(diff_lb, diff_ub, (1, max(1, n_dots - 1)))
        match_set = set(sample(range(n_dots), n_match))

        for idx, ii in enumerate(dot_rows):
            fc = choice(dot_colors)
            if idx in match_set:
                mc = fc
            else:
                other = [c for c in dot_colors if c != fc]
                mc = choice(other) if other else fc
            gi = fill(gi, fc, frozenset({(ii, fix_adj)}))
            gi = fill(gi, mc, frozenset({(ii, mov_dot_col)}))

        go = verify_7d7772cc(gi)
        return {'input': gi, 'output': go}


def generate_7ddcd7ec(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    crns = (((0, 0), (-1, -1)), ((0, 1), (-1, 1)), ((1, 0), (1, -1)), ((1, 1), (1, 1)))
