    if orient_vertical:
        nbars = unifint(diff_lb, diff_ub, (3, 6))
        minsep = 4
        maxbars = min(6, (w - 6) // minsep + 1)
        nbars = min(nbars, maxbars)
        span = (nbars - 1) * minsep + 1
        startj_lo = 1
        startj_hi = w - 2 - span
        if startj_hi < startj_lo:
            nbars = 3
            span = (nbars - 1) * minsep + 1
            startj_hi = w - 2 - span
        startj = randint(startj_lo, startj_hi)
        js = [startj + k * minsep for k in range(nbars)]
        extra = w - 2 - js[-1]
        for k in range(1, nbars):
            addgap = randint(0, extra // (nbars - 1) if nbars > 1 else 0)
            js[k] += addgap
            extra -= addgap
        js = sorted(js)

        centers_i = []
        used = set()
        for j in js:
            for _ in range(100):
                ci = randint(1, h - 2)
                if all(abs(ci - x) >= 4 for x in centers_i):
                    centers_i.append(ci)
                    used.add(ci)
                    break
            else:
                cands = [x for x in range(1, h - 1) if all(abs(x - y) >= 4 for y in centers_i)]
                ci = choice(cands) if len(cands) > 0 else randint(1, h - 2)
                centers_i.append(ci)
        for ci, j in zip(centers_i, js):
            gi = fill(gi, barc, connect((ci - 1, j), (ci + 1, j)))

        left_j = randint(0, max(0, js[0] - 2))
        right_j = randint(min(w - 1, js[-1] + 2), w - 1)
        p1 = (randint(0, h - 1), left_j)
        p2 = (randint(0, h - 1), right_j)
        if p1 == p2:
            p2 = ((p2[0] + 1) % h, p2[1])
        gi = fill(gi, linec, frozenset({p1, p2}))
    else:
        nbars = unifint(diff_lb, diff_ub, (3, 6))
        minsep = 4
        maxbars = min(6, (h - 6) // minsep + 1)
        nbars = min(nbars, maxbars)
        span = (nbars - 1) * minsep + 1
        starti_lo = 1
        starti_hi = h - 2 - span
        if starti_hi < starti_lo:
            nbars = 3
            span = (nbars - 1) * minsep + 1
            starti_hi = h - 2 - span
        starti = randint(starti_lo, starti_hi)
        is_ = [starti + k * minsep for k in range(nbars)]
        extra = h - 2 - is_[-1]
        for k in range(1, nbars):
            addgap = randint(0, extra // (nbars - 1) if nbars > 1 else 0)
            is_[k] += addgap
            extra -= addgap
        is_ = sorted(is_)

        centers_j = []
        for i in is_:
            for _ in range(100):
                cj = randint(1, w - 2)
                if all(abs(cj - x) >= 4 for x in centers_j):
                    centers_j.append(cj)
                    break
            else:
                cands = [x for x in range(1, w - 1) if all(abs(x - y) >= 4 for y in centers_j)]
                cj = choice(cands) if len(cands) > 0 else randint(1, w - 2)
                centers_j.append(cj)
        for i, cj in zip(is_, centers_j):
            gi = fill(gi, barc, connect((i, cj - 1), (i, cj + 1)))

        top_i = randint(0, max(0, is_[0] - 2))
        bot_i = randint(min(h - 1, is_[-1] + 2), h - 1)
        p1 = (top_i, randint(0, w - 1))
        p2 = (bot_i, randint(0, w - 1))
        if p1 == p2:
            p2 = (p2[0], (p2[1] + 1) % w)
        gi = fill(gi, linec, frozenset({p1, p2}))

    go = verify_7e576d6e(gi)
    return {'input': gi, 'output': go}


