def generate_7ee1c6ea(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(FIVE, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (8, 16))
    w = unifint(diff_lb, diff_ub, (8, 16))
    top = unifint(diff_lb, diff_ub, (1, max(1, h - 5)))
    left = unifint(diff_lb, diff_ub, (1, max(1, w - 5)))
    bottom = unifint(diff_lb, diff_ub, (top + 3, h - 2))
    right = unifint(diff_lb, diff_ub, (left + 3, w - 2))

    c1, c2 = sample(remove(ZERO, cols), 2)
    outside_cols = remove(c1, remove(c2, cols))

    gi = canvas(ZERO, (h, w))

    out_n = unifint(diff_lb, diff_ub, (max(1, (h * w) // 6), max(1, (h * w) // 3)))
    all_inds = totuple(asindices(gi))
    out_locs = sample(all_inds, min(len(all_inds), out_n))
    for ij in out_locs:
        gi = fill(gi, choice(outside_cols), initset(ij))

    frame = box(frozenset({(top, left), (bottom, right)}))
    gi = fill(gi, FIVE, frame)

    for i in range(top + 1, bottom):
        for j in range(left + 1, right):
            gi = fill(gi, choice((ZERO, c1, c2)), initset((i, j)))

    inside = frozenset((i, j) for i in range(top + 1, bottom) for j in range(left + 1, right))
    obj_inside = toobject(inside, gi)
    pal = difference(palette(obj_inside), frozenset({ZERO, FIVE}))
    if len(pal) < 2:
        cells = totuple(inside)
        if len(cells) >= 2:
            a, b = sample(cells, 2)
            gi = fill(gi, c1, initset(a))
            gi = fill(gi, c2, initset(b))
        elif len(cells) == 1:
            gi = fill(gi, c1, initset(cells[0]))

    go = verify_7ee1c6ea(gi)
    return {'input': gi, 'output': go}


def generate_7f4411dc(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc, fgc = sample(cols, 2)
    nsq = unifint(diff_lb, diff_ub, (1, (h * w) // 15))
    maxtr = 4 * nsq
    tr = 0
    succ = 0
    go = canvas(bgc, (h, w))
    inds = asindices(go)
    while tr < maxtr and succ < nsq:
        oh = randint(2, 6)
        ow = randint(2, 6)
        cands = sfilter(inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
        if len(cands) == 0:
            break
        loc = choice(totuple(cands))
        loci, locj = loc
        obj = backdrop(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
        obj = shift(obj, loc)
        if obj.issubset(inds):
            go = fill(go, fgc, obj)
            succ += 1
            inds = (inds - obj) - outbox(obj)
        tr += 1
    inds = ofcolor(go, bgc)
    nnoise = unifint(diff_lb, diff_ub, (0, len(inds) // 2 - 1))
    gi = tuple(e for e in go)
    for k in range(nnoise):
        loc = choice(totuple(inds))
        inds = inds - dneighbors(loc)
        gi = fill(gi, fgc, {loc})
    return {'input': gi, 'output': go}


def generate_7fe24cdd(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (1, 15))
    w = h
    bgc = choice(cols)
