def generate_84f2aca1(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(1, 10, 1), (5, 7))
    h = unifint(diff_lb, diff_ub, (6, 18))
    w = unifint(diff_lb, diff_ub, (6, 18))
    gi = canvas(0, (h, w))

    nmax = max(1, min(6, (h * w) // 16))
    nframes = unifint(diff_lb, diff_ub, (1, nmax))

    occupied = set()
    halo = set()
    placed = 0
    trials = 0
    maxtrials = 200

    while placed < nframes and trials < maxtrials:
        trials += 1

        fh = unifint(diff_lb, diff_ub, (3, min(5, h)))
        fw = unifint(diff_lb, diff_ub, (3, min(5, w)))
        if fh > h or fw > w:
            continue

        ri = randint(0, h - fh)
        cj = randint(0, w - fw)

        rect = connect((ri, cj), (ri + fh - 1, cj + fw - 1))
        frm = box(rect)
        interior = delta(frm)
        if len(interior) not in (1, 2):
            continue

        if any((i, j) in halo for i, j in frm):
            continue
        if any((i, j) in occupied for i, j in interior):
            continue

        col = choice(cols)
        gi = fill(gi, col, frm)

        occupied |= set(frm) | set(interior)
        for i, j in backdrop(frm):
            for ni, nj in neighbors((i, j)) | frozenset({(i, j)}):
                if 0 <= ni < h and 0 <= nj < w:
                    halo.add((ni, nj))
        placed += 1

    if placed == 0:
        fh, fw = choice(((3, 3), (3, 4), (4, 3)))
        ri = max(0, (h - fh) // 2)
        cj = max(0, (w - fw) // 2)
        rect = connect((ri, cj), (ri + fh - 1, cj + fw - 1))
        frm = box(rect)
        gi = fill(gi, choice(cols), frm)

    go = verify_84f2aca1(gi)
    return {'input': gi, 'output': go}


