def generate_880c1354(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(FOUR, remove(SEVEN, interval(0, 10, 1)))
    ncols = unifint(diff_lb, diff_ub, (2, 4))
    cseq = sample(cols, ncols)

    if ncols == 2:
        h = w = 8
        k = unifint(diff_lb, diff_ub, (2, 6))
        if k == 4:
            k = 3 if choice((True, False)) else 5
        gi = canvas(cseq[0], (h, w))
        for i in range(h):
            for j in range(w):
                if i + j < k:
                    gi = fill(gi, cseq[1], frozenset({(i, j)}))
        for i in range(h):
            for j in range(w):
                if i + j == k:
                    gi = fill(gi, SEVEN, frozenset({(i, j)}))
                elif i + j > k:
                    gi = fill(gi, FOUR, frozenset({(i, j)}))
        if choice((True, False)):
            gi = rot90(gi)
        if choice((True, False)):
            gi = vmirror(gi)
    elif ncols == 3:
        h = w = 8
        gi = canvas(cseq[0], (h, w))
        mode = choice((0, 1))
        if mode == 0:
            k = unifint(diff_lb, diff_ub, (1, 5))
            m = unifint(diff_lb, diff_ub, (4, 7))
            if m <= k + 1:
                m = min(7, k + 2)
            for i in range(h):
                for j in range(w):
                    s = i + j
                    if s < k:
                        gi = fill(gi, cseq[1], frozenset({(i, j)}))
                    elif s > m:
                        gi = fill(gi, cseq[2], frozenset({(i, j)}))
            for i in range(h):
                for j in range(w):
                    s = i + j
                    if s == k or s == m:
                        gi = fill(gi, SEVEN, frozenset({(i, j)}))
                    elif k < s < m:
                        gi = fill(gi, FOUR, frozenset({(i, j)}))
        else:
            k = unifint(diff_lb, diff_ub, (1, 5))
            m = unifint(diff_lb, diff_ub, (4, 7))
            if m <= k + 1:
                m = min(7, k + 2)
            for i in range(h):
                for j in range(w):
                    if i < k:
                        gi = fill(gi, cseq[1], frozenset({(i, j)}))
                    elif i > m:
                        gi = fill(gi, cseq[2], frozenset({(i, j)}))
            for i in range(h):
                for j in range(w):
                    if i == k or i == m:
                        gi = fill(gi, SEVEN, frozenset({(i, j)}))
                    elif k < i < m:
                        gi = fill(gi, FOUR, frozenset({(i, j)}))
        rotf = choice((identity, rot90, rot180, rot270))
        gi = rotf(gi)
    else:
        h = w = 8
        a = unifint(diff_lb, diff_ub, (1, 2))
        b = unifint(diff_lb, diff_ub, (4, 6))
        if b <= a + 1:
            b = a + 2
        if b > 6:
            b = 6
        gi = canvas(cseq[0], (h, w))
        for i in range(h):
            for j in range(w):
                if i + j < a:
                    gi = fill(gi, cseq[1], frozenset({(i, j)}))
                elif i + j > b:
                    gi = fill(gi, cseq[3], frozenset({(i, j)}))
                elif i > j and a <= i + j <= b:
                    gi = fill(gi, cseq[2], frozenset({(i, j)}))
        for i in range(h):
            for j in range(w):
                s = i + j
                if s == a or s == b or (a <= s <= b and i == j):
                    gi = fill(gi, SEVEN, frozenset({(i, j)}))
                elif a < s < b and i < j:
                    gi = fill(gi, FOUR, frozenset({(i, j)}))
        rotf = choice((identity, rot90, rot180, rot270))
        gi = rotf(gi)

    go = verify_880c1354(gi)
    return {'input': gi, 'output': go}


def generate_88207623(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (12, 22))
    w = unifint(diff_lb, diff_ub, (12, 22))
    bgc = 0
    axisc = 2
    shapec = 4
    marker_cols = (1, 3, 5, 6, 7, 8, 9)

    gi = canvas(bgc, (h, w))

    nobj_max = min(3, max(1, w // 6))
    nobj = unifint(diff_lb, diff_ub, (1, nobj_max))

    used_rows = []
    used_axes = []

    for k in range(nobj):
        placed = False
        for _ in range(200):
            ph = unifint(diff_lb, diff_ub, (4, min(7, h - 2)))
            pw = unifint(diff_lb, diff_ub, (2, min(5, w - 4)))

            top = randint(1, h - ph - 1)

            okrow = True
            for a, b in used_rows:
                if not (top + ph + 1 < a or b + 1 < top):
                    okrow = False
                    break
            if not okrow:
                continue

            side = choice((-1, 1))  # shape side relative to axis
            if side == -1:
                axis_j_min = pw + 1
                axis_j_max = w - 3
            else:
                axis_j_min = 2
                axis_j_max = w - pw - 2
            if axis_j_min > axis_j_max:
                continue

            axis_j = randint(axis_j_min, axis_j_max)

            okaxis = True
            for aj in used_axes:
                if abs(axis_j - aj) < 4:
                    okaxis = False
                    break
            if not okaxis:
                continue

            if side == -1:
                left = axis_j - pw
                marker_j_min = axis_j + 1
                marker_j_max = min(w - 1, axis_j + pw)
            else:
                left = axis_j + 1
                marker_j_min = max(0, axis_j - pw)
                marker_j_max = axis_j - 1
            if marker_j_min > marker_j_max:
                continue

            marker_i = randint(top, top + ph - 1)
            marker_j = randint(marker_j_min, marker_j_max)
            marker_c = choice(marker_cols)

            cells = set()
            for i in range(ph):
                roww = unifint(diff_lb, diff_ub, (1, pw))
                startmax = pw - roww
                start = randint(0, startmax)
                for j in range(start, start + roww):
                    cells.add((top + i, left + j))

            if len(cells) == 0:
                continue

            if (marker_i, marker_j) in cells:
                continue

            refl = set()
            bad = False
            for i, j in cells:
                jj = 2 * axis_j - j
                if not (0 <= jj < w):
                    bad = True
                    break
                refl.add((i, jj))
            if bad:
                continue

            if (marker_i, marker_j) not in refl:
                continue

            axis_inds = connect((top, axis_j), (top + ph - 1, axis_j))

            occ = toindices(asobject(gi))
            if len(occ & (frozenset(cells) | refl | axis_inds | frozenset({(marker_i, marker_j)}))) > 0:
                continue

            gi = fill(gi, axisc, axis_inds)
            gi = fill(gi, shapec, frozenset(cells))
            gi = fill(gi, marker_c, frozenset({(marker_i, marker_j)}))

            used_rows.append((top, top + ph - 1))
            used_axes.append(axis_j)
            placed = True
            break

        if not placed:
            # fallback single simple instance
            ph = min(5, h - 2)
            pw = min(3, max(2, w // 4))
            top = max(1, (h - ph) // 2)
            axis_j = max(pw + 1, w // 2)
            if axis_j > w - 3:
                axis_j = w - 3
            left = axis_j - pw
            cells = frozenset({
                (top, left + pw - 1),
                (top + 1, left),
                (top + 1, left + 1),
                (top + 1, left + 2),
                (top + 2, left),
                (top + 2, left + 1),
                (top + 3, left + 1),
            })
            marker_c = choice(marker_cols)
            marker = (top + 1, axis_j + 1)
            gi = canvas(bgc, (h, w))
            gi = fill(gi, axisc, connect((top, axis_j), (top + ph - 1, axis_j)))
            gi = fill(gi, shapec, cells)
            gi = fill(gi, marker_c, frozenset({marker}))
            break

    go = verify_88207623(gi)
    return {'input': gi, 'output': go}


def generate_8886d717(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (8, 20))
    w = unifint(diff_lb, diff_ub, (8, 20))
    side = choice((0, 1, 2, 3))  # top, bottom, left, right

    gi = canvas(7, (h, w))

    if side == 0:
        gi = fill(gi, 9, connect((0, 0), (0, w - 1)))
        away = (1, 0)
        interior_rows = interval(1, h, 1)
        interior_cols = interval(0, w, 1)
    elif side == 1:
        gi = fill(gi, 9, connect((h - 1, 0), (h - 1, w - 1)))
        away = (-1, 0)
        interior_rows = interval(0, h - 1, 1)
        interior_cols = interval(0, w, 1)
    elif side == 2:
        gi = fill(gi, 9, connect((0, 0), (h - 1, 0)))
        away = (0, 1)
        interior_rows = interval(0, h, 1)
        interior_cols = interval(1, w, 1)
    else:
        gi = fill(gi, 9, connect((0, w - 1), (h - 1, w - 1)))
        away = (0, -1)
        interior_rows = interval(0, h, 1)
        interior_cols = interval(0, w - 1, 1)

    cells = frozenset((i, j) for i in interior_rows for j in interior_cols)

    max_rect_h = max(2, min(7, len(interior_rows)))
    max_rect_w = max(2, min(7, len(interior_cols)))
    rh = unifint(diff_lb, diff_ub, (2, max_rect_h))
    rw = unifint(diff_lb, diff_ub, (2, max_rect_w))
    r0 = randint(min(interior_rows), max(interior_rows) - rh + 1)
    c0 = randint(min(interior_cols), max(interior_cols) - rw + 1)
    rect = connect((r0, c0), (r0 + rh - 1, c0 + rw - 1))
    gi = fill(gi, 2, rect)

    extra2 = unifint(diff_lb, diff_ub, (0, max(0, (h * w) // 10)))
    reg2 = set(rect)
    frontier = set(mapply(dneighbors, reg2) & cells)
    for _ in range(extra2):
        cands = tuple(frontier - reg2)
        if len(cands) == 0:
            break
        loc = choice(cands)
        reg2.add(loc)
        frontier |= set(dneighbors(loc) & cells)
    gi = fill(gi, 2, frozenset(reg2))

    all2 = ofcolor(gi, 2)
    absorb_cands = tuple((mapply(dneighbors, all2) & cells) - all2)
    n_absorb = unifint(diff_lb, diff_ub, (1, max(1, min(len(absorb_cands), (h * w) // 12))))
    if len(absorb_cands) > 0:
        for loc in sample(absorb_cands, min(n_absorb, len(absorb_cands))):
            gi = fill(gi, 8, frozenset({loc}))

    all2 = ofcolor(gi, 2)
    all8 = ofcolor(gi, 8)
    safe = set()
    for loc in cells:
        if loc in all2 or loc in all8:
            continue
        if (loc[0] + away[0], loc[1] + away[1]) not in cells:
            continue
        if len(dneighbors(loc) & all2) > 0:
            continue
        if len(dneighbors((loc[0] + away[0], loc[1] + away[1])) & all2) > 0:
            continue
        safe.add(loc)

    safe = tuple(safe)
    n_iso = unifint(diff_lb, diff_ub, (1, max(1, min(len(safe), (h * w) // 8))))
    if len(safe) > 0:
        for loc in sample(safe, min(n_iso, len(safe))):
            gi = fill(gi, 8, frozenset({loc}))

    if len(ofcolor(gi, 8)) == 0:
        fallback = tuple((mapply(dneighbors, ofcolor(gi, 2)) & cells) - ofcolor(gi, 2))
        if len(fallback) > 0:
            gi = fill(gi, 8, frozenset({choice(fallback)}))
        else:
            for loc in cells:
                nxt = (loc[0] + away[0], loc[1] + away[1])
                if nxt in cells:
                    gi = fill(gi, 8, frozenset({loc}))
                    break

    go = verify_8886d717(gi)
    return {'input': gi, 'output': go}


def generate_88a10436(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (8, 30))
    w = unifint(diff_lb, diff_ub, (8, 30))
    objh = unifint(diff_lb, diff_ub, (0, 2))
    objw = unifint(diff_lb, diff_ub, (0 if objh > 0 else 1, 2))
    objh = objh * 2 + 1
    objw = objw * 2 + 1
    bb = asindices(canvas(-1, (objh, objw)))
    sp = (objh // 2, objw // 2)
    obj = {sp}
    bb = remove(sp, bb)
    ncells = unifint(diff_lb, diff_ub, (max(objh, objw), objh * objw))
    for k in range(ncells - 1):
        obj.add(choice(totuple((bb - obj) & mapply(dneighbors, obj))))
    while height(obj) != objh or width(obj) != objw:
        obj.add(choice(totuple((bb - obj) & mapply(dneighbors, obj))))
    bgc, fgc = sample(cols, 2)
    remcols = remove(bgc, remove(fgc, cols))
    ncols = unifint(diff_lb, diff_ub, (1, 8))
    ccols = sample(remcols, ncols)
    obj = {(choice(ccols), ij) for ij in obj}
    obj = normalize(obj)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    loci = randint(0, h - objh)
    locj = randint(0, w - objw)
    loc = (loci, locj)
    plcd = shift(obj, loc)
    gi = paint(gi, plcd)
    go = paint(go, plcd)
    inds = (asindices(gi) - toindices(plcd)) - mapply(neighbors, toindices(plcd))
    nobjs = unifint(diff_lb, diff_ub, (1, (h * w) // (2 * ncells)))
    maxtrials = 4 * nobjs
    tr = 0
    succ = 0
    while succ < nobjs and tr <= maxtrials:
        if len(inds) == 0:
            break
        loc = choice(totuple(inds))
        plcd = shift(obj, loc)
        plcdi = toindices(plcd)
        if plcdi.issubset(inds):
            go = paint(go, plcd)
            gi = fill(gi, fgc, {center(plcdi)})
            succ += 1
            inds = (inds - plcdi) - mapply(dneighbors, plcdi)
        tr += 1
    return {'input': gi, 'output': go}


