def generate_8d510a79(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (1, 2))
    h = unifint(diff_lb, diff_ub, (5, 30))
    w = unifint(diff_lb, diff_ub, (3, 30))
    barloci = randint(2, h - 3)
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    barcol = choice(remcols)
    gi = canvas(bgc, (h, w))
    bar = connect((barloci, 0), (barloci, w - 1))
    gi = fill(gi, barcol, bar)
    go = tuple(e for e in gi)
    jinds = interval(0, w, 1)
    numtop = unifint(diff_lb, diff_ub, (1, w - 1))
    numbot = unifint(diff_lb, diff_ub, (1, w - 1))
    tops = sample(jinds, numtop)
    bots = sample(jinds, numbot)
    for t in tops:
        loci = randint(0, barloci - 2)
        col = choice((1, 2))
        loc = (loci, t)
        gi = fill(gi, col, {loc})
        if col == 1:
            go = fill(go, col, connect(loc, (0, t)))
        else:
            go = fill(go, col, connect(loc, (barloci - 1, t)))
    for t in bots:
        loci = randint(barloci + 2, h - 1)
        col = choice((1, 2))
        loc = (loci, t)
        gi = fill(gi, col, {loc})
        if col == 1:
            go = fill(go, col, connect(loc, (h - 1, t)))
        else:
            go = fill(go, col, connect(loc, (barloci + 1, t)))
    if choice((True, False)):
        gi = dmirror(gi)
        go = dmirror(go)
    return {'input': gi, 'output': go}


def generate_8dab14c2(diff_lb: float, diff_ub: float) -> dict:
    bgc = 8
    fgc = 1
    for _ in range(100):
        h = unifint(diff_lb, diff_ub, (12, 20))
        w = unifint(diff_lb, diff_ub, (12, 20))

        rh = unifint(diff_lb, diff_ub, (3, max(3, min(6, h - 4))))
        cw = unifint(diff_lb, diff_ub, (2, max(2, min(5, w - 4))))
        rw = unifint(diff_lb, diff_ub, (6, max(6, w - 3)))
        ch = unifint(diff_lb, diff_ub, (6, max(6, h - 3)))

        if rw < cw + 2 or ch < rh + 2:
            continue

        r0max = h - ch
        c0max = w - rw
        if r0max < 1 or c0max < 1:
            continue

        r0 = unifint(diff_lb, diff_ub, (1, r0max))
        c0 = unifint(diff_lb, diff_ub, (1, c0max))

        vr0 = r0
        vc0 = c0 + unifint(diff_lb, diff_ub, (1, rw - cw - 1))
        hr0 = r0 + unifint(diff_lb, diff_ub, (1, ch - rh - 1))
        hc0 = c0

        vrect = backdrop(frozenset({(vr0, vc0), (vr0 + ch - 1, vc0 + cw - 1)}))
        hrect = backdrop(frozenset({(hr0, hc0), (hr0 + rh - 1, hc0 + rw - 1)}))
        cross = vrect | hrect

        gi = canvas(bgc, (h, w))
        gi = fill(gi, fgc, cross)

        holes = set()
        protrusions = set()

        n_holes = unifint(diff_lb, diff_ub, (1, max(1, min(4, (rh + cw) // 2))))
        n_prots = unifint(diff_lb, diff_ub, (1, max(1, min(4, (rh + cw) // 2))))

        hole_candidates = []
        for i in range(hr0, hr0 + rh):
            for j in range(hc0, hc0 + rw):
                if not (vc0 <= j <= vc0 + cw - 1):
                    if hr0 > 0 or hr0 + rh < h - 1:
                        hole_candidates.append((i, j))
        for i in range(vr0, vr0 + ch):
            for j in range(vc0, vc0 + cw):
                if not (hr0 <= i <= hr0 + rh - 1):
                    if vc0 > 0 or vc0 + cw < w - 1:
                        hole_candidates.append((i, j))
        hole_candidates = list(dedupe(tuple(hole_candidates)))
        shuffle(hole_candidates)

        for cell in hole_candidates:
            if len(holes) >= n_holes:
                break
            i, j = cell
            added = False
            if hr0 <= i <= hr0 + rh - 1 and hc0 <= j <= hc0 + rw - 1 and not (vc0 <= j <= vc0 + cw - 1):
                if hr0 > 0 and hr0 + rh < h - 1:
                    if choice((True, False)):
                        protrusions.add((hr0 - 1, j))
                    else:
                        protrusions.add((hr0 + rh, j))
                    added = True
                elif hr0 > 0:
                    protrusions.add((hr0 - 1, j))
                    added = True
                elif hr0 + rh < h:
                    protrusions.add((hr0 + rh, j))
                    added = True
            elif vr0 <= i <= vr0 + ch - 1 and vc0 <= j <= vc0 + cw - 1 and not (hr0 <= i <= hr0 + rh - 1):
                if vc0 > 0 and vc0 + cw < w - 1:
                    if choice((True, False)):
                        protrusions.add((i, vc0 - 1))
                    else:
                        protrusions.add((i, vc0 + cw))
                    added = True
                elif vc0 > 0:
                    protrusions.add((i, vc0 - 1))
                    added = True
                elif vc0 + cw < w:
                    protrusions.add((i, vc0 + cw))
                    added = True
            if added:
                holes.add(cell)

        prot_candidates = []
        if hr0 > 0:
            for j in range(hc0, hc0 + rw):
                if not (vc0 <= j <= vc0 + cw - 1):
                    prot_candidates.append((hr0 - 1, j))
        if hr0 + rh < h:
            for j in range(hc0, hc0 + rw):
                if not (vc0 <= j <= vc0 + cw - 1):
                    prot_candidates.append((hr0 + rh, j))
        if vc0 > 0:
            for i in range(vr0, vr0 + ch):
                if not (hr0 <= i <= hr0 + rh - 1):
                    prot_candidates.append((i, vc0 - 1))
        if vc0 + cw < w:
            for i in range(vr0, vr0 + ch):
                if not (hr0 <= i <= hr0 + rh - 1):
                    prot_candidates.append((i, vc0 + cw))
        prot_candidates = [p for p in dedupe(tuple(prot_candidates)) if p not in protrusions]
        shuffle(prot_candidates)

        for cell in prot_candidates:
            if len(protrusions) >= n_prots:
                break
            i, j = cell
            added = False
            if j < vc0 or j > vc0 + cw - 1:
                if vr0 <= i <= vr0 + ch - 1 and not (hr0 <= i <= hr0 + rh - 1):
                    if j < vc0:
                        holes.add((i, vc0))
                    else:
                        holes.add((i, vc0 + cw - 1))
                    added = True
            if not added and (i < hr0 or i > hr0 + rh - 1):
                if hc0 <= j <= hc0 + rw - 1 and not (vc0 <= j <= vc0 + cw - 1):
                    if i < hr0:
                        holes.add((hr0, j))
                    else:
                        holes.add((hr0 + rh - 1, j))
                    added = True
            if added:
                protrusions.add(cell)

        if len(holes) == 0 and len(protrusions) == 0:
            continue

        gi = fill(gi, bgc, frozenset(holes))
        gi = fill(gi, fgc, frozenset(protrusions))

        go = verify_8dab14c2(gi)
        if gi != go and palette(gi) == frozenset({bgc, fgc}):
            return {'input': gi, 'output': go}

    h, w = 14, 15
    gi = canvas(8, (h, w))
    vrect = backdrop(frozenset({(2, 9), (11, 12)}))
    hrect = backdrop(frozenset({(7, 2), (11, 12)}))
    gi = fill(gi, 1, vrect | hrect)
    gi = fill(gi, 8, frozenset({(11, 11)}))
    gi = fill(gi, 1, frozenset({(9, 13)}))
    go = verify_8dab14c2(gi)
    return {'input': gi, 'output': go}


def generate_8dae5dfc(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (14, 30))
    w = unifint(diff_lb, diff_ub, (14, 30))
    gi = canvas(0, (h, w))

    nobj_max = max(1, min(4, (h * w) // 80))
    nobj = unifint(diff_lb, diff_ub, (1, nobj_max))

    occ = set()
    tries = 0
    succ = 0
    maxtries = 80

    allcols = remove(0, interval(0, 10, 1))

    while succ < nobj and tries < maxtries:
        tries += 1

        layers = unifint(diff_lb, diff_ub, (2, 5))
        minside = 2 * layers - 1
        oh = unifint(diff_lb, diff_ub, (minside, min(15, h - 1)))
        ow = unifint(diff_lb, diff_ub, (minside, min(15, w - 1)))
        if oh < minside or ow < minside:
            continue

        max_i = h - oh
        max_j = w - ow
        if max_i < 0 or max_j < 0:
            continue

        loci = unifint(diff_lb, diff_ub, (0, max_i))
        locj = unifint(diff_lb, diff_ub, (0, max_j))

        bbox = backdrop(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
        halo = bbox | mapply(neighbors, bbox)
        if len(halo & occ) > 0:
            continue

        if layers > len(allcols):
            layers = len(allcols)
        cols = sample(tuple(allcols), layers)

        g2 = gi
        for d in range(layers):
            top = loci + d
            left = locj + d
            bot = loci + oh - 1 - d
            right = locj + ow - 1 - d
            rect = backdrop(frozenset({(top, left), (bot, right)}))
            g2 = fill(g2, cols[d], rect)

        gi = g2
        occ |= halo
        succ += 1

    if succ == 0:
        layers = 3
        oh = 2 * layers
        ow = 2 * layers
        loci = max(0, (h - oh) // 2)
        locj = max(0, (w - ow) // 2)
        cols = sample(tuple(allcols), layers)
        for d in range(layers):
            top = loci + d
            left = locj + d
            bot = loci + oh - 1 - d
            right = locj + ow - 1 - d
            rect = backdrop(frozenset({(top, left), (bot, right)}))
            gi = fill(gi, cols[d], rect)

    go = verify_8dae5dfc(gi)
    return {'input': gi, 'output': go}


def generate_8e1813be(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc, sqc = sample(cols, 2)
    remcols = remove(bgc, remove(sqc, cols))
    nbars = unifint(diff_lb, diff_ub, (3, 8))
    ccols = sample(remcols, nbars)
    w = unifint(diff_lb, diff_ub, (nbars+3, 30))
    hmarg = unifint(diff_lb, diff_ub, (2 * nbars, 30 - nbars))
    ccols = list(ccols)
    go = tuple(repeat(col, nbars) for col in ccols)
    gi = tuple(repeat(col, w) for col in ccols)
    r = repeat(bgc, w)
    for k in range(hmarg):
        idx = randint(0, len(go) - 1)
        gi = gi[:idx] + (r,) + gi[idx:]
    h2 = nbars + hmarg
    oh, ow = nbars, nbars
    loci = randint(1, h2 - oh - 2)
    locj = randint(1, w - ow - 2)
    sq = backdrop(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
    gi = fill(gi, sqc, sq)
    gi = fill(gi, bgc, outbox(sq))
    if choice((True, False)):
        gi = dmirror(gi)
        go = dmirror(go)
    return {'input': gi, 'output': go}


