def generate_902510d5(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    for _ in range(100):
        h = unifint(diff_lb, diff_ub, (6, 15))
        w = unifint(diff_lb, diff_ub, (6, 15))
        bgc = 0
        mainc = choice(cols)
        remcols = remove(mainc, cols)

        corner = choice(((0, 0), (0, w - 1), (h - 1, 0), (h - 1, w - 1)))
        maxtri = min(h, w)
        if maxtri < 2:
            continue
        n_single = unifint(diff_lb, diff_ub, (2, maxtri))
        wedgec = choice(remcols)

        gi = canvas(bgc, (h, w))

        # build one large connected monochrome pattern, not touching corners
        ph = unifint(diff_lb, diff_ub, (3, max(3, min(8, h - 1))))
        pw = unifint(diff_lb, diff_ub, (3, max(3, min(8, w - 1))))
        ph = min(ph, h)
        pw = min(pw, w)
        if ph < 3 or pw < 3:
            continue

        mini = 1 if h - ph >= 2 else 0
        maxi = h - ph - 1 if h - ph >= 2 else h - ph
        minj = 1 if w - pw >= 2 else 0
        maxj = w - pw - 1 if w - pw >= 2 else w - pw
        if maxi < mini or maxj < minj:
            continue
        oi = randint(mini, maxi)
        oj = randint(minj, maxj)

        bounds = asindices(canvas(-1, (ph, pw)))
        start = choice(totuple(bounds))
        shp = {start}
        target = unifint(diff_lb, diff_ub, (5, min(len(bounds), max(5, (ph * pw * 2) // 3))))
        for _k in range(target - 1):
            frontier = (bounds - shp) & mapply(dneighbors, shp)
            if len(frontier) == 0:
                break
            shp.add(choice(totuple(frontier)))
        shp = normalize(frozenset(shp))
        if len(shp) < 5:
            continue
        pobj = shift(recolor(mainc, shp), (oi, oj))
        if len(pobj) <= n_single:
            continue
        gi = paint(gi, pobj)

        pinds = toindices(pobj)
        forbidden = pinds | mapply(neighbors, pinds)

        # choose singleton positions, exactly one in a corner
        allinds = asindices(gi)
        freeinds = allinds - forbidden
        freeinds = freeinds - corners(allinds)
        if len(freeinds) < n_single - 1:
            continue

        singles = {corner}
        free_list = list(totuple(freeinds))
        shuffle(free_list)
        ok = True
        for loc in free_list:
            if len(singles) >= n_single:
                break
            if all(loc not in neighbors(s) and loc != s for s in singles):
                singles.add(loc)
        if len(singles) != n_single:
            ok = False
        if not ok:
            continue

        # colors for singleton cells, wedge color is majority among discarded singletons
        othercols = remove(wedgec, remcols)
        single_cells = []
        for loc in singles:
            if loc == corner:
                c = wedgec
            else:
                if len(othercols) > 0 and choice((True, False)):
                    c = choice(othercols)
                else:
                    c = wedgec
            single_cells.append((c, loc))

        # ensure wedge color is unique majority
        cntw = sum(1 for c, _ in single_cells if c == wedgec)
        if cntw <= n_single // 2:
            need = n_single // 2 + 1 - cntw
            changed = 0
            newcells = []
            for c, loc in single_cells:
                if loc != corner and c != wedgec and changed < need:
                    newcells.append((wedgec, loc))
                    changed += 1
                else:
                    newcells.append((c, loc))
            single_cells = newcells

        gi = paint(gi, frozenset(single_cells))
        go = verify_902510d5(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    # fallback
    h, w = 8, 8
    gi = canvas(0, (h, w))
    mainobj = frozenset({
        (8, (2, 4)), (8, (3, 3)), (8, (4, 2)), (8, (4, 3)),
        (8, (5, 2)), (8, (5, 4)), (8, (6, 5))
    })
    gi = paint(gi, mainobj)
    gi = paint(gi, frozenset({(7, (0, 0)), (7, (7, 7)), (4, (1, 6))}))
    go = verify_902510d5(gi)
    return {'input': gi, 'output': go}


def generate_90347967(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (3, 12))
    w = unifint(diff_lb, diff_ub, (3, 12))
    gi = canvas(0, (h, w))

    pi = unifint(diff_lb, diff_ub, (0, h - 1))
    pj = unifint(diff_lb, diff_ub, (0, w - 1))
    pivot = (pi, pj)
    gi = fill(gi, 5, initset(pivot))

    maxrad_i = min(pi, h - 1 - pi)
    maxrad_j = min(pj, w - 1 - pj)

    candidates = []
    for i in range(h):
        for j in range(w):
            if (i, j) == pivot:
                continue
            ri = 2 * pi - i
            rj = 2 * pj - j
            if 0 <= ri < h and 0 <= rj < w:
                if i < pi or (i == pi and j < pj):
                    candidates.append((i, j))

    if len(candidates) == 0:
        if maxrad_i > 0:
            candidates = [(pi - 1, pj)]
        elif maxrad_j > 0:
            candidates = [(pi, pj - 1)]
        else:
            if pi > 0:
                candidates = [(pi - 1, pj)]
            elif pj > 0:
                candidates = [(pi, pj - 1)]
            elif pi < h - 1:
                candidates = [(pi + 1, pj)]
            else:
                candidates = [(pi, pj + 1)]

    maxn = len(candidates)
    nobj = unifint(diff_lb, diff_ub, (1, maxn))
    locs = sample(candidates, nobj)

    cols = remove(5, interval(1, 10, 1))
    for loc in locs:
        gi = fill(gi, choice(cols), initset(loc))

    go = verify_90347967(gi)
    return {'input': gi, 'output': go}


def generate_90c28cc7(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
