def generate_93b4f4b3(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(ZERO, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (8, 20))
    halfw = unifint(diff_lb, diff_ub, (4, 10))
    bgc = choice(cols)
    avail_shape_cols = remove(bgc, cols)
    maxobjs = min(4, len(avail_shape_cols), h // 2)
    nobjs = unifint(diff_lb, diff_ub, (2, maxobjs))
    shape_cols = sample(tuple(avail_shape_cols), nobjs)

    left = canvas(bgc, (h, halfw))
    right = canvas(ZERO, (h, halfw))

    rows = list(range(1, h - 1))
    shuffle(rows)
    starts = sorted(rows[:nobjs])

    def rand_shape(oh, ow):
        bounds = asindices(canvas(-1, (oh, ow)))
        cells = {choice(totuple(bounds))}
        target = unifint(diff_lb, diff_ub, (max(2, (oh * ow) // 3), max(2, oh * ow - 1)))
        for _ in range(200):
            if len(cells) >= target and shape(frozenset(cells)) == (oh, ow):
                break
            frontier = (bounds - frozenset(cells)) & mapply(dneighbors, frozenset(cells))
            if len(frontier) == 0:
                frontier = bounds - frozenset(cells)
            if len(frontier) == 0:
                break
            cells.add(choice(totuple(frontier)))
        inds = frozenset(cells)
        for _ in range(200):
            if shape(inds) == (oh, ow):
                break
            frontier = (bounds - inds) & mapply(dneighbors, inds)
            if len(frontier) == 0:
                frontier = bounds - inds
            if len(frontier) == 0:
                break
            inds = inds | frozenset({choice(totuple(frontier))})
        return normalize(inds)

    used_norms = []
    placed = 0
    for idx in range(nobjs):
        rem = nobjs - idx - 1
        top = starts[idx]
        bottom_limit = starts[idx + 1] - 1 if idx < nobjs - 1 else h - 2
        maxh = bottom_limit - top + 1
        if maxh < 2:
            continue
        oh = unifint(diff_lb, diff_ub, (2, maxh))
        ow = unifint(diff_lb, diff_ub, (2, halfw - 1))
        shp = None
        for _ in range(100):
            cand = rand_shape(oh, ow)
            if all(toindices(cand) != prev for prev in used_norms):
                shp = cand
                break
        if shp is None:
            continue
        used_norms.append(toindices(shp))
        color = shape_cols[idx]
        left = fill(left, ZERO, shift(shp, (top, 1)))
        rj = randint(1, halfw - ow)
        right = fill(right, color, shift(shp, (top, rj)))
        placed += 1

    if placed == 0:
        oh = 2
        ow = 2
        shp = frozenset({(0, 0), (0, 1), (1, 0)})
        left = fill(left, ZERO, shift(shp, (1, 1)))
        right = fill(right, shape_cols[0], shift(shp, (1, 1)))

    gi = hconcat(left, right)
    go = verify_93b4f4b3(gi)
    return {'input': gi, 'output': go}


def generate_93b581b8(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    numcols = unifint(diff_lb, diff_ub, (1, 9))
    ccols = sample(remcols, numcols)
    numocc = unifint(diff_lb, diff_ub, (1, (h * w) // 50))
    succ = 0
    tr = 0
    maxtr = 10 * numocc
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    inds = asindices(gi)
    fullinds = asindices(gi)
    while tr < maxtr and succ < numocc:
        tr += 1
        cands = sfilter(inds, lambda ij: ij[0] <= h - 2 and ij[1] <= w - 2)
        if len(cands) == 0:
            break
        loc = choice(totuple(cands))
        c1, c2, c3, c4 = [choice(ccols) for k in range(4)]
        q = {(0, 0), (0, 1), (1, 0), (1, 1)}
        inobj = {(c1, (0, 0)), (c2, (0, 1)), (c3, (1, 0)), (c4, (1, 1))}
        outobj = inobj | recolor(c4, shift(q, (-2, -2))) | recolor(c3, shift(q, (-2, 2))) | recolor(c2, shift(q, (2, -2))) | recolor(c1, shift(q, (2, 2)))
        inobjplcd = shift(inobj, loc)
        outobjplcd = shift(outobj, loc)
        outobjplcd = sfilter(outobjplcd, lambda cij: cij[1] in fullinds)
        outobjplcdi = toindices(outobjplcd)
        if outobjplcdi.issubset(inds):
            succ += 1
            inds = (inds - outobjplcdi) - mapply(dneighbors, toindices(inobjplcd))
            gi = paint(gi, inobjplcd)
            go = paint(go, outobjplcd)
    return {'input': gi, 'output': go}


def generate_93c31fbe(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(1, remove(0, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (18, 30))
    framec = choice(cols)
    gi = canvas(0, (h, w))

    ngroups_max = max(1, min(4, (h * w) // 80))
    ngroups = unifint(diff_lb, diff_ub, (1, ngroups_max))

    occupied = set()
    groups = []
    tries = 0
    maxtries = 300

    while len(groups) < ngroups and tries < maxtries:
        tries += 1
        # meta-rectangle dimensions (must be non-square so reflection axis is unambiguous)
        mh = unifint(diff_lb, diff_ub, (4, min(12, h - 2)))
        mw = unifint(diff_lb, diff_ub, (4, min(12, w - 2)))
        if mh == mw:
            if mw < min(12, w - 2):
                mw += 1
            elif mh > 4:
                mh -= 1
            else:
                continue
        # top-left of meta-rectangle
        ri = randint(0, h - mh - 1)
        rj = randint(0, w - mw - 1)
        # halo for spacing
        halo = set()
        for r in range(max(0, ri - 2), min(h, ri + mh + 2)):
            for c in range(max(0, rj - 2), min(w, rj + mw + 2)):
                halo.add((r, c))
        if len(halo & occupied) > 0:
            continue
        # corners of meta-rectangle
        # UL corner mark at (ri, rj): 2x2 L missing LR cell
        # UR corner mark at (ri, rj+mw-1): 2x2 L missing LL cell
        # LL corner mark at (ri+mh-1, rj): 2x2 L missing UR cell
        # LR corner mark at (ri+mh-1, rj+mw-1): 2x2 L missing UL cell
        ul_r, ul_c = ri, rj
        ur_r, ur_c = ri, rj + mw - 1
        ll_r, ll_c = ri + mh - 1, rj
        lr_r, lr_c = ri + mh - 1, rj + mw - 1
        # Check bounds for 2x2 marks
        if ul_r + 1 >= h or ul_c + 1 >= w:
            continue
        if ur_r + 1 >= h or ur_c + 1 >= w:
            continue
        if ll_r + 1 >= h or ll_c + 1 >= w:
            continue
        if lr_r + 1 >= h or lr_c + 1 >= w:
            continue
        # UL mark (missing LR = bottom-right of 2x2): type 0
        ul_mark = frozenset({(ul_r, ul_c), (ul_r, ul_c + 1), (ul_r + 1, ul_c)})
        # UR mark (missing LL = bottom-left of 2x2): type 1
        ur_mark = frozenset({(ur_r, ur_c), (ur_r, ur_c + 1), (ur_r + 1, ur_c + 1)})
        # LL mark (missing UR = top-right of 2x2): type 2
        ll_mark = frozenset({(ll_r, ll_c), (ll_r + 1, ll_c), (ll_r + 1, ll_c + 1)})
        # LR mark (missing UL = top-left of 2x2): type 3
        lr_mark = frozenset({(lr_r + 1, lr_c), (lr_r, lr_c + 1), (lr_r + 1, lr_c + 1)})
        all_marks = ul_mark | ur_mark | ll_mark | lr_mark
        gi = fill(gi, framec, all_marks)
        groups.append((ri, rj, mh, mw))
        occupied |= halo

    if len(groups) == 0:
        # fallback: place one group
        mh, mw = 6, 8
        ri, rj = 2, 2
        ul_mark = frozenset({(ri, rj), (ri, rj + 1), (ri + 1, rj)})
        ur_mark = frozenset({(ri, rj + mw - 1), (ri, rj + mw), (ri + 1, rj + mw)})
        ll_mark = frozenset({(ri + mh - 1, rj), (ri + mh, rj), (ri + mh, rj + 1)})
        lr_mark = frozenset({(ri + mh, rj + mw - 1), (ri + mh - 1, rj + mw), (ri + mh, rj + mw)})
        gi = fill(gi, framec, ul_mark | ur_mark | ll_mark | lr_mark)
        groups.append((ri, rj, mh, mw))

    # Add 1-cells inside each meta-rectangle (in one half for reflection)
    onecells = set()
    for (ri, rj, mh, mw) in groups:
        # interior of meta-rectangle (excluding corners' 2x2 regions)
        interior = set()
        for r in range(ri, ri + mh + 1):
            for c in range(rj, rj + mw + 1):
                interior.add((r, c))
        # remove frame-colored cells
        frame_cells = ofcolor(gi, framec)
        interior -= frame_cells
        if mh > mw:
            # taller: reflect vertically (across horizontal axis)
            # place 1s in top half
            mid_r = ri + mh // 2
            half = set()
            for (r, c) in interior:
                if r <= mid_r:
                    half.add((r, c))
        else:
            # wider: reflect horizontally (across vertical axis)
            # place 1s in left half
            mid_c = rj + mw // 2
            half = set()
            for (r, c) in interior:
                if c <= mid_c:
                    half.add((r, c))
        half_list = list(half)
        if len(half_list) == 0:
            continue
        nseed_hi = max(1, min(len(half_list), max(1, (mh * mw) // 6)))
        nseed = unifint(diff_lb, diff_ub, (1, nseed_hi))
        seeds = sample(half_list, nseed)
        onecells |= set(seeds)

    gi = fill(gi, 1, frozenset(onecells))

    # Add noise 1-cells outside all meta-rectangles
    all_meta = set()
    for (ri, rj, mh, mw) in groups:
        for r in range(ri, ri + mh + 2):
            for c in range(rj, rj + mw + 2):
                all_meta.add((r, c))
    free = set()
    for r in range(h):
        for c in range(w):
            if (r, c) not in all_meta and gi[r][c] == 0:
                free.add((r, c))
    free = list(free)
    if len(free) > 0:
        nnoise_hi = max(1, min(len(free), max(1, (h * w) // 25)))
        nnoise = unifint(diff_lb, diff_ub, (1, nnoise_hi))
        noise = sample(free, nnoise)
        gi = fill(gi, 1, frozenset(noise))

    go = verify_93c31fbe(gi)
    return {'input': gi, 'output': go}


def generate_94133066(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, remove(1, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (18, 30))

    ph = unifint(diff_lb, diff_ub, (8, min(14, h - 6)))
    pw = unifint(diff_lb, diff_ub, (8, min(14, w - 6)))

    loci = randint(1, h - ph - 1)
    locj = randint(1, w - pw - 1)

    gi = canvas(0, (h, w))
    patch = canvas(1, (ph, pw))

    nmark = choice((3, 4))
    markcols = sample(cols, nmark)

    corner_pos = ((1, 1), (1, pw - 2), (ph - 2, 1), (ph - 2, pw - 2))
    chosen_corner_ids = sample((0, 1, 2, 3), nmark)
    corner_color_map = {}
    for cid, c in zip(chosen_corner_ids, markcols):
        corner_color_map[cid] = c
        patch = fill(patch, c, frozenset({corner_pos[cid]}))

    interior = frozenset((i, j) for i in range(1, ph - 1) for j in range(1, pw - 1))
    forbidden = frozenset(corner_pos)
    fillable = difference(interior, forbidden)

    pattern_color = choice(remove(1, remove(0, markcols)))
    ncells = unifint(diff_lb, diff_ub, (max(3, (ph * pw) // 12), max(4, (ph * pw) // 5)))
    ncells = min(ncells, len(fillable))
    cells = frozenset(sample(totuple(fillable), ncells))
    patch = fill(patch, pattern_color, cells)

    extra_colors = remove(pattern_color, remove(1, remove(0, markcols)))
    nextra = unifint(diff_lb, diff_ub, (0, min(3, len(extra_colors))))
    if nextra > 0:
        excols = sample(extra_colors, nextra)
        rem = tuple(c for c in fillable if c not in cells)
        shuffle(rem := list(rem))
        idx = 0
        for ec in excols:
            if idx >= len(rem):
                break
            k = unifint(diff_lb, diff_ub, (1, min(4, len(rem) - idx)))
            pts = frozenset(rem[idx:idx + k])
            idx += k
            patch = fill(patch, ec, pts)

    tfs = (identity, rot90, rot180, rot270, hmirror, vmirror, dmirror, cmirror)
    tf = choice(tfs)
    shown_patch = tf(patch)

    gi = paint(gi, shift(asobject(shown_patch), (loci, locj)))

    outside = set()
    rectbox = frozenset((i, j) for i in range(loci, loci + height(shown_patch)) for j in range(locj, locj + width(shown_patch)))
    for i in range(h):
        for j in range(w):
            if (i, j) not in rectbox:
                outside.add((i, j))
    outside = tuple(outside)

    out_h = height(shown_patch)
    out_w = width(shown_patch)
    marker_targets = (
        (loci + 1, locj + 1),
        (loci + 1, locj + out_w - 2),
        (loci + out_h - 2, locj + 1),
        (loci + out_h - 2, locj + out_w - 2),
    )

    used = set()
    for cid, c in corner_color_map.items():
        target = marker_targets[cid]
        cands = [p for p in outside if p not in used and p[0] != target[0] and p[1] != target[1]]
        if len(cands) == 0:
            cands = [p for p in outside if p not in used]
        pos = choice(cands)
        used.add(pos)
        gi = fill(gi, c, frozenset({pos}))

    go = verify_94133066(gi)
    return {'input': gi, 'output': go}


def generate_941d9a10(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (1, 2, 3))
    h = unifint(diff_lb, diff_ub, (5, 30))
    w = unifint(diff_lb, diff_ub, (5, 30))
    opts = interval(2, (h-1)//2 + 1, 2)
    nhidx = unifint(diff_lb, diff_ub, (0, len(opts) - 1))
    nh = opts[nhidx]
    opts = interval(2, (w-1)//2 + 1, 2)
    nwidx = unifint(diff_lb, diff_ub, (0, len(opts) - 1))
    nw = opts[nwidx]
    bgc, fgc = sample(cols, 2)
    hgrid = canvas(bgc, (2*nh+1, w))
    for j in range(1, h, 2):
        hgrid = fill(hgrid, fgc, connect((j, 0), (j, w)))
    for k in range(h - (2*nh+1)):
        loc = randint(0, height(hgrid) - 1)
        hgrid = hgrid[:loc] + canvas(bgc, (1, w)) + hgrid[loc:]
    wgrid = canvas(bgc, (2*nw+1, h))
    for j in range(1, w, 2):
        wgrid = fill(wgrid, fgc, connect((j, 0), (j, h)))
    for k in range(w - (2*nw+1)):
        loc = randint(0, height(wgrid) - 1)
        wgrid = wgrid[:loc] + canvas(bgc, (1, h)) + wgrid[loc:]
    wgrid = dmirror(wgrid)
    gi = canvas(bgc, (h, w))
    fronts = ofcolor(hgrid, fgc) | ofcolor(wgrid, fgc)
    gi = fill(gi, fgc, fronts)
    objs = objects(gi, T, T, F)
    objs = colorfilter(objs, bgc)
    blue = argmin(objs, lambda o: leftmost(o) + uppermost(o))
    green = argmax(objs, lambda o: leftmost(o) + uppermost(o))
    f1 = lambda o: len(sfilter(objs, lambda o2: leftmost(o2) < leftmost(o))) == len(sfilter(objs, lambda o2: leftmost(o2) > leftmost(o)))
    f2 = lambda o: len(sfilter(objs, lambda o2: uppermost(o2) < uppermost(o))) == len(sfilter(objs, lambda o2: uppermost(o2) > uppermost(o)))
    red = extract(objs, lambda o: f1(o) and f2(o))
    go = fill(gi, 1, blue)
    go = fill(go, 3, green)
    go = fill(go, 2, red)
    return {'input': gi, 'output': go}


