def generate_94be5b80(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(ZERO, interval(0, 10, 1))

    ph = unifint(diff_lb, diff_ub, (3, 6))
    pw = unifint(diff_lb, diff_ub, (4, 8))
    ncols = unifint(diff_lb, diff_ub, (3, 5))

    maxh = min(30, ph * ncols + ph + 8)
    h = unifint(diff_lb, diff_ub, (ph * ncols + 1, maxh))
    w = unifint(diff_lb, diff_ub, (max(pw + 4, ncols + 4), min(30, pw + 10)))

    keycols = sample(cols, ncols)
    basec = choice(keycols)
    present_count = unifint(diff_lb, diff_ub, (1, max(1, ncols - 1)))
    present_cols = sample(keycols, present_count)
    if basec not in present_cols:
        present_cols[0] = basec
        shuffle(present_cols)

    shape_cells = set()
    total = ph * pw
    target = unifint(diff_lb, diff_ub, (max(4, total // 3), max(4, total - 1)))
    seed = (randint(0, ph - 1), randint(0, pw - 1))
    shape_cells.add(seed)
    frontier = set(neighbors(seed) & asindices(canvas(0, (ph, pw))))
    tries = 0
    while len(shape_cells) < target and tries < total * 10:
        tries += 1
        if len(frontier) == 0:
            frontier = set(mapply(neighbors, frozenset(shape_cells)) & asindices(canvas(0, (ph, pw))))
            frontier -= shape_cells
            if len(frontier) == 0:
                break
        cell = choice(tuple(frontier))
        shape_cells.add(cell)
        frontier |= set(neighbors(cell) & asindices(canvas(0, (ph, pw))))
        frontier -= shape_cells

    shape_norm = frozenset(shape_cells)
    if len(shape_norm) < 4:
        shape_norm = frozenset({(0, 0), (0, 1), (1, 0), (1, 1)})

    key_top = randint(0, max(0, h - 3))
    key_left = randint(0, max(0, w - ncols))

    base_index = keycols.index(basec)
    min_top = max(0, key_top - base_index * ph)
    max_top = min(h - ph * ncols, key_top + (ncols - 1 - base_index) * ph)
    if min_top > max_top:
        stack_top = max(0, min(h - ph * ncols, key_top))
    else:
        stack_top = randint(min_top, max_top)

    stack_left_candidates = [j for j in range(0, w - pw + 1) if j > key_left + ncols or j + pw <= key_left - 1]
    if len(stack_left_candidates) == 0:
        stack_left = randint(0, w - pw)
    else:
        stack_left = choice(stack_left_candidates)

    gi = canvas(ZERO, (h, w))

    for idx, c in enumerate(keycols):
        bar = connect((key_top, key_left + idx), (key_top + 2, key_left + idx))
        gi = fill(gi, c, bar)

    for c in present_cols:
        idx = keycols.index(c)
        top = stack_top + idx * ph
        obj = shift(shape_norm, (top, stack_left))
        gi = fill(gi, c, obj)

    go = verify_94be5b80(gi)
    return {'input': gi, 'output': go}


