def generate_97a05b5b(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (15, 30))
    w = unifint(diff_lb, diff_ub, (15, 30))
    sgh = randint(h//3, h//3*2)
    sgw = randint(w//3, w//3*2)
    bgc, sqc = sample(cols, 2)
    remcols = remove(bgc, remove(sqc, cols))
    gi = canvas(bgc, (h, w))
    oh = randint(2, sgh//2)
    ow = randint(2, sgw//2)
    nobjs = unifint(diff_lb, diff_ub, (1, 8))
    objs = set()
    cands = asindices(canvas(-1, (oh, ow)))
    forbidden = set()
    tr = 0
    maxtr = 4 * nobjs
    while len(objs) != nobjs and tr < maxtr:
        tr += 1
        obj = {choice(totuple(cands))}
        ncells = randint(1, oh * ow - 1)
        for k in range(ncells - 1):
            obj.add(choice(totuple((cands - obj) & mapply(neighbors, obj))))
        obj |= choice((dmirror, cmirror, vmirror, hmirror))(obj)
        if len(obj) == height(obj) * width(obj):
            continue
        obj = frozenset(obj)
        objn = normalize(obj)
        if objn not in forbidden:
            objs.add(objn)
        for augmf1 in (identity, dmirror, cmirror, hmirror, vmirror):
            for augmf2 in (identity, dmirror, cmirror, hmirror, vmirror):
                forbidden.add(augmf1(augmf2(objn)))
    tr = 0
    maxtr = 5 * nobjs
    succ = 0
    loci = randint(0, h - sgh)
    locj = randint(0, w - sgw)
    bd = backdrop(frozenset({(loci, locj), (loci + sgh - 1, locj + sgw - 1)}))
    gi = fill(gi, sqc, bd)
    go = canvas(sqc, (sgh, sgw))
    goinds = asindices(go)
    giinds = asindices(gi) - shift(goinds, (loci, locj))
    giinds = giinds - mapply(neighbors, shift(goinds, (loci, locj)))
    while succ < nobjs and tr < maxtr and len(objs) > 0:
        tr += 1
        obj = choice(totuple(objs))
        col = choice(remcols)
        subgi = fill(canvas(col, shape(obj)), sqc, obj)
        if len(palette(subgi)) == 1:
            continue
        f1 = choice((identity, dmirror, vmirror, cmirror, hmirror))
        f2 = choice((identity, dmirror, vmirror, cmirror, hmirror))
        f = compose(f1, f2)
        subgo = f(subgi)
        giobj = asobject(subgi)
        goobj = asobject(subgo)
        ohi, owi = shape(giobj)
        oho, owo = shape(goobj)
        gocands = sfilter(goinds, lambda ij: ij[0] <= sgh - oho and ij[1] <= sgw - owo)
        if len(gocands) == 0:
            continue
        goloc = choice(totuple(gocands))
        goplcd = shift(goobj, goloc)
        goplcdi = toindices(goplcd)
        if goplcdi.issubset(goinds):
            gicands = sfilter(giinds, lambda ij: ij[0] <= h - ohi and ij[1] <= owi)
            if len(gicands) == 0:
                continue
            giloc = choice(totuple(gicands))
            giplcd = shift(giobj, giloc)
            giplcdi = toindices(giplcd)
            if giplcdi.issubset(giinds):
                succ += 1
                remcols = remove(col, remcols)
                objs = remove(obj, objs)
                goinds = goinds - goplcdi
                giinds = (giinds - giplcdi) - mapply(neighbors, giplcdi)
                gi = paint(gi, giplcd)
                gi = fill(gi, bgc, sfilter(shift(goplcd, (loci, locj)), lambda cij: cij[0] == sqc))
                go = paint(go, goplcd)
    return {'input': gi, 'output': go}


def generate_97c75046(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (6, 18))
    w = unifint(diff_lb, diff_ub, (6, 18))

    # choose approach side for the misplaced 5
    side = choice(("top", "bottom", "left", "right"))

    if side in ("top", "bottom"):
        maxlen = max(3, min(w - 1, unifint(diff_lb, diff_ub, (3, max(3, w - 1)))))
        nrows = max(2, min(h - 1, unifint(diff_lb, diff_ub, (2, max(2, h - 1)))))
        lens = [maxlen]
        cur = maxlen
        for _ in range(nrows - 1):
            cur = randint(max(1, cur - 2), cur)
            lens.append(cur)
        if side == "top":
            lens = lens[::-1]
        maxl = max(lens)
        minl = min(lens)
        if side == "right":
            anchor = randint(maxl - 1, w - 1)
            rows = []
            if side == "top":
                starti = randint(1, max(1, h - nrows - 1))
            else:
                starti = randint(0, max(0, h - nrows - 2))
            for k, ln in enumerate(lens):
                i = starti + k
                rows.append(connect((i, anchor - ln + 1), (i, anchor)))
            zeros = merge(tuple(rows))
            if side == "top":
                five = (randint(0, starti - 1), anchor)
            else:
                five = (randint(starti + nrows, h - 1), anchor)
        else:
            anchor = randint(0, w - maxl)
            rows = []
            if side == "top":
                starti = randint(1, max(1, h - nrows - 1))
            else:
                starti = randint(0, max(0, h - nrows - 2))
            for k, ln in enumerate(lens):
                i = starti + k
                rows.append(connect((i, anchor), (i, anchor + ln - 1)))
            zeros = merge(tuple(rows))
            if side == "top":
                five = (randint(0, starti - 1), anchor)
            else:
                five = (randint(starti + nrows, h - 1), anchor)
    else:
        maxlen = max(3, min(h - 1, unifint(diff_lb, diff_ub, (3, max(3, h - 1)))))
        ncols = max(2, min(w - 1, unifint(diff_lb, diff_ub, (2, max(2, w - 1)))))
        lens = [maxlen]
        cur = maxlen
        for _ in range(ncols - 1):
            cur = randint(max(1, cur - 2), cur)
            lens.append(cur)
        if side == "left":
            lens = lens[::-1]
        maxl = max(lens)
        minl = min(lens)
        if side == "bottom":
            anchor = randint(maxl - 1, h - 1)
            cols = []
            if side == "left":
                startj = randint(1, max(1, w - ncols - 1))
            else:
                startj = randint(0, max(0, w - ncols - 2))
            for k, ln in enumerate(lens):
                j = startj + k
                cols.append(connect((anchor - ln + 1, j), (anchor, j)))
            zeros = merge(tuple(cols))
            if side == "left":
                five = (anchor, randint(0, startj - 1))
            else:
                five = (anchor, randint(startj + ncols, w - 1))
        else:
            anchor = randint(0, h - maxl)
            cols = []
            if side == "left":
                startj = randint(1, max(1, w - ncols - 1))
            else:
                startj = randint(0, max(0, w - ncols - 2))
            for k, ln in enumerate(lens):
                j = startj + k
                cols.append(connect((anchor, j), (anchor + ln - 1, j)))
            zeros = merge(tuple(cols))
            if side == "left":
                five = (anchor, randint(0, startj - 1))
            else:
                five = (anchor, randint(startj + ncols, w - 1))

    gi = canvas(7, (h, w))
    gi = fill(gi, 0, zeros)
    gi = fill(gi, 5, frozenset({five}))
    go = verify_97c75046(gi)
    return {'input': gi, 'output': go}


def generate_981add89(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (12, 30))
    w = unifint(diff_lb, diff_ub, (12, 30))
    bgc = choice(cols)
    rem = remove(bgc, cols)
    gi = canvas(bgc, (h, w))

    nstripe = unifint(diff_lb, diff_ub, (2, max(2, min(7, w // 3))))
    stripe_cols = sample(interval(0, w, 1), nstripe)
    stripe_colors = [choice(rem) for _ in range(nstripe)]
    for j, c in zip(stripe_cols, stripe_colors):
        gi = fill(gi, c, frozenset({(0, j)}))

    nrect = unifint(diff_lb, diff_ub, (2, max(2, min(8, (h * w) // 40 + 2))))
    used = set()
    for _ in range(nrect):
        rh = unifint(diff_lb, diff_ub, (3, max(3, min(10, h - 2))))
        rw = unifint(diff_lb, diff_ub, (3, max(3, min(10, w - 2))))
        top = unifint(diff_lb, diff_ub, (1, h - rh))
        left = unifint(diff_lb, diff_ub, (0, w - rw))
        rect = connect((top, left), (top + rh - 1, left + rw - 1))
        if len(rect & used) > 0:
            continue
        used |= set(rect)
        rcol = choice(rem)
        gi = fill(gi, rcol, rect)

    if h >= 8 and w >= 8:
        nsmall = unifint(diff_lb, diff_ub, (0, 4))
        free = list(asindices(gi) - frozenset({(0, j) for j in range(w)}) - frozenset(used))
        if len(free) > 0:
            take = min(nsmall, len(free))
            for loc in sample(free, take):
                gi = fill(gi, choice(rem), frozenset({loc}))

    go = verify_981add89(gi)
    if gi == go:
        cand = tuple(j for j in range(w) if gi[0][j] != bgc)
        if len(cand) > 0:
            j = choice(cand)
            i = unifint(diff_lb, diff_ub, (1, h - 1))
            blocker_cols = remove(gi[0][j], rem)
            if len(blocker_cols) == 0:
                blocker = bgc
            else:
                blocker = choice(blocker_cols)
            gi = fill(gi, blocker, frozenset({(i, j)}))
            go = verify_981add89(gi)
    return {'input': gi, 'output': go}


def generate_9841fdad(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    borderc = choice(cols)
    rem = remove(borderc, cols)
    leftbg, rightbg = sample(list(rem), 2)
    rem2 = remove(leftbg, remove(rightbg, rem))
    objcols = list(rem2)

    h = unifint(diff_lb, diff_ub, (9, 20))
    # left panel interior width (cols x8..x9 = x5+2..x6-2)
    # left panel total = interior + 2 padding cells of leftbg on each side
    # so left_panel_cols = divider0+1 .. divider1-1, interior = divider0+2 .. divider1-2
    # interior width = divider1 - divider0 - 3, minimum 2 so divider1-divider0 >= 5
    lpw = unifint(diff_lb, diff_ub, (5, 9))  # left panel total width (between dividers)
    rpw = unifint(diff_lb, diff_ub, (8, 15))  # right panel total width

    # Columns: 0=border, 1..lpw=left panel, lpw+1=border divider, lpw+2..lpw+1+rpw=right panel, lpw+2+rpw=border
    w = lpw + rpw + 3  # 1 + lpw + 1 + rpw + 1

    div0 = 0
    div1 = lpw + 1
    div2 = w - 1

    # Interior boundaries (where shapes live)
    x8 = div0 + 2  # = 2
    x9 = div1 - 2  # = lpw - 1
    interior_w = x9 - x8 + 1  # = lpw - 2

    if interior_w < 2:
        lpw = 5
        w = lpw + rpw + 3
        div1 = lpw + 1
        div2 = w - 1
        x8 = 2
        x9 = lpw - 1
        interior_w = x9 - x8 + 1

    gi = canvas(borderc, (h, w))

    inner_rows = interval(1, h - 1, 1)
    left_panel_cols = interval(1, div1, 1)       # cols 1..lpw
    right_panel_cols = interval(div1 + 1, div2, 1)  # cols lpw+2..w-2

    gi = fill(gi, leftbg, product(inner_rows, left_panel_cols))
    gi = fill(gi, rightbg, product(inner_rows, right_panel_cols))

    # Place shapes in the left panel interior (cols x8..x9)
    # Each shape must touch x8 (left), x9 (right), or span both (full)
    nobj = unifint(diff_lb, diff_ub, (2, min(6, h - 3)))
    rows_avail = list(inner_rows)
    shuffle(rows_avail)

    used = set()
    objs = []

    for r in rows_avail:
        if len(objs) >= nobj:
            break
        if r in used:
            continue
        maxrh = min(3, h - 2 - r)
        if maxrh < 1:
            continue
        rh = unifint(diff_lb, diff_ub, (1, maxrh))
        rset = tuple(range(r, r + rh))
        if any(rr in used for rr in rset):
            continue

        role = choice(("left", "right", "full"))
        c = choice(objcols)

        if role == "full":
            # span entire interior width
            col_inds = interval(x8, x9 + 1, 1)
        elif role == "left":
            # touch left edge x8, extend rightward
            maxow = min(interior_w - 1, 4)
            if maxow < 1:
                maxow = 1
            ow = unifint(diff_lb, diff_ub, (1, maxow))
            col_inds = interval(x8, x8 + ow, 1)
        else:
            # touch right edge x9, extend leftward
            maxow = min(interior_w - 1, 4)
            if maxow < 1:
                maxow = 1
            ow = unifint(diff_lb, diff_ub, (1, maxow))
            col_inds = interval(x9 - ow + 1, x9 + 1, 1)

        inds = product(rset, col_inds)
        gi = fill(gi, c, inds)
        objs.append((c, inds))
        for rr in rset:
            used.add(rr)

    # Ensure at least one shape was placed
    if len(objs) == 0:
        r = 2 if h > 4 else 1
        c = choice(objcols)
        ow = min(2, interior_w)
        inds = product((r,), interval(x8, x8 + ow, 1))
        gi = fill(gi, c, inds)

    go = verify_9841fdad(gi)
    if gi == go:
        return generate_9841fdad(diff_lb, diff_ub)
    return {'input': gi, 'output': go}


def generate_984d8a3e(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (6, 18))
    w = unifint(diff_lb, diff_ub, (8, 18))
    leftc, midc, rightc = sample(cols, 3)

    min_right = unifint(diff_lb, diff_ub, (max(1, w // 4), max(1, w // 2)))
    if min_right >= w:
        min_right = w - 1
    max_left = w - min_right
    if max_left < 1:
        max_left = 1
        min_right = w - 1

    rows = []
    varied = False
    for _ in range(h):
        l = unifint(diff_lb, diff_ub, (0, max_left))
        rstart = unifint(diff_lb, diff_ub, (max(l + 1, min_right), w))
        if rstart > w:
            rstart = w
        if rstart <= l:
            rstart = min(w, l + 1)
        row = repeat(leftc, l) + repeat(midc, rstart - l) + repeat(rightc, w - rstart)
        rows.append(row)

    if len(set(rows)) == 1:
        i = randint(0, h - 1)
        l = min(max_left, rows[i].count(leftc) + 1)
        rstart = max(min_right, l + 1)
        if rstart > w:
            rstart = w
            l = min(l, w - 1)
        rows[i] = repeat(leftc, l) + repeat(midc, rstart - l) + repeat(rightc, w - rstart)

    gi = tuple(rows)
    go = verify_984d8a3e(gi)

    if gi == go:
        for k in range(h):
            l = 0
            while l < w and gi[k][l] == leftc:
                l += 1
            r = w - 1
            rcnt = 0
            while r >= 0 and gi[k][r] == rightc:
                rcnt += 1
                r -= 1
            rstart = w - rcnt
            if l > 0 and rstart > min_right:
                newl = l - 1
                newrstart = rstart - 1
                rows2 = [tuple(rw) for rw in gi]
                rows2[k] = repeat(leftc, newl) + repeat(midc, newrstart - newl) + repeat(rightc, w - newrstart)
                gi = tuple(rows2)
                go = verify_984d8a3e(gi)
                if gi != go:
                    break

    return {'input': gi, 'output': go}


def generate_985ae207(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc = 8 if choice((True, False)) else choice(cols)
    rem = remove(bgc, cols)
    nseeds = unifint(diff_lb, diff_ub, (1, 4))
    h = unifint(diff_lb, diff_ub, (16, 24))
    w = unifint(diff_lb, diff_ub, (16, 24))
    if h < 8:
        h = 8
    if w < 8:
        w = 8
    gi = canvas(bgc, (h, w))

    seed_pairs = []
    used_centers = set()
    used_rects = []

    for _ in range(100):
        if len(seed_pairs) >= nseeds:
            break
        if len(rem) < 2:
            break
        outer, inner = sample(rem, 2)
        orient = choice(("H", "V"))
        if orient == "H":
            sh = 3
            sw = 3
            rh = unifint(diff_lb, diff_ub, (2, 5))
            rw = unifint(diff_lb, diff_ub, (2, 8))
            if choice((True, False)):
                side = "L"
                max_seed_j = w - (rw + 4)
                if max_seed_j < 0:
                    continue
                si = randint(0, h - 3)
                sj = randint(0, max_seed_j)
                gapk = unifint(diff_lb, diff_ub, (1, max(1, (w - (sj + 3 + rw)) // 3)))
                rtop = si + randint(0, 1)
                rleft = sj + 3 + 3 * gapk
            else:
                side = "R"
                min_seed_j = rw + 3
                if min_seed_j > w - 3:
                    continue
                si = randint(0, h - 3)
                sj = randint(min_seed_j, w - 3)
                gapk = unifint(diff_lb, diff_ub, (1, max(1, (sj - rw) // 3)))
                rtop = si + randint(0, 1)
                rleft = sj - 3 * gapk - rw
            rect = backdrop(frozenset({(rtop, rleft), (rtop + rh - 1, rleft + rw - 1)}))
            seedbox = backdrop(frozenset({(si, sj), (si + 2, sj + 2)}))
            center = (si + 1, sj + 1)
        else:
            sh = 3
            sw = 3
            rh = unifint(diff_lb, diff_ub, (2, 8))
            rw = unifint(diff_lb, diff_ub, (2, 5))
            if choice((True, False)):
                side = "U"
                max_seed_i = h - (rh + 4)
                if max_seed_i < 0:
                    continue
                si = randint(0, max_seed_i)
                sj = randint(0, w - 3)
                gapk = unifint(diff_lb, diff_ub, (1, max(1, (h - (si + 3 + rh)) // 3)))
                rtop = si + 3 + 3 * gapk
                rleft = sj + randint(0, 1)
            else:
                side = "D"
                min_seed_i = rh + 3
                if min_seed_i > h - 3:
                    continue
                si = randint(min_seed_i, h - 3)
                sj = randint(0, w - 3)
                gapk = unifint(diff_lb, diff_ub, (1, max(1, (si - rh) // 3)))
                rtop = si - 3 * gapk - rh
                rleft = sj + randint(0, 1)
            rect = backdrop(frozenset({(rtop, rleft), (rtop + rh - 1, rleft + rw - 1)}))
            seedbox = backdrop(frozenset({(si, sj), (si + 2, sj + 2)}))
            center = (si + 1, sj + 1)

        if center in used_centers:
            continue
        occ = seedbox | rect
        bad = False
        for rr in used_rects:
            if len(intersection(occ, rr)) > 0:
                bad = True
                break
        if bad:
            continue

        gi = fill(gi, outer, seedbox)
        gi = fill(gi, inner, initset(center))
        gi = fill(gi, inner, rect)

        used_centers.add(center)
        used_rects.append(occ)
        seed_pairs.append((outer, inner))

    if len(seed_pairs) == 0:
        outer, inner = sample(rem, 2)
        gi = fill(gi, outer, backdrop(frozenset({(1, 1), (3, 3)})))
        gi = fill(gi, inner, initset((2, 2)))
        gi = fill(gi, inner, backdrop(frozenset({(1, 10), (3, 12)})))

    go = verify_985ae207(gi)
    return {'input': gi, 'output': go}


def generate_98c475bf(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    borderc = choice(cols)
    marker_opts = remove(borderc, cols)

    h = 20
    w = 20
    gi = canvas(0, (h, w))
    gi = fill(gi, borderc, connect((0, 0), (h - 1, 0)))
    gi = fill(gi, borderc, connect((0, w - 1), (h - 1, w - 1)))

    possible_markers = (1, 2, 3, 6, 7)
    nmarkers = unifint(diff_lb, diff_ub, (1, 3))
    marker_cols = sample(possible_markers, nmarkers)

    row_min = 3
    row_max = 16
    rows = sample(interval(row_min, row_max + 1, 1), nmarkers)

    for c, r in zip(marker_cols, rows):
        gi = fill(gi, c, frozenset({(r, 1), (r, 18)}))

    noise_cols = tuple(c for c in marker_opts if c not in marker_cols)
    nnoise = unifint(diff_lb, diff_ub, (0, 2))
    if nnoise > 0 and len(noise_cols) > 0:
        chosen_noise = sample(noise_cols, min(nnoise, len(noise_cols)))
        available_rows = tuple(r for r in interval(1, h - 1, 1) if r not in rows)
        if len(available_rows) > 0:
            noise_rows = sample(available_rows, min(len(chosen_noise), len(available_rows)))
            for c, r in zip(chosen_noise, noise_rows):
                side = choice((1, 18))
                gi = fill(gi, c, frozenset({(r, side)}))

    distractor_cols = tuple(c for c in marker_opts if c not in marker_cols)
    ndistr = unifint(diff_lb, diff_ub, (0, 2))
    if ndistr > 0 and len(distractor_cols) > 0:
        chosen_distr = sample(distractor_cols, min(ndistr, len(distractor_cols)))
        for c in chosen_distr:
            top = unifint(diff_lb, diff_ub, (0, h - 6))
            left = unifint(diff_lb, diff_ub, (2, w - 7))
            hh = unifint(diff_lb, diff_ub, (2, 6))
            ww = unifint(diff_lb, diff_ub, (2, 6))
            inds = connect((top, left), (min(h - 1, top + hh - 1), min(w - 2, left + ww - 1)))
            carve_n = unifint(diff_lb, diff_ub, (0, max(0, len(inds) // 3)))
            inds_t = totuple(inds)
            if carve_n > 0 and len(inds_t) > carve_n:
                rem = sample(inds_t, carve_n)
                inds = difference(inds, rem)
            gi = fill(gi, c, inds)

    go = verify_98c475bf(gi)
    return {'input': gi, 'output': go}


def generate_98cf29f8(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    objh = unifint(diff_lb, diff_ub, (2, h - 5))
    objw = unifint(diff_lb, diff_ub, (2, w - 5))
    loci = randint(0, h - objh)
    locj = randint(0, w - objw)
    loc = (loci, locj)
    obj = backdrop(frozenset({(loci, locj), (loci + objh - 1, locj + objw - 1)}))
    bgc, objc, otherc = sample(cols, 3)
    gi = canvas(bgc, (h, w))
    gi = fill(gi, objc, obj)
    bmarg = h - (loci + objh)
    rmarg = w - (locj + objw)
    tmarg = loci
    lmarg = locj
    margs = (bmarg, rmarg, tmarg, lmarg)
    options = [idx for idx, marg in enumerate(margs) if marg > 2]
    pos = choice(options)
    for k in range(pos):
        gi = rot90(gi)
    h, w = shape(gi)
    ofc = ofcolor(gi, objc)
    locis = randint(lowermost(ofc)+2, h-2)
    locie = randint(locis+1, h-1)
    locjs = randint(0, min(w - 2, rightmost(ofc)))
    locje = randint(max(locjs+1, leftmost(ofc)), w - 1)
    otherobj = backdrop(frozenset({(locis, locjs), (locie, locje)}))
    ub = min(rightmost(ofc), rightmost(otherobj))
    lb = max(leftmost(ofc), leftmost(otherobj))
    jloc = randint(lb, ub)
    ln = connect((lowermost(ofc)+1, jloc), (uppermost(otherobj)-1, jloc))
    gib = tuple(e for e in gi)
    gi = fill(gi, otherc, otherobj)
    gi = fill(gi, otherc, ln)
    go = fill(gib, otherc, shift(otherobj, (-len(ln), 0)))
    mfs = (identity, dmirror, cmirror, vmirror, hmirror, rot90, rot180, rot270)
    nmfs = choice((1, 2))
    for fn in sample(mfs, nmfs):
        gi = fn(gi)
        go = fn(go)
    return {'input': gi, 'output': go}


