def generate_99306f82(diff_lb: float, diff_ub: float) -> dict:
    bg = 0
    ncols = unifint(diff_lb, diff_ub, (1, 6))
    cols = remove(0, remove(1, interval(0, 10, 1)))
    dcols = tuple(sample(cols, ncols))
    # Interior must fit ncols concentric rings: min(inner_h, inner_w) >= 2*ncols
    inner_min = 2 * ncols
    inner_max = max(inner_min, inner_min + 6)
    inner_h = unifint(diff_lb, diff_ub, (inner_min, inner_max))
    inner_w = unifint(diff_lb, diff_ub, (inner_min, inner_max))
    frame_h = inner_h + 2
    frame_w = inner_w + 2
    start = ncols
    h = frame_h + start + unifint(diff_lb, diff_ub, (0, 3))
    w = frame_w + start + unifint(diff_lb, diff_ub, (0, 3))
    if h > 30:
        h = 30
    if w > 30:
        w = 30
    gi = canvas(bg, (h, w))
    for k, c in enumerate(dcols):
        gi = fill(gi, c, frozenset({(k, k)}))
    r1, c1 = start, start
    r2, c2 = start + frame_h - 1, start + frame_w - 1
    frame = box(frozenset({(r1, c1), (r2, c2)}))
    gi = fill(gi, 1, frame)
    go = verify_99306f82(gi)
    return {'input': gi, 'output': go}


