def generate_9a4bb226(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    h = unifint(diff_lb, diff_ub, (12, 20))
    w = unifint(diff_lb, diff_ub, (12, 20))
    gi = canvas(bgc, (h, w))

    nobj = unifint(diff_lb, diff_ub, (3, 5))
    cols = remove(0, interval(0, 10, 1))

    motifs = []
    used_pairs = set()
    used_triples = set()

    # unique 3-color winner
    triple = tuple(sample(cols, 3))
    used_triples.add(frozenset(triple))
    winner = (
        (triple[0], triple[0], triple[0]),
        (triple[1], triple[2], triple[2]),
        (triple[1], triple[0], triple[0]),
    )
    motifs.append(winner)

    # remaining 2-color motifs, all distinct color sets
    for _ in range(nobj - 1):
        for _tr in range(50):
            paircols = tuple(sample(cols, 2))
            key = frozenset(paircols)
            if key in used_pairs:
                continue
            used_pairs.add(key)
            a, b = paircols
            patopts = (
                (
                    (a, a, a),
                    (b, b, a),
                    (b, a, a),
                ),
                (
                    (a, a, a),
                    (b, a, a),
                    (b, b, a),
                ),
                (
                    (a, b, b),
                    (a, a, b),
                    (a, b, b),
                ),
                (
                    (a, b, b),
                    (a, b, a),
                    (a, a, a),
                ),
                (
                    (a, b, a),
                    (b, a, b),
                    (b, b, b),
                ),
            )
            motifs.append(choice(patopts))
            break

    shuffle(motifs)

    occ = set()
    margin = 1
    for mot in motifs:
        placed = False
        for _ in range(100):
            i = randint(margin, h - 3 - margin)
            j = randint(margin, w - 3 - margin)
            cells = {(i + di, j + dj) for di in range(3) for dj in range(3)}
            halo = {(r, c) for r in range(i - 1, i + 4) for c in range(j - 1, j + 4)}
            if any((r, c) in occ for r, c in halo):
                continue
            obj = frozenset((mot[di][dj], (i + di, j + dj)) for di in range(3) for dj in range(3))
            gi = paint(gi, obj)
            occ |= halo
            placed = True
            break
        if not placed:
            # deterministic fallback scan
            done = False
            for i in range(margin, h - 3 - margin + 1):
                for j in range(margin, w - 3 - margin + 1):
                    halo = {(r, c) for r in range(i - 1, i + 4) for c in range(j - 1, j + 4)}
                    if any((r, c) in occ for r, c in halo):
                        continue
                    obj = frozenset((mot[di][dj], (i + di, j + dj)) for di in range(3) for dj in range(3))
                    gi = paint(gi, obj)
                    occ |= halo
                    done = True
                    break
                if done:
                    break

    go = verify_9a4bb226(gi)
    return {'input': gi, 'output': go}


