def generate_9f27f097(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    bgc = choice(cols)  # bgc is never 0, since cols is 1-9
    patcols_all = remove(bgc, cols)

    ph = unifint(diff_lb, diff_ub, (3, 6))
    pw = unifint(diff_lb, diff_ub, (4, 7))

    margin_top = unifint(diff_lb, diff_ub, (0, 3))
    margin_bottom = unifint(diff_lb, diff_ub, (0, 3))
    margin_left = unifint(diff_lb, diff_ub, (0, 3))
    margin_right = unifint(diff_lb, diff_ub, (0, 3))
    gap_r = unifint(diff_lb, diff_ub, (1, 3))
    gap_c = unifint(diff_lb, diff_ub, (1, 3))

    vertical = choice((True, False))
    if vertical:
        h = ph * 2 + gap_r + margin_top + margin_bottom
        w = pw + margin_left + margin_right
    else:
        h = ph + margin_top + margin_bottom
        w = pw * 2 + gap_c + margin_left + margin_right

    if h > 30:
        excess = h - 30
        if vertical:
            margin_top = max(0, margin_top - excess // 2)
            margin_bottom = max(0, margin_bottom - (excess - excess // 2))
            h = ph * 2 + gap_r + margin_top + margin_bottom
    if w > 30:
        excess = w - 30
        if not vertical:
            margin_left = max(0, margin_left - excess // 2)
            margin_right = max(0, margin_right - (excess - excess // 2))
            w = pw * 2 + gap_c + margin_left + margin_right

    gi = canvas(bgc, (h, w))

    npatcols = unifint(diff_lb, diff_ub, (2, min(4, len(patcols_all))))
    patcols = sample(patcols_all, npatcols)

    for _ in range(100):
        pat = []
        for i in range(ph):
            row = []
            for j in range(pw):
                row.append(choice(patcols))
            pat.append(tuple(row))
        pat = tuple(pat)

        if len(set(v for r in pat for v in r)) < 2:
            ii = randint(0, ph - 1)
            jj = randint(0, pw - 1)
            alt = other(patcols, pat[ii][jj]) if len(patcols) > 1 else patcols[0]
            patl = [list(r) for r in pat]
            patl[ii][jj] = alt
            pat = tuple(tuple(r) for r in patl)

        if vmirror(pat) != pat:
            break
    else:
        # Force asymmetry: swap two different-colored cells in first row
        patl = [list(r) for r in pat]
        patl[0][0], patl[0][-1] = patl[0][-1], patl[0][0]
        if patl[0][0] == patl[0][-1]:
            patl[0][-1] = other(patcols, patl[0][0]) if len(patcols) > 1 else patcols[0]
        pat = tuple(tuple(r) for r in patl)

    if vertical:
        top_first = choice((True, False))
        c = margin_left
        if top_first:
            pr, pc = margin_top, c
            zr, zc = margin_top + ph + gap_r, c
        else:
            zr, zc = margin_top, c
            pr, pc = margin_top + ph + gap_r, c
    else:
        left_first = choice((True, False))
        r = margin_top
        if left_first:
            pr, pc = r, margin_left
            zr, zc = r, margin_left + pw + gap_c
        else:
            zr, zc = r, margin_left
            pr, pc = r, margin_left + pw + gap_c

    pobj = shift(asobject(pat), (pr, pc))
    gi = paint(gi, pobj)
    zrect = backdrop(frozenset({(0, (zr, zc)), (0, (zr + ph - 1, zc + pw - 1))}))
    gi = fill(gi, 0, zrect)

    go = verify_9f27f097(gi)
    return {'input': gi, 'output': go}


def generate_9f41bd9c(diff_lb: float, diff_ub: float) -> dict:
    # motif is 5 wide, has 2 solid rows + alt_rows alternating rows
    # staircase extends alt_rows columns beyond the 5-wide motif
    # need: motif_h + 3 <= w (width for staircase)
    # need: top_margin + motif_h + 1 <= h (room for magenta below)
    # need: top_margin >= 1

    h = unifint(diff_lb, diff_ub, (8, 26))
    w = unifint(diff_lb, diff_ub, (8, 26))

    max_motif_h = min(w - 3, h - 2)
    if max_motif_h < 3:
        h = max(h, 6)
        w = max(w, 8)
        max_motif_h = min(w - 3, h - 2)

    motif_h = unifint(diff_lb, diff_ub, (3, max(3, max_motif_h)))

    max_top = h - motif_h - 1
    top_margin = unifint(diff_lb, diff_ub, (1, max(1, max_top)))

    mag_top = top_margin + motif_h
    side = choice((0, 1))  # 0 = left, 1 = right

    gi = canvas(ONE, (h, w))

    # fill magenta region (rectangle from mag_top to bottom)
    mag_inds = frozenset((r, c) for r in range(mag_top, h) for c in range(w))
    gi = fill(gi, SIX, mag_inds)

    startj = 0 if side == 0 else w - 5

    # two solid rows
    gi = fill(gi, FIVE, connect((top_margin, startj), (top_margin, startj + 4)))
    gi = fill(gi, FIVE, connect((top_margin + 1, startj), (top_margin + 1, startj + 4)))

    # alternating rows: columns 0, 2, 4 relative to startj
    for r in range(top_margin + 2, top_margin + motif_h):
        inds = frozenset({(r, startj + k) for k in (0, 2, 4)})
        gi = fill(gi, FIVE, inds)

    go = verify_9f41bd9c(gi)
    return {'input': gi, 'output': go}


def generate_9f5f939b(diff_lb: float, diff_ub: float) -> dict:
    # Grid has azure (8) background with blue (1) 2-cell horizontal and vertical bars.
    # A center cell becomes 4 when:
    #   - Two horizontal bars in the same row separated by gap=4 (center between them)
    #   - Two vertical bars in the same column: lowermost of top bar is 2 above center,
    #     uppermost of bottom bar is 2 below center
    # Cross layout around center (r, c):
    #   Top vbar:    (r-3, c), (r-2, c)
    #   Bottom vbar: (r+2, c), (r+3, c)
    #   Left hbar:   (r, c-3), (r, c-2)
    #   Right hbar:  (r, c+2), (r, c+3)

    h = unifint(diff_lb, diff_ub, (8, 20))
    w = unifint(diff_lb, diff_ub, (8, 20))
    gi = canvas(8, (h, w))
    occupied = set()

    ncrosses = unifint(diff_lb, diff_ub, (1, max(1, min(3, (h * w) // 70))))

    centers = []
    for _ in range(ncrosses):
        placed = False
        for _t in range(200):
            r = randint(3, h - 4)
            c = randint(3, w - 4)
            cells = {
                (r, c - 3), (r, c - 2),
                (r, c + 2), (r, c + 3),
                (r - 3, c), (r - 2, c),
                (r + 2, c), (r + 3, c),
            }
            buffer = cells | {(r, c), (r, c - 1), (r, c + 1), (r - 1, c), (r + 1, c)}
            if buffer & occupied:
                continue
            if r - 3 < 0 or r + 3 >= h or c - 3 < 0 or c + 3 >= w:
                continue
            occupied |= buffer
            centers.append((r, c))
            gi = fill(gi, 1, frozenset({(r, c - 3), (r, c - 2)}))
            gi = fill(gi, 1, frozenset({(r, c + 2), (r, c + 3)}))
            gi = fill(gi, 1, frozenset({(r - 3, c), (r - 2, c)}))
            gi = fill(gi, 1, frozenset({(r + 2, c), (r + 3, c)}))
            placed = True
            break

    # Add decoy bars that won't accidentally complete a cross
    ndecoys = unifint(diff_lb, diff_ub, (1, max(1, (h * w) // 25)))
    for _ in range(ndecoys):
        for _t in range(50):
            if choice((True, False)):
                r = randint(0, h - 1)
                c = randint(0, w - 2)
                cells = {(r, c), (r, c + 1)}
            else:
                r = randint(0, h - 2)
                c = randint(0, w - 1)
                cells = {(r, c), (r + 1, c)}
            if cells & occupied:
                continue
            occupied |= cells
            gi = fill(gi, 1, frozenset(cells))
            break

    go = verify_9f5f939b(gi)
    if gi == go:
        return generate_9f5f939b(diff_lb, diff_ub)
    return {'input': gi, 'output': go}


def generate_9f669b64(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc = choice(cols)
    rem = remove(bgc, cols)
    c1, c2, c3 = sample(rem, 3)

    orient = choice(("vertical", "horizontal"))
    h = 10
    w = 10
    gi = canvas(bgc, (h, w))

    if orient == "vertical":
        conn_h = unifint(diff_lb, diff_ub, (2, 4))
