    cuts = sorted(sample(interval(1, ncols, 1), k - 1))
    seglens = []
    prev = 0
    for c in cuts + [ncols]:
        seglens.append(c - prev)
        prev = c

    rowcounts = [1] * k
    rem = nrows - k
    if rem > 0:
        extras = sorted(sample(interval(1, rem + k, 1), k - 1)) if k > 1 else []
        parts = []
        prev = 0
        for c in extras + [rem + k]:
            parts.append(c - prev)
            prev = c
        rowcounts = parts

    bottom = []
    for col, ln in zip(colors, seglens):
        bottom += [col] * ln
    rightcol = []
    for col, cnt in zip(colors, rowcounts):
        rightcol += [col] * cnt

    if choice((True, False)):
        pairings = list(pair(tuple(colors), tuple(seglens)))
        shuffle(pairings)
        colors = [p[0] for p in pairings]
        seglens = [p[1] for p in pairings]
        bottom = []
        for col, ln in zip(colors, seglens):
            bottom += [col] * ln
        rightcol = []
        for col, cnt in zip(colors, rowcounts):
            rightcol += [col] * cnt

    if choice((True, False)):
        pairings = list(pair(tuple(colors), tuple(rowcounts)))
        shuffle(pairings)
        colors = [p[0] for p in pairings]
        rowcounts = [p[1] for p in pairings]
        rightcol = []
        for col, cnt in zip(colors, rowcounts):
            rightcol += [col] * cnt
        bottom = []
        for col, ln in zip(colors, seglens):
            bottom += [col] * ln

    gi = canvas(0, (h, w))
    for i, col in enumerate(rightcol):
        gi = fill(gi, col, initset((i, w - 1)))
    for j, col in enumerate(bottom):
        gi = fill(gi, col, initset((h - 1, j)))
    gi = fill(gi, bottom[-1], initset((h - 1, w - 1)))

    go = verify_a406ac07(gi)
    return {'input': gi, 'output': go}


