    blocks = []

    for _ in range(100):
        gi = canvas(bg, (h, w))
        occ = set()
        blocks = []
        target = nblocks
        for _b in range(target):
            placed = False
            for _try in range(100):
                ph = unifint(diff_lb, diff_ub, (2, 4))
                pw = unifint(diff_lb, diff_ub, (2, 4))
