def generate_aa18de87(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (3, 12))
    w = unifint(diff_lb, diff_ub, (6, 20))
    fgc = choice(remove(2, remove(0, interval(0, 10, 1))))
    gi = canvas(0, (h, w))

    mode = choice((0, 1, 2, 3))
    rows = interval(0, h, 1)

    if mode == 0:
        start = unifint(diff_lb, diff_ub, (0, max(0, w - 2)))
        gap = unifint(diff_lb, diff_ub, (1, max(1, (w - start - 1) // max(1, h - 1) if h > 1 else w - start - 1)))
        for i in rows:
            j = start + i * gap
            if 0 <= j < w:
                gi = fill(gi, fgc, initset((i, j)))
                if i < h - 1:
                    j2 = j + gap
                    if 0 <= j2 < w:
                        gi = fill(gi, fgc, initset((i, j2)))
    elif mode == 1:
        start = unifint(diff_lb, diff_ub, (1, max(1, w - 1)))
        gap = unifint(diff_lb, diff_ub, (1, max(1, start // max(1, h - 1) if h > 1 else start)))
        for i in rows:
            j = start - i * gap
            if 0 <= j < w:
                gi = fill(gi, fgc, initset((i, j)))
                if i > 0:
                    j2 = j + gap
                    if 0 <= j2 < w:
                        gi = fill(gi, fgc, initset((i, j2)))
    elif mode == 2:
        center = unifint(diff_lb, diff_ub, (1, max(1, w - 2)))
        maxd = min(center, w - 1 - center)
        step = unifint(diff_lb, diff_ub, (1, max(1, maxd // max(1, h - 1) if h > 1 else maxd)))
        for i in rows:
            d = i * step
            if d <= maxd:
                gi = fill(gi, fgc, initset((i, center - d)))
                if d > 0:
                    gi = fill(gi, fgc, initset((i, center + d)))
    else:
        nrows_multi = unifint(diff_lb, diff_ub, (1, h))
        multirows = set(sample(rows, nrows_multi))
        for i in rows:
            if i in multirows:
                maxpts = min(5, w)
                npts = unifint(diff_lb, diff_ub, (2, maxpts))
                cols = sample(interval(0, w, 1), npts)
                for j in cols:
                    gi = fill(gi, fgc, initset((i, j)))
            else:
                if choice((True, False)):
                    j = unifint(diff_lb, diff_ub, (0, w - 1))
                    gi = fill(gi, fgc, initset((i, j)))

    if colorcount(gi, fgc) < 2:
        j1 = unifint(diff_lb, diff_ub, (0, w - 2))
        j2 = unifint(diff_lb, diff_ub, (j1 + 1, w - 1))
        gi = fill(gi, fgc, frozenset({(0, j1), (0, j2)}))

    go = verify_aa18de87(gi)
    return {'input': gi, 'output': go}


def generate_aa300dc3(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (8, 20))
    w = unifint(diff_lb, diff_ub, (8, 20))
    gi = canvas(5, (h, w))

    ori = choice((0, 1))  # 0: down-right, 1: down-left
    margin = 1
    maxlen = min(h - 2, w - 2)
    dlen = unifint(diff_lb, diff_ub, (4, max(4, maxlen)))
    dlen = min(dlen, maxlen)

    if ori == 0:
        si = randint(margin, h - dlen - 1)
        sj = randint(margin, w - dlen - 1)
        main_diag = connect((si, sj), (si + dlen - 1, sj + dlen - 1))
    else:
        si = randint(margin, h - dlen - 1)
        sj = randint(dlen, w - 2)
        main_diag = connect((si, sj), (si + dlen - 1, sj - dlen + 1))

    gi = fill(gi, 0, main_diag)

    noise_budget = unifint(diff_lb, diff_ub, (dlen, min(h * w // 3, dlen * 4 + 8)))
    zeros = set(main_diag)

    for _ in range(noise_budget):
        cand = set()
        for p in zeros:
            cand.update(neighbors(p))
        cand = [p for p in cand if 0 < p[0] < h - 1 and 0 < p[1] < w - 1 and p not in zeros]
        if len(cand) == 0:
            break
        p = choice(cand)
        zeros.add(p)
        gi = fill(gi, 0, frozenset({p}))

    extra_seeds = unifint(diff_lb, diff_ub, (1, 4))
    for _ in range(extra_seeds):
        if len(zeros) == 0:
            break
        base = choice(tuple(zeros))
        cand = [p for p in neighbors(base) if 0 < p[0] < h - 1 and 0 < p[1] < w - 1]
        if len(cand) == 0:
            continue
        p = choice(cand)
        zeros.add(p)
        gi = fill(gi, 0, frozenset({p}))
        grow = unifint(diff_lb, diff_ub, (0, 3))
        frontier = {p}
        for _ in range(grow):
            cand2 = set()
            for q in frontier:
                cand2.update(neighbors(q))
            cand2 = [q for q in cand2 if 0 < q[0] < h - 1 and 0 < q[1] < w - 1 and q not in zeros]
            if len(cand2) == 0:
                break
            q = choice(cand2)
            frontier = {q}
            zeros.add(q)
            gi = fill(gi, 0, frozenset({q}))

    go = verify_aa300dc3(gi)
    return {'input': gi, 'output': go}


def generate_aa62e3f4(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    bgc = choice(cols)
    rem = remove(bgc, cols)
    rare = choice(rem)
    rem2 = remove(rare, rem)
    mid = choice(rem2)

    h = unifint(diff_lb, diff_ub, (7, 20))
    w = unifint(diff_lb, diff_ub, (7, 20))

    gi = canvas(bgc, (h, w))

    orient = choice((0, 1))
    if orient == 0:
        hh = unifint(diff_lb, diff_ub, (5, min(9, h - 2)))
        ww = hh
    else:
        hh = unifint(diff_lb, diff_ub, (5, min(9, h - 2)))
        ww = unifint(diff_lb, diff_ub, (5, min(9, w - 2)))

    top = unifint(diff_lb, diff_ub, (1, h - hh))
    left = unifint(diff_lb, diff_ub, (1, w - ww))

    outer = connect((top, left), (top + hh - 1, left + ww - 1))
    gi = fill(gi, mid, outer)

    inner_cells = []
    for i in range(top + 1, top + hh - 1):
        for j in range(left + 1, left + ww - 1):
            inner_cells.append((i, j))

    nrare = unifint(diff_lb, diff_ub, (1, max(1, min(len(inner_cells), (hh * ww) // 5))))
    rare_cells = sample(inner_cells, nrare)
    gi = fill(gi, rare, frozenset(rare_cells))

    if len(inner_cells) > nrare:
        remaining = [ij for ij in inner_cells if ij not in rare_cells]
        nmid_extra_max = max(1, len(remaining) - 1)
        nmid_extra = unifint(diff_lb, diff_ub, (1, nmid_extra_max))
        mid_extra = sample(remaining, nmid_extra)
        gi = fill(gi, mid, frozenset(mid_extra))

    go = verify_aa62e3f4(gi)
    return {'input': gi, 'output': go}


def generate_aab50785(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(8, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (10, 18))
    w = unifint(diff_lb, diff_ub, (10, 20))
    npairs = unifint(diff_lb, diff_ub, (1, max(1, min(h // 2, 4))))
    bgc = choice(cols)
    gi = canvas(bgc, (h, w))

    maxpairs_fit = h // 2
    npairs = min(npairs, maxpairs_fit)
    rowstarts = sample(list(range(0, h - 1)), npairs)
    rowstarts = sorted([r for r in rowstarts if r + 1 < h])
    used = set()
    filtered = []
    for r in rowstarts:
        if r not in used and r + 1 not in used:
            filtered.append(r)
            used.add(r)
            used.add(r + 1)
    rowstarts = filtered
    if len(rowstarts) == 0:
        rowstarts = [0]
    npairs = len(rowstarts)

    for r in rowstarts:
        gap = unifint(diff_lb, diff_ub, (1, max(1, w - 5)))
        max_left = w - gap - 4
        if max_left < 0:
            max_left = 0
        left = unifint(diff_lb, diff_ub, (0, max_left))
        right = left + gap + 2

        leftblk = backdrop(frozenset({(r, left), (r + 1, left + 1)}))
        rightblk = backdrop(frozenset({(r, right), (r + 1, right + 1)}))
        gi = fill(gi, 8, leftblk)
        gi = fill(gi, 8, rightblk)

        for i in range(h):
            for j in range(w):
                if (r <= i <= r + 1 and left <= j <= left + 1) or (r <= i <= r + 1 and right <= j <= right + 1):
                    continue
                if randint(0, 99) < 65:
                    gi = fill(gi, choice(cols), frozenset({(i, j)}))

    go = verify_aab50785(gi)
    return {'input': gi, 'output': go}


def generate_aabf363d(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (3, 28))
    w = unifint(diff_lb, diff_ub, (3, 28))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    cola = choice(remcols)
    remcols = remove(cola, remcols)
    colb = choice(remcols)
    c = canvas(bgc, (h, w))
    bounds = asindices(c)
    sp = choice(totuple(bounds))
    ub = min(h * w - 1, max(1, (2/3) * h * w))
    ncells = unifint(diff_lb, diff_ub, (1, ub))
    shp = {sp}
    for k in range(ncells):
        ij = choice(totuple((bounds - shp) & mapply(neighbors, shp)))
        shp.add(ij)
    shp = shift(shp, (1, 1))
    c2 = canvas(bgc, (h+2, w+2))
    gi = fill(c2, cola, shp)
    go = fill(c2, colb, shp)
    gi = fill(gi, colb, {choice(totuple(ofcolor(gi, bgc)))})
    return {'input': gi, 'output': go}


def generate_aaecdb9a(diff_lb: float, diff_ub: float) -> dict:
    target_cols = (5, 2, 8, 9, 6)
    h = unifint(diff_lb, diff_ub, (10, 18))
    w = unifint(diff_lb, diff_ub, (10, 18))
    gi = canvas(7, (h, w))

    present_dev = unifint(diff_lb, diff_ub, (2, 5))
    npresent = choice((present_dev, 5))
    npresent = min(max(2, npresent), 5)
    present_cols = sample(target_cols, npresent)

    occupied = set()
    forbidden = set()

    def valid_component(comp):
        if len(comp) == 0:
            return False
        for cell in comp:
            if cell in forbidden:
                return False
            if not (0 <= cell[0] < h and 0 <= cell[1] < w):
                return False
        return True

    def add_component(comp, col):
        nonlocal gi, occupied, forbidden
        gi = fill(gi, col, frozenset(comp))
        occupied |= set(comp)
        for c in comp:
            forbidden.add(c)
            forbidden |= set(neighbors(c))

    for col in present_cols:
        maxsize = min(5, max(1, (h * w) // 20))
        sz = unifint(diff_lb, diff_ub, (1, maxsize))
        placed = False
        for _ in range(200):
            si = randint(0, h - 1)
            sj = randint(0, w - 1)
            if (si, sj) in forbidden:
                continue
            comp = {(si, sj)}
            frontier = set()
            frontier |= set(dneighbors((si, sj)))
            for _k in range(sz - 1):
                cands = [p for p in frontier if 0 <= p[0] < h and 0 <= p[1] < w and p not in forbidden]
                if len(cands) == 0:
                    break
                nxt = choice(cands)
                comp.add(nxt)
                frontier |= set(dneighbors(nxt))
                frontier -= comp
            if len(comp) == sz and valid_component(comp):
                add_component(comp, col)
                placed = True
                break
        if not placed:
            for _ in range(200):
                si = randint(0, h - 1)
                sj = randint(0, w - 1)
                if (si, sj) in forbidden:
                    continue
                add_component({(si, sj)}, col)
                placed = True
                break

    nnoise = unifint(diff_lb, diff_ub, (0, 6))
    noise_cols = (0, 1, 3, 4)
    for _ in range(nnoise):
        ncol = choice(noise_cols)
        nsz = unifint(diff_lb, diff_ub, (1, 4))
        for _tr in range(100):
            si = randint(0, h - 1)
            sj = randint(0, w - 1)
            if (si, sj) in forbidden:
                continue
            comp = {(si, sj)}
            frontier = set(dneighbors((si, sj)))
            for _k in range(nsz - 1):
                cands = [p for p in frontier if 0 <= p[0] < h and 0 <= p[1] < w and p not in forbidden]
                if len(cands) == 0:
                    break
                nxt = choice(cands)
                comp.add(nxt)
                frontier |= set(dneighbors(nxt))
                frontier -= comp
            if valid_component(comp):
                add_component(comp, ncol)
                break

    go = verify_aaecdb9a(gi)
    return {'input': gi, 'output': go}


