def generate_aba27056(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(4, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (6, 30))
    w = unifint(diff_lb, diff_ub, (6, 30))
    bgc, sqc = sample(cols, 2)
    canv = canvas(bgc, (h, w))
    oh = randint(3, h)
    ow = unifint(diff_lb, diff_ub, (5, w - 1))
    loci = unifint(diff_lb, diff_ub, (0, h - oh))
    locj = randint(0, w - ow)
    bx = box(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
    maxk = (ow - 4) // 2
    k = randint(0, maxk)
    hole = connect((loci, locj + 2 + k), (loci, locj + ow - 3 - k))
    gi = fill(canv, sqc, bx)
    gi = fill(gi, bgc, hole)
    go = fill(canv, 4, backdrop(bx))
    go = fill(go, sqc, bx)
    bar = mapply(rbind(shoot, (-1, 0)), hole)
    go = fill(go, 4, bar)
    go = fill(go, 4, shoot(add((-1, 1), urcorner(hole)), (-1, 1)))
    go = fill(go, 4, shoot(add((-1, -1), ulcorner(hole)), (-1, -1)))
    rotf = choice((identity, rot90, rot180, rot270))
    gi = rotf(gi)
    go = rotf(go)
    return {'input': gi, 'output': go}


def generate_abbfd121(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)

    ph = unifint(diff_lb, diff_ub, (2, 5))
    pw = unifint(diff_lb, diff_ub, (2, 5))

    kh = unifint(diff_lb, diff_ub, (4, min(8, 30 // ph)))
    kw = unifint(diff_lb, diff_ub, (4, min(8, 30 // pw)))
    h = ph * kh
    w = pw * kw

    bgc = choice(cols)
    rem = remove(bgc, cols)
    # Reserve some colors for occluders (at least 1)
    nocc = unifint(diff_lb, diff_ub, (1, min(3, len(rem))))
    occ_colors = sample(list(rem), nocc)
    occ_set = set(occ_colors)
    # Tile colors: bgc + some non-occluder colors
    tile_avail = [c for c in rem if c not in occ_set]
    if len(tile_avail) == 0:
        # Not enough colors; reduce occluders
        occ_colors = [occ_colors[0]]
        occ_set = set(occ_colors)
        tile_avail = [c for c in rem if c not in occ_set]
    nmore = unifint(diff_lb, diff_ub, (1, min(3, len(tile_avail))))
    extras = sample(tile_avail, nmore)
    pcols = (bgc,) + tuple(extras)

    tile = canvas(bgc, (ph, pw))
    for i in range(ph):
        for j in range(pw):
            if i == 0 or j == 0:
                col = bgc
            else:
                col = choice(pcols)
            tile = fill(tile, col, frozenset({(i, j)}))

    # Ensure tile has at least 2 colors (verifier needs multicolor rows/cols)
    tile_colors = set()
    for row in tile:
        for v in row:
            tile_colors.add(v)
    if len(tile_colors) < 2:
        ci = randint(1, ph - 1)
        cj = randint(1, pw - 1)
        fc = choice(extras)
        tile = fill(tile, fc, frozenset({(ci, cj)}))

    clean = canvas(bgc, (h, w))
    for bi in range(kh):
        for bj in range(kw):
            clean = paint(clean, shift(asobject(tile), (bi * ph, bj * pw)))

    # Occluder sizing: must leave at least one full tile column and row clean
    # so the verifier can find the period and a clean tile block
    max_occ_h = min(h - 1, ph * (kh - 2))
    max_occ_w = min(w - 1, pw * (kw - 2))
    if max_occ_h < ph + 1:
        max_occ_h = ph + 1
    if max_occ_w < pw + 1:
        max_occ_w = pw + 1

    maxrh = unifint(diff_lb, diff_ub, (ph + 1, max(ph + 1, max_occ_h)))
    maxrw = unifint(diff_lb, diff_ub, (pw + 1, max(pw + 1, max_occ_w)))

    gi = clean

    # Place largest occluding rectangle
    top = randint(0, h - maxrh)
    left = randint(0, w - maxrw)
    largest_patch = backdrop(frozenset({(top, left), (top + maxrh - 1, left + maxrw - 1)}))
    gi = fill(gi, occ_colors[0], largest_patch)

    # Place smaller occluding rectangles with unique colors
    for k in range(1, len(occ_colors)):
        sh = unifint(diff_lb, diff_ub, (1, max(1, maxrh - 1)))
        sw = unifint(diff_lb, diff_ub, (1, max(1, maxrw - 1)))
        if sh >= maxrh and sw >= maxrw:
            sh = max(1, sh - 1)
        r = randint(0, h - sh)
        c = randint(0, w - sw)
        patch = backdrop(frozenset({(r, c), (r + sh - 1, c + sw - 1)}))
        gi = fill(gi, occ_colors[k], patch)

    go = verify_abbfd121(gi)
    return {'input': gi, 'output': go}


def generate_ac0a08a4(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (2, 5))
    w = unifint(diff_lb, diff_ub, (2, 5))
