def generate_b1986d4b(diff_lb: float, diff_ub: float) -> dict:

    def rect_indices(i, j, s):
        return frozenset((r, c) for r in range(i, i + s) for c in range(j, j + s))

    def _output_width(a, b, c):
        x26 = min(a, b, c)
        r4, r3, r2 = a - x26, b - x26, c - x26
        x30 = min(r4, r3) if r4 > 0 and r3 > 0 else 0
        r4 -= x30
        r3 -= x30
        x31 = min(r3, r2) if r3 > 0 and r2 > 0 else 0
        r3 -= x31
        r2 -= x31
        x36 = max(0, r2 - 1)
        return 5 * x26 + 5 * x30 + 4 * x31 + 5 * r4 + 4 * r3 + 3 * x36

    for _ in range(100):
        cols = interval(0, 10, 1)
        bgc = choice(cols)
        noisec = choice(remove(bgc, cols))
        sqcols = sample(remove(bgc, remove(noisec, cols)), 3)
        c4, c3, c2 = sqcols[0], sqcols[1], sqcols[2]

        n4 = unifint(diff_lb, diff_ub, (1, 6))
        n3 = unifint(diff_lb, diff_ub, (1, 6))
        n2 = unifint(diff_lb, diff_ub, (1, 6))

        while _output_width(n4, n3, n2) > 30:
            m = max(n4, n3, n2)
            if n4 == m:
                n4 -= 1
            elif n3 == m:
                n3 -= 1
            else:
                n2 -= 1

        h = unifint(diff_lb, diff_ub, (22, 30))
        w = unifint(diff_lb, diff_ub, (22, 30))
        gi = canvas(bgc, (h, w))
        occ = set()

        def place_squares(n, s, col):
            nonlocal gi, occ
            placed = 0
            trials = 0
            maxtr = 500
            while placed < n and trials < maxtr:
                trials += 1
                i = randint(0, h - s)
                j = randint(0, w - s)
                sq = rect_indices(i, j, s)
                halo = outbox(sq)
                if len((sq | halo) & frozenset(occ)) == 0:
                    gi = fill(gi, col, sq)
                    occ |= set(sq)
                    occ |= set(halo)
                    placed += 1
            return placed

        p4 = place_squares(n4, 4, c4)
        p3 = place_squares(n3, 3, c3)
        p2 = place_squares(n2, 2, c2)

        if p4 == 0 or p3 == 0 or p2 == 0:
            continue
        if _output_width(p4, p3, p2) > 30:
            continue

        maxnoise = max(1, (h * w) // 8)
        nnoise = unifint(diff_lb, diff_ub, (10, maxnoise))
        free = list(asindices(gi) - ofcolor(gi, c4) - ofcolor(gi, c3) - ofcolor(gi, c2))
        if len(free) > 0:
            k = min(nnoise, len(free))
            for loc in sample(free, k):
                gi = fill(gi, noisec, frozenset({loc}))

        go = verify_b1986d4b(gi)
        return {'input': gi, 'output': go}

    # Fallback with guaranteed layout
    bgc = 1
    noisec = 8
    c4, c3, c2 = 4, 3, 2
    h, w = 28, 28
    gi = canvas(bgc, (h, w))
    fixed = [
        (2, 2, 4, c4), (2, 10, 3, c3), (2, 16, 2, c2),
        (10, 2, 4, c4), (10, 10, 3, c3), (10, 16, 2, c2),
    ]
    for i, j, s, col in fixed:
        gi = fill(gi, col, rect_indices(i, j, s))
    nnoise = unifint(diff_lb, diff_ub, (15, 50))
    free = list(asindices(gi) - ofcolor(gi, c4) - ofcolor(gi, c3) - ofcolor(gi, c2))
    if len(free) > 0:
        k = min(nnoise, len(free))
        for loc in sample(free, k):
            gi = fill(gi, noisec, frozenset({loc}))
    go = verify_b1986d4b(gi)
    return {'input': gi, 'output': go}


def generate_b1fc8b8e(diff_lb: float, diff_ub: float) -> dict:
    gi = canvas(0, (6, 6))
    full = unifint(diff_lb, diff_ub, (0, 1)) == 1

    motif_full = frozenset({(0, 0), (0, 1), (1, 0), (1, 1)})
    motif_l = frozenset({(0, 1), (1, 0), (1, 1)})
    motif = motif_full if full else motif_l

    anchors = [(0, 0), (0, 2), (2, 0), (2, 2)]
    cells = frozenset()
    for a in anchors:
        cells = combine(cells, shift(motif, a))

    shifts = [(-1, -1), (-1, 0), (0, -1), (0, 0)]
    valid_shifts = []
    for di, dj in shifts:
        shifted = shift(cells, (di, dj))
        if uppermost(shifted) >= 0 and leftmost(shifted) >= 0 and lowermost(shifted) < 6 and rightmost(shifted) < 6:
            valid_shifts.append((di, dj))
    off = choice(valid_shifts)
    cells = shift(cells, off)

    gi = fill(gi, 8, cells)
    go = verify_b1fc8b8e(gi)
    return {'input': gi, 'output': go}


def generate_b20f7c8b(diff_lb: float, diff_ub: float) -> dict:
    # Colors for legend entries (not 0=bg, 8=legend_bg, 1=pattern_fg, 2=pattern_border)
    available_cols = [3, 4, 5, 6, 7, 9]
    nlegend = unifint(diff_lb, diff_ub, (3, 5))
    nlegend = min(nlegend, len(available_cols))
    legend_cols = sample(available_cols, nlegend)

    # 3x3 shapes for legend entries (3-5 cells each)
    all_shapes = [
        frozenset({(0, 1), (1, 1), (2, 0), (2, 2)}),
        frozenset({(0, 0), (0, 2), (1, 0), (1, 2), (2, 1)}),
        frozenset({(0, 1), (1, 0), (1, 1), (1, 2)}),
        frozenset({(0, 1), (1, 0), (1, 1), (2, 1)}),
        frozenset({(0, 0), (1, 0), (1, 1), (2, 1)}),
        frozenset({(0, 0), (0, 1), (1, 1), (2, 1)}),
        frozenset({(0, 1), (1, 1), (1, 2), (2, 1)}),
        frozenset({(0, 0), (0, 1), (1, 0), (2, 0)}),
        frozenset({(0, 0), (0, 1), (0, 2), (1, 1)}),
        frozenset({(0, 1), (1, 0), (1, 2), (2, 1)}),
        frozenset({(0, 0), (0, 1), (1, 1), (1, 2)}),
        frozenset({(0, 0), (1, 0), (1, 1), (1, 2)}),
        frozenset({(0, 0), (0, 1), (1, 0), (1, 1)}),
        frozenset({(0, 1), (1, 0), (1, 1), (2, 0)}),
        frozenset({(0, 0), (0, 2), (1, 1)}),
        frozenset({(0, 1), (1, 0), (2, 1)}),
    ]
    shuffle(all_shapes)
    legend_shapes = all_shapes[:nlegend]

    h, w = 18, 22
    gi = canvas(ZERO, (h, w))

    # Legend: 6 cols on left or right
    legend_on_left = choice((True, False))
    if legend_on_left:
        lc0 = 0
    else:
        lc0 = w - 6  # 16

    # Fill legend rectangle with 8
    legend_indices = frozenset((r, c) for r in range(h) for c in range(lc0, lc0 + 6))
    gi = fill(gi, EIGHT, legend_indices)

    # Place legend shapes vertically, each in its own ~(h//nlegend)-row slot
    slot_h = h // nlegend
    for k in range(nlegend):
        sr = k * slot_h + max(0, (slot_h - 3) // 2)
        sc = lc0 + 1
        colored_shp = recolor(legend_cols[k], legend_shapes[k])
        gi = paint(gi, shift(colored_shp, (sr, sc)))

    # Block area: the 16-col non-legend region
    if legend_on_left:
        ba_left = 6
    else:
        ba_left = 0

    # Block grid dimensions
    nrows_blocks = unifint(diff_lb, diff_ub, (1, 2))
    ncols_blocks = unifint(diff_lb, diff_ub, (1, 2))

    # Position blocks in the block area
    # Blocks are 5x5, with gaps of 2 between them
    # Total width needed: ncols_blocks * 5 + (ncols_blocks - 1) * 2
    # Total height needed: nrows_blocks * 5 + (nrows_blocks - 1) * 2
    total_bw = ncols_blocks * 5 + (ncols_blocks - 1) * 2
    total_bh = nrows_blocks * 5 + (nrows_blocks - 1) * 2

    # Center blocks in the available area
    btop = max(1, (h - total_bh) // 2)
    bleft = ba_left + max(1, (16 - total_bw) // 2)

    # 8 symmetry transforms on 3x3 indices
    def apply_transform(shp, idx):
        if idx == 0:
            return shp
        elif idx == 1:
            return frozenset((c, 2 - r) for r, c in shp)
        elif idx == 2:
            return frozenset((2 - r, 2 - c) for r, c in shp)
        elif idx == 3:
            return frozenset((2 - c, r) for r, c in shp)
        elif idx == 4:
            return frozenset((2 - r, c) for r, c in shp)
        elif idx == 5:
            return frozenset((r, 2 - c) for r, c in shp)
        elif idx == 6:
            return frozenset((c, r) for r, c in shp)
        else:
            return frozenset((2 - c, 2 - r) for r, c in shp)

    for br in range(nrows_blocks):
        for bc in range(ncols_blocks):
            top = btop + br * 7
            left = bleft + bc * 7

            if top + 5 > h or left + 5 > ba_left + 16:
                continue

            chosen_idx = randint(0, nlegend - 1)
            lcol = legend_cols[chosen_idx]
            lshp = legend_shapes[chosen_idx]

            block_indices = frozenset(
                (top + dr, left + dc) for dr in range(5) for dc in range(5)
            )

            if choice((True, False)):
                # Solid block: fill with legend color
                gi = fill(gi, lcol, block_indices)
            else:
                # Pattern block: 2 background with 1s forming a transformed shape
                gi = fill(gi, TWO, block_indices)
                tidx = randint(0, 7)
                tshp = apply_transform(lshp, tidx)
                # Normalize to top-left corner of 3x3
                min_r = min(r for r, c in tshp)
                min_c = min(c for r, c in tshp)
                tshp = frozenset((r - min_r, c - min_c) for r, c in tshp)
                colored_inner = recolor(ONE, tshp)
                gi = paint(gi, shift(colored_inner, (top + 1, left + 1)))

    go = verify_b20f7c8b(gi)
    return {'input': gi, 'output': go}


def generate_b230c067(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (1, 2))
    while True:
        h = unifint(diff_lb, diff_ub, (10, 30))
        w = unifint(diff_lb, diff_ub, (10, 30))
        oh = unifint(diff_lb, diff_ub, (2, h // 3 - 1))
        ow = unifint(diff_lb, diff_ub, (2, w // 3 - 1))
        numcd = unifint(diff_lb, diff_ub, (0, (oh * ow) // 2))
        numc = choice((numcd, oh * ow - numcd))
        numca = min(max(2, numc), oh * ow - 2)
        bounds = asindices(canvas(-1, (oh, ow)))
        sp = choice(totuple(bounds))
        shp = {sp}
        for k in range(numca):
            ij = choice(totuple((bounds - shp) & mapply(neighbors, shp)))
            shp.add(ij)
        shpa = normalize(shp)
        shpb = set(normalize(shp))
        mxnch = oh * ow - len(shpa)
        nchinv = unifint(diff_lb, diff_ub, (1, mxnch))
        nch = mxnch - nchinv
        nch = min(max(1, nch), mxnch)
        for k in range(nch):
            ij = choice(totuple((bounds - shpb) & mapply(neighbors, shpb)))
            shpb.add(ij)
        if choice((True, False)):
            shpa, shpb = shpb, shpa
        bgc, fgc = sample(cols, 2)
        c = canvas(bgc, (h, w))
        inds = asindices(c)
        acands = sfilter(inds, lambda ij: ij[0] <= h - height(shpa) and ij[1] <= w - width(shpa))
        aloc = choice(totuple(acands))
        aplcd = shift(shpa, aloc)
        gi = fill(c, fgc, aplcd)
        go = fill(c, 2, aplcd)
        maxtrials = 10
        tr = 0
        succ = 0
        inds = (inds - aplcd) - mapply(neighbors, aplcd)
        inds = sfilter(inds, lambda ij: ij[0] <= h - height(shpb) and ij[1] <= w - width(shpb))
        while succ < 2 and tr <= maxtrials:
            if len(inds) == 0:
                break
            loc = choice(totuple(inds))
            plcbd = shift(shpb, loc)
            if plcbd.issubset(inds):
                gi = fill(gi, fgc, plcbd)
                go = fill(go, 1, plcbd)
                succ += 1
                inds = (inds - plcbd) - mapply(neighbors, plcbd)
            tr += 1
        if succ == 2:
            break
    return {'input': gi, 'output': go}


def generate_b25e450b(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (6, 18))
    w = unifint(diff_lb, diff_ub, (6, 18))

    rows = []
    for i in range(h):
        row = []
        for j in range(w):
            row.append(choice((5, 7)))
        rows.append(row)

    maxobjs = 4
    nobjs = unifint(diff_lb, diff_ub, (1, maxobjs))
    sides = ['top', 'bottom', 'left', 'right']
    shuffle(sides)
    chosen_sides = sides[:nobjs]

    occupied = set()

    def rect_cells(r0, r1, c0, c1):
        return {(i, j) for i in range(r0, r1 + 1) for j in range(c0, c1 + 1)}

    for side in chosen_sides:
        placed = False
        for _ in range(100):
            if side in ('top', 'bottom'):
                rh = unifint(diff_lb, diff_ub, (1, max(1, h // 3)))
                rw = unifint(diff_lb, diff_ub, (1, max(1, w // 3)))
                rw = min(rw, w)
                rh = min(rh, h - 1)
                if rh < 1:
                    rh = 1
                if side == 'top':
                    r0, r1 = 0, rh - 1
                else:
                    r0, r1 = h - rh, h - 1
                c0 = randint(0, w - rw)
                c1 = c0 + rw - 1
            else:
                rh = unifint(diff_lb, diff_ub, (1, max(1, h // 3)))
                rw = unifint(diff_lb, diff_ub, (1, max(1, w // 3)))
                rh = min(rh, h)
                rw = min(rw, w - 1)
                if rw < 1:
                    rw = 1
                if side == 'left':
                    c0, c1 = 0, rw - 1
                else:
                    c0, c1 = w - rw, w - 1
                r0 = randint(0, h - rh)
                r1 = r0 + rh - 1

            cells = rect_cells(r0, r1, c0, c1)

            ok = True
            for ii, jj in cells:
                for ni, nj in dneighbors((ii, jj)):
                    if 0 <= ni < h and 0 <= nj < w and (ni, nj) in occupied and (ni, nj) not in cells:
                        ok = False
                        break
                if not ok:
                    break
            if not ok:
                continue

            for ii, jj in cells:
                rows[ii][jj] = 0
            occupied |= cells
            placed = True
            break

        if not placed:
            if side == 'top':
                cells = {(0, 0)}
            elif side == 'bottom':
                cells = {(h - 1, w - 1)}
            elif side == 'left':
                cells = {(h - 1, 0)}
            else:
                cells = {(0, w - 1)}
            for ii, jj in cells:
                rows[ii][jj] = 0
            occupied |= cells

    gi = tuple(tuple(r) for r in rows)
    go = verify_b25e450b(gi)
    return {'input': gi, 'output': go}


def generate_b27ca6d3(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(3, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (4, 30))
    w = unifint(diff_lb, diff_ub, (4, 30))
    bgc, dotc = sample(cols, 2)
    c = canvas(bgc, (h, w))
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    ndots = unifint(diff_lb, diff_ub, (0, (h * w) // 5))
    nbars = unifint(diff_lb, diff_ub, (0, (h * w) // 12))
    dot = frozenset({(dotc, (1, 1))}) | recolor(bgc, dneighbors((1, 1)))
    bar1 = fill(canvas(bgc, (4, 3)), dotc, {(1, 1), (2, 1)})
    bar2 = dmirror(bar1)
    bar1 = asobject(bar1)
    bar2 = asobject(bar2)
    opts = [dot] * ndots + [choice((bar1, bar2)) for k in range(nbars)]
    shuffle(opts)
    inds = shift(asindices(canvas(-1, (h+2, w+2))), (-1, -1))
    for elem in opts:
        loc = (-1, -1)
        tr = 0
        while not toindices(shift(elem, loc)).issubset(inds) and tr < 5:
            loc = choice(totuple(inds))
            tr += 1
        xx = shift(elem, loc)
        if toindices(xx).issubset(inds):
            gi = paint(gi, xx)
            if len(elem) == 12:
                go = paint(go, {cel if cel[0] != bgc else (3, cel[1]) for cel in xx})
            else:
                go = paint(go, xx)
            inds = inds - toindices(xx)
    return {'input': gi, 'output': go}


def generate_b2862040(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (8,))
