def _rect(top, left, rh, rw):
    return shift(asindices(canvas(1, (rh, rw))), (top, left))

def generate_d4c90558(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    gray = 5
    cols = remove(gray, remove(bgc, interval(1, 10, 1)))

    nobj = unifint(diff_lb, diff_ub, (2, 4))
    maxtries = 100

    for _ in range(maxtries):
        h = unifint(diff_lb, diff_ub, (18, 30))
        w = unifint(diff_lb, diff_ub, (18, 30))
        gi = canvas(bgc, (h, w))

        colors = sample(cols, nobj)
        rects = []
        occupied = set()

        ok = True
        for k in range(nobj):
            placed = False
            for __ in range(100):
                rh = unifint(diff_lb, diff_ub, (5, min(14, h - 2)))
                rw = unifint(diff_lb, diff_ub, (5, min(14, w - 2)))
                if rh < 5 or rw < 5:
                    continue
                extra_bottom = randint(0, 2)
                extra_right = randint(0, 2)
                total_h = rh + extra_bottom
                total_w = rw + extra_right
                if total_h > h - 1 or total_w > w - 1:
                    continue
                top = randint(0, h - total_h)
                left = randint(0, w - total_w)
                full_cells = _rect(top, left, total_h, total_w)
                halo = _rect(
                    max(0, top - 1), max(0, left - 1),
                    min(h, top + total_h + 1) - max(0, top - 1),
                    min(w, left + total_w + 1) - max(0, left - 1)
                )
                if len(occupied & halo) == 0:
                    rects.append((colors[k], top, left, rh, rw, extra_bottom, extra_right))
                    occupied |= full_cells
                    placed = True
                    break
            if not placed:
                ok = False
                break
        if not ok:
            continue

        counts = []
        for col, top, left, rh, rw, eb, er in rects:
            total_h = rh + eb
            total_w = rw + er
            full = _rect(top, left, total_h, total_w)
            gi = fill(gi, col, full)

            ih = rh - 2
            iw = rw - 2
            inner = _rect(top + 1, left + 1, ih, iw)
            gi = fill(gi, bgc, inner)

            area = ih * iw
            cnt = unifint(diff_lb, diff_ub, (1, min(30, max(1, area - 1))))
            cnt = min(max(1, cnt), area, 30)
            inner_cells = sample(totuple(inner), cnt)
            gi = fill(gi, gray, frozenset(inner_cells))
            counts.append(cnt)

        if len(set(counts)) != len(counts):
            continue

        go = verify_d4c90558(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    h = 20
    w = 20
    gi = canvas(0, (h, w))
    specs = (
        (2, 1, 1, 8, 8, 1, 1, 3),
        (6, 10, 10, 7, 7, 0, 0, 4),
    )
    for col, top, left, rh, rw, eb, er, cnt in specs:
        total_h = rh + eb
        total_w = rw + er
        full = _rect(top, left, total_h, total_w)
        gi = fill(gi, col, full)
        ih = rh - 2
        iw = rw - 2
        inner = _rect(top + 1, left + 1, ih, iw)
        gi = fill(gi, 0, inner)
        cells = sample(totuple(inner), cnt)
        gi = fill(gi, 5, frozenset(cells))
    go = verify_d4c90558(gi)
    return {'input': gi, 'output': go}


def generate_d4f3cd78(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(8, interval(0, 10, 1))    
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    ih = unifint(diff_lb, diff_ub, (3, h//3*2))
    iw = unifint(diff_lb, diff_ub, (3, w//3*2))
    loci = randint(1, h - ih - 1)
    locj = randint(1, w - iw - 1)
    crns = frozenset({(loci, locj), (loci + ih - 1, locj + iw - 1)})
    fullcrns = corners(crns)
    bx = box(crns)
    opts = bx - fullcrns
    bgc, fgc = sample(cols, 2)
    c = canvas(bgc, (h, w))
    nholes = unifint(diff_lb, diff_ub, (1, len(opts)))
    holes = sample(totuple(opts), nholes)
    gi = fill(c, fgc, bx - set(holes))
    bib = backdrop(inbox(bx))
    go = fill(gi, 8, bib)
    A, B = ulcorner(bib)
    C, D = lrcorner(bib)
    f1 = lambda idx: 1 if idx > C else (-1 if idx < A else 0)
    f2 = lambda idx: 1 if idx > D else (-1 if idx < B else 0)
    f = lambda d: shoot(d, (f1(d[0]), f2(d[1])))
    res = mapply(f, set(holes))
    go = fill(go, 8, res)
    return {'input': gi, 'output': go}


def generate_d511f180(diff_lb: float, diff_ub: float) -> dict:
    cols = difference(interval(0, 10, 1), (5, 8))
    h = unifint(diff_lb, diff_ub, (2, 30))
    w = unifint(diff_lb, diff_ub, (2, 30))
