def generate_d56f2372(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    cols = remove(bgc, interval(0, 10, 1))

    h = unifint(diff_lb, diff_ub, (18, 28))
    w = unifint(diff_lb, diff_ub, (16, 26))
    gi = canvas(bgc, (h, w))

    nobj = unifint(diff_lb, diff_ub, (4, 5))
    objcols = sample(cols, nobj)

    def make_vsym_patch():
        ph = unifint(diff_lb, diff_ub, (3, 7))
        pw = unifint(diff_lb, diff_ub, (3, 7))
        halfw = (pw + 1) // 2
        rows = []
        for i in range(ph):
            left = [0] * halfw
            if i == 0 or i == ph - 1:
                mn = 1
            else:
                mn = 0
            mx = halfw
            cnt = unifint(diff_lb, diff_ub, (mn, mx))
            picks = sample(interval(0, halfw, 1), cnt) if cnt > 0 else ()
            for j in picks:
                left[j] = 1
            if max(left) == 0:
                left[choice(interval(0, halfw, 1))] = 1
            if pw % 2 == 0:
                row = left + left[::-1]
            else:
                row = left + left[:-1][::-1]
            rows.append(row)
        if all(sum(r) == pw for r in rows):
            ii = unifint(diff_lb, diff_ub, (0, ph - 1))
            jj = unifint(diff_lb, diff_ub, (0, halfw - 1))
            rows[ii][jj] = 0
            rows[ii][pw - 1 - jj] = 0
        return tuple(tuple(v for v in r) for r in rows)

    def make_non_vsym_patch():
        for _ in range(50):
            ph = unifint(diff_lb, diff_ub, (3, 7))
            pw = unifint(diff_lb, diff_ub, (3, 7))
            rows = []
            for i in range(ph):
                row = [0] * pw
                mn = 1 if i in (0, ph - 1) else 0
                cnt = unifint(diff_lb, diff_ub, (mn, pw))
                picks = sample(interval(0, pw, 1), cnt) if cnt > 0 else ()
                for j in picks:
                    row[j] = 1
                rows.append(row)
            if all(sum(r) == 0 for r in rows):
                rows[0][0] = 1
            patch = tuple(tuple(v for v in r) for r in rows)
            if patch != vmirror(patch):
                return patch
        rows = [[1, 0, 0], [1, 1, 0], [0, 1, 0]]
        return tuple(tuple(v for v in r) for r in rows)

    patches = [make_non_vsym_patch() for _ in range(nobj - 1)]
    sym_patch = make_vsym_patch()
    sym_idx = randint(0, nobj - 1)
    patches.insert(sym_idx, sym_patch)

    dims = [shape(p) for p in patches]
    order_idx = list(range(nobj))
    shuffle(order_idx)

    placed = []
    occupied = set()

    for k in order_idx:
        ph, pw = dims[k]
        placed_ok = False
        for _ in range(200):
            loci = randint(1, h - ph - 1)
            locj = randint(1, w - pw - 1)
            cells = {(loci + i, locj + j) for i in range(ph) for j in range(pw)}
            halo = set()
            for i, j in cells:
                for ni in range(i - 1, i + 2):
                    for nj in range(j - 1, j + 2):
                        if 0 <= ni < h and 0 <= nj < w:
                            halo.add((ni, nj))
            if len(occupied & halo) == 0:
                placed.append((k, loci, locj))
                occupied |= cells
                placed_ok = True
                break
        if not placed_ok:
            loci = 1
            locj = 1
            placed.append((k, loci, locj))

    for k, loci, locj in placed:
        patch = patches[k]
        col = objcols[k]
        inds = frozenset(
            (loci + i, locj + j)
            for i in range(len(patch))
            for j in range(len(patch[0]))
            if patch[i][j] == 1
        )
        gi = fill(gi, col, inds)

    go = verify_d56f2372(gi)
    return {'input': gi, 'output': go}


def generate_d5c634a2(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    tc = 2

    max_up = 4
    max_down = 4
    total = unifint(diff_lb, diff_ub, (1, 8))
    nup = randint(0, min(max_up, total))
    ndown = total - nup
    if ndown > max_down:
        overflow = ndown - max_down
        ndown = max_down
        nup = min(max_up, nup + overflow)
    if nup + ndown == 0:
        nup = 1

    n = nup + ndown
    h = unifint(diff_lb, diff_ub, (5, min(30, max(5, 3 * n + 3))))
    w = unifint(diff_lb, diff_ub, (4, min(30, max(4, 4 * n + 3))))

    def tshape_up(r, c):
        return frozenset({(r, c), (r + 1, c - 1), (r + 1, c), (r + 1, c + 1)})

    def tshape_down(r, c):
        return frozenset({(r, c - 1), (r, c), (r, c + 1), (r + 1, c)})

    gi = canvas(bgc, (h, w))
    occupied = set()

    kinds = ['u'] * nup + ['d'] * ndown
    shuffle(kinds)

    placed = 0
    for k in kinds:
        ok = False
        for _ in range(200):
            r = randint(0, h - 2)
            c = randint(1, w - 2)
            cells = tshape_up(r, c) if k == 'u' else tshape_down(r, c)

            bad = False
            for i, j in cells:
                for ni in range(i - 1, i + 2):
                    for nj in range(j - 1, j + 2):
                        if (ni, nj) in occupied:
                            bad = True
                            break
                    if bad:
                        break
                if bad:
                    break
            if bad:
                continue

            gi = fill(gi, tc, cells)
            occupied |= set(cells)
            placed += 1
            ok = True
            break
        if not ok:
            break

    if placed == 0:
        gi = canvas(bgc, (5, 4))
        gi = fill(gi, tc, frozenset({(0, 0), (0, 1), (0, 2), (1, 1)}))

    go = verify_d5c634a2(gi)
    return {'input': gi, 'output': go}


def generate_d5d6de2d(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(3, interval(0, 10, 1))    
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    num = unifint(diff_lb, diff_ub, (1, 16))
    indss = asindices(gi)
    maxtrials = 4 * num
    tr = 0
    succ = 0
    while succ < num and tr <= maxtrials:
        if len(remcols) == 0 or len(indss) == 0:
            break
        oh = randint(1, 7)
        ow = randint(1, 7)
        subs = totuple(sfilter(indss, lambda ij: ij[0] < h - oh and ij[1] < w - ow))
        if len(subs) == 0:
            tr += 1
            continue
        loci, locj = choice(subs)
        obj = frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)})
        bd = backdrop(obj)
        col = choice(remcols)
        if bd.issubset(indss):
            gi = fill(gi, col, box(bd))
            if oh > 2 and ow > 2:
                go = fill(go, 3, backdrop(inbox(bd)))
            succ += 1
            indss = (indss - bd) - outbox(bd)
        tr += 1
    return {'input': gi, 'output': go}


def generate_d631b094(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
