def generate_e39e9282(diff_lb: float, diff_ub: float) -> dict:
    bg = 8
    h = unifint(diff_lb, diff_ub, (9, 20))
    w = unifint(diff_lb, diff_ub, (9, 20))
    gi = canvas(bg, (h, w))

    max_blocks = max(1, min(6, (h // 4) * (w // 4)))
    nblocks = unifint(diff_lb, diff_ub, (1, max_blocks))

    cells = [(i, j) for i in range(h - 2) for j in range(w - 2)]
    shuffle(cells)
    blocks = []

    for i, j in cells:
        if len(blocks) >= nblocks:
            break
        ok = True
        for bi, bj, _ in blocks:
            if not (i + 2 < bi - 1 or bi + 2 < i - 1 or j + 2 < bj - 1 or bj + 2 < j - 1):
                ok = False
                break
        if ok:
            col = choice((5, 6))
            blocks.append((i, j, col))

    if len(blocks) == 0:
        i = unifint(diff_lb, diff_ub, (0, h - 3))
        j = unifint(diff_lb, diff_ub, (0, w - 3))
        blocks = [(i, j, 6)]

    if all(col == 5 for _, _, col in blocks):
        k = randint(0, len(blocks) - 1)
        bi, bj, _ = blocks[k]
        blocks[k] = (bi, bj, 6)

    adj_dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    placed9 = set()
    has_adj6 = False

    for bi, bj, col in blocks:
        gi = fill(gi, col, connect((bi, bj), (bi + 2, bj + 2)))
        nadj = unifint(diff_lb, diff_ub, (0, 2))
        dirs = sample(adj_dirs, nadj) if nadj > 0 else []
        for di, dj in dirs:
            if di == -1:
                opts = [(bi - 1, bj + k) for k in range(3)]
            elif di == 1:
                opts = [(bi + 3, bj + k) for k in range(3)]
            elif dj == -1:
                opts = [(bi + k, bj - 1) for k in range(3)]
            else:
                opts = [(bi + k, bj + 3) for k in range(3)]
            opts = [p for p in opts if 0 <= p[0] < h and 0 <= p[1] < w]
            opts = [p for p in opts if p not in placed9]
            if len(opts) == 0:
                continue
            loc = choice(opts)
            placed9.add(loc)
            gi = fill(gi, 9, initset(loc))
            if col == 6:
                has_adj6 = True

    freecells = [p for p in asindices(gi) if p not in placed9]
    extra_cap = max(0, len(freecells) // 20)
    nextra = unifint(diff_lb, diff_ub, (0, min(4, extra_cap)))
    if nextra > 0 and len(freecells) > 0:
        extras = sample(totuple(frozenset(freecells)), min(nextra, len(freecells)))
        for loc in extras:
            gi = fill(gi, 9, initset(loc))
            placed9.add(loc)

    if not has_adj6:
        sixblocks = [(bi, bj) for bi, bj, col in blocks if col == 6]
        if len(sixblocks) > 0:
            bi, bj = choice(sixblocks)
            candsets = []
            if bi - 1 >= 0:
                candsets.append([(bi - 1, bj + k) for k in range(3)])
            if bi + 3 < h:
                candsets.append([(bi + 3, bj + k) for k in range(3)])
            if bj - 1 >= 0:
                candsets.append([(bi + k, bj - 1) for k in range(3)])
            if bj + 3 < w:
                candsets.append([(bi + k, bj + 3) for k in range(3)])
            cands = []
            for cs in candsets:
                for p in cs:
                    if p not in placed9:
                        cands.append(p)
            if len(cands) > 0:
                loc = choice(cands)
                gi = fill(gi, 9, initset(loc))
                placed9.add(loc)

    go = verify_e39e9282(gi)
    return {'input': gi, 'output': go}


def generate_e3f79277(diff_lb: float, diff_ub: float) -> dict:
    bgc, objc = sample(interval(0, 10, 1), 2)
    h = unifint(diff_lb, diff_ub, (2, 10))
    w = unifint(diff_lb, diff_ub, (2, 10))
