    for r in range(m):
        for c in range(r + 1):
            tri.add((r, c))
    tri = frozenset(tri)

    if corner == "ul":
        patch = tri
    elif corner == "ur":
        patch = shift(vmirror(tri), (0, w - m))
    elif corner == "ll":
        patch = shift(hmirror(tri), (h - m, 0))
    else:
        patch = shift(hmirror(vmirror(tri)), (h - m, w - m))

