def generate_e4941b18(diff_lb: float, diff_ub: float) -> dict:
    bgc = 7
    rectc = 5
    c2 = 2
    c8 = 8

    h = unifint(diff_lb, diff_ub, (6, 20))
    w = unifint(diff_lb, diff_ub, (6, 20))

    # Rectangle dimensions — need room for markers above and 8 destination on a side
    rect_h = unifint(diff_lb, diff_ub, (2, h - 2))
    rect_w = unifint(diff_lb, diff_ub, (2, w - 3))

    # Rectangle touches the bottom of the grid
    top = h - rect_h

    # Left edge: need at least 1 col free on one side for 8 destination
    # Ensure left >= 1 OR left + rect_w <= w - 2 (at least one side has room)
    # Simplest: ensure both sides have room
    left = unifint(diff_lb, diff_ub, (1, w - rect_w - 1))

    gi = canvas(bgc, (h, w))

    # Create filled rectangle using backdrop of two corner points
    rect = backdrop(frozenset({(top, left), (h - 1, left + rect_w - 1)}))
    gi = fill(gi, rectc, rect)

    # Markers go in the row immediately above the rectangle
    marker_row = unifint(diff_lb, diff_ub, (0, top - 1))

    # Decide arrangement: side=0 means 2 is left of 8, side=1 means 2 is right of 8
    side = choice((0, 1))

    if side == 0:
        # 2 left of 8 → output places 8 at (bottom, right+1)
        # Need right+1 = left+rect_w < w, ensured by left <= w - rect_w - 1
        # Both markers within rect column span
        j2 = unifint(diff_lb, diff_ub, (left, left + rect_w - 2))
        j8 = unifint(diff_lb, diff_ub, (j2 + 1, left + rect_w - 1))
    else:
        # 2 right of 8 → output places 8 at (bottom, left-1)
        # Need left-1 >= 0, ensured by left >= 1
        # Both markers within rect column span
        j8 = unifint(diff_lb, diff_ub, (left, left + rect_w - 2))
        j2 = unifint(diff_lb, diff_ub, (j8 + 1, left + rect_w - 1))

    gi = fill(gi, c2, initset((marker_row, j2)))
    gi = fill(gi, c8, initset((marker_row, j8)))

    go = verify_e4941b18(gi)
    return {'input': gi, 'output': go}


def generate_e5062a87(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    h = unifint(diff_lb, diff_ub, (10, 30))
    w = unifint(diff_lb, diff_ub, (10, 30))
