def generate_e5790162(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (6, 12))
    w = unifint(diff_lb, diff_ub, (6, 12))
    gi = canvas(ZERO, (h, w))

    si = unifint(diff_lb, diff_ub, (0, h - 1))
    sj = unifint(diff_lb, diff_ub, (0, max(0, w - 4)))
    gi = fill(gi, THREE, initset((si, sj)))

    dirs = [RIGHT]
    pos = (si, sj)
    markers = []
    used = {pos}

    maxturns = min(4, h + w)
    nturns = unifint(diff_lb, diff_ub, (1, maxturns))

    for _ in range(nturns):
        di, dj = dirs[-1]
        if di == 0 and dj == 1:
            maxstep = w - 1 - pos[1]
        elif di == 0 and dj == -1:
            maxstep = pos[1]
        elif di == 1 and dj == 0:
            maxstep = h - 1 - pos[0]
        else:
            maxstep = pos[0]

        if maxstep < 2:
            break

        step = unifint(diff_lb, diff_ub, (2, maxstep))
        mpos = (pos[0] + di * step, pos[1] + dj * step)

        pathcells = []
        ok = True
        for k in range(1, step):
            cell = (pos[0] + di * k, pos[1] + dj * k)
            if cell in used:
                ok = False
                break
            pathcells.append(cell)
        if not ok or mpos in used:
            break

        turnc = choice((SIX, EIGHT))
        gi = fill(gi, turnc, initset(mpos))
        markers.append((mpos, turnc))
        for cell in pathcells:
            used.add(cell)
        used.add(mpos)

        if turnc == EIGHT:
            ndir = (-dj, di)
        else:
            ndir = (dj, -di)
        dirs.append(ndir)
        pos = (mpos[0] - di, mpos[1] - dj)

    if len(markers) == 0:
        step = unifint(diff_lb, diff_ub, (2, max(2, w - 1 - sj)))
        step = min(step, w - 1 - sj)
        if step >= 2:
            mpos = (si, sj + step)
            gi = fill(gi, choice((SIX, EIGHT)), initset(mpos))

    go = verify_e5790162(gi)
    return {'input': gi, 'output': go}


