def generate_e619ca6e(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    objc = 3

    h = unifint(diff_lb, diff_ub, (20, 30))
    w = unifint(diff_lb, diff_ub, (20, 30))
    gi = canvas(bgc, (h, w))

    nobj = unifint(diff_lb, diff_ub, (1, 4))

    rects = []
    occ = set()

    for _ in range(200):
        rects = []
        occ = set()
        success = True

        for k in range(nobj):
            rh = unifint(diff_lb, diff_ub, (2, 4))
            rw = unifint(diff_lb, diff_ub, (2, 5))

            max_i = h - rh - 1
            max_j = w - rw
            if max_i < 0 or max_j < 0:
                success = False
                break

            placed = False
            for _try in range(100):
                i = randint(0, max_i)
                j = randint(0, max_j)
                rect = connect((i, j), (i + rh - 1, j + rw - 1))

                if rect & occ:
                    continue

                ok = True
                for prev in rects:
                    pi, pj, prh, prw, prect = prev
                    if not (i + rh <= pi or pi + prh <= i or j + rw <= pj or pj + prw <= j):
                        ok = False
                        break
                    if abs(i - pi) < max(rh, prh):
                        if not (j + rw <= pj or pi + prh <= i or i + rh <= pi or pj + prw <= j):
                            ok = False
                            break
                if not ok:
                    continue

                rects.append((i, j, rh, rw, rect))
                occ |= set(rect)
                placed = True
                break

            if not placed:
                success = False
                break

        if success:
            break

    if len(rects) == 0:
        rh = min(2, h)
        rw = min(2, w)
        rect = connect((0, 0), (rh - 1, rw - 1))
        gi = fill(gi, objc, rect)
        go = verify_e619ca6e(gi)
        return {'input': gi, 'output': go}

    for i, j, rh, rw, rect in rects:
        gi = fill(gi, objc, rect)

    go = verify_e619ca6e(gi)
    return {'input': gi, 'output': go}


