def generate_e6721834(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (6, 15))
    w = unifint(diff_lb, diff_ub, (8, 30))
    bgc1, bgc2, sqc = sample(cols, 3)
    remcols = difference(cols, (bgc1, bgc2, sqc))
    gi1 = canvas(bgc1, (h, w))
    gi2 = canvas(bgc2, (h, w))
    noccs = unifint(diff_lb, diff_ub, (1, (h * w) // 16))
    tr = 0
    succ = 0
    maxtr = 5 * noccs
    gi1inds = asindices(gi1)
    gi2inds = asindices(gi2)
    go = canvas(bgc2, (h, w))
    seen = []
    while tr < maxtr and succ < noccs:
        tr += 1
        oh = randint(2, min(6, h//2))
        ow = randint(2, min(6, w//2))
        cands = sfilter(gi1inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
        if len(cands) == 0:
            continue
        loc = choice(totuple(cands))
        bounds = shift(asindices(canvas(-1, (oh, ow))), loc)
        ncells = unifint(diff_lb, diff_ub, (1, (oh * ow) // 2))
        obj = set(sample(totuple(bounds), ncells))
        objc = choice(remcols)
        objn = normalize(obj)
        if (objn, objc) in seen:
            continue
        seen.append(((objn, objc)))
        if bounds.issubset(gi1inds):
            succ += 1
            gi1inds = (gi1inds - bounds) - mapply(neighbors, bounds)
            gi1 = fill(gi1, sqc, bounds)
            gi1 = fill(gi1, objc, obj)
            cands2 = sfilter(gi2inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
            if len(cands2) == 0:
                continue
            loc2 = choice(totuple(cands2))
            bounds2 = shift(shift(bounds, invert(loc)), loc2)
            obj2 = shift(shift(obj, invert(loc)), loc2)
            if bounds2.issubset(gi2inds):
                gi2inds = (gi2inds - bounds2) - mapply(neighbors, bounds2)
                gi2 = fill(gi2, objc, obj2)
                go = fill(go, sqc, bounds2)
                go = fill(go, objc, obj2)
    gi = vconcat(gi1, gi2)
    mfs = (identity, dmirror, cmirror, vmirror, hmirror, rot90, rot180, rot270)
    nmfs = choice((1, 2))
    for fn in sample(mfs, nmfs):
        gi = fn(gi)
        go = fn(go)
    return {'input': gi, 'output': go}


def generate_e681b708(diff_lb: float, diff_ub: float) -> dict:
    cols = (2, 3, 6, 8)
    h = unifint(diff_lb, diff_ub, (18, 30))
    w = unifint(diff_lb, diff_ub, (18, 30))

    orient = choice((0, 1))  # 0 main horizontal, 1 main vertical

    if orient == 0:
        mr = unifint(diff_lb, diff_ub, (3, h - 4))
        nmarks = unifint(diff_lb, diff_ub, (3, min(5, w - 2)))
        js = sorted(sample(tuple(range(1, w - 1)), nmarks - 2))
        js = [0] + js[1:-1] + [w - 1] if nmarks > 2 else [0, w - 1]
        if nmarks > 2:
            mids = sorted(sample(tuple(range(1, w - 1)), nmarks - 2))
            js = [0] + mids + [w - 1]
        else:
            js = [0, w - 1]
        mark_pos = [(mr, j) for j in js]

        gi = canvas(0, (h, w))
        gi = fill(gi, 1, connect((mr, 0), (mr, w - 1)))

        top_possible = [j for j in js if mr >= 3]
        bot_possible = [j for j in js if h - 1 - mr >= 3]
        ntop = 0 if len(top_possible) == 0 else unifint(diff_lb, diff_ub, (1, len(top_possible)))
        nbot = 0 if len(bot_possible) == 0 else unifint(diff_lb, diff_ub, (1, len(bot_possible)))
        top_js = sample(top_possible, ntop) if ntop > 0 else []
        bot_js = sample(bot_possible, nbot) if nbot > 0 else []

        for j in top_js:
            gi = fill(gi, 1, connect((0, j), (mr, j)))
            mark_pos.append((0, j))
        for j in bot_js:
            gi = fill(gi, 1, connect((mr, j), (h - 1, j)))
            mark_pos.append((h - 1, j))

        mark_pos = list(dict.fromkeys(mark_pos))
        mark_cols = {}
        for p in mark_pos:
            mark_cols[p] = choice(cols)
        if len(js) >= 2:
            for a, b in zip(js[:-1], js[1:]):
                if b - a >= 2:
                    if randint(0, 1) == 0:
                        mark_cols[(mr, a)] = choice(cols)
                    else:
                        mark_cols[(mr, b)] = choice(cols)

        for j in top_js:
            if mr >= 3:
                if randint(0, 1) == 0:
                    mark_cols[(0, j)] = choice(cols)
                else:
                    mark_cols[(mr, j)] = choice(cols)
        for j in bot_js:
            if h - 1 - mr >= 3:
                if randint(0, 1) == 0:
                    mark_cols[(h - 1, j)] = choice(cols)
                else:
                    mark_cols[(mr, j)] = choice(cols)

        for p, c in mark_cols.items():
            gi = fill(gi, c, frozenset({p}))

        rooms = []
        top_set = set(top_js)
        bot_set = set(bot_js)
        for a, b in zip(js[:-1], js[1:]):
            if b - a >= 2:
                if a in top_set and b in top_set:
                    rooms.append((1, mr - 1, a + 1, b - 1, [(0, a), (0, b), (mr, a), (mr, b)]))
                if a in bot_set and b in bot_set:
                    rooms.append((mr + 1, h - 2, a + 1, b - 1, [(mr, a), (mr, b), (h - 1, a), (h - 1, b)]))

        nnoise = unifint(diff_lb, diff_ub, (6, max(6, (h * w) // 10)))
        free = [(i, j) for i in range(h) for j in range(w) if gi[i][j] == 0]
        shuffle(free)
        for p in free[:nnoise]:
            gi = fill(gi, 1, frozenset({p}))

        for (r1, r2, c1, c2, corners) in rooms:
            area = [(i, j) for i in range(r1, r2 + 1) for j in range(c1, c2 + 1)]
            if len(area) == 0:
                continue
            nfill = unifint(diff_lb, diff_ub, (1, max(1, len(area) // 4)))
            picks = sample(area, min(nfill, len(area)))
            for p in picks:
                gi = fill(gi, 1, frozenset({p}))

        go = verify_e681b708(gi)
