def generate_e6de6e8f(diff_lb: float, diff_ub: float) -> dict:
    w = 12
    h = 2
    maxsteps = 7
    nsteps = unifint(diff_lb, diff_ub, (1, maxsteps))
    startcol = 3
    cur = startcol
    steps = []
    for k in range(nsteps):
        opts = [0]
        if cur > 0:
            opts.append(1)
        if cur < 5:
            opts.append(2)
        step = choice(tuple(opts))
        steps.append(step)
        if step == 1:
            cur -= 1
        elif step == 2:
            cur += 1
    cols = [0] * w
    pos = 0
    for s in steps:
        if pos >= w:
            break
        cols[pos] = s
        if s == 0:
            pos += 1
        else:
            if pos + 1 < w:
                cols[pos + 1] = s
            pos += 3
    gi = canvas(0, (h, w))
    for j, s in enumerate(cols):
        if s == 1:
            gi = fill(gi, 2, frozenset({(1, j)}))
        elif s == 2:
            gi = fill(gi, 2, frozenset({(0, j), (1, j)}))
    go = verify_e6de6e8f(gi)
    return {'input': gi, 'output': go}


def generate_e729b7be(diff_lb: float, diff_ub: float) -> dict:
    bgc = SEVEN
    divc = FOUR
    markc = EIGHT
    cols = (ONE, TWO, THREE, FIVE, SIX, NINE)

    h = unifint(diff_lb, diff_ub, (11, 29))
    w = unifint(diff_lb, diff_ub, (11, 29))
    if h % 2 == 0:
        h = h + 1 if h < 29 else h - 1
    if w % 2 == 0:
        w = w + 1 if w < 29 else w - 1

    ci = h // 2
    cj = w // 2

    gi = canvas(bgc, (h, w))
    gi = fill(gi, divc, connect((0, cj), (h - 1, cj)))
    gi = fill(gi, markc, frozenset({(ci, 0), (ci, cj), (ci, w - 1)}))

    max_left_w = cj
    max_up = ci
    max_down = h - 1 - ci

    ncolors = unifint(diff_lb, diff_ub, (2, min(4, len(cols))))
    usecols = sample(cols, ncolors)

    nseeds = unifint(diff_lb, diff_ub, (6, max(6, min((h * w) // 8, 40))))
    painted = 0
    tries = 0
    maxtries = nseeds * 20

    while painted < nseeds and tries < maxtries:
        tries += 1
        col = choice(usecols)
        rh = unifint(diff_lb, diff_ub, (1, min(4, h)))
        rw = unifint(diff_lb, diff_ub, (1, min(4, max_left_w)))
        top = randint(0, h - rh)
        left = randint(0, max_left_w - rw)
        patch = connect((top, left), (top + rh - 1, left + rw - 1))

        valid = True
        for i, j in patch:
            mi = 2 * ci - i
            mj = 2 * cj - j
            if not (0 <= mi < h and 0 <= mj < w):
                valid = False
                break
            if mj <= cj:
                valid = False
                break
            if i == ci and j == 0:
                valid = False
                break
            if i == ci and j == cj:
                valid = False
                break
            if mi == ci and mj == w - 1:
                valid = False
                break
            if mi == ci and mj == cj:
                valid = False
                break
        if not valid:
            continue

        gi2 = fill(gi, col, patch)
        if gi2 != gi:
            gi = gi2
            painted += 1

    if painted == 0:
        fallback = frozenset({(ci, max(1, cj - 1))})
        gi = fill(gi, choice(usecols), fallback)

    go = verify_e729b7be(gi)
    return {'input': gi, 'output': go}


