    for c in vlines:
        gi = fill(gi, 8, connect((0, c), (h - 1, c)))

    cells = [(br, bc) for br in range(nrows) for bc in range(ncols)]

    def cell_patch(br, bc):
        r0 = br * (cellh + 1)
        c0 = bc * (cellw + 1)
        return connect((r0, c0), (r0 + cellh - 1, c0 + cellw - 1))

    def rand_in_cell(br, bc):
        r0 = br * (cellh + 1)
        c0 = bc * (cellw + 1)
        return (r0 + randint(0, cellh - 1), c0 + randint(0, cellw - 1))

    red_cells = set()
    green_cells = set()

    mode = choice((0, 1, 2))

    if mode == 0:
        rr = randint(0, nrows - 1)
