def generate_e7dd8335(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (6, 18))
    w = unifint(diff_lb, diff_ub, (6, 18))
    gi = canvas(0, (h, w))

    nobj_max = min(4, max(1, (h * w) // 30 + 1))
    nobj = unifint(diff_lb, diff_ub, (1, nobj_max))

    occupied = set()

    def ring_shape(oh, ow):
        cells = set()
        for i in range(oh):
            for j in range(ow):
                if i == 0 or i == oh - 1 or j == 0 or j == ow - 1:
                    cells.add((i, j))
        return frozenset(cells)

    def u_shape(oh, ow):
        cells = set()
        for i in range(oh):
            cells.add((i, 0))
            cells.add((i, ow - 1))
        for j in range(ow):
            cells.add((oh - 1, j))
        return frozenset(cells)

    def t_shape(oh, ow):
        cells = set()
        mid = ow // 2
        for j in range(ow):
            cells.add((0, j))
        for i in range(oh):
            cells.add((i, mid))
        return frozenset(cells)

    def plus_shape(oh, ow):
        cells = set()
        mi = oh // 2
        mj = ow // 2
        for j in range(ow):
            cells.add((mi, j))
        for i in range(oh):
            cells.add((i, mj))
        return frozenset(cells)

    def x_shape(n):
        cells = set()
        for i in range(n):
            cells.add((i, i))
            cells.add((i, n - 1 - i))
        return frozenset(cells)

    def diamond_shape(r):
        cells = set()
        c = r
        for i in range(2 * r + 1):
            d = abs(i - r)
            span = r - d
            cells.add((i, c - span))
            cells.add((i, c + span))
        return frozenset(cells)

    placed = 0
    for _ in range(80):
        if placed >= nobj:
            break

        typ = choice(("ring", "u", "t", "plus", "x", "diamond"))

        if typ == "ring":
            oh = unifint(diff_lb, diff_ub, (4, min(9, h)))
            ow = unifint(diff_lb, diff_ub, (4, min(9, w)))
            shp = ring_shape(oh, ow)
        elif typ == "u":
            oh = unifint(diff_lb, diff_ub, (4, min(9, h)))
            ow = unifint(diff_lb, diff_ub, (3, min(9, w)))
            shp = u_shape(oh, ow)
        elif typ == "t":
            ohopts = tuple(v for v in interval(3, min(10, h + 1), 1) if v >= 3)
            owopts = tuple(v for v in interval(3, min(10, w + 1), 1) if v >= 3 and v % 2 == 1)
            if len(ohopts) == 0 or len(owopts) == 0:
                continue
            oh = ohopts[unifint(diff_lb, diff_ub, (0, len(ohopts) - 1))]
            ow = owopts[unifint(diff_lb, diff_ub, (0, len(owopts) - 1))]
            shp = t_shape(oh, ow)
        elif typ == "plus":
            ohopts = tuple(v for v in interval(3, min(10, h + 1), 1) if v % 2 == 1)
            owopts = tuple(v for v in interval(3, min(10, w + 1), 1) if v % 2 == 1)
            if len(ohopts) == 0 or len(owopts) == 0:
                continue
            oh = ohopts[unifint(diff_lb, diff_ub, (0, len(ohopts) - 1))]
            ow = owopts[unifint(diff_lb, diff_ub, (0, len(owopts) - 1))]
            shp = plus_shape(oh, ow)
        elif typ == "x":
            nmax = min(h, w, 9)
            if nmax < 3:
                continue
            nopts = tuple(v for v in interval(3, nmax + 1, 1) if v % 2 == 1)
            if len(nopts) == 0:
                continue
            n = nopts[unifint(diff_lb, diff_ub, (0, len(nopts) - 1))]
            oh = n
            ow = n
            shp = x_shape(n)
        else:
            rmax = min((h - 1) // 2, (w - 1) // 2, 4)
            if rmax < 1:
                continue
            r = unifint(diff_lb, diff_ub, (1, rmax))
            oh = 2 * r + 1
            ow = 2 * r + 1
            shp = diamond_shape(r)

        if oh > h or ow > w:
            continue

        loci = unifint(diff_lb, diff_ub, (0, h - oh))
        locj = unifint(diff_lb, diff_ub, (0, w - ow))
        placed_cells = shift(shp, (loci, locj))

        ok = True
        for cell in placed_cells:
            if cell in occupied:
                ok = False
                break
        if not ok:
            continue

        halo = mapply(neighbors, placed_cells) | placed_cells
        if len(halo & frozenset(occupied)) > 0:
            continue

        gi = fill(gi, 1, placed_cells)
        occupied |= set(placed_cells)
        placed += 1

    if placed == 0:
        oh = min(6, h)
        ow = min(4, w)
        shp = ring_shape(oh, ow)
        gi = fill(gi, 1, shift(shp, (0, 0)))

    go = verify_e7dd8335(gi)
    return {'input': gi, 'output': go}


