def generate_ecaa0ec1(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (10, 14))
    w = unifint(diff_lb, diff_ub, (10, 14))
    gi = canvas(0, (h, w))

    pats = (
        ((8, 1, 8), (1, 8, 8), (1, 1, 1)),
        ((1, 1, 1), (8, 1, 8), (8, 1, 1)),
        ((1, 1, 1), (8, 8, 8), (1, 8, 1)),
        ((8, 1, 8), (8, 1, 8), (1, 1, 8)),
    )
    pat = choice(pats)

    top = unifint(diff_lb, diff_ub, (3, h - 5))
    left = unifint(diff_lb, diff_ub, (3, w - 5))

    objcells = []
    for i in range(3):
        for j in range(3):
            objcells.append((pat[i][j], (top + i, left + j)))
    gi = paint(gi, frozenset(objcells))

    outer_corners = (
        (top - 1, left - 1),
        (top - 1, left + 3),
        (top + 3, left + 3),
        (top + 3, left - 1),
    )
    near_idx = choice((0, 1, 2, 3))
    gi = fill(gi, 4, frozenset({outer_corners[near_idx]}))

    center = (top + 1, left + 1)
    quad_targets = (
        lambda p: p[0] < center[0] and p[1] > center[1],
        lambda p: p[0] > center[0] and p[1] > center[1],
        lambda p: p[0] > center[0] and p[1] < center[1],
        lambda p: p[0] < center[0] and p[1] < center[1],
    )

    n_other = unifint(diff_lb, diff_ub, (2, 4))
    allinds = totuple(asindices(gi))
    forbidden = set()
    for i in range(top - 1, top + 4):
        for j in range(left - 1, left + 4):
            if 0 <= i < h and 0 <= j < w:
                forbidden.add((i, j))
    candidates = [ij for ij in allinds if ij not in forbidden]
    shuffle(candidates)

    chosen = []
    for target_idx in sample((0, 1, 2, 3), 4):
        if len(chosen) >= n_other:
            break
        quadcands = [ij for ij in candidates if quad_targets[target_idx](ij)]
        if len(quadcands) > 0:
            loc = choice(quadcands)
            chosen.append(loc)
            candidates = [ij for ij in candidates if ij != loc]

    while len(chosen) < n_other and len(candidates) > 0:
        loc = choice(candidates)
        chosen.append(loc)
        candidates = [ij for ij in candidates if ij != loc]

    if len(chosen) == 0:
        fallback = (0, 0)
        if fallback in forbidden:
            fallback = (0, w - 1)
        chosen = [fallback]

    gi = fill(gi, 4, frozenset(chosen))
    go = verify_ecaa0ec1(gi)
    return {'input': gi, 'output': go}


def generate_ecb67b6d(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (4, 18))
    w = unifint(diff_lb, diff_ub, (5, 18))
    gi = canvas(7, (h, w))

    nobj = unifint(diff_lb, diff_ub, (3, min(12, (h * w) // 3)))
    allinds = set(totuple(asindices(gi)))
    occupied = set()
    made_pos = False
    made_neg = False

    def has_diag3_patch(p):
        x0 = frozenset(p)
        x1 = shift(x0, (1, 1))
        x2 = shift(x0, (2, 2))
        x3 = intersection(x0, intersection(x1, x2))
        x4 = shift(x0, (1, -1))
        x5 = shift(x0, (2, -2))
        x6 = intersection(x0, intersection(x4, x5))
        return greater(size(combine(x3, x6)), 0)

    def add_component(cells):
        nonlocal gi, occupied
        gi = fill(gi, 5, frozenset(cells))
        occupied |= set(cells)

    for k in range(nobj):
        force_pos = (k == nobj - 1 and not made_pos)
        force_neg = (k == nobj - 1 and not made_neg and not force_pos)
        typ = choice(("single", "pair", "blob", "diagp", "diagn"))
        if force_pos:
            typ = "diagp"
        if force_neg:
            typ = choice(("single", "pair", "blob"))

        placed = False
        for _ in range(80):
            if typ == "single":
                cand = {choice(tuple(allinds))}
            elif typ == "pair":
                ori = choice(((1, 0), (0, 1), (1, 1), (1, -1)))
                i = randint(0, h - 1)
                j = randint(0, w - 1)
                cand = {(i, j), (i + ori[0], j + ori[1])}
            elif typ == "blob":
                bh = unifint(diff_lb, diff_ub, (2, min(5, h)))
                bw = unifint(diff_lb, diff_ub, (2, min(5, w)))
                bi = randint(0, h - bh)
                bj = randint(0, w - bw)
                boxinds = set(totuple(backdrop(frozenset({(bi, bj), (bi + bh - 1, bj + bw - 1)}))))
                nc = unifint(diff_lb, diff_ub, (3, min(len(boxinds), max(3, (bh * bw + 1) // 2))))
                start = choice(tuple(boxinds))
                cand = {start}
                for __ in range(nc - 1):
                    frontier = (boxinds - cand) & set(mapply(neighbors, frozenset(cand)))
                    if len(frontier) == 0:
                        rem = boxinds - cand
                        if len(rem) == 0:
                            break
                        frontier = rem
                    cand.add(choice(tuple(frontier)))
            elif typ == "diagp":
                ln = unifint(diff_lb, diff_ub, (3, min(6, h, w)))
                i = randint(0, h - ln)
                j = randint(0, w - ln)
                cand = set(totuple(connect((i, j), (i + ln - 1, j + ln - 1))))
                extra = unifint(diff_lb, diff_ub, (0, min(4, h * w - ln)))
                for __ in range(extra):
                    frontier = set(mapply(neighbors, frozenset(cand))) - cand
                    frontier = {(a, b) for (a, b) in frontier if 0 <= a < h and 0 <= b < w}
                    if len(frontier) == 0:
                        break
                    cand.add(choice(tuple(frontier)))
            else:
                ln = unifint(diff_lb, diff_ub, (3, min(6, h, w)))
                i = randint(0, h - ln)
                j = randint(ln - 1, w - 1)
                cand = set(totuple(connect((i, j), (i + ln - 1, j - ln + 1))))
                extra = unifint(diff_lb, diff_ub, (0, min(4, h * w - ln)))
                for __ in range(extra):
                    frontier = set(mapply(neighbors, frozenset(cand))) - cand
                    frontier = {(a, b) for (a, b) in frontier if 0 <= a < h and 0 <= b < w}
                    if len(frontier) == 0:
                        break
                    cand.add(choice(tuple(frontier)))

            if any(not (0 <= i < h and 0 <= j < w) for i, j in cand):
                continue
            if len(cand & occupied) > 0:
                continue

            touch = False
            for cell in cand:
                if len(neighbors(cell) & occupied) > 0:
                    touch = True
                    break
            if touch:
                continue

            hd = has_diag3_patch(cand)
            if typ in ("single", "pair", "blob") and hd and not force_pos:
                continue
            add_component(cand)
            made_pos = made_pos or hd
            made_neg = made_neg or (not hd)
            placed = True
            break

        if not placed:
            for _ in range(80):
                cell = choice(tuple(allinds - occupied)) if len(allinds - occupied) > 0 else (0, 0)
                if len(neighbors(cell) & occupied) == 0:
                    add_component({cell})
                    made_neg = True
                    placed = True
                    break

    if not made_pos:
        ln = min(3, h, w)
        cand = set(totuple(connect((0, 0), (ln - 1, ln - 1))))
        if len(cand & occupied) == 0:
            add_component(cand)
        else:
            gi = fill(gi, 7, frozenset(occupied))
            occupied = set()
            add_component(cand)
            if h > 1 and w > 1:
                add_component({(h - 1, 0)})
        made_pos = True

    if not made_neg:
        for cell in totuple(asindices(gi)):
            if gi[cell[0]][cell[1]] == 7 and len(neighbors(cell) & occupied) == 0:
                add_component({cell})
                made_neg = True
                break

    go = verify_ecb67b6d(gi)
    return {'input': gi, 'output': go}


def generate_ecdecbb3(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (4, 30))
    w = unifint(diff_lb, diff_ub, (4, 30))
    bgc, dotc, linc = sample(cols, 3)
    gi = canvas(bgc, (h, w))
    nl = unifint(diff_lb, diff_ub, (1, h//4))
    inds = interval(0, h, 1)
    locs = []
    for k in range(nl):
        if len(inds) == 0:
            break
        idx = choice(inds)
        locs.append(idx)
        inds = remove(idx, inds)
        inds = remove(idx - 1, inds)
        inds = remove(idx + 1, inds)
        inds = remove(idx - 2, inds)
        inds = remove(idx + 2, inds)
    locs = sorted(locs)
    for ii in locs:
        gi = fill(gi, linc, hfrontier((ii, 0)))
    iopts = difference(difference(difference(interval(0, h, 1), locs), apply(increment, locs)), apply(decrement, locs))
    jopts = interval(0, w, 1)
    ndots = unifint(diff_lb, diff_ub, (1, min(len(iopts), w // 2)))
    dlocs = []
    for k in range(ndots):
        if len(iopts) == 0 or len(jopts) == 0:
            break
        loci = choice(iopts)
        locj = choice(jopts)
        dlocs.append((loci, locj))
        jopts = remove(locj, jopts)
        jopts = remove(locj+1, jopts)
        jopts = remove(locj-1, jopts)
    go = gi
    for d in dlocs:
        loci, locj = d
        if loci < min(locs):
            go = fill(go, dotc, connect(d, (min(locs), locj)))
            go = fill(go, linc, neighbors((min(locs), locj)))
        elif loci > max(locs):
            go = fill(go, dotc, connect(d, (max(locs), locj)))
            go = fill(go, linc, neighbors((max(locs), locj)))
        else:
            sp = [e for e in locs if e < loci][-1]
            ep = [e for e in locs if e > loci][0]
            go = fill(go, dotc, connect((sp, locj), (ep, locj)))
            go = fill(go, linc, neighbors((sp, locj)))
            go = fill(go, linc, neighbors((ep, locj)))
        gi = fill(gi, dotc, {d})
    if choice((True, False)):
        gi = dmirror(gi)
        go = dmirror(go)
    return {'input': gi, 'output': go}


