def generate_edcc2ff0(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    w = 10
    pic_h = unifint(diff_lb, diff_ub, (8, 23))
    bg = choice(cols)
    rem = remove(bg, cols)

    nsel_present = unifint(diff_lb, diff_ub, (1, 3))
    sel_colors = sample(rem, 3)
    present_sel = sample(sel_colors, nsel_present)
    rem2 = tuple(c for c in rem if c not in sel_colors)

    gi = canvas(0, (7, w))
    gi = fill(gi, sel_colors[0], initset((1, 0)))
    gi = fill(gi, sel_colors[1], initset((3, 0)))
    gi = fill(gi, sel_colors[2], initset((5, 0)))

    pic = canvas(bg, (pic_h, w))

    comps_by_color = {}
    for c in present_sel:
        maxn = min(4, w)
        nobj = unifint(diff_lb, diff_ub, (1, maxn))
        comps = []
        used = set()
        attempts = 0
        while len(comps) < nobj and attempts < 200:
            attempts += 1
            sh = unifint(diff_lb, diff_ub, (1, 3))
            sw = unifint(diff_lb, diff_ub, (1, 4))
            if sh > pic_h or sw > w:
                continue
            i = unifint(diff_lb, diff_ub, (0, pic_h - sh))
            j = unifint(diff_lb, diff_ub, (0, w - sw))
            cells = connect((i, j), (i + sh - 1, j + sw - 1))
            ok = True
            for a, b in cells:
                for ni, nj in neighbors((a, b)) | initset((a, b)):
                    if (ni, nj) in used:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                comps.append(cells)
                used |= set(cells)
                pic = fill(pic, c, cells)
        if len(comps) == 0:
            cell = initset((unifint(diff_lb, diff_ub, (0, pic_h - 1)), unifint(diff_lb, diff_ub, (0, w - 1))))
            comps = [cell]
            pic = fill(pic, c, cell)
        comps_by_color[c] = comps

    nnoise_cols = 0
    if len(rem2) > 0:
        nnoise_cols = unifint(diff_lb, diff_ub, (0, min(3, len(rem2))))
    noise_cols = sample(rem2, nnoise_cols) if nnoise_cols > 0 else []

    occupied = set()
    for c in present_sel:
        for comp in comps_by_color.get(c, []):
            occupied |= set(comp)

    for c in noise_cols:
        nobj = unifint(diff_lb, diff_ub, (1, 3))
        made = 0
        attempts = 0
        while made < nobj and attempts < 150:
            attempts += 1
            sh = unifint(diff_lb, diff_ub, (1, 3))
            sw = unifint(diff_lb, diff_ub, (1, 4))
            if sh > pic_h or sw > w:
                continue
            i = unifint(diff_lb, diff_ub, (0, pic_h - sh))
            j = unifint(diff_lb, diff_ub, (0, w - sw))
            cells = connect((i, j), (i + sh - 1, j + sw - 1))
            ok = True
            for a, b in cells:
                for ni, nj in neighbors((a, b)) | initset((a, b)):
                    if (ni, nj) in occupied:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                occupied |= set(cells)
                pic = fill(pic, c, cells)
                made += 1

    gi = vconcat(gi, pic)
    go = verify_edcc2ff0(gi)
    return {'input': gi, 'output': go}


def generate_ef135b50(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(9, interval(0, 10, 1))
    while True:
        h = unifint(diff_lb, diff_ub, (8, 30))
        w = unifint(diff_lb, diff_ub, (8, 30))
        bgc = choice(cols)
        remcols = remove(bgc, cols)
        numc = unifint(diff_lb, diff_ub, (1, 8))
        ccols = sample(remcols, numc)
        gi = canvas(bgc, (h, w))
        nsq = unifint(diff_lb, diff_ub, (2, (h * w) // 30))
        succ = 0
        tr = 0
        maxtr = 5 * nsq
        inds = asindices(gi)
        pats = set()
        while tr < maxtr and succ < nsq:
            tr += 1
            oh = randint(1, (h//3*2))
            ow = randint(1, (w//3*2))
            cands = sfilter(inds, lambda ij: ij[0] <= h - oh and ij[1] <= w - ow)
            if len(cands) == 0:
                continue
            loc = choice(totuple(cands))
            loci, locj = loc
            bd = backdrop(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
            if bd.issubset(inds):
                succ += 1
                inds = (inds - bd) - mapply(neighbors, bd)
                gi = fill(gi, choice(ccols), bd)
                pats.add(bd)
        res = set()
        ofc = ofcolor(gi, bgc)
        for pat1 in pats:
            for pat2 in remove(pat1, pats):
                if hmatching(pat1, pat2):
                    um = max(uppermost(pat1), uppermost(pat2))
                    bm = min(lowermost(pat1), lowermost(pat2))
                    lm = min(rightmost(pat1), rightmost(pat2)) + 1
                    rm = max(leftmost(pat1), leftmost(pat2)) - 1
                    res = res | backdrop(frozenset({(um, lm), (bm, rm)}))
        res = (res & ofc) - box(asindices(gi))
        go = fill(gi, 9, res)
        if go != gi:
            break
    return {'input': gi, 'output': go}


