def generate_f0100645(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (7, 18))
    w = unifint(diff_lb, diff_ub, (7, 18))
    bgc, lc, rc = sample(cols, 3)

    gi = canvas(bgc, (h, w))
    gi = fill(gi, lc, connect((0, 0), (h - 1, 0)))
    gi = fill(gi, rc, connect((0, w - 1), (h - 1, w - 1)))

    max_left = max(1, (w - 3) // 2)
    max_right = max(1, (w - 3) // 2)
    nleft = unifint(diff_lb, diff_ub, (1, min(h, max_left + 2)))
    nright = unifint(diff_lb, diff_ub, (1, min(h, max_right + 2)))

    left_rows = sample(interval(0, h, 1), nleft)
    right_rows = sample(interval(0, h, 1), nright)

    left_patch = frozenset()
    for r in left_rows:
        maxj = max(1, w - 3)
        j = unifint(diff_lb, diff_ub, (1, maxj))
        left_patch = combine(left_patch, frozenset({(r, j)}))

    right_patch = frozenset()
    for r in right_rows:
        minj = 1
        maxj = max(1, w - 2)
        j = unifint(diff_lb, diff_ub, (minj, maxj))
        right_patch = combine(right_patch, frozenset({(r, j)}))

    left_comps = connected_components(left_patch, False)
    right_comps = connected_components(right_patch, False)

    gi = fill(gi, lc, left_patch)
    gi = fill(gi, rc, right_patch)

    if len(left_comps) == 0 or len(right_comps) == 0:
        gi = fill(gi, lc, frozenset({(0, 1)}))
        gi = fill(gi, rc, frozenset({(h - 1, w - 2)}))

    go = verify_f0100645(gi)
    return {'input': gi, 'output': go}


