def generate_f0df5ff0(diff_lb: float, diff_ub: float) -> dict:
    h = 15
    w = 15
    gi = canvas(0, (h, w))

    palette_nonzero = remove(0, interval(0, 10, 1))
    palette_nonblue = remove(1, palette_nonzero)

    nnoise = unifint(diff_lb, diff_ub, (45, 95))
    max_blues = unifint(diff_lb, diff_ub, (3, 6))
    nblue = min(max_blues, 8)

    allinds = totuple(asindices(gi))

    blue_positions = []
    tries = 0
    maxtries = 300
    target_blues = nblue
    while len(blue_positions) < target_blues and tries < maxtries:
        cand = choice(allinds)
        ok = True
        for p in blue_positions:
            if max(abs(cand[0] - p[0]), abs(cand[1] - p[1])) <= 2:
                ok = False
                break
        if ok:
            blue_positions.append(cand)
        tries += 1

    if len(blue_positions) == 0:
        blue_positions = [choice(allinds)]

    blue_set = frozenset(blue_positions)
    expansion = mapply(neighbors, blue_set) | blue_set

    available_noise = difference(asindices(gi), blue_set)
    avail_tuple = totuple(available_noise)
    nnoise = min(nnoise, len(avail_tuple))
    noise_cells = sample(avail_tuple, nnoise) if nnoise > 0 else ()

    obj = frozenset((choice(palette_nonblue), ij) for ij in noise_cells)
    gi = paint(gi, obj)
    gi = fill(gi, 1, blue_set)

    if len(intersection(expansion, ofcolor(gi, 0))) == 0:
        candzeros = totuple(difference(expansion, blue_set))
        if len(candzeros) > 0:
            keepzero = choice(candzeros)
            gi = fill(gi, 0, initset(keepzero))
        else:
            for bp in blue_positions:
                nb = totuple(neighbors(bp))
                shuffle(nb)
                done = False
                for q in nb:
                    if 0 <= q[0] < h and 0 <= q[1] < w and q not in blue_set:
                        gi = fill(gi, 0, initset(q))
                        done = True
                        break
                if done:
                    break

    go = verify_f0df5ff0(gi)
    return {'input': gi, 'output': go}


def generate_f0f8a26d(diff_lb: float, diff_ub: float) -> dict:
    bgc = 7
    h = unifint(diff_lb, diff_ub, (8, 16))
    w = unifint(diff_lb, diff_ub, (8, 16))
    objc = choice(remove(bgc, interval(0, 10, 1)))
    gi = canvas(bgc, (h, w))

    occ = set()
    nobj = unifint(diff_lb, diff_ub, (4, 8))
    nline = unifint(diff_lb, diff_ub, (2, max(2, nobj - 1)))
    nline = min(nline, nobj)

    kinds = ['line'] * nline + ['other'] * (nobj - nline)
    shuffle(kinds)

    def free(cells):
        for i, j in cells:
            if not (0 <= i < h and 0 <= j < w):
                return False
            if (i, j) in occ:
                return False
        return True

    def reserve(cells):
        for c in cells:
            occ.add(c)

    def add_line():
        for _ in range(100):
            orient = choice(('h', 'v'))
            if orient == 'h':
                ln = unifint(diff_lb, diff_ub, (2, max(2, min(7, w))))
                ln = min(ln, w)
                i = randint(0, h - 1)
                j = randint(0, w - ln)
                cells = connect((i, j), (i, j + ln - 1))
            else:
                ln = unifint(diff_lb, diff_ub, (2, max(2, min(7, h))))
                ln = min(ln, h)
                i = randint(0, h - ln)
                j = randint(0, w - 1)
                cells = connect((i, j), (i + ln - 1, j))
            if free(cells):
                reserve(cells)
                return cells
        return None

    def add_other():
        for _ in range(200):
            oh = unifint(diff_lb, diff_ub, (2, min(5, h)))
            ow = unifint(diff_lb, diff_ub, (2, min(5, w)))
            i0 = randint(0, h - oh)
            j0 = randint(0, w - ow)
            bounds = shift(asindices(canvas(-1, (oh, ow))), (i0, j0))
            sp = choice(totuple(bounds))
            obj = {sp}
            target = unifint(diff_lb, diff_ub, (3, max(3, min(oh * ow, 7))))
            target = min(target, oh * ow)
            for _k in range(target - 1):
                frontier = (bounds - frozenset(obj)) & mapply(dneighbors, frozenset(obj))
                if len(frontier) == 0:
                    break
                obj.add(choice(totuple(frontier)))
            obj = frozenset(obj)
            if size(obj) < 3:
                continue
            if hline(obj) or vline(obj):
                continue
            if free(obj):
                reserve(obj)
                return obj
        return None

    made = []
    for k in kinds:
        shp = add_line() if k == 'line' else add_other()
        if shp is not None:
            made.append(shp)

    if len(made) == 0:
        cells = connect((0, 0), (0, 1))
        made.append(cells)

    has_line = any(hline(x) or vline(x) for x in made)
    has_other = any((not hline(x)) and (not vline(x)) for x in made)

    if not has_line:
        for _ in range(100):
            shp = add_line()
            if shp is not None:
                made.append(shp)
                has_line = True
                break
    if not has_other:
        for _ in range(100):
            shp = add_other()
            if shp is not None:
                made.append(shp)
                has_other = True
                break

    allcells = frozenset()
    for shp in made:
        allcells = combine(allcells, shp)
    gi = fill(gi, objc, allcells)

    go = verify_f0f8a26d(gi)
    return {'input': gi, 'output': go}


def generate_f15e1fac(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(2, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (4, 30))
    w = unifint(diff_lb, diff_ub, (4, 30))
    nsps = unifint(diff_lb, diff_ub, (1, (w-1) // 2))
    ngps = unifint(diff_lb, diff_ub, (1, (h-1) // 2))
    spsj = sorted(sample(interval(1, w - 1, 1), nsps))
    gpsi = sorted(sample(interval(1, h - 1, 1), ngps))
    ofs = 0
    bgc, linc = sample(cols, 2)
    gi = canvas(bgc, (h, w))
    gi = fill(gi, linc, {(0, jj) for jj in spsj})
    gi = fill(gi, 2, {(ii, 0) for ii in gpsi})
    go = tuple(e for e in gi)
    for a, b in zip([0] + gpsi, [x - 1 for x in gpsi] + [h - 1]):
        for jj in spsj:
            go = fill(go, linc, connect((a, jj + ofs), (b, jj + ofs)))
        ofs += 1
    mfs = (identity, dmirror, cmirror, vmirror, hmirror, rot90, rot180, rot270)
    nmfs = choice((1, 2))
    for fn in sample(mfs, nmfs):
        gi = fn(gi)
        go = fn(go)
    return {'input': gi, 'output': go}


def generate_f18ec8cc(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (6, 14))
    nstrips = unifint(diff_lb, diff_ub, (3, 6))
    widths = [1] * nstrips
    extra = unifint(diff_lb, diff_ub, (0, 14 - nstrips))
    for _ in range(extra):
        widths[randint(0, nstrips - 1)] += 1
    w = sum(widths)

    cols = interval(1, 10, 1)
    stripcols = sample(cols, nstrips)

    if choice((True, False)):
        stripcols = tuple(sorted(stripcols))
    else:
        for _ in range(50):
            cand = sample(cols, nstrips)
            if tuple(sorted(cand)) != tuple(cand):
                stripcols = cand
                break
        else:
            a = tuple(sorted(sample(cols, nstrips)))
            stripcols = a[1:] + a[:1]

    gi = canvas(0, (h, w))
    starts = []
    c0 = 0
    for sw, sc in zip(widths, stripcols):
        starts.append(c0)
        gi = fill(gi, sc, connect((0, c0), (h - 1, c0 + sw - 1)))
        c0 += sw

    max_noise = max(1, (h * w) // 8)
    nnoise = unifint(diff_lb, diff_ub, (1, max_noise))
    for _ in range(nnoise):
        si = randint(0, nstrips - 1)
        sw = widths[si]
        sc = stripcols[si]
        r = randint(0, h - 1)
        c = randint(starts[si], starts[si] + sw - 1)
        others = remove(sc, cols)
        nc = choice(others)
        gi = fill(gi, nc, frozenset({(r, c)}))

    go = verify_f18ec8cc(gi)
    return {'input': gi, 'output': go}


def generate_f1bcbc2c(diff_lb: float, diff_ub: float) -> dict:
    h = 10
    w = 10

    def build_path():
        for _ in range(200):
            nseg = unifint(diff_lb, diff_ub, (4, 8))
            starti = unifint(diff_lb, diff_ub, (1, h - 2))
            startj = unifint(diff_lb, diff_ub, (1, w - 2))
            path = [(starti, startj)]
            used = {path[0]}
            dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]
            ok = True
            for _k in range(nseg):
                cands = []
                ci, cj = path[-1]
                for di, dj in dirs:
                    maxlen = 0
                    ni, nj = ci + di, cj + dj
                    while 1 <= ni < h - 1 and 1 <= nj < w - 1 and (ni, nj) not in used:
                        maxlen += 1
                        ni += di
                        nj += dj
                    if maxlen > 0:
                        cands.append((di, dj, maxlen))
                if len(cands) == 0:
                    ok = False
                    break
                di, dj, maxlen = choice(cands)
                seglen = unifint(diff_lb, diff_ub, (1, min(4, maxlen)))
                ci, cj = path[-1]
                for t in range(1, seglen + 1):
                    np = (ci + di * t, cj + dj * t)
                    path.append(np)
                    used.add(np)
            if not ok or len(path) < 6:
                continue
            inds = frozenset(path)
            if height(inds) < 5 or width(inds) < 4:
                continue
            return inds
        return frozenset({(1, 4), (2, 4), (3, 4), (4, 4), (4, 5), (4, 6), (5, 6), (6, 6), (7, 6), (8, 6)})

    corridor = build_path()
    gi = canvas(0, (h, w))

    wall = frozenset()
    for p in corridor:
        for q in dneighbors(p):
            qi, qj = q
            if 0 <= qi < h and 0 <= qj < w and q not in corridor:
                wall = insert(q, wall)

    gi = fill(gi, 7, wall)

    comps = connected_components(ofcolor(gi, 0), False)
    corr_comp = None
    for comp in comps:
        if corridor.issubset(comp):
            corr_comp = comp
            break
    if corr_comp is None:
        corr_comp = corridor

    adjcorr = sfilter(corr_comp, lambda x: positive(size(intersection(dneighbors(x), wall))))
    if size(adjcorr) == 0:
        adjcorr = corridor

    place9 = choice((True, False))
    if place9:
        inside = choice((True, False))
        if inside:
            p9 = choice(totuple(adjcorr))
        else:
            others = tuple(sorted(ofcolor(gi, 0) - corr_comp))
            if len(others) == 0:
                p9 = choice(totuple(adjcorr))
            else:
                p9 = choice(others)
        gi = fill(gi, 9, frozenset({p9}))

    go = verify_f1bcbc2c(gi)
    return {'input': gi, 'output': go}


def generate_f1cefba8(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (7, 30))
    w = unifint(diff_lb, diff_ub, (7, 30))
    ih = unifint(diff_lb, diff_ub, (6, h - 1))
    iw = unifint(diff_lb, diff_ub, (6, w - 1))
    loci = randint(0, h - ih)
    locj = randint(0, w - iw)
    bgc, ringc, inc = sample(cols, 3)
    obj = frozenset({(loci, locj), (loci + ih - 1, locj + iw - 1)})
    ring1 = box(obj)
    ring2 = inbox(obj)
    bd = backdrop(obj)
    c = canvas(bgc, (h, w))
    c = fill(c, inc, bd)
    c = fill(c, ringc, ring1 | ring2)
    cands = totuple(ring2 - corners(ring2))
    numc = unifint(diff_lb, diff_ub, (1, len(cands) // 2))
    locs = sample(cands, numc)
    gi = fill(c, inc, locs)
    lm = lowermost(ring2)
    hori = sfilter(locs, lambda ij: ij[0] > loci + 1 and ij[0] < lm)
    verti = difference(locs, hori)
    hlines = mapply(hfrontier, hori)
    vlines = mapply(vfrontier, verti)
    fulllocs = set(hlines) | set(vlines)
    topaintinc = fulllocs & ofcolor(c, bgc)
    topaintringc = fulllocs & ofcolor(c, inc)
    go = fill(c, inc, topaintinc)
    go = fill(go, ringc, topaintringc)
    return {'input': gi, 'output': go}


def generate_f21745ec(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    bgc = 0

    for _ in range(100):
        ph = unifint(diff_lb, diff_ub, (2, 6))
        pw = unifint(diff_lb, diff_ub, (2, 6))
        fh, fw = ph + 2, pw + 2

        nmatch = unifint(diff_lb, diff_ub, (2, 4))
        nother = unifint(diff_lb, diff_ub, (1, 3))
        nrects = nmatch + nother

        rects = []
        dims_used = {(fh, fw)}

        for _k in range(nother):
            for _t in range(50):
                oh = unifint(diff_lb, diff_ub, (4, 10))
                ow = unifint(diff_lb, diff_ub, (4, 10))
                if (oh - 2, ow - 2) != (ph, pw) and (oh, ow) not in dims_used:
                    dims_used.add((oh, ow))
                    rects.append((oh, ow, False))
                    break

        for _k in range(nmatch):
            rects.append((fh, fw, True))

        shuffle(rects)

        total_area = sum(h * w for h, w, _ in rects)
        side = max(max(h for h, w, _ in rects), max(w for h, w, _ in rects))
        base = max(side + 2, int(total_area ** 0.5) + 4)
        h = min(30, max(base, unifint(diff_lb, diff_ub, (max(side + 2, 12), 30))))
        w = min(30, max(base, unifint(diff_lb, diff_ub, (max(side + 2, 12), 30))))

        placed = []
        ok = True
        for rh, rw, same in rects:
            candidates = []
            for i in range(0, h - rh + 1):
                for j in range(0, w - rw + 1):
                    good = True
                    for pi, pj, phh, pww, _s in placed:
                        if not (i + rh + 1 <= pi or pi + phh + 1 <= i or j + rw + 1 <= pj or pj + pww + 1 <= j):
                            good = False
                            break
                    if good:
                        candidates.append((i, j))
            if len(candidates) == 0:
                ok = False
                break
            loci, locj = choice(candidates)
            placed.append((loci, locj, rh, rw, same))

        if not ok:
            continue

        colors = sample(cols, len(placed))
        gi = canvas(bgc, (h, w))

        pat_n = unifint(diff_lb, diff_ub, (1, max(1, ph * pw - 1)))
        interior_cells = sample(totuple(asindices(canvas(0, (ph, pw)))), pat_n)
        pattern = frozenset(interior_cells)

        template_idx = randint(0, len(placed) - 1)
        while not placed[template_idx][4]:
            template_idx = randint(0, len(placed) - 1)

        for idx, (loci, locj, rh, rw, same) in enumerate(placed):
            col = colors[idx]
            frame = box(frozenset({(loci, locj), (loci + rh - 1, locj + rw - 1)}))
            gi = fill(gi, col, frame)
            if idx == template_idx:
                shifted_pat = shift(pattern, (loci + 1, locj + 1))
                gi = fill(gi, col, shifted_pat)

        go = verify_f21745ec(gi)
        if gi != go:
            return {'input': gi, 'output': go}

    ph, pw = 4, 4
    fh, fw = ph + 2, pw + 2
    h, w = 18, 18
    gi = canvas(0, (h, w))
    rect_specs = [
        (1, 1, fh, fw, 2, True),
        (1, 10, fh, fw, 3, True),
        (10, 1, 8, 5, 4, False),
        (9, 10, fh, fw, 5, True),
    ]
    pattern = frozenset({(0, 1), (1, 0), (1, 1), (2, 2), (3, 0), (3, 3)})
    for k, (i, j, rh, rw, c, same) in enumerate(rect_specs):
        frame = box(frozenset({(i, j), (i + rh - 1, j + rw - 1)}))
        gi = fill(gi, c, frame)
        if k == 1:
            gi = fill(gi, c, shift(pattern, (i + 1, j + 1)))
    go = verify_f21745ec(gi)
    return {'input': gi, 'output': go}


def generate_f25fbde4(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(0, 10, 1)
    h = unifint(diff_lb, diff_ub, (2, 30))
    w = unifint(diff_lb, diff_ub, (2, 30))
    ncd = unifint(diff_lb, diff_ub, (1, max(1, (min(15, h-1) * min(15, w-1)) // 2)))
    nc = choice((ncd, (h-1) * (w-1) - ncd))
    nc = min(max(1, ncd), (h-1) * (w-1) - 1)
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    fgc = choice(remcols)
    c = canvas(bgc, (h, w))
    bounds = asindices(canvas(-1, (min(15, h - 1), min(15, w - 1))))
    ch = choice(totuple(bounds))
    shp = {ch}
    bounds = remove(ch, bounds)
    for j in range(nc):
        shp.add(choice(totuple((bounds - shp) & mapply(neighbors, shp))))
    shp = normalize(shp)
    oh, ow = shape(shp)
    loci = randint(0, h - oh)
    locj = randint(0, w - ow)
    loc = (loci, locj)
    plcd = shift(shp, loc)
    gi = fill(c, fgc, plcd)
    go = compress(gi)
    go = upscale(go, 2)
    return {'input': gi, 'output': go}


def generate_f25ffba3(diff_lb: float, diff_ub: float) -> dict:
    cols = interval(1, 10, 1)
    h = unifint(diff_lb, diff_ub, (1, 14))
    h = h * 2 + 1
    w = unifint(diff_lb, diff_ub, (3, 15))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    numcols = unifint(diff_lb, diff_ub, (1, 8))
    remcols = sample(remcols, numcols)
    canv = canvas(bgc, (h, w))
    nc = unifint(diff_lb, diff_ub, (2, h * w - 2))
    bx = asindices(canv)
    obj = {(choice(remcols), choice(totuple(bx)))}
    for kk in range(nc - 1):
        dns = mapply(neighbors, toindices(obj))
        ch = choice(totuple(bx & dns))
        obj.add((choice(remcols), ch))
        bx = bx - {ch}
    while uppermost(obj) > h // 2 - 1 or lowermost(obj) < h // 2 + 1:
        dns = mapply(neighbors, toindices(obj))
        ch = choice(totuple(bx & dns))
        obj.add((choice(remcols), ch))
        bx = bx - {ch}
    gix = paint(canv, obj)
    gix = apply(rbind(order, matcher(identity, bgc)), gix)
    gi = hconcat(gix, canv)
    go = hconcat(gix, vmirror(gix))
    if choice((True, False)):
        gi = vmirror(gi)
        go = vmirror(go)
    if choice((True, False)):
        gi = hmirror(gi)
        go = hmirror(go)
    return {'input': gi, 'output': go}


def generate_f2829549(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(3, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (2, 30))
    w = unifint(diff_lb, diff_ub, (2, 14))
    bgc = choice(cols)
    remcols = remove(bgc, cols)
    linc = choice(remcols)
    remcols = remove(linc, remcols)
    acol = choice(remcols)
    remcols = remove(acol, remcols)
    bcol = choice(remcols)
    c = canvas(bgc, (h, w))
    inds = totuple(asindices(c))
    bar = canvas(linc, (h, 1))
    numadev = unifint(diff_lb, diff_ub, (0, (h * w) // 2))
    numbdev = unifint(diff_lb, diff_ub, (0, (h * w) // 2))
    numa = choice((numadev, h * w - numadev))
    numb = choice((numadev, h * w - numbdev))
    numa = min(max(1, numa), h * w - 1)
    numb = min(max(1, numb), h * w - 1)
    aset = sample(inds, numa)
    bset = sample(inds, numb)
    A = fill(c, acol, aset)
    B = fill(c, bcol, bset)
    gi = hconcat(hconcat(A, bar), B)
    res = (set(inds) - set(aset)) & (set(inds) - set(bset))
    go = fill(c, 3, res)
    if choice((True, False)):
        gi = dmirror(gi)
        go = dmirror(go)
    return {'input': gi, 'output': go}


def generate_f28a3cbb(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(SIX, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (9, 18))
    w = unifint(diff_lb, diff_ub, (9, 18))
    c1, c2 = sample(list(cols), 2)

    # Place two 3x3 anchor blocks
    # Anchor 1 near top-left region, anchor 2 near bottom-right region
    max_tli = max(0, h // 2 - 3)
    max_tlj = max(0, w // 2 - 3)
    min_bri = min(h - 3, h // 2)
    min_brj = min(w - 3, w // 2)

    tli = unifint(diff_lb, diff_ub, (0, max_tli))
    tlj = unifint(diff_lb, diff_ub, (0, max_tlj))
    bri = unifint(diff_lb, diff_ub, (min_bri, h - 3))
    brj = unifint(diff_lb, diff_ub, (min_brj, w - 3))

    # Build 3x3 filled blocks as indices
    anc1 = frozenset((tli + di, tlj + dj) for di in range(3) for dj in range(3))
    anc2 = frozenset((bri + di, brj + dj) for di in range(3) for dj in range(3))

    # Ensure anchors don't overlap
    if len(anc1 & anc2) > 0:
        return generate_f28a3cbb(diff_lb, diff_ub)

    gi = canvas(SIX, (h, w))
    gi = fill(gi, c1, anc1)
    gi = fill(gi, c2, anc2)

    # Cells adjacent to anchor (4-connected neighbors just outside the 3x3 block)
    def anchor_border(ai, aj):
        border = set()
        for di in range(3):
            for dj in range(3):
                for ni, nj in [(ai+di-1, aj+dj), (ai+di+1, aj+dj), (ai+di, aj+dj-1), (ai+di, aj+dj+1)]:
                    if 0 <= ni < h and 0 <= nj < w and not (ai <= ni <= ai+2 and aj <= nj <= aj+2):
                        border.add((ni, nj))
        return border

    border1 = anchor_border(tli, tlj)
    border2 = anchor_border(bri, brj)

    # Valid stray positions: not in any anchor, not adjacent to own anchor, not in other anchor
    all_cells = frozenset((i, j) for i in range(h) for j in range(w))
    forbidden1 = anc1 | anc2 | border1  # can't be in anchors or adjacent to own anchor
    forbidden2 = anc1 | anc2 | border2
    cand1 = list(all_cells - forbidden1)
    cand2 = list(all_cells - forbidden2)

    n1 = unifint(diff_lb, diff_ub, (2, min(8, max(2, len(cand1)))))
    n2 = unifint(diff_lb, diff_ub, (2, min(8, max(2, len(cand2)))))

    shuffle(cand1)
    stray1 = cand1[:n1]

    # Remove stray1 positions from cand2 to avoid overlap
    stray1_set = set(stray1)
    cand2 = [c for c in cand2 if c not in stray1_set]
    if len(cand2) < 2:
        return generate_f28a3cbb(diff_lb, diff_ub)
    shuffle(cand2)
    stray2 = cand2[:n2]

    gi = fill(gi, c1, frozenset(stray1))
    gi = fill(gi, c2, frozenset(stray2))

    go = verify_f28a3cbb(gi)
    return {'input': gi, 'output': go}


def generate_f341894c(diff_lb: float, diff_ub: float) -> dict:
    h = unifint(diff_lb, diff_ub, (8, 18))
    w = unifint(diff_lb, diff_ub, (8, 18))
    gi = canvas(EIGHT, (h, w))

    maxpairs = max(3, min((h * w) // 10, 10))
    npairs = unifint(diff_lb, diff_ub, (3, maxpairs))
    nsevens = unifint(diff_lb, diff_ub, (max(2, npairs), min(h + w, npairs + 6)))

    occupied = set()
    pair_cells = []
    seven_cells = []

    def free(cells):
        for c in cells:
            i, j = c
            if not (0 <= i < h and 0 <= j < w):
                return False
            if c in occupied:
                return False
        return True

    # place some 7s first, biased toward borders like the training examples
    border_spots = []
    for j in range(w):
        border_spots.append((0, j))
        border_spots.append((h - 1, j))
    for i in range(1, h - 1):
        border_spots.append((i, 0))
        border_spots.append((i, w - 1))
    border_spots = list(dict.fromkeys(border_spots))
    shuffle(border_spots)

    target_border = min(len(border_spots), max(2, nsevens - 1))
    for loc in border_spots[:target_border]:
        if len(seven_cells) >= nsevens:
            break
        if loc not in occupied:
            seven_cells.append(loc)
            occupied.add(loc)

    allinds = [(i, j) for i in range(h) for j in range(w)]
    shuffle(allinds)
    for loc in allinds:
        if len(seven_cells) >= nsevens:
            break
        if loc not in occupied:
            seven_cells.append(loc)
            occupied.add(loc)

    # place adjacent 1/6 pairs, each aligned with at least one 7 in same row/col
    attempts = 0
    max_attempts = 500
    while len(pair_cells) < npairs and attempts < max_attempts:
        attempts += 1
        orient = choice((0, 1))  # 0 horizontal, 1 vertical
        if orient == 0:
            i = randint(0, h - 1)
            j = randint(0, w - 2)
            a = (i, j)
            b = (i, j + 1)
            if not free((a, b)):
                continue
            aligned = [s for s in seven_cells if s[0] == i]
            if len(aligned) == 0:
                continue
            if choice((True, False)):
                gi = fill(gi, ONE, frozenset({a}))
                gi = fill(gi, SIX, frozenset({b}))
            else:
                gi = fill(gi, SIX, frozenset({a}))
                gi = fill(gi, ONE, frozenset({b}))
            occupied.add(a)
            occupied.add(b)
            pair_cells.append((a, b))
        else:
            i = randint(0, h - 2)
            j = randint(0, w - 1)
            a = (i, j)
            b = (i + 1, j)
            if not free((a, b)):
                continue
            aligned = [s for s in seven_cells if s[1] == j]
            if len(aligned) == 0:
                continue
            if choice((True, False)):
                gi = fill(gi, ONE, frozenset({a}))
                gi = fill(gi, SIX, frozenset({b}))
            else:
                gi = fill(gi, SIX, frozenset({a}))
                gi = fill(gi, ONE, frozenset({b}))
            occupied.add(a)
            occupied.add(b)
            pair_cells.append((a, b))

    # if too few pairs got placed, add supporting 7s and retry a bit
    retry = 0
    while len(pair_cells) < 2 and retry < 50:
        retry += 1
        loc = choice(allinds)
        if loc not in occupied:
            seven_cells.append(loc)
            occupied.add(loc)
        attempts = 0
        while len(pair_cells) < 3 and attempts < 100:
            attempts += 1
            orient = choice((0, 1))
            if orient == 0:
                i = randint(0, h - 1)
                j = randint(0, w - 2)
                a = (i, j)
                b = (i, j + 1)
                if not free((a, b)):
                    continue
                aligned = [s for s in seven_cells if s[0] == i]
                if len(aligned) == 0:
                    continue
                if choice((True, False)):
                    gi = fill(gi, ONE, frozenset({a}))
                    gi = fill(gi, SIX, frozenset({b}))
                else:
                    gi = fill(gi, SIX, frozenset({a}))
                    gi = fill(gi, ONE, frozenset({b}))
                occupied.add(a)
                occupied.add(b)
                pair_cells.append((a, b))
            else:
                i = randint(0, h - 2)
                j = randint(0, w - 1)
                a = (i, j)
                b = (i + 1, j)
                if not free((a, b)):
                    continue
                aligned = [s for s in seven_cells if s[1] == j]
                if len(aligned) == 0:
                    continue
                if choice((True, False)):
                    gi = fill(gi, ONE, frozenset({a}))
                    gi = fill(gi, SIX, frozenset({b}))
                else:
                    gi = fill(gi, SIX, frozenset({a}))
                    gi = fill(gi, ONE, frozenset({b}))
                occupied.add(a)
                occupied.add(b)
                pair_cells.append((a, b))

    for s in seven_cells:
        gi = fill(gi, SEVEN, frozenset({s}))

    go = verify_f341894c(gi)

    if gi == go:
        # force at least one changing pair
        for _ in range(200):
            orient = choice((0, 1))
            if orient == 0:
                i = randint(0, h - 1)
                js = [j for j in range(w - 1) if (i, j) not in occupied and (i, j + 1) not in occupied]
                if len(js) == 0:
                    continue
                sj_candidates = [s for s in seven_cells if s[0] == i]
                if len(sj_candidates) == 0:
                    continue
                s = choice(sj_candidates)
                if s[1] < w - 1:
                    a, b = (i, max(0, s[1] + 1)), (i, min(w - 1, s[1] + 2))
                    if b[1] != a[1] + 1 or not free((a, b)):
                        continue
                    gi = fill(gi, SIX, frozenset({a}))
                    gi = fill(gi, ONE, frozenset({b}))
                    occupied.add(a)
                    occupied.add(b)
                    break
                elif s[1] > 0:
                    a, b = (i, max(0, s[1] - 2)), (i, max(0, s[1] - 1))
                    if b[1] != a[1] + 1 or not free((a, b)):
                        continue
                    gi = fill(gi, ONE, frozenset({a}))
                    gi = fill(gi, SIX, frozenset({b}))
                    occupied.add(a)
                    occupied.add(b)
                    break
            else:
                j = randint(0, w - 1)
                si_candidates = [s for s in seven_cells if s[1] == j]
                if len(si_candidates) == 0:
                    continue
                s = choice(si_candidates)
                if s[0] < h - 1:
                    a, b = (max(0, s[0] + 1), j), (min(h - 1, s[0] + 2), j)
                    if b[0] != a[0] + 1 or not free((a, b)):
                        continue
                    gi = fill(gi, SIX, frozenset({a}))
                    gi = fill(gi, ONE, frozenset({b}))
                    occupied.add(a)
                    occupied.add(b)
                    break
                elif s[0] > 0:
                    a, b = (max(0, s[0] - 2), j), (max(0, s[0] - 1), j)
                    if b[0] != a[0] + 1 or not free((a, b)):
                        continue
                    gi = fill(gi, ONE, frozenset({a}))
                    gi = fill(gi, SIX, frozenset({b}))
                    occupied.add(a)
                    occupied.add(b)
                    break
        go = verify_f341894c(gi)

    return {'input': gi, 'output': go}


def generate_f35d900a(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(5, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (4, 30))
    w = unifint(diff_lb, diff_ub, (4, 30))
    bgc, c1, c2 = sample(cols, 3)
    oh = unifint(diff_lb, diff_ub, (4, h))
    ow = unifint(diff_lb, diff_ub, (4, w))
    loci = randint(0, h - oh)
    locj = randint(0, w - ow)
    bx = box(frozenset({(loci, locj), (loci + oh - 1, locj + ow - 1)}))
    gi = canvas(bgc, (h, w))
    go = canvas(bgc, (h, w))
    gi = fill(gi, c1, {ulcorner(bx), lrcorner(bx)})
    gi = fill(gi, c2, {urcorner(bx), llcorner(bx)})
    go = fill(go, c1, {ulcorner(bx), lrcorner(bx)})
    go = fill(go, c2, {urcorner(bx), llcorner(bx)})
    go = fill(go, c1, neighbors(urcorner(bx)) | neighbors(llcorner(bx)))
    go = fill(go, c2, neighbors(ulcorner(bx)) | neighbors(lrcorner(bx)))
    crns = corners(bx)
    for c in crns:
        cobj = {c}
        remcorns = remove(c, crns)
        belongto = sfilter(bx, lambda ij: manhattan(cobj, {ij}) <= valmin(remcorns, lambda cc: manhattan({ij}, {cc})))
        valids = sfilter(belongto, lambda ij: manhattan(cobj, {ij}) > 1 and manhattan(cobj, {ij}) % 2 == 0)
        go = fill(go, 5, valids)
    return {'input': gi, 'output': go}


def generate_f3b10344(diff_lb: float, diff_ub: float) -> dict:
    bgc = 0
    cols = remove(0, remove(8, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (22, 30))
    w = unifint(diff_lb, diff_ub, (24, 30))
    gi = canvas(bgc, (h, w))

    ncols = unifint(diff_lb, diff_ub, (2, 3))
    usecols = sample(list(cols), ncols)

    occ = set()

    def rect_indices(r, c, hh, ww):
        return frozenset((r + dr, c + dc) for dr in range(hh) for dc in range(ww))

    def clear_with_margin(cells):
        for i, j in cells:
            for a in range(i - 1, i + 2):
                for b in range(j - 1, j + 2):
                    if 0 <= a < h and 0 <= b < w and (a, b) in occ:
                        return False
        return True

    def place_rect(color, r, c, hh, ww):
        nonlocal gi
        cells = rect_indices(r, c, hh, ww)
        gi = fill(gi, color, cells)
        occ.update(cells)

    def try_horizontal_pair(color):
        for _ in range(80):
            hh1 = unifint(diff_lb, diff_ub, (3, 8))
            hh2 = unifint(diff_lb, diff_ub, (3, 8))
            ww1 = unifint(diff_lb, diff_ub, (3, 8))
            ww2 = unifint(diff_lb, diff_ub, (3, 8))
            gap = unifint(diff_lb, diff_ub, (2, max(2, min(10, w - ww1 - ww2 - 4))))
            # Row overlap must be >= 4 so that after inset by 1 on each side, bridge height >= 2
            min_ov = 4
            ov = unifint(diff_lb, diff_ub, (min_ov, min(hh1, hh2)))
            if ov < min_ov:
                continue
            r1_max = h - max(hh1, hh2) - abs(hh1 - hh2)
            if r1_max < 0:
                continue
            r1 = randint(0, min(r1_max, h - hh1))
            # r2 must share ov rows with r1..r1+hh1-1
            r2_lo = max(0, r1 + hh1 - ov - (hh2 - ov))
            r2_lo = max(0, r1 - hh2 + ov)
            r2_hi = min(h - hh2, r1 + hh1 - ov)
            if r2_lo > r2_hi:
                continue
            r2 = randint(r2_lo, r2_hi)
            c1_max = w - (ww1 + gap + ww2)
            if c1_max < 0:
                continue
            c1 = randint(0, c1_max)
            c2 = c1 + ww1 + gap
            a = rect_indices(r1, c1, hh1, ww1)
            b = rect_indices(r2, c2, hh2, ww2)
            if clear_with_margin(a) and clear_with_margin(b):
                place_rect(color, r1, c1, hh1, ww1)
                place_rect(color, r2, c2, hh2, ww2)
                return True
        return False

    def try_vertical_pair(color):
        for _ in range(80):
            ww1 = unifint(diff_lb, diff_ub, (3, 8))
            ww2 = unifint(diff_lb, diff_ub, (3, 8))
            hh1 = unifint(diff_lb, diff_ub, (3, 8))
            hh2 = unifint(diff_lb, diff_ub, (3, 8))
            gap = unifint(diff_lb, diff_ub, (2, max(2, min(10, h - hh1 - hh2 - 4))))
            min_ov = 4
            ov = unifint(diff_lb, diff_ub, (min_ov, min(ww1, ww2)))
            if ov < min_ov:
                continue
            c1_max = w - max(ww1, ww2) - abs(ww1 - ww2)
            if c1_max < 0:
                continue
            c1 = randint(0, min(c1_max, w - ww1))
            c2_lo = max(0, c1 - ww2 + ov)
            c2_hi = min(w - ww2, c1 + ww1 - ov)
            if c2_lo > c2_hi:
                continue
            c2 = randint(c2_lo, c2_hi)
            r1_max = h - (hh1 + gap + hh2)
            if r1_max < 0:
                continue
            r1 = randint(0, r1_max)
            r2 = r1 + hh1 + gap
            a = rect_indices(r1, c1, hh1, ww1)
            b = rect_indices(r2, c2, hh2, ww2)
            if clear_with_margin(a) and clear_with_margin(b):
                place_rect(color, r1, c1, hh1, ww1)
                place_rect(color, r2, c2, hh2, ww2)
                return True
        return False

    def try_single(color):
        for _ in range(80):
            hh = unifint(diff_lb, diff_ub, (3, 8))
            ww = unifint(diff_lb, diff_ub, (3, 8))
            if hh > h or ww > w:
                continue
            r = randint(0, h - hh)
            c = randint(0, w - ww)
            a = rect_indices(r, c, hh, ww)
            if clear_with_margin(a):
                place_rect(color, r, c, hh, ww)
                return True
        return False

    # Ensure at least one bridgeable pair per color used as pair
    paircols = sample(usecols, unifint(diff_lb, diff_ub, (1, ncols)))
    for col in usecols:
        if col in paircols:
            if choice((True, False)):
                ok = try_horizontal_pair(col)
                if not ok:
                    ok = try_vertical_pair(col)
            else:
                ok = try_vertical_pair(col)
                if not ok:
                    ok = try_horizontal_pair(col)
            if not ok:
                try_single(col)
                try_single(col)
        else:
            ns = unifint(diff_lb, diff_ub, (1, 3))
            for _ in range(ns):
                if not try_single(col):
                    break

    go = verify_f3b10344(gi)
    if gi == go:
        # Fallback: force a bridgeable pair
        col = choice(usecols)
        if choice((True, False)):
            if not try_horizontal_pair(col):
                try_vertical_pair(col)
        else:
            if not try_vertical_pair(col):
                try_horizontal_pair(col)
        go = verify_f3b10344(gi)

    return {'input': gi, 'output': go}


