def generate_f3e14006(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, interval(0, 10, 1))
    h = unifint(diff_lb, diff_ub, (10, 20))
    w = unifint(diff_lb, diff_ub, (10, 20))

    rowc, colc = sample(cols, 2)
    rem = remove(rowc, remove(colc, cols))
    nminor_row = unifint(diff_lb, diff_ub, (1, min(3, w - 2)))
    nminor_col = unifint(diff_lb, diff_ub, (1, min(3, h - 2)))
    row_minor_cols = sample(rem, nminor_row)
    rem2 = tuple(c for c in rem if c not in row_minor_cols)
    if len(rem2) == 0:
        rem2 = rem
    col_minor_cols = sample(rem2, nminor_col)

    ri = randint(2, h - 3)
    cj = randint(2, w - 3)

    max_row_occ = max(1, (w - 1) // 4)
    max_col_occ = max(1, (h - 1) // 4)
    row_occ = {}
    col_occ = {}
    for c in row_minor_cols:
        row_occ[c] = randint(1, max_row_occ)
    for c in col_minor_cols:
        col_occ[c] = randint(1, max_col_occ)

    row_positions_pool = [j for j in range(w) if j != cj]
    shuffle(row_positions_pool)
    row_assign = []
    idx = 0
    for c in row_minor_cols:
        for _ in range(row_occ[c]):
            row_assign.append((row_positions_pool[idx], c))
            idx += 1

    col_positions_pool = [i for i in range(h) if i != ri]
    shuffle(col_positions_pool)
    col_assign = []
    idx = 0
    for c in col_minor_cols:
        for _ in range(col_occ[c]):
            col_assign.append((col_positions_pool[idx], c))
            idx += 1

    gi = canvas(0, (h, w))
    gi = fill(gi, rowc, connect((ri, 0), (ri, w - 1)))
    gi = fill(gi, colc, connect((0, cj), (h - 1, cj)))

    for j, c in row_assign:
        gi = fill(gi, c, frozenset({(ri, j)}))
    for i, c in col_assign:
        gi = fill(gi, c, frozenset({(i, cj)}))

    if choice((True, False)):
        gi = fill(gi, choice(row_minor_cols), frozenset({(ri, cj)}))
    else:
        gi = fill(gi, choice((rowc, colc)), frozenset({(ri, cj)}))

    go = verify_f3e14006(gi)
    return {'input': gi, 'output': go}


