def generate_f5c89df1(diff_lb: float, diff_ub: float) -> dict:
    h = 13
    w = 13
    gi = canvas(0, (h, w))

    maxrad = unifint(diff_lb, diff_ub, (1, 4))
    cr = unifint(diff_lb, diff_ub, (maxrad, h - 1 - maxrad))
    cc = unifint(diff_lb, diff_ub, (maxrad, w - 1 - maxrad))
    center = (cr, cc)

    all_offsets = []
    for di in range(-maxrad, maxrad + 1):
        for dj in range(-maxrad, maxrad + 1):
            if di == 0 and dj == 0:
                continue
            if 0 <= cr + di < h and 0 <= cc + dj < w:
                all_offsets.append((di, dj))

    nblue = unifint(diff_lb, diff_ub, (1, len(all_offsets)))
    blue_offsets = sample(all_offsets, nblue)
    blue_cells = frozenset((cr + di, cc + dj) for di, dj in blue_offsets)

    valid_reds = []
    for i in range(h):
        for j in range(w):
            if (i, j) == center or (i, j) in blue_cells:
                continue
            ok = True
            for di, dj in blue_offsets:
                ni, nj = i + di, j + dj
                if not (0 <= ni < h and 0 <= nj < w):
                    ok = False
                    break
            if ok:
                valid_reds.append((i, j))

    maxreds = min(len(valid_reds), unifint(diff_lb, diff_ub, (1, 5)))
    if maxreds < 1:
        maxreds = 1
    nreds = unifint(diff_lb, diff_ub, (1, maxreds))
    red_cells = sample(valid_reds, nreds)

    gi = fill(gi, 8, blue_cells)
    gi = fill(gi, 3, frozenset({center}))
    gi = fill(gi, 2, frozenset(red_cells))

    go = verify_f5c89df1(gi)
    return {'input': gi, 'output': go}


def generate_f76d97a5(diff_lb: float, diff_ub: float) -> dict:
    cols = remove(0, remove(5, interval(0, 10, 1)))
    h = unifint(diff_lb, diff_ub, (4, 30))
